/* AUTO-GENERATED — Iowa Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["IA"] = {"code":"IA","name":"Iowa","agency":"Iowa DOT","agencyShort":"DOT","handbook":"https://iowadot.gov/drivers-licenses-ids/commercial-drivers","links":{},"en":[{"q":"What is the maximum legal width of a commercial vehicle on Iowa highways without an oversize permit?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"Iowa Code section 321.454 sets the maximum width of a vehicle, including load, at 8 feet 6 inches (102 inches). Anything wider requires an oversize permit. Source: Iowa Code 321.454; Iowa DOT oversize/overweight permit requirements.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle and load on Iowa highways without a permit?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","14 feet 6 inches"],"answer":0,"explanation":"Iowa Code section 321.456 limits vehicle height to 13 feet 6 inches. Loads taller than this require an oversize permit. Source: Iowa Code 321.456; Iowa DOT permit requirements.","handbook":"","hbref":""},{"q":"On Iowa highways, what is the maximum legal length of a semitrailer operating in a tractor-semitrailer combination without a permit?","options":["53 feet","48 feet","57 feet","45 feet"],"answer":0,"explanation":"Iowa allows a semitrailer up to 53 feet long (loaded or empty) in a tractor-semitrailer combination without a permit. Lowboy trailers hauling construction equipment may be up to 57 feet. Source: Iowa Code chapter 321; Iowa DOT permit requirements.","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight allowed on Iowa highways without an overweight permit?","options":["80,000 pounds","73,280 pounds","84,000 pounds","76,000 pounds"],"answer":0,"explanation":"Iowa Code section 321.463 caps the maximum gross weight at 80,000 pounds, consistent with the federal limit. Exceeding it requires an overweight permit. Source: Iowa Code 321.463; Iowa DOT.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a single axle on Iowa highways?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"answer":0,"explanation":"Iowa Code section 321.463 limits a single axle to 20,000 pounds, the same as the federal Interstate standard. Source: Iowa Code 321.463; Iowa DOT.","handbook":"","hbref":""},{"q":"What is the maximum weight allowed on a tandem axle group on Iowa highways?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"answer":0,"explanation":"Iowa Code section 321.463 limits a tandem axle to 34,000 pounds, matching the federal standard. Source: Iowa Code 321.463; Iowa DOT.","handbook":"","hbref":""},{"q":"Iowa uses which method to determine the maximum gross weight on any group of two or more consecutive axles?","options":["The federal Bridge Formula (Formula B)","A flat 80,000 lb cap regardless of spacing","The total tire-load rating only","A 600-pounds-per-inch-of-tire-width rule"],"answer":0,"explanation":"Iowa applies the federal Bridge Formula (W = 500[(LN/(N-1)) + 12N + 36]) to limit weight on groups of consecutive axles based on the number of axles (N) and the spacing (L). Source: Iowa Code 321.463; 23 CFR 658.17; Iowa DOT.","handbook":"","hbref":""},{"q":"In the federal Bridge Formula as applied in Iowa, what do the variables L and N represent?","options":["L is the distance in feet between the outer axles of the group; N is the number of axles in the group","L is the load in pounds; N is the number of tires","L is the legal length of the trailer; N is the net weight","L is the lane width; N is the number of permits required"],"answer":0,"explanation":"In W = 500[(LN/(N-1)) + 12N + 36], L is the distance in feet between the outermost axles of any group of two or more consecutive axles, and N is the number of axles in that group. Source: 23 CFR 658.17 as adopted by Iowa Code 321.463.","handbook":"","hbref":""},{"q":"How do Iowa's gross and axle weight limits on the Interstate system compare to those on the state's primary (non-Interstate) highways?","options":["The 80,000 lb gross and 20,000/34,000 lb axle limits are the same; certain higher weights are allowed only on non-Interstate roads","Non-Interstate roads allow only 73,280 lb gross","The Interstate allows 90,000 lb gross","There are no weight limits on non-Interstate roads"],"answer":0,"explanation":"Iowa's basic limits (80,000 lb gross, 20,000 lb single, 34,000 lb tandem) apply on both Interstate and primary highways. Some statutory exceptions for additional weight apply only to the non-Interstate system, since the Interstate is federally capped at 80,000 lb. Source: Iowa Code 321.463; Iowa DOT.","handbook":"","hbref":""},{"q":"An Iowa five-axle livestock vehicle with a spread-axle trailer meeting spacing requirements may carry a higher gross weight on which roads?","options":["Non-Interstate (primary) highways only, up to 86,000 pounds","Interstate highways only, up to 86,000 pounds","All highways including Interstates, up to 90,000 pounds","Only gravel county roads, up to 80,000 pounds"],"answer":0,"explanation":"Iowa Code section 321.463 allows a five-axle livestock vehicle up to 86,000 lb gross on non-Interstate highways when it has at least 61 feet between the first and fifth axles and at least 8 feet 1 inch between the two rear (spread) axles. This does not apply on the Interstate. Source: Iowa Code 321.463.","handbook":"","hbref":""},{"q":"Under Iowa law, a vehicle hauling raw agricultural products may exceed its registered (registration) gross weight by up to what percentage?","options":["25 percent","10 percent","15 percent","50 percent"],"answer":0,"explanation":"Iowa allows trucks transporting raw agricultural products to operate up to 25 percent above their registered weight while in Iowa (still subject to axle and Bridge Formula limits). Source: Iowa DOT motor carrier guidance; Iowa Code chapter 321.","handbook":"","hbref":""},{"q":"When is an Iowa DOT oversize/overweight permit required for a load?","options":["When the load is nondivisible and exceeds the legal size or weight limits","Whenever the vehicle weighs more than 26,001 pounds","Only when the vehicle crosses a state line","Any time a CDL driver operates after dark"],"answer":0,"explanation":"A permit is issued for a nondivisible vehicle or load that exceeds the statutory size or weight limits. A load is considered nondivisible if separating it would destroy its value, compromise its intended use, or require more than eight work hours to dismantle. Source: Iowa DOT oversize/overweight permit requirements; Iowa Code chapter 321E.","handbook":"","hbref":""},{"q":"What does it mean for a load to be \"nondivisible\" so that it qualifies for an Iowa oversize/overweight permit?","options":["It cannot be reasonably reduced to legal dimensions/weight without destroying its value, compromising its use, or taking more than 8 work hours to dismantle","It is sealed in a locked container","It is owned by a single carrier","It weighs exactly 80,000 pounds"],"answer":0,"explanation":"Iowa, following federal definitions, treats a load as nondivisible when reducing it to legal limits would destroy its value, compromise its intended use, or require more than eight work hours to dismantle with proper equipment. Divisible loads generally cannot be permitted. Source: Iowa DOT permit requirements; 23 CFR 658.5.","handbook":"","hbref":""},{"q":"How does a carrier apply for an Iowa DOT oversize/overweight permit?","options":["Online through the Iowa DOT permit system (ia.gotpermits.com) or by mail","Only in person at the county sheriff's office","By calling the Federal Motor Carrier Safety Administration","Only through the vehicle's manufacturer"],"answer":0,"explanation":"Iowa DOT oversize/overweight permits are obtained online through the state's permit portal (ia.gotpermits.com) or by mail. Permits cover only state and Interstate highways; separate permits are needed for city or county roads. Source: Iowa DOT oversize/overweight permits.","handbook":"","hbref":""},{"q":"A standard Iowa single-trip oversize/overweight permit is typically valid for how long?","options":["5 days","24 hours","30 days","1 year"],"answer":0,"explanation":"A standard Iowa single-trip (single/round trip) permit is valid for 5 calendar days. Multi-trip permits run 60 days and annual permits 12 months. Source: Iowa DOT oversize/overweight permit types.","handbook":"","hbref":""},{"q":"An Iowa DOT oversize/overweight permit authorizes travel on which roadways?","options":["State and Interstate highways only; separate permits are needed for city and county roads","All public roads in Iowa, including all city streets and county roads","Only the Interstate system","Only private haul roads"],"answer":0,"explanation":"Iowa DOT permits cover the state primary and Interstate highway system. To travel on city streets or county roads, a carrier must obtain separate permits from those local jurisdictions. Source: Iowa DOT oversize/overweight permit requirements.","handbook":"","hbref":""},{"q":"On Iowa highways, oversize-load warning signs and corner flags are generally required once the vehicle and load exceed which dimensions?","options":["75 feet in length, 8 feet 6 inches in width, or 14 feet 4 inches in height","40 feet in length or 8 feet in width","100 feet in length or 12 feet in width","53 feet in length or 10 feet in width"],"answer":0,"explanation":"Iowa requires \"Oversize Load\" signs and flags when a permitted vehicle and load exceeds 75 feet in length, 8 feet 6 inches in width, and/or 14 feet 4 inches in height. Red flags (18-inch square) mark the load's extremities. Source: Iowa DOT/Iowa Admin. Code ch. 761-511 permit conditions.","handbook":"","hbref":""},{"q":"For an oversize load, at approximately what width does Iowa generally begin requiring at least one escort (pilot) vehicle?","options":["When the load is wider than 14 feet 6 inches","When the load is wider than 8 feet 6 inches","When the load is wider than 10 feet","Escorts are never required in Iowa"],"answer":0,"explanation":"In Iowa, loads over 14 feet 6 inches wide generally require at least one escort vehicle; loads up to 14 feet 6 inches that occupy more than half the roadway may instead use a front escort or amber warning lights. Specific routes can impose stricter requirements. Source: Iowa DOT/Iowa Admin. Code ch. 761-511 permit conditions.","handbook":"","hbref":""},{"q":"Under typical Iowa permit conditions, when may a large oversize load (one too big for 24/7 travel) move?","options":["From one-half hour before sunrise to one-half hour after sunset, including Saturdays and Sundays, with proper safety equipment","Only between midnight and 4 a.m.","Only on weekdays, never on weekends or holidays","At any time with no time-of-day restriction"],"answer":0,"explanation":"Iowa permit conditions allow larger oversize loads to travel from one-half hour before sunrise to one-half hour after sunset, including weekends, with proper lighting/marking. Smaller permitted loads (within set limits) may move continuously (24/7). Source: Iowa DOT/Iowa Admin. Code ch. 761-511 permit conditions.","handbook":"","hbref":""},{"q":"Iowa offers a specialty oversize/overweight permit specifically for hauling which forest-related commodity at higher-than-legal weights?","options":["Raw forest products","Finished furniture","Paper currency","Christmas ornaments"],"answer":0,"explanation":"Among Iowa's specialty permits is a Raw Forest Products permit, which (like the agricultural variances) accommodates harvesting/hauling of unprocessed forest products above standard limits under set conditions. Source: Iowa DOT oversize/overweight permit types.","handbook":"","hbref":""},{"q":"Under Iowa rules, which CDL class is required to operate a combination vehicle with a gross combination weight rating (GCWR) of 26,001 pounds or more, where the towed unit(s) have a GVWR of more than 10,000 pounds?","options":["Class A","Class B","Class C","Class D (chauffeur)"],"answer":0,"explanation":"Iowa issues a Class A CDL for combination vehicles with a GCWR of 26,001+ lbs where the towed unit exceeds 10,000 lbs GVWR. Source: Iowa DOT CDL Manual / 761 IAC 607.16; Iowa DOT 'Driver's License Types, Restrictions, & Endorsements.'","handbook":"","hbref":""},{"q":"An Iowa driver operates a single straight truck with a GVWR of 30,000 pounds and tows a small trailer rated at 8,000 pounds GVWR. Which CDL class is required?","options":["Class C","Class A","Class B","No CDL is required"],"answer":2,"explanation":"Iowa's Class B CDL covers a single vehicle with a GVWR of 26,001+ lbs, including towing a unit not over 10,000 lbs GVWR. Since the trailer is under 10,001 lbs, this is Class B, not Class A. Source: Iowa DOT CDL Manual / Iowa DOT license types page; 761 IAC 607.16.","handbook":"","hbref":""},{"q":"In Iowa, a vehicle that is under 26,001 lbs GVWR but is designed to transport 16 or more people (including the driver), or is used to carry placarded hazardous materials, requires which CDL class?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"Iowa's Class C CDL applies to vehicles below the Class A/B weight thresholds that either carry 16+ persons (including the driver) or transport hazardous materials requiring placards. Source: Iowa DOT 'Driver's License Types, Restrictions, & Endorsements'; 761 IAC 607.16.","handbook":"","hbref":""},{"q":"In Iowa, what is the minimum age to obtain a CDL for INTRASTATE driving (operating commercial vehicles only within Iowa)?","options":["16 years old","18 years old","21 years old","19 years old"],"answer":1,"explanation":"Iowa allows a CDL for intrastate (within-Iowa) commerce at age 18. Interstate driving requires age 21. Source: Iowa DOT Commercial Drivers / Iowa Tax And Tags CDL Endorsements; FMCSA standard adopted by Iowa.","handbook":"","hbref":""},{"q":"In Iowa, what is the minimum age to operate a commercial motor vehicle in INTERSTATE commerce (crossing state lines)?","options":["18 years old","19 years old","21 years old","20 years old"],"answer":2,"explanation":"Iowa, following the federal standard, requires drivers to be at least 21 to drive in interstate commerce or to transport hazardous materials. Drivers 18-20 are limited to intrastate operation. Source: Iowa DOT Commercial Drivers; FMCSA 49 CFR 391.11 as applied in Iowa.","handbook":"","hbref":""},{"q":"Which CDL endorsement does Iowa require for transporting hazardous materials in quantities that require the vehicle to be placarded?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"answer":1,"explanation":"The H (Hazardous Materials) endorsement is required to haul placarded hazmat. Source: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual. (Note: an X endorsement indicates a combined tank + hazmat endorsement.)","handbook":"","hbref":""},{"q":"Beyond passing the written knowledge test, what additional federal requirement must an Iowa applicant satisfy to obtain (and to renew) the HazMat (H) endorsement?","options":["A separate road skills test in a tanker","A TSA fingerprint-based security threat assessment (background check)","A minimum of two years of CDL experience","A vision waiver from the FMCSA"],"answer":1,"explanation":"The H endorsement requires a fingerprint-based TSA security threat assessment at initial application and again at each renewal, in addition to the HazMat knowledge test. Source: Iowa Tax And Tags CDL Endorsements; TSA HazMat Endorsement Threat Assessment Program adopted in Iowa.","handbook":"","hbref":""},{"q":"Which Iowa CDL endorsement is required to drive a tank vehicle, defined as transporting liquids or gases in a tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of 1,000 gallons or more?","options":["N (Tank)","H (HazMat)","T (Doubles/Triples)","P (Passenger)"],"answer":0,"explanation":"The N (Tank) endorsement covers tank vehicles meeting the 119-gallon individual and 1,000-gallon aggregate capacity thresholds, and requires passing the Tanker knowledge exam. Source: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual.","handbook":"","hbref":""},{"q":"Which Iowa CDL endorsement is required to pull double or triple trailers?","options":["P endorsement","N endorsement","T endorsement","S endorsement"],"answer":2,"explanation":"The T (Doubles/Triples) endorsement, obtained by passing the Double and Triple Trailers knowledge exam, is required to pull multiple trailers. Source: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual.","handbook":"","hbref":""},{"q":"Regarding triple trailers in Iowa, which statement is correct for a driver holding the T endorsement?","options":["Iowa law prohibits operating triple trailers within the state, even though a resident may obtain the T endorsement for use in other states","Triple trailers may be operated on any Iowa interstate highway","Triple trailers are allowed only on Iowa toll roads","Iowa requires a separate 'Y' endorsement for triples"],"answer":0,"explanation":"Iowa law prohibits triple-trailer operation within the state; however, an Iowa resident may still obtain the T endorsement to operate triples lawfully in states that permit them. Source: Iowa Tax And Tags CDL Endorsements; Iowa Code Ch. 321 length/combination limits.","handbook":"","hbref":""},{"q":"Which Iowa CDL endorsement is required to drive a vehicle designed to transport 16 or more people, including the driver?","options":["S (School Bus)","P (Passenger)","N (Tank)","C (Chauffeur)"],"answer":1,"explanation":"The P (Passenger) endorsement is required for vehicles designed to carry 16 or more persons including the driver. It requires the passenger knowledge test plus skills testing in a representative vehicle. Source: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual.","handbook":"","hbref":""},{"q":"In Iowa, what must a driver hold in addition to the School Bus (S) endorsement in order to legally operate a school bus?","options":["The Passenger (P) endorsement","The Tank (N) endorsement","The HazMat (H) endorsement","Nothing further; the S endorsement alone is sufficient"],"answer":0,"explanation":"Iowa requires BOTH the School Bus (S) and Passenger (P) endorsements to operate a school bus; the P endorsement alone is not valid for school bus operation. Source: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual.","handbook":"","hbref":""},{"q":"How long must an applicant hold an Iowa Commercial Learner's Permit (CLP) before being allowed to take the CDL skills (road) test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"Federal rule, applied in Iowa, requires holding the CLP for a minimum of 14 days before taking the skills test. Source: Iowa DOT Commercial Learner Permits (CLP) page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"What is the validity period of an Iowa Commercial Learner's Permit (CLP)?","options":["180 days, renewable once","One year from issuance, with no renewal period","Two years, renewable","90 days, non-renewable"],"answer":1,"explanation":"An Iowa CLP costs $12 and is valid for one year from the date of issuance, with no renewal period. Source: Iowa DOT Commercial Learner Permits (CLP) page.","handbook":"","hbref":""},{"q":"What must an applicant already possess before applying for an Iowa Commercial Learner's Permit (CLP) or CDL?","options":["A valid Iowa non-commercial driver's license","A federal TWIC card","Two years of military driving experience","A Class M motorcycle license"],"answer":0,"explanation":"Iowa requires applicants to hold a valid Iowa non-commercial driver's license before applying for a CLP or CDL. Source: Iowa DOT Commercial Learner Permits (CLP) page / Iowa Tax And Tags.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) in Iowa must be completed through which entity before testing?","options":["Any private driving instructor of the applicant's choice","A provider listed on the FMCSA Training Provider Registry (TPR)","The local county treasurer's office","The Iowa State Patrol training academy only"],"answer":1,"explanation":"ELDT must be provided by an entity listed on the FMCSA Training Provider Registry; only registered providers may deliver the required training. Source: FMCSA Training Provider Registry; Iowa DOT Commercial Drivers (ELDT applies in Iowa).","handbook":"","hbref":""},{"q":"ELDT (Entry-Level Driver Training) is required for first-time applicants of which of the following in Iowa?","options":["A Class A or Class B CDL, and first-time S, P, or H endorsements","Only the HazMat (H) endorsement","Only the Doubles/Triples (T) endorsement","Renewals of any existing CDL"],"answer":0,"explanation":"ELDT is required for first-time Class A or Class B CDL applicants, for a Class B-to-Class A upgrade, and for first-time School Bus (S), Passenger (P), or HazMat (H) endorsements (theory only for H). Source: FMCSA ELDT rule (CLP obtained on/after Feb 7, 2022); applies in Iowa.","handbook":"","hbref":""},{"q":"An Iowa CDL holder who drives a commercial vehicle in interstate commerce and is NOT exempt from federal physical-qualification rules should self-certify in which medical category?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","Excepted intrastate"],"answer":1,"explanation":"A non-excepted interstate driver must self-certify as such AND keep a current Medical Examiner's Certificate on file with the Iowa DOT; failure to do so leads to a downgrade. Source: Iowa DOT Medical Cards & Certification; 761 IAC 607.50.","handbook":"","hbref":""},{"q":"Which medical self-certification category does NOT require submitting a Medical Examiner's Certificate to the Iowa DOT?","options":["Non-excepted interstate","Non-excepted intrastate","All four categories must submit it","Only out-of-state drivers are exempt"],"answer":1,"explanation":"Only the non-excepted interstate category must submit the Medical Examiner's Certificate to the Iowa DOT. Non-excepted intrastate drivers carry it but need not file it, and excepted categories need none; intrastate categories receive a 'K' restriction. Source: Iowa DOT Medical Cards & Certification; 761 IAC 607.50.","handbook":"","hbref":""},{"q":"Which set of documents does the Iowa DOT require an applicant to provide when first applying for a CDL/CLP?","options":["Proof of identity/lawful presence, Social Security number, and Iowa residency","Only a passport","A military DD-214 form only","Proof of vehicle insurance and registration only"],"answer":0,"explanation":"Iowa requires proof of identity and U.S. citizenship or lawful presence, a Social Security number, and verification of Iowa residency (e.g., current Iowa-address license). Source: Iowa DOT Commercial Learner Permits (CLP) page; 761 IAC 607.","handbook":"","hbref":""},{"q":"In Iowa, what is the maximum alcohol concentration a person may have and still legally operate a commercial motor vehicle (CMV)?","options":["0.04","0.08","0.02","0.05"],"answer":0,"explanation":"Iowa Code 321.208(1)(a) disqualifies a driver who operates a CMV with an alcohol concentration (as defined in 321J.1) of 0.04 or more. The legal limit for a CMV is therefore below 0.04, half the 0.08 limit that applies to ordinary drivers. Source: Iowa Code 321.208 / Iowa CDL Manual.","handbook":"","hbref":""},{"q":"Under Iowa's implied consent law, what happens to a CDL holder who refuses to submit to chemical testing required under Chapter 321J after a lawful request?","options":["It is treated as a major offense, the same as an alcohol conviction, and brings disqualification","Nothing happens to the CDL because refusal is a constitutional right","Only a small civil fine is assessed with no disqualification","The driver receives a written warning for a first refusal"],"answer":0,"explanation":"Iowa Code 321.208(2)(b) and 321.208(13) treat refusal to submit to chemical testing under Chapter 321J as a major offense, carrying the same disqualification as an OWI conviction. Source: Iowa Code 321.208 / Iowa CDL Manual.","handbook":"","hbref":""},{"q":"How long is a driver disqualified from operating a CMV for a FIRST major offense (such as OWI or driving a CMV with 0.04 or more) when NOT hauling placarded hazardous materials?","options":["1 year","3 years","60 days","Lifetime"],"answer":0,"explanation":"Iowa Code 321.208(1) and (2) impose a one-year CMV disqualification for a first major offense such as operating with an alcohol concentration of 0.04 or more, OWI, or test refusal. Source: Iowa Code 321.208 (mirrors 49 CFR 383.51).","handbook":"","hbref":""},{"q":"If a first major offense (such as OWI or 0.04 BAC) occurs while the driver is operating a CMV transporting placarded hazardous materials, the disqualification increases to how long?","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"Iowa Code 321.208(3) raises the first-offense disqualification from one year to three years when the offense occurs while the CMV is transporting hazardous materials requiring placards under 49 CFR 383.5. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"What is the penalty for committing a SECOND major offense (in two or more separate incidents), such as a second OWI or test refusal?","options":["Lifetime disqualification (which may later be reduced to 10 years)","3-year disqualification","1-year disqualification","120-day disqualification"],"answer":0,"explanation":"Iowa Code 321.208(4) disqualifies a driver for life upon two or more major offenses from separate incidents. The lifetime disqualification may be reduced to 10 years as provided in 49 CFR 383.51 by department rule. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"How long is a driver disqualified for accumulating TWO serious traffic violations while operating a CMV within a three-year period?","options":["60 days","120 days","30 days","1 year"],"answer":0,"explanation":"Iowa Code 321.208(8) imposes a 60-day disqualification for two serious traffic violations within any three-year period. Source: Iowa Code 321.208 / Iowa CDL Manual.","handbook":"","hbref":""},{"q":"How long is a driver disqualified for accumulating THREE serious traffic violations while operating a CMV within a three-year period?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"Iowa Code 321.208(8) imposes a 120-day disqualification for three serious traffic violations within any three-year period. Multiple disqualification periods run consecutively. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation that counts toward a CMV disqualification in Iowa?","options":["Speeding 15 mph or more over the legal speed limit","Speeding 5 mph over the legal speed limit","A parking violation in a CMV","A vehicle weight (overweight) violation"],"answer":0,"explanation":"Iowa Code 321.208(7)(d) lists speeding 15 mph or more over the limit as a serious violation. Parking and vehicle weight violations are expressly excluded from the serious-violation count. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"Under Iowa law, texting while driving a commercial motor vehicle is categorized as which type of CDL violation?","options":["A serious traffic violation","A major offense bringing a 1-year disqualification","An out-of-service order violation","A minor equipment violation with no disqualification effect"],"answer":0,"explanation":"Iowa Code 321.208(7)(i) lists violating a law prohibiting texting while driving a CMV as a serious traffic violation, which counts toward the 60-day/120-day disqualifications. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"Using a hand-held mobile telephone while driving a CMV, in violation of a traffic-control law, is treated in Iowa as:","options":["A serious traffic violation counting toward disqualification","A major offense with a lifetime disqualification","A violation with no CDL consequence","An automatic 1-year disqualification"],"answer":0,"explanation":"Iowa Code 321.208(7)(j) lists violating a law restricting or prohibiting use of a hand-held mobile telephone while driving a CMV as a serious traffic violation, which counts toward the 60/120-day disqualification thresholds. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"For a FIRST violation of an out-of-service order (not involving hazmat or a vehicle designed for 16+ passengers), the Iowa disqualification range is:","options":["No less than 180 days and no more than 1 year","No less than 60 days and no more than 120 days","No less than 30 days and no more than 90 days","No less than 2 years and no more than 5 years"],"answer":0,"explanation":"Iowa Code 321.208(10)(a) sets the first out-of-service order violation at no less than 180 days and no more than one year. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"For a SECOND violation of an out-of-service order in separate incidents within 10 years (non-hazmat), the Iowa disqualification range is:","options":["No less than 2 years and no more than 5 years","No less than 180 days and no more than 1 year","No less than 1 year and no more than 3 years","Lifetime"],"answer":0,"explanation":"Iowa Code 321.208(10)(a) sets a second out-of-service order violation (within a 10-year period) at no less than two years and no more than five years. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"A first violation of an out-of-service order committed while transporting placarded hazardous materials, or while operating a CMV designed to carry more than 15 passengers, results in a disqualification of:","options":["1 year","180 days","3 years","60 days"],"answer":0,"explanation":"Iowa Code 321.208(10)(b) imposes a one-year disqualification for a first out-of-service order violation when hauling placarded hazmat or operating a CMV designed for more than 15 passengers (driver included). Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"How long is a driver disqualified for a FIRST railroad-highway grade crossing violation committed while operating a CMV in Iowa?","options":["60 days","120 days","30 days","1 year"],"answer":0,"explanation":"Iowa Code 321.208(11)(a) imposes a 60-day disqualification for a first railroad crossing at grade violation (under 321.341 or 321.343) committed while operating a CMV. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"A driver convicted of a SECOND railroad-highway grade crossing violation in a CMV, within three years of the first, is disqualified for:","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"Iowa Code 321.208(11)(b) imposes a 120-day disqualification for a second railroad crossing at grade violation in a CMV occurring within three years of the first. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"A driver convicted of a THIRD or subsequent railroad-highway grade crossing violation in a CMV, within three years of the first, is disqualified for:","options":["1 year","120 days","60 days","180 days"],"answer":0,"explanation":"Iowa Code 321.208(11)(c) imposes a one-year disqualification for a third or subsequent railroad crossing at grade violation in a CMV occurring within three years of the first. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"Using a commercial motor vehicle in the commission of a felony involving the manufacture, distribution, or dispensing of a controlled substance results in what CDL penalty in Iowa?","options":["Lifetime disqualification with no possibility of reduction","1-year disqualification","3-year disqualification","120-day disqualification"],"answer":0,"explanation":"Iowa Code 321.208(5) imposes a lifetime disqualification, not subject to the 10-year reduction, when a CMV is used in a felony involving manufacturing, distributing, or dispensing a controlled substance. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"When the Iowa DOT receives a record of a disqualifying conviction, how much advance notice does it give before the CMV disqualification takes effect?","options":["30 days","10 days","60 days","24 hours"],"answer":0,"explanation":"Iowa Code 321.208(12) and (13) provide that the department disqualifies the driver without a preliminary hearing upon 30 days' advance notice; the disqualification's effective date is 30 days after notification. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"A CMV driver found by an enforcement officer to have an alcohol concentration of 0.04 or more is, in addition to facing disqualification, immediately:","options":["Placed out of service for 24 hours","Allowed to drive after a 1-hour rest","Permitted to continue if under 0.08","Fined $25 and released to drive"],"answer":0,"explanation":"Federal rules adopted in Iowa (49 CFR 392.5) require any driver with an alcohol concentration of 0.04 or greater to be placed out of service for 24 hours, separate from the formal disqualification under Iowa Code 321.208. Source: 49 CFR 392.5 / Iowa CDL Manual.","handbook":"","hbref":""},{"q":"Two separate major-offense convictions arising from two separate incidents lead to a lifetime CDL disqualification in Iowa. Under federal rule adopted by Iowa, this lifetime period may be reduced to a minimum of:","options":["10 years","5 years","3 years","1 year"],"answer":0,"explanation":"Iowa Code 321.208(4) makes a lifetime disqualification (for two or more major offenses) subject to reduction to a 10-year disqualification as provided in 49 CFR 383.51 and adopted by department rule. Source: Iowa Code 321.208.","handbook":"","hbref":""},{"q":"Under Iowa's Move Over law, when you approach a stopped emergency vehicle with its flashing lights on while driving on an interstate with two lanes in your direction, what does Iowa Code require you to do first?","options":["Move into a lane not adjacent to the stopped vehicle if it is safe to do so","Come to a complete stop on the shoulder until the emergency vehicle leaves","Sound your horn and continue past in the same lane at your current speed","Pull onto the left shoulder and wait for a peace officer to wave you on"],"answer":0,"explanation":"Iowa Code 321.323A requires a driver approaching a stationary vehicle with activated flashing lights, on a road with two or more lanes in the driver's direction, to make a lane change into a lane not adjacent to that vehicle when it is safe and lawful. Source: Iowa Code 321.323A; Iowa DOT 'Move Over or Slow Down.'","handbook":"","hbref":""},{"q":"Under Iowa's Move Over law, if changing lanes away from a stopped vehicle displaying flashing lights is impossible or unsafe, what must an Iowa driver do?","options":["Maintain the posted speed but turn on hazard flashers","Reduce speed to less than the posted speed limit and be prepared to stop","Reduce speed to exactly 20 mph below the posted speed limit","Slow to 10 mph regardless of the posted speed limit"],"answer":1,"explanation":"Iowa Code 321.323A states that when a lane change is impossible, prohibited, or unsafe, the driver must reduce speed to a reasonable and proper speed that is less than the posted speed limit and be prepared to stop. Iowa does NOT set a fixed mph reduction. Source: Iowa Code 321.323A; Iowa DOT.","handbook":"","hbref":""},{"q":"Which of these stationary vehicles, when displaying its required flashing or warning lights, is covered by Iowa's Move Over law (Iowa Code 321.323A)?","options":["Only law enforcement and fire vehicles","Only ambulances and tow trucks","A solid waste or recycling collection vehicle","Only vehicles owned by the Iowa DOT"],"answer":2,"explanation":"Iowa Code 321.323A covers stationary authorized emergency vehicles, tow/recovery, maintenance and construction vehicles, solid waste or recycling collection vehicles with flashing lights, and any motor vehicle continuously displaying its hazard lamps. Source: Iowa Code 321.323A; Iowa DOT.","handbook":"","hbref":""},{"q":"On a rural Iowa interstate highway, what is the maximum speed limit that applies to a tractor-trailer?","options":["55 mph","60 mph","65 mph","70 mph"],"answer":3,"explanation":"Iowa Code 321.285 sets the speed limit on the interstate road system at 70 mph for all vehicular traffic. Iowa does not impose a separate, lower truck speed limit on interstates. Source: Iowa Code 321.285.","handbook":"","hbref":""},{"q":"Does Iowa set a lower interstate speed limit for trucks than for passenger cars?","options":["Yes, trucks are limited to 65 mph while cars may drive 70 mph","No, the 70 mph interstate limit applies to all vehicular traffic alike","Yes, trucks are limited to 60 mph statewide","Yes, trucks over 26,000 lbs are limited to 55 mph"],"answer":1,"explanation":"Unlike some states with 'split' speed limits, Iowa Code 321.285 applies the 70 mph interstate maximum to all vehicular traffic, with no separate posted truck limit. Source: Iowa Code 321.285.","handbook":"","hbref":""},{"q":"An Iowa transit bus carrying passengers for hire approaches a railroad grade crossing. Where must the driver stop?","options":["Not less than 15 feet and not more than 50 feet from the nearest rail","Not less than 10 feet and not more than 25 feet from the nearest rail","Not less than 25 feet and not more than 75 feet from the nearest rail","Within 5 feet of the nearest rail"],"answer":0,"explanation":"Iowa Code 321.343 requires a vehicle carrying passengers for hire, a school bus, or a placarded hazardous-materials vehicle to stop within 50 feet but not less than 15 feet from the nearest rail before crossing. Source: Iowa Code 321.343.","handbook":"","hbref":""},{"q":"A driver hauling a placarded load of hazardous material in Iowa reaches a railroad crossing that is posted with an 'EXEMPT' sign. What is required?","options":["Stop within 15 to 50 feet of the nearest rail anyway","Stop only if a train is in sight","The driver is not required to stop at that crossing","Stop and set out warning triangles before crossing"],"answer":2,"explanation":"Iowa Code 321.343 requires the stop for buses, passenger-for-hire vehicles, and placarded HazMat vehicles, but a crossing posted with an official 'EXEMPT' sign does not require a stop. Source: Iowa Code 321.343; Iowa CDL Manual.","handbook":"","hbref":""},{"q":"After stopping at a railroad crossing, what must an Iowa school bus driver do before proceeding across the tracks?","options":["Sound the horn twice and proceed without delay","Open the entrance door, look and listen for trains, then cross only when safe","Wait a full 60 seconds regardless of conditions","Activate the amber warning lamps and ease across"],"answer":1,"explanation":"Under Iowa Code 321.343, after stopping 15 to 50 feet from the nearest rail the school bus driver must open the entrance door, look and listen for an approaching train, and not proceed until it is safe. Source: Iowa Code 321.343.","handbook":"","hbref":""},{"q":"On a two-lane Iowa highway, a school bus stops, activates its flashing red lamps, and extends its stop arm to unload children. What must an approaching motorist do?","options":["Slow to 20 mph and pass with caution","Stop no closer than 15 feet from the bus and remain stopped until the stop arm is withdrawn","Stop only if children are visible in the roadway","Move to the far lane and pass the bus slowly"],"answer":1,"explanation":"Iowa Code 321.372 requires vehicles meeting or overtaking a stopped school bus with red lamps flashing and stop arm extended to stop no closer than 15 feet and remain stopped until the stop arm is withdrawn and the bus moves again. Source: Iowa Code 321.372.","handbook":"","hbref":""},{"q":"Under Iowa's school bus law, on what kind of highway may a driver who MEETS a stopped school bus traveling in the opposite direction continue without stopping?","options":["Any highway with a painted center line","A highway providing two or more lanes of travel in each direction","Any highway with a posted speed of 55 mph or higher","A highway with paved shoulders at least 8 feet wide"],"answer":1,"explanation":"Iowa Code 321.372 provides that a driver on a highway with two or more lanes in each direction need not stop upon MEETING a school bus traveling in the opposite direction, even if it is stopped. On undivided roads, all directions must stop. Source: Iowa Code 321.372.","handbook":"","hbref":""},{"q":"On an Iowa highway with two lanes in each direction separated by a median, a school bus stops in the opposite-direction lanes with its red lights flashing. A driver traveling the other way is:","options":["Required to stop until the red lights go off","Required to slow to 10 mph but may continue","Not required to stop because the road has two or more lanes in each direction","Required to stop only if the median is less than 6 feet wide"],"answer":2,"explanation":"Iowa Code 321.372's divided-highway exception turns on the number of lanes: on a highway with two or more lanes in each direction, drivers meeting an opposite-direction stopped bus need not stop. Source: Iowa Code 321.372.","handbook":"","hbref":""},{"q":"A school bus is operating on an Iowa highway with four or more lanes. Regarding pupils who must cross the highway, the bus:","options":["May load or unload them anywhere as long as red lights are on","Shall not stop to load or unload pupils who must cross the highway except at designated points","Must use the left lane to discharge them","May discharge them only between 7 a.m. and 7 p.m."],"answer":1,"explanation":"Iowa Code 321.372 prohibits a school bus on a highway of four or more lanes from stopping to load or unload pupils who must cross the highway, except at designated stops/points with traffic-control devices or officers. Source: Iowa Code 321.372.","handbook":"","hbref":""},{"q":"When an Iowa school bus is preparing to stop for passengers, which warning lamps must it display before activating the red flashing lamps?","options":["Green flashing lamps","Blue flashing lamps","Amber (yellow) flashing warning lamps","White strobe lamps"],"answer":2,"explanation":"Iowa law and Iowa school transportation rules require the driver to display amber flashing warning lamps in advance of the stop, then switch to red flashing lamps and extend the stop arm at the stop. Source: Iowa Code 321.372; Iowa Admin. Code 281-43.","handbook":"","hbref":""},{"q":"A CDL driver stops a truck on a level, straight two-lane Iowa highway and must set out the three required warning triangles. The correct placement is:","options":["One at 10 ft to the rear, one at 100 ft to the rear, and one at 100 ft to the front","One at 25 ft to the rear, one at 250 ft to the rear, and one at 250 ft to the front","One at 5 ft, one at 50 ft, and one at 150 ft, all to the rear","All three placed 200 ft to the rear of the vehicle"],"answer":0,"explanation":"Iowa follows the federal rule (49 CFR 392.22) taught in the Iowa CDL Manual: on a two-lane road place triangles about 10 ft behind, 100 ft behind, and 100 ft ahead of the vehicle. Source: 49 CFR 392.22; Iowa CDL Manual.","handbook":"","hbref":""},{"q":"Per the Iowa CDL Manual, how soon after stopping a disabled commercial motor vehicle on the roadway or shoulder must warning devices (triangles) be placed?","options":["Within 3 minutes","Within 10 minutes","Within 30 minutes","Within 1 hour"],"answer":1,"explanation":"Iowa follows 49 CFR 392.22, requiring the driver to place the required warning devices within 10 minutes of stopping. Source: 49 CFR 392.22; Iowa CDL Manual.","handbook":"","hbref":""},{"q":"A CDL driver stops on a one-way or divided Iowa highway. Where do the three warning triangles belong?","options":["10 ft, 100 ft, and 200 ft toward the approaching traffic (rear)","10 ft, 100 ft, and 100 ft, one to the rear and two to the front","All three 10 ft from the vehicle on each side","100 ft ahead, 100 ft behind, and one beside the cab"],"answer":0,"explanation":"Iowa follows 49 CFR 392.22: on a one-way or divided highway, place triangles 10 ft, 100 ft, and 200 ft toward the approaching traffic. Source: 49 CFR 392.22; Iowa CDL Manual.","handbook":"","hbref":""},{"q":"Iowa's general 'keep right' rule (Iowa Code 321.297) directs which vehicles to drive in the right-hand lane?","options":["Only vehicles registered as commercial motor vehicles","Only vehicles towing trailers","Any vehicle moving slower than the normal speed of traffic, except when passing or turning left","Only vehicles over 26,000 pounds gross weight"],"answer":2,"explanation":"Iowa Code 321.297 requires any vehicle proceeding slower than the normal speed of traffic to use the right-hand lane, except when passing or preparing for a left turn. Iowa has no truck-specific left-lane ban; the rule applies to all slower traffic. Source: Iowa Code 321.297.","handbook":"","hbref":""},{"q":"In Iowa, before a vehicle/load requires an oversize permit, the legal maximum WIDTH for travel on public highways is:","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"Iowa, consistent with the federal standard, sets the legal maximum width at 8 feet 6 inches; anything wider needs an oversize permit. Source: Iowa DOT Motor Carrier Services, Oversize/Overweight Permit Requirements; Iowa Code ch. 321.","handbook":"","hbref":""},{"q":"In Iowa, an indivisible load reaches 13 feet 6 inches in height. Without a permit, this height is:","options":["Over the legal limit; a permit is required above 13 feet 6 inches","Well under the limit; legal up to 16 feet","Over the limit; the legal maximum is 12 feet","Legal only if the load is no wider than 8 feet"],"answer":0,"explanation":"Iowa DOT lists the legal maximum height as 13 feet 6 inches; loads exceeding 13 feet 6 inches require an oversize permit. Source: Iowa DOT Oversize/Overweight Permit Requirements.","handbook":"","hbref":""},{"q":"Under Iowa oversize-permit rules, when is movement of an oversize load generally allowed?","options":["Only between 9 a.m. and 3 p.m. on weekdays","24 hours a day with no time limits","From one-half hour before sunrise to one-half hour after sunset","Only at night to avoid traffic"],"answer":2,"explanation":"Iowa generally permits oversize-load movement from one-half hour before sunrise to one-half hour after sunset, seven days a week, with restrictions on certain holidays and for very large loads. Source: Iowa DOT Motor Carrier Services oversize/overweight permit rules.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in Iowa?","options":["The Iowa Department of Transportation (Iowa DOT)","The Federal Motor Carrier Safety Administration (FMCSA)","The Iowa Department of Public Safety","The Transportation Security Administration (TSA)"],"answer":0,"explanation":"Iowa CDLs are issued by the Iowa Department of Transportation (Iowa DOT), the state driver licensing agency. The FMCSA sets federal CDL standards but does not issue licenses. Source: Iowa DOT, Commercial Drivers / How to Get a CDL (iowadot.gov).","handbook":"","hbref":""},{"q":"Where can an applicant take the Iowa CDL knowledge and skills tests?","options":["At select Iowa DOT and County Treasurer driver license service locations","Only at the single Iowa DOT headquarters in Ames","At any FMCSA field office in the state","At any local police department in Iowa"],"answer":0,"explanation":"Iowa CDL testing is administered at select Iowa DOT and County Treasurer driver license locations; additional sites are listed on the Iowa DOT CDL Testing Locations page. Source: Iowa DOT, CDL Testing (iowadot.gov).","handbook":"","hbref":""},{"q":"What is the general minimum age to obtain an Iowa CDL for intrastate (within-Iowa-only) driving?","options":["18 years old","16 years old","21 years old","25 years old"],"answer":0,"explanation":"Iowa requires a CDL applicant to be at least 18 to drive commercially within Iowa (intrastate). Driving across state lines (interstate) requires age 21. Source: Iowa DOT, How to Get a CDL (iowadot.gov).","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a commercial motor vehicle in interstate commerce with an Iowa CDL?","options":["21 years old","18 years old","19 years old","23 years old"],"answer":0,"explanation":"Under the federal rule applied in Iowa, a driver must be at least 21 to operate a CMV in interstate commerce; 18- to 20-year-olds are limited to intrastate driving. Source: Iowa DOT, How to Get a CDL; 49 CFR 391.11 (federal standard).","handbook":"","hbref":""},{"q":"Which document must an Iowa CDL applicant provide to prove identity and lawful status when applying?","options":["Proof of full name, date of birth, Social Security number, and citizenship or lawful status","Only a current utility bill in the applicant's name","A signed letter from a current employer only","A high school diploma or GED certificate"],"answer":0,"explanation":"Iowa requires proof of full legal name, date of birth, Social Security number, and citizenship or lawful permanent residency (e.g., birth certificate, passport, or permanent resident card), plus proof of Iowa residency. Source: Iowa DOT, How to Get a CDL (iowadot.gov).","handbook":"","hbref":""},{"q":"Before testing, every Iowa CDL applicant must 'self-certify.' What does self-certification mean?","options":["Declaring to Iowa DOT which of four driving categories describes how you operate a CMV","Signing a statement that you have no traffic tickets","Promising to complete training within one year","Certifying that you own the vehicle you will test in"],"answer":0,"explanation":"Self-certification is the driver's declaration to Iowa DOT of which of the four categories of CMV operation applies to them; it determines whether a medical examiner's certificate must be on file. Source: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50.","handbook":"","hbref":""},{"q":"How many self-certification categories must an Iowa CDL holder choose from?","options":["Four","Two","Three","Six"],"answer":0,"explanation":"There are four categories: interstate non-excepted, interstate excepted, intrastate non-excepted, and intrastate excepted. Source: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50.","handbook":"","hbref":""},{"q":"Which self-certification category REQUIRES a current Medical Examiner's Certificate to be on file with Iowa DOT?","options":["Interstate non-excepted","Interstate excepted","Intrastate excepted","Intrastate non-excepted"],"answer":0,"explanation":"Only interstate non-excepted drivers must submit and keep a current Medical Examiner's Certificate on file with Iowa DOT. Excepted drivers do not, and intrastate non-excepted drivers must carry the card but need not file it with the state. Source: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50.","handbook":"","hbref":""},{"q":"For an Iowa interstate non-excepted driver, how is the DOT Medical Examiner's Certificate submitted to the state?","options":["The certified medical examiner submits it electronically to the national registry/state system","The driver mails a paper copy to FMCSA in Washington, D.C.","The driver's employer faxes it to the county treasurer","It is automatically transferred from the doctor's billing software"],"answer":0,"explanation":"In Iowa, the certified medical examiner submits the certificate electronically; results flow through the National Registry of Certified Medical Examiners to the state. The driver does not file it themselves for interstate non-excepted status. Source: Iowa DOT, Medical Cards & Certification.","handbook":"","hbref":""},{"q":"An Iowa interstate non-excepted CDL holder lets their Medical Examiner's Certificate expire without filing a new one. What happens to the CDL?","options":["Iowa DOT downgrades the CDL, removing commercial privileges after a notice/grace period","Nothing changes until the CDL itself expires","The CDL is permanently revoked the same day the card expires","The driver is automatically moved to the excepted intrastate category"],"answer":0,"explanation":"If the medical certificate lapses, Iowa DOT sets the medical status to 'not certified,' gives written notice, and removes the CMV privileges (downgrade) if a current certificate is not received within the 60-day period. Source: Iowa Admin. Code r. 761-607.50.","handbook":"","hbref":""},{"q":"What is the first credential an Iowa applicant obtains in the CDL process, before the skills test?","options":["A Commercial Learner's Permit (CLP)","A full unrestricted CDL","A hazardous materials endorsement","A medical waiver certificate"],"answer":0,"explanation":"After passing the required knowledge test(s) and meeting document/medical requirements, the applicant receives a Commercial Learner's Permit (CLP), which allows supervised practice before the skills test. Source: Iowa DOT, How to Get a CDL; Commercial Learner Permits (iowadot.gov).","handbook":"","hbref":""},{"q":"What must an Iowa applicant pass to be issued a Commercial Learner's Permit (CLP)?","options":["The applicable CDL knowledge (written) test and vision screening","The three-part skills test only","A road test in their personal car","The hazmat TSA background check"],"answer":0,"explanation":"A CLP is issued after the applicant passes the applicable CDL knowledge test(s) and vision screening, and provides required documents; the skills test comes later. Source: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov).","handbook":"","hbref":""},{"q":"How long must an Iowa applicant hold a Commercial Learner's Permit before taking the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"Iowa applies the federal rule requiring a CLP to be held for a minimum of 14 days before the skills test may be taken. Source: Iowa DOT, How to Get a CDL / Commercial Learner Permits; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is an Iowa Commercial Learner's Permit (CLP) valid, and can it be renewed?","options":["Valid for one year and cannot be renewed (a new CLP must be obtained)","Valid for 180 days and can be renewed once","Valid for two years and renewable annually","Valid for 60 days with unlimited renewals"],"answer":0,"explanation":"An Iowa CLP is valid for one year from issuance and is non-renewable; if it expires, the applicant must reapply. Source: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov).","handbook":"","hbref":""},{"q":"For CLPs issued on or after February 7, 2022, what must be completed and verified before an Iowa applicant can take the CDL skills test?","options":["Entry-Level Driver Training (ELDT) from a registered training provider","A defensive driving course at a community college","A minimum of 160 hours of unpaid road time","A second knowledge test taken at least 30 days later"],"answer":0,"explanation":"Entry-Level Driver Training (ELDT) from an FMCSA Training Provider Registry-listed provider must be completed and verified before skills testing for CLPs issued on or after February 7, 2022. Source: Iowa DOT, How to Get a CDL; 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"Where is ELDT completion recorded so that Iowa DOT can verify it before scheduling a skills test?","options":["In the FMCSA Training Provider Registry (TPR)","On the applicant's CLP card by hand","In a paper logbook kept by the driver","In the TSA Hazmat database"],"answer":0,"explanation":"Registered providers upload ELDT certification to the FMCSA Training Provider Registry; Iowa DOT verifies that record before the skills test can be scheduled. Source: Iowa DOT, How to Get a CDL; FMCSA Training Provider Registry (49 CFR Part 380).","handbook":"","hbref":""},{"q":"The Iowa CDL skills test consists of three parts. Which list correctly names them?","options":["Pre-trip vehicle inspection, basic control skills, and on-road driving","Written exam, vision test, and hearing test","Air-brake quiz, hazmat quiz, and combination quiz","Backing only, parallel parking only, and highway merging only"],"answer":0,"explanation":"The Iowa skills test has three parts: the pre-trip vehicle inspection, the basic control skills test (maneuvers and backing around cones), and the on-road driving test. Source: Iowa DOT, CDL Testing (iowadot.gov); Iowa CDL Manual.","handbook":"","hbref":""},{"q":"During the Iowa pre-trip vehicle inspection portion of the skills test, what is the applicant expected to do?","options":["Walk around the vehicle and point to or touch each item while explaining what is checked and why","Simply state that the vehicle is in good condition","Disassemble the brake system for the examiner","Drive the vehicle on the highway while describing the gauges"],"answer":0,"explanation":"In the pre-trip inspection, the applicant walks around the vehicle, points to or touches each item, and explains to the examiner what is being checked and why, to show the vehicle is safe to drive. Source: Iowa DOT, CDL Testing (iowadot.gov); Iowa CDL Manual.","handbook":"","hbref":""},{"q":"What is the typical maximum validity period of an Iowa CDL renewal cycle for most adult drivers?","options":["Up to 8 years (shorter for older drivers, capped near age 80)","Exactly 1 year for all drivers","Up to 15 years","Exactly 30 days"],"answer":0,"explanation":"Iowa driver licenses, including CDLs, may be issued for up to 8 years, with shorter terms for older drivers and a cap so the credential does not extend past about the driver's 80th birthday. Source: Iowa Code 321.196; Iowa DOT, Renew a CDL.","handbook":"","hbref":""},{"q":"At each Iowa CDL renewal, why must a holder of a hazardous materials (H) endorsement renew in person rather than online?","options":["They must retake the hazmat knowledge test and complete a TSA threat assessment/background check","Online renewal is never available for any CDL holder in Iowa","They must surrender the endorsement permanently","They must complete a new ELDT theory course online first"],"answer":0,"explanation":"Hazmat endorsement holders must retake the hazmat knowledge test and complete a TSA security threat assessment (fingerprint-based background check) at each renewal, so they cannot renew online and must apply in person. Source: Iowa DOT, Renew a CDL; 49 CFR 1572 (TSA).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина коммерческого транспортного средства на автодорогах штата Айова без разрешения на перевозку негабаритного груза?","options":["8 футов 6 дюймов","8 футов 0 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Раздел 321.454 Кодекса штата Айова устанавливает максимальную ширину транспортного средства, включая груз, в 8 футов 6 дюймов (102 inches). Всё, что шире, требует разрешения на перевозку негабаритного груза. Источник: Iowa Code 321.454; требования Iowa DOT к разрешениям на негабаритные/сверхтяжёлые грузы."},"1":{"q":"Какова максимальная разрешённая высота транспортного средства с грузом на автодорогах штата Айова без разрешения?","options":["13 футов 6 дюймов","13 футов 0 дюймов","14 футов 0 дюймов","14 футов 6 дюймов"],"explanation":"Раздел 321.456 Кодекса штата Айова ограничивает высоту транспортного средства до 13 футов 6 дюймов. Грузы выше этого требуют разрешения на перевозку негабаритного груза. Источник: Iowa Code 321.456; требования Iowa DOT к разрешениям."},"2":{"q":"Какова максимальная разрешённая длина полуприцепа, эксплуатируемого в составе автопоезда тягач-полуприцеп, на автодорогах штата Айова без разрешения?","options":["53 фута","48 футов","57 футов","45 футов"],"explanation":"Айова допускает полуприцеп длиной до 53 футов (с грузом или без) в составе автопоезда тягач-полуприцеп без разрешения. Низкорамные прицепы (lowboy), перевозящие строительную технику, могут быть длиной до 57 футов. Источник: Iowa Code, глава 321; требования Iowa DOT к разрешениям."},"3":{"q":"Какова максимальная полная масса транспортного средства, разрешённая на автодорогах штата Айова без разрешения на перевозку сверхтяжёлого груза?","options":["80,000 pounds","73,280 pounds","84,000 pounds","76,000 pounds"],"explanation":"Раздел 321.463 Кодекса штата Айова ограничивает максимальную полную массу до 80,000 pounds, что соответствует федеральному лимиту. Превышение требует разрешения на перевозку сверхтяжёлого груза. Источник: Iowa Code 321.463; Iowa DOT."},"4":{"q":"Какова максимальная нагрузка, разрешённая на одиночную ось на автодорогах штата Айова?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Раздел 321.463 Кодекса штата Айова ограничивает нагрузку на одиночную ось до 20,000 pounds, что совпадает с федеральным стандартом для системы автомагистралей Interstate. Источник: Iowa Code 321.463; Iowa DOT."},"5":{"q":"Какова максимальная нагрузка, разрешённая на сдвоенную группу осей (тандем) на автодорогах штата Айова?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Раздел 321.463 Кодекса штата Айова ограничивает нагрузку на сдвоенную ось (тандем) до 34,000 pounds, что соответствует федеральному стандарту. Источник: Iowa Code 321.463; Iowa DOT."},"6":{"q":"Какой метод использует Айова для определения максимальной полной массы на любой группе из двух или более последовательных осей?","options":["Федеральная мостовая формула (Formula B)","Фиксированный лимит 80,000 lb независимо от расстояния между осями","Только суммарную грузоподъёмность шин","Правило 600 фунтов на дюйм ширины шины"],"explanation":"Айова применяет федеральную мостовую формулу (W = 500[(LN/(N-1)) + 12N + 36]) для ограничения массы на группах последовательных осей в зависимости от числа осей (N) и расстояния между ними (L). Источник: Iowa Code 321.463; 23 CFR 658.17; Iowa DOT."},"7":{"q":"Что в федеральной мостовой формуле, применяемой в Айове, обозначают переменные L и N?","options":["L — расстояние в футах между крайними осями группы; N — число осей в группе","L — нагрузка в фунтах; N — число шин","L — допустимая длина прицепа; N — масса нетто","L — ширина полосы движения; N — число требуемых разрешений"],"explanation":"В формуле W = 500[(LN/(N-1)) + 12N + 36] L — это расстояние в футах между крайними осями любой группы из двух или более последовательных осей, а N — число осей в этой группе. Источник: 23 CFR 658.17, принятый Iowa Code 321.463."},"8":{"q":"Как лимиты Айовы по полной массе и нагрузке на ось на системе Interstate соотносятся с лимитами на первичных (не относящихся к Interstate) автодорогах штата?","options":["Лимиты 80,000 lb полной массы и 20,000/34,000 lb на ось одинаковы; некоторые повышенные массы допускаются только на дорогах, не относящихся к Interstate","Дороги, не относящиеся к Interstate, допускают только 73,280 lb полной массы","Система Interstate допускает 90,000 lb полной массы","На дорогах, не относящихся к Interstate, нет ограничений по массе"],"explanation":"Базовые лимиты Айовы (80,000 lb полной массы, 20,000 lb на одиночную ось, 34,000 lb на тандем) применяются как на Interstate, так и на первичных автодорогах. Некоторые предусмотренные законом исключения для дополнительной массы применяются только к системе, не относящейся к Interstate, поскольку для Interstate федеральный лимит составляет 80,000 lb. Источник: Iowa Code 321.463; Iowa DOT."},"9":{"q":"Пятиосное транспортное средство для перевозки скота в Айове с прицепом с разнесёнными осями, соответствующим требованиям по расстоянию между осями, может перевозить повышенную полную массу на каких дорогах?","options":["Только на первичных автодорогах (не относящихся к Interstate), до 86,000 pounds","Только на автомагистралях Interstate, до 86,000 pounds","На всех дорогах, включая Interstate, до 90,000 pounds","Только на гравийных окружных дорогах, до 80,000 pounds"],"explanation":"Раздел 321.463 Кодекса штата Айова допускает пятиосному транспортному средству для перевозки скота полную массу до 86,000 lb на автодорогах, не относящихся к Interstate, при условии, что между первой и пятой осями не менее 61 фута, а между двумя задними (разнесёнными) осями не менее 8 футов 1 дюйма. Это не применяется на Interstate. Источник: Iowa Code 321.463."},"10":{"q":"Согласно законодательству Айовы, транспортное средство, перевозящее сырую сельскохозяйственную продукцию, может превышать свою зарегистрированную (регистрационную) полную массу не более чем на какой процент?","options":["25 percent","10 percent","15 percent","50 percent"],"explanation":"Айова разрешает грузовикам, перевозящим сырую сельскохозяйственную продукцию, работать с превышением зарегистрированной массы до 25 percent в пределах Айовы (при этом всё равно соблюдая лимиты по осям и мостовую формулу). Источник: рекомендации Iowa DOT для автоперевозчиков; Iowa Code, глава 321."},"11":{"q":"Когда для груза требуется разрешение Iowa DOT на перевозку негабаритного/сверхтяжёлого груза?","options":["Когда груз неделим и превышает допустимые ограничения по размеру или массе","Всякий раз, когда транспортное средство весит более 26,001 pounds","Только когда транспортное средство пересекает границу штата","Каждый раз, когда водитель с CDL работает после наступления темноты"],"explanation":"Разрешение выдаётся для неделимого транспортного средства или груза, который превышает установленные законом ограничения по размеру или массе. Груз считается неделимым, если его разделение уничтожит его ценность, нарушит его целевое назначение или потребует более восьми рабочих часов на демонтаж. Источник: требования Iowa DOT к разрешениям на негабаритные/сверхтяжёлые грузы; Iowa Code, глава 321E."},"12":{"q":"Что означает «неделимость» груза, благодаря которой он подходит для получения разрешения Айовы на перевозку негабаритного/сверхтяжёлого груза?","options":["Его нельзя разумно уменьшить до допустимых габаритов/массы без уничтожения его ценности, нарушения его использования или без затрат более 8 рабочих часов на демонтаж","Он запечатан в запертом контейнере","Он принадлежит одному перевозчику","Он весит ровно 80,000 pounds"],"explanation":"Айова, следуя федеральным определениям, считает груз неделимым, когда его уменьшение до допустимых лимитов уничтожило бы его ценность, нарушило бы его целевое назначение или потребовало бы более восьми рабочих часов на демонтаж с использованием надлежащего оборудования. На делимые грузы, как правило, разрешение получить нельзя. Источник: требования Iowa DOT к разрешениям; 23 CFR 658.5."},"13":{"q":"Как перевозчик подаёт заявку на разрешение Iowa DOT на перевозку негабаритного/сверхтяжёлого груза?","options":["Онлайн через систему разрешений Iowa DOT (ia.gotpermits.com) или по почте","Только лично в офисе шерифа округа","Позвонив в Федеральную администрацию по безопасности автоперевозчиков (Federal Motor Carrier Safety Administration)","Только через производителя транспортного средства"],"explanation":"Разрешения Iowa DOT на перевозку негабаритных/сверхтяжёлых грузов оформляются онлайн через портал разрешений штата (ia.gotpermits.com) или по почте. Разрешения распространяются только на дороги штата и Interstate; для городских или окружных дорог нужны отдельные разрешения. Источник: разрешения Iowa DOT на негабаритные/сверхтяжёлые грузы."},"14":{"q":"Стандартное разрешение Айовы на разовую поездку с негабаритным/сверхтяжёлым грузом обычно действительно в течение какого срока?","options":["5 days","24 hours","30 days","1 year"],"explanation":"Стандартное разрешение Айовы на разовую поездку (в один конец/туда и обратно) действительно в течение 5 calendar days. Разрешения на несколько поездок действуют 60 days, а годовые разрешения — 12 months. Источник: типы разрешений Iowa DOT на негабаритные/сверхтяжёлые грузы."},"15":{"q":"Разрешение Iowa DOT на перевозку негабаритного/сверхтяжёлого груза даёт право двигаться по каким дорогам?","options":["Только по дорогам штата и Interstate; для городских и окружных дорог нужны отдельные разрешения","По всем дорогам общего пользования в Айове, включая все городские улицы и окружные дороги","Только по системе Interstate","Только по частным технологическим дорогам"],"explanation":"Разрешения Iowa DOT распространяются на первичную систему автодорог штата и систему Interstate. Чтобы двигаться по городским улицам или окружным дорогам, перевозчик должен получить отдельные разрешения от соответствующих местных юрисдикций. Источник: требования Iowa DOT к разрешениям на негабаритные/сверхтяжёлые грузы."},"16":{"q":"На автодорогах Айовы предупреждающие знаки о негабаритном грузе и угловые флажки, как правило, требуются, как только транспортное средство с грузом превышает какие габариты?","options":["75 футов в длину, 8 футов 6 дюймов в ширину или 14 футов 4 дюйма в высоту","40 футов в длину или 8 футов в ширину","100 футов в длину или 12 футов в ширину","53 фута в длину или 10 футов в ширину"],"explanation":"Айова требует знаки «Oversize Load» и флажки, когда транспортное средство с грузом, на которое выдано разрешение, превышает 75 футов в длину, 8 футов 6 дюймов в ширину и/или 14 футов 4 дюйма в высоту. Красные флажки (квадратные, 18 дюймов) обозначают крайние точки груза. Источник: условия разрешений Iowa DOT/Iowa Admin. Code ch. 761-511."},"17":{"q":"При какой примерно ширине негабаритного груза Айова, как правило, начинает требовать как минимум одно сопровождающее (пилотное) транспортное средство?","options":["Когда груз шире 14 футов 6 дюймов","Когда груз шире 8 футов 6 дюймов","Когда груз шире 10 футов","В Айове сопровождение никогда не требуется"],"explanation":"В Айове грузы шириной более 14 футов 6 дюймов, как правило, требуют как минимум одно сопровождающее транспортное средство; грузы шириной до 14 футов 6 дюймов, которые занимают более половины проезжей части, могут вместо этого использовать переднее сопровождение или жёлтые проблесковые маячки. Конкретные маршруты могут устанавливать более строгие требования. Источник: условия разрешений Iowa DOT/Iowa Admin. Code ch. 761-511."},"18":{"q":"Согласно типовым условиям разрешений Айовы, когда может перемещаться крупный негабаритный груз (слишком большой для круглосуточного движения)?","options":["С получаса до восхода солнца до получаса после заката, включая субботу и воскресенье, при наличии надлежащего оборудования безопасности","Только между полуночью и 4 a.m.","Только в будние дни, никогда по выходным или праздникам","В любое время без ограничений по времени суток"],"explanation":"Условия разрешений Айовы позволяют более крупным негабаритным грузам перемещаться с получаса до восхода солнца до получаса после заката, включая выходные, при наличии надлежащего освещения/маркировки. Менее крупные грузы, на которые выдано разрешение (в пределах установленных лимитов), могут перемещаться непрерывно (24/7). Источник: условия разрешений Iowa DOT/Iowa Admin. Code ch. 761-511."},"19":{"q":"Айова предлагает специальное разрешение на перевозку негабаритного/сверхтяжёлого груза специально для перевозки какого связанного с лесом товара при массе выше допустимой?","options":["Сырьевые лесопродукты","Готовая мебель","Бумажные деньги","Ёлочные игрушки"],"explanation":"Среди специальных разрешений Айовы есть разрешение на сырьевые лесопродукты (Raw Forest Products), которое (подобно сельскохозяйственным послаблениям) учитывает заготовку/перевозку необработанных лесопродуктов сверх стандартных лимитов при установленных условиях. Источник: типы разрешений Iowa DOT на негабаритные/сверхтяжёлые грузы."},"20":{"q":"Согласно правилам Айовы, какой класс CDL требуется для управления автопоездом с полной массой автопоезда (GCWR) 26,001 pounds или более, где буксируемое(-ые) звено(-ья) имеет(-ют) GVWR более 10,000 pounds?","options":["Класс A","Класс B","Класс C","Класс D (шофёр)"],"explanation":"Айова выдаёт CDL класса A для автопоездов с GCWR 26,001+ lbs, где буксируемое звено превышает 10,000 lbs GVWR. Источник: Iowa DOT CDL Manual / 761 IAC 607.16; Iowa DOT «Driver's License Types, Restrictions, & Endorsements»."},"21":{"q":"Водитель в Айове управляет одиночным бортовым грузовиком с GVWR 30,000 pounds и буксирует небольшой прицеп с номинальной GVWR 8,000 pounds. Какой класс CDL требуется?","options":["Класс C","Класс A","Класс B","CDL не требуется"],"explanation":"CDL класса B в Айове охватывает одиночное транспортное средство с GVWR 26,001+ lbs, включая буксировку звена не более 10,000 lbs GVWR. Поскольку прицеп весит менее 10,001 lbs, это класс B, а не класс A. Источник: Iowa DOT CDL Manual / страница типов лицензий Iowa DOT; 761 IAC 607.16."},"22":{"q":"В Айове транспортное средство с GVWR менее 26,001 lbs, но предназначенное для перевозки 16 или более человек (включая водителя) либо используемое для перевозки опасных грузов, требующих информационных табло (placard), требует какого класса CDL?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"CDL класса C в Айове применяется к транспортным средствам ниже весовых порогов классов A/B, которые либо перевозят 16+ человек (включая водителя), либо перевозят опасные грузы, требующие информационных табло. Источник: Iowa DOT «Driver's License Types, Restrictions, & Endorsements»; 761 IAC 607.16."},"23":{"q":"Каков в Айове минимальный возраст для получения CDL для ВНУТРИШТАТНОГО вождения (управление коммерческими транспортными средствами только в пределах Айовы)?","options":["16 лет","18 лет","21 год","19 лет"],"explanation":"Айова допускает CDL для внутриштатной (в пределах Айовы) коммерции с 18 лет. Для межштатного вождения требуется 21 год. Источник: Iowa DOT Commercial Drivers / Iowa Tax And Tags CDL Endorsements; федеральный стандарт FMCSA, принятый Айовой."},"24":{"q":"Каков в Айове минимальный возраст для управления коммерческим транспортным средством в МЕЖШТАТНОЙ коммерции (с пересечением границ штатов)?","options":["18 лет","19 лет","21 год","20 лет"],"explanation":"Айова, следуя федеральному стандарту, требует, чтобы водителям было не менее 21 года для вождения в межштатной коммерции или для перевозки опасных грузов. Водители 18-20 лет ограничены внутриштатной эксплуатацией. Источник: Iowa DOT Commercial Drivers; FMCSA 49 CFR 391.11 в применении Айовы."},"25":{"q":"Какое дополнение к CDL (endorsement) требует Айова для перевозки опасных грузов в количествах, при которых транспортное средство должно иметь информационные табло (placard)?","options":["Дополнение N","Дополнение H","Дополнение T","Дополнение X"],"explanation":"Дополнение H (Hazardous Materials) требуется для перевозки опасных грузов с информационными табло. Источник: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual. (Примечание: дополнение X означает совмещённое дополнение цистерна + опасные грузы.)"},"26":{"q":"Помимо сдачи письменного теста на знания, какое дополнительное федеральное требование должен выполнить заявитель в Айове, чтобы получить (и продлить) дополнение HazMat (H)?","options":["Отдельный практический экзамен по вождению цистерны","Оценку угрозы безопасности по отпечаткам пальцев от TSA (проверка благонадёжности)","Минимум два года опыта работы с CDL","Отказ от требований по зрению (waiver) от FMCSA"],"explanation":"Дополнение H требует проведения оценки угрозы безопасности TSA на основе отпечатков пальцев при первоначальной подаче заявки и снова при каждом продлении, в дополнение к тесту на знания по HazMat. Источник: Iowa Tax And Tags CDL Endorsements; программа TSA HazMat Endorsement Threat Assessment, принятая в Айове."},"27":{"q":"Какое дополнение к CDL в Айове требуется для управления транспортным средством-цистерной, определяемым как перевозка жидкостей или газов в цистерне с индивидуальной номинальной ёмкостью более 119 gallons и совокупной номинальной ёмкостью 1,000 gallons или более?","options":["N (цистерна)","H (опасные грузы)","T (сдвоенные/строенные прицепы)","P (пассажиры)"],"explanation":"Дополнение N (цистерна) охватывает транспортные средства-цистерны, отвечающие порогам индивидуальной ёмкости 119 gallons и совокупной ёмкости 1,000 gallons, и требует сдачи экзамена на знания по цистернам. Источник: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"28":{"q":"Какое дополнение к CDL в Айове требуется для буксировки сдвоенных или строенных прицепов?","options":["Дополнение P","Дополнение N","Дополнение T","Дополнение S"],"explanation":"Дополнение T (сдвоенные/строенные прицепы), получаемое путём сдачи экзамена на знания по сдвоенным и строенным прицепам, требуется для буксировки нескольких прицепов. Источник: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"29":{"q":"Что касается строенных прицепов в Айове, какое утверждение верно для водителя с дополнением T?","options":["Закон Айовы запрещает эксплуатацию строенных прицепов в пределах штата, хотя резидент может получить дополнение T для использования в других штатах","Строенные прицепы можно эксплуатировать на любой автомагистрали Interstate в Айове","Строенные прицепы разрешены только на платных дорогах Айовы","Айова требует отдельное дополнение «Y» для строенных прицепов"],"explanation":"Закон Айовы запрещает эксплуатацию строенных прицепов в пределах штата; однако резидент Айовы всё равно может получить дополнение T, чтобы законно эксплуатировать строенные прицепы в штатах, которые их разрешают. Источник: Iowa Tax And Tags CDL Endorsements; Iowa Code Ch. 321 ограничения по длине/составу автопоезда."},"30":{"q":"Какое дополнение к CDL в Айове требуется для управления транспортным средством, предназначенным для перевозки 16 или более человек, включая водителя?","options":["S (школьный автобус)","P (пассажиры)","N (цистерна)","C (шофёр)"],"explanation":"Дополнение P (пассажиры) требуется для транспортных средств, предназначенных для перевозки 16 или более человек, включая водителя. Оно требует теста на знания по пассажирским перевозкам плюс практического экзамена на репрезентативном транспортном средстве. Источник: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"31":{"q":"Что в Айове водитель должен иметь в дополнение к дополнению «Школьный автобус» (S), чтобы законно управлять школьным автобусом?","options":["Дополнение «Пассажиры» (P)","Дополнение «Цистерна» (N)","Дополнение «Опасные грузы» (H)","Ничего больше; одного дополнения S достаточно"],"explanation":"Айова требует ОБА дополнения — «Школьный автобус» (S) и «Пассажиры» (P) — для управления школьным автобусом; одного дополнения P недостаточно для управления школьным автобусом. Источник: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"32":{"q":"Как долго заявитель должен владеть коммерческим ученическим разрешением Айовы (CLP), прежде чем ему будет разрешено сдавать практический (дорожный) экзамен на CDL?","options":["Не менее 7 days","Не менее 14 days","Не менее 30 days","Не менее 60 days"],"explanation":"Федеральное правило, применяемое в Айове, требует владеть CLP минимум 14 days перед сдачей практического экзамена. Источник: страница Iowa DOT Commercial Learner Permits (CLP); 49 CFR 383.25."},"33":{"q":"Каков срок действия коммерческого ученического разрешения Айовы (CLP)?","options":["180 days, продлевается один раз","Один год с момента выдачи, без периода продления","Два года, с возможностью продления","90 days, без возможности продления"],"explanation":"CLP в Айове стоит $12 и действителен в течение одного года с даты выдачи, без периода продления. Источник: страница Iowa DOT Commercial Learner Permits (CLP)."},"34":{"q":"Что заявитель уже должен иметь, прежде чем подавать заявку на коммерческое ученическое разрешение Айовы (CLP) или CDL?","options":["Действительные некоммерческие водительские права Айовы","Федеральную карту TWIC","Два года опыта вождения в армии","Мотоциклетную лицензию класса M"],"explanation":"Айова требует, чтобы заявители имели действительные некоммерческие водительские права Айовы перед подачей заявки на CLP или CDL. Источник: страница Iowa DOT Commercial Learner Permits (CLP) / Iowa Tax And Tags."},"35":{"q":"Обучение водителей начального уровня (ELDT) в Айове должно быть пройдено через какую организацию перед сдачей экзаменов?","options":["Любого частного инструктора по вождению по выбору заявителя","Провайдера, внесённого в реестр провайдеров обучения FMCSA (Training Provider Registry, TPR)","Местный офис казначея округа","Только в учебной академии Iowa State Patrol"],"explanation":"ELDT должно предоставляться организацией, внесённой в реестр провайдеров обучения FMCSA (Training Provider Registry); только зарегистрированные провайдеры могут проводить требуемое обучение. Источник: FMCSA Training Provider Registry; Iowa DOT Commercial Drivers (ELDT применяется в Айове)."},"36":{"q":"ELDT (обучение водителей начального уровня) требуется в Айове для впервые подающих заявку на что из перечисленного?","options":["CDL класса A или класса B, а также впервые получаемые дополнения S, P или H","Только дополнение HazMat (H)","Только дополнение «Сдвоенные/строенные прицепы» (T)","Продление любого существующего CDL"],"explanation":"ELDT требуется для впервые подающих заявку на CDL класса A или класса B, для повышения с класса B до класса A, а также для впервые получаемых дополнений «Школьный автобус» (S), «Пассажиры» (P) или HazMat (H) (для H только теория). Источник: правило FMCSA ELDT (CLP, полученный 7 февраля 2022 года или позже); применяется в Айове."},"37":{"q":"Владелец CDL в Айове, который управляет коммерческим транспортным средством в межштатной коммерции и НЕ освобождён от федеральных правил физической пригодности, должен самостоятельно сертифицироваться в какой медицинской категории?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"Водитель категории non-excepted interstate должен самостоятельно сертифицироваться как таковой И держать действующий сертификат медицинского эксперта (Medical Examiner's Certificate) на учёте в Iowa DOT; несоблюдение этого ведёт к понижению. Источник: Iowa DOT Medical Cards & Certification; 761 IAC 607.50."},"38":{"q":"Какая категория медицинской самосертификации НЕ требует подачи сертификата медицинского эксперта в Iowa DOT?","options":["Non-excepted interstate","Non-excepted intrastate","Все четыре категории должны его подавать","Освобождены только водители из других штатов"],"explanation":"Только категория non-excepted interstate должна подавать сертификат медицинского эксперта в Iowa DOT. Водители категории non-excepted intrastate носят его при себе, но подавать не обязаны, а категории excepted не нуждаются в нём вовсе; внутриштатные категории получают ограничение «K». Источник: Iowa DOT Medical Cards & Certification; 761 IAC 607.50."},"39":{"q":"Какой набор документов Iowa DOT требует от заявителя при первой подаче заявки на CDL/CLP?","options":["Подтверждение личности/законного пребывания, номер социального страхования и резидентство в Айове","Только паспорт","Только военную форму DD-214","Только подтверждение страховки и регистрации транспортного средства"],"explanation":"Айова требует подтверждение личности и гражданства США или законного пребывания, номер социального страхования и подтверждение резидентства в Айове (например, действующие права с адресом в Айове). Источник: страница Iowa DOT Commercial Learner Permits (CLP); 761 IAC 607."},"40":{"q":"Какова в Айове максимальная концентрация алкоголя, которую человек может иметь и при этом законно управлять коммерческим транспортным средством (CMV)?","options":["0.04","0.08","0.02","0.05"],"explanation":"Iowa Code 321.208(1)(a) дисквалифицирует водителя, который управляет CMV с концентрацией алкоголя (как определено в 321J.1) 0.04 или более. Таким образом, законный предел для CMV ниже 0.04, что вдвое меньше предела 0.08, применяемого к обычным водителям. Источник: Iowa Code 321.208 / Iowa CDL Manual."},"41":{"q":"Согласно закону Айовы о подразумеваемом согласии, что происходит с владельцем CDL, который отказывается пройти химическое тестирование, требуемое по главе 321J, после законного требования?","options":["Это рассматривается как тяжкое нарушение, наравне с осуждением за алкоголь, и влечёт дисквалификацию","Ничего не происходит с CDL, потому что отказ — это конституционное право","Налагается лишь небольшой гражданский штраф без дисквалификации","Водитель получает письменное предупреждение за первый отказ"],"explanation":"Iowa Code 321.208(2)(b) и 321.208(13) рассматривают отказ от прохождения химического тестирования по главе 321J как тяжкое нарушение, влекущее ту же дисквалификацию, что и осуждение за OWI. Источник: Iowa Code 321.208 / Iowa CDL Manual."},"42":{"q":"На какой срок водитель дисквалифицируется от управления CMV за ПЕРВОЕ тяжкое нарушение (например, OWI или управление CMV с 0.04 или более), когда НЕ перевозятся опасные грузы с информационными табло?","options":["1 year","3 years","60 days","Пожизненно"],"explanation":"Iowa Code 321.208(1) и (2) налагают дисквалификацию от управления CMV на один год за первое тяжкое нарушение, такое как управление с концентрацией алкоголя 0.04 или более, OWI или отказ от теста. Источник: Iowa Code 321.208 (отражает 49 CFR 383.51)."},"43":{"q":"Если первое тяжкое нарушение (например, OWI или 0.04 BAC) происходит, когда водитель управляет CMV, перевозящим опасные грузы с информационными табло, дисквалификация увеличивается до какого срока?","options":["3 years","1 year","5 years","Пожизненно"],"explanation":"Iowa Code 321.208(3) увеличивает дисквалификацию за первое нарушение с одного года до трёх лет, когда нарушение происходит во время перевозки на CMV опасных грузов, требующих информационных табло согласно 49 CFR 383.5. Источник: Iowa Code 321.208."},"44":{"q":"Каково наказание за совершение ВТОРОГО тяжкого нарушения (в двух или более отдельных инцидентах), например второго OWI или отказа от теста?","options":["Пожизненная дисквалификация (которая впоследствии может быть сокращена до 10 years)","Дисквалификация на 3 years","Дисквалификация на 1 year","Дисквалификация на 120 days"],"explanation":"Iowa Code 321.208(4) дисквалифицирует водителя пожизненно при двух или более тяжких нарушениях из отдельных инцидентов. Пожизненная дисквалификация может быть сокращена до 10 years, как предусмотрено в 49 CFR 383.51, по правилу департамента. Источник: Iowa Code 321.208."},"45":{"q":"На какой срок водитель дисквалифицируется за накопление ДВУХ серьёзных нарушений ПДД при управлении CMV в течение трёхлетнего периода?","options":["60 days","120 days","30 days","1 year"],"explanation":"Iowa Code 321.208(8) налагает дисквалификацию на 60 days за два серьёзных нарушения ПДД в течение любого трёхлетнего периода. Источник: Iowa Code 321.208 / Iowa CDL Manual."},"46":{"q":"На какой срок водитель дисквалифицируется за накопление ТРЁХ серьёзных нарушений ПДД при управлении CMV в течение трёхлетнего периода?","options":["120 days","60 days","180 days","1 year"],"explanation":"Iowa Code 321.208(8) налагает дисквалификацию на 120 days за три серьёзных нарушения ПДД в течение любого трёхлетнего периода. Несколько периодов дисквалификации исполняются последовательно. Источник: Iowa Code 321.208."},"47":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение ПДД, учитываемое при дисквалификации от управления CMV в Айове?","options":["Превышение скорости на 15 mph или более сверх установленного ограничения","Превышение скорости на 5 mph сверх установленного ограничения","Нарушение правил парковки на CMV","Нарушение по массе транспортного средства (перегруз)"],"explanation":"Iowa Code 321.208(7)(d) перечисляет превышение скорости на 15 mph или более сверх ограничения как серьёзное нарушение. Нарушения парковки и массы транспортного средства прямо исключены из подсчёта серьёзных нарушений. Источник: Iowa Code 321.208."},"48":{"q":"Согласно закону Айовы, набор текстовых сообщений во время управления коммерческим транспортным средством классифицируется как какой тип нарушения CDL?","options":["Серьёзное нарушение ПДД","Тяжкое нарушение, влекущее дисквалификацию на 1 year","Нарушение предписания о выводе из эксплуатации (out-of-service order)","Незначительное нарушение по оборудованию без влияния на дисквалификацию"],"explanation":"Iowa Code 321.208(7)(i) перечисляет нарушение закона, запрещающего набор текстовых сообщений во время управления CMV, как серьёзное нарушение ПДД, которое учитывается при дисквалификациях на 60 days/120 days. Источник: Iowa Code 321.208."},"49":{"q":"Использование портативного мобильного телефона во время управления CMV в нарушение закона о регулировании дорожного движения рассматривается в Айове как:","options":["Серьёзное нарушение ПДД, учитываемое при дисквалификации","Тяжкое нарушение с пожизненной дисквалификацией","Нарушение без последствий для CDL","Автоматическая дисквалификация на 1 year"],"explanation":"Iowa Code 321.208(7)(j) перечисляет нарушение закона, ограничивающего или запрещающего использование портативного мобильного телефона во время управления CMV, как серьёзное нарушение ПДД, которое учитывается при достижении порогов дисквалификации на 60/120 days. Источник: Iowa Code 321.208."},"50":{"q":"За ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service order) (не связанное с опасными грузами или транспортным средством, рассчитанным на 16+ пассажиров) диапазон дисквалификации в Айове составляет:","options":["Не менее 180 days и не более 1 year","Не менее 60 days и не более 120 days","Не менее 30 days и не более 90 days","Не менее 2 years и не более 5 years"],"explanation":"Iowa Code 321.208(10)(a) устанавливает за первое нарушение предписания о выводе из эксплуатации срок не менее 180 days и не более одного года. Источник: Iowa Code 321.208."},"51":{"q":"За ВТОРОЕ нарушение предписания о выводе из эксплуатации (out-of-service order) в отдельных инцидентах в течение 10 years (без опасных грузов) диапазон дисквалификации в Айове составляет:","options":["Не менее 2 years и не более 5 years","Не менее 180 days и не более 1 year","Не менее 1 year и не более 3 years","Пожизненно"],"explanation":"Iowa Code 321.208(10)(a) устанавливает за второе нарушение предписания о выводе из эксплуатации (в течение десятилетнего периода) срок не менее двух лет и не более пяти лет. Источник: Iowa Code 321.208."},"52":{"q":"Первое нарушение предписания о выводе из эксплуатации (out-of-service order), совершённое во время перевозки опасных грузов с информационными табло или во время управления CMV, рассчитанным на перевозку более 15 пассажиров, влечёт дисквалификацию на:","options":["1 year","180 days","3 years","60 days"],"explanation":"Iowa Code 321.208(10)(b) налагает дисквалификацию на один год за первое нарушение предписания о выводе из эксплуатации при перевозке опасных грузов с информационными табло или при управлении CMV, рассчитанным более чем на 15 пассажиров (включая водителя). Источник: Iowa Code 321.208."},"53":{"q":"На какой срок водитель дисквалифицируется за ПЕРВОЕ нарушение на железнодорожном переезде в одном уровне, совершённое во время управления CMV в Айове?","options":["60 days","120 days","30 days","1 year"],"explanation":"Iowa Code 321.208(11)(a) налагает дисквалификацию на 60 days за первое нарушение на железнодорожном переезде в одном уровне (по 321.341 или 321.343), совершённое во время управления CMV. Источник: Iowa Code 321.208."},"54":{"q":"Водитель, осуждённый за ВТОРОЕ нарушение на железнодорожном переезде в одном уровне на CMV в течение трёх лет после первого, дисквалифицируется на:","options":["120 days","60 days","180 days","1 year"],"explanation":"Iowa Code 321.208(11)(b) налагает дисквалификацию на 120 days за второе нарушение на железнодорожном переезде в одном уровне на CMV, произошедшее в течение трёх лет после первого. Источник: Iowa Code 321.208."},"55":{"q":"Водитель, осуждённый за ТРЕТЬЕ или последующее нарушение на железнодорожном переезде в одном уровне на CMV в течение трёх лет после первого, дисквалифицируется на:","options":["1 year","120 days","60 days","180 days"],"explanation":"Iowa Code 321.208(11)(c) налагает дисквалификацию на один год за третье или последующее нарушение на железнодорожном переезде в одном уровне на CMV, произошедшее в течение трёх лет после первого. Источник: Iowa Code 321.208."},"56":{"q":"Использование коммерческого транспортного средства при совершении тяжкого преступления (felony), связанного с изготовлением, распространением или отпуском контролируемого вещества, влечёт какое наказание для CDL в Айове?","options":["Пожизненную дисквалификацию без возможности сокращения","Дисквалификацию на 1 year","Дисквалификацию на 3 years","Дисквалификацию на 120 days"],"explanation":"Iowa Code 321.208(5) налагает пожизненную дисквалификацию, не подлежащую сокращению до 10 лет, когда CMV используется в тяжком преступлении, связанном с изготовлением, распространением или отпуском контролируемого вещества. Источник: Iowa Code 321.208."},"57":{"q":"Когда Iowa DOT получает запись о дисквалифицирующем осуждении, за какое время заранее он направляет уведомление до вступления дисквалификации от управления CMV в силу?","options":["30 days","10 days","60 days","24 hours"],"explanation":"Iowa Code 321.208(12) и (13) предусматривают, что департамент дисквалифицирует водителя без предварительного слушания при уведомлении за 30 days; дата вступления дисквалификации в силу — через 30 days после уведомления. Источник: Iowa Code 321.208."},"58":{"q":"Водитель CMV, у которого сотрудник правоохранительных органов обнаружил концентрацию алкоголя 0.04 или более, помимо угрозы дисквалификации, немедленно:","options":["Выводится из эксплуатации на 24 hours","Допускается к вождению после 1-часового отдыха","Допускается к продолжению движения, если показатель ниже 0.08","Штрафуется на $25 и отпускается за руль"],"explanation":"Федеральные правила, принятые в Айове (49 CFR 392.5), требуют, чтобы любой водитель с концентрацией алкоголя 0.04 или более был выведен из эксплуатации на 24 hours, отдельно от официальной дисквалификации по Iowa Code 321.208. Источник: 49 CFR 392.5 / Iowa CDL Manual."},"59":{"q":"Два отдельных осуждения за тяжкие нарушения, возникшие из двух отдельных инцидентов, ведут к пожизненной дисквалификации CDL в Айове. Согласно федеральному правилу, принятому Айовой, этот пожизненный срок может быть сокращён минимум до:","options":["10 years","5 years","3 years","1 year"],"explanation":"Iowa Code 321.208(4) делает пожизненную дисквалификацию (за два или более тяжких нарушения) подлежащей сокращению до дисквалификации на 10 years, как предусмотрено в 49 CFR 383.51 и принято правилом департамента. Источник: Iowa Code 321.208."},"60":{"q":"Согласно закону Айовы «Move Over», когда вы приближаетесь к стоящему автомобилю экстренной службы с включёнными мигающими огнями, двигаясь по межштатной автомагистрали с двумя полосами в вашем направлении, что Кодекс Айовы требует сделать в первую очередь?","options":["Перестроиться в полосу, не примыкающую к стоящему автомобилю, если это безопасно","Полностью остановиться на обочине и ждать, пока автомобиль экстренной службы не уедет","Подать звуковой сигнал и продолжить движение мимо в той же полосе с прежней скоростью","Съехать на левую обочину и ждать, пока сотрудник полиции не даст знак продолжить движение"],"explanation":"Кодекс Айовы 321.323A требует, чтобы водитель, приближающийся к стоящему автомобилю с включёнными мигающими огнями на дороге с двумя или более полосами в направлении движения водителя, перестроился в полосу, не примыкающую к этому автомобилю, когда это безопасно и законно. Источник: Кодекс Айовы 321.323A; Iowa DOT «Move Over or Slow Down»."},"61":{"q":"Согласно закону Айовы «Move Over», если перестроение из полосы в сторону от стоящего автомобиля с мигающими огнями невозможно или небезопасно, что должен сделать водитель в Айове?","options":["Сохранять установленную скорость, но включить аварийную сигнализацию","Снизить скорость до уровня ниже установленного ограничения скорости и быть готовым остановиться","Снизить скорость ровно на 20 mph ниже установленного ограничения скорости","Снизить скорость до 10 mph независимо от установленного ограничения скорости"],"explanation":"Кодекс Айовы 321.323A гласит, что когда перестроение невозможно, запрещено или небезопасно, водитель должен снизить скорость до разумной и приемлемой, которая ниже установленного ограничения скорости, и быть готовым остановиться. Айова НЕ устанавливает фиксированное снижение в mph. Источник: Кодекс Айовы 321.323A; Iowa DOT."},"62":{"q":"Какой из этих стоящих автомобилей, когда на нём включены необходимые мигающие или предупреждающие огни, подпадает под действие закона Айовы «Move Over» (Кодекс Айовы 321.323A)?","options":["Только автомобили правоохранительных органов и пожарной службы","Только машины скорой помощи и эвакуаторы","Автомобиль для сбора твёрдых отходов или вторсырья","Только автомобили, принадлежащие Iowa DOT"],"explanation":"Кодекс Айовы 321.323A распространяется на стоящие уполномоченные автомобили экстренных служб, эвакуационную/буксировочную технику, ремонтные и строительные машины, автомобили для сбора твёрдых отходов или вторсырья с мигающими огнями, а также любой автомобиль, на котором непрерывно включена аварийная сигнализация. Источник: Кодекс Айовы 321.323A; Iowa DOT."},"63":{"q":"На сельской межштатной автомагистрали Айовы какое максимальное ограничение скорости применяется к седельному тягачу с прицепом?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Кодекс Айовы 321.285 устанавливает ограничение скорости на системе межштатных автомагистралей в 70 mph для всего транспортного движения. Айова не вводит отдельное, более низкое ограничение скорости для грузовиков на межштатных автомагистралях. Источник: Кодекс Айовы 321.285."},"64":{"q":"Устанавливает ли Айова более низкое ограничение скорости на межштатных автомагистралях для грузовиков, чем для легковых автомобилей?","options":["Да, грузовики ограничены 65 mph, тогда как легковые автомобили могут ехать 70 mph","Нет, ограничение 70 mph на межштатных автомагистралях применяется ко всему транспортному движению одинаково","Да, грузовики ограничены 60 mph по всему штату","Да, грузовики массой свыше 26,000 lbs ограничены 55 mph"],"explanation":"В отличие от некоторых штатов с «раздельными» ограничениями скорости, Кодекс Айовы 321.285 применяет максимум 70 mph на межштатных автомагистралях ко всему транспортному движению без отдельного установленного ограничения для грузовиков. Источник: Кодекс Айовы 321.285."},"65":{"q":"Транзитный автобус в Айове, перевозящий пассажиров за плату, приближается к железнодорожному переезду в одном уровне. Где водитель должен остановиться?","options":["Не ближе 15 футов и не дальше 50 футов от ближайшего рельса","Не ближе 10 футов и не дальше 25 футов от ближайшего рельса","Не ближе 25 футов и не дальше 75 футов от ближайшего рельса","В пределах 5 футов от ближайшего рельса"],"explanation":"Кодекс Айовы 321.343 требует, чтобы автомобиль, перевозящий пассажиров за плату, школьный автобус или автомобиль с табличками опасных грузов остановился в пределах 50 футов, но не ближе 15 футов от ближайшего рельса перед переездом. Источник: Кодекс Айовы 321.343."},"66":{"q":"Водитель, перевозящий груз опасных материалов с табличками в Айове, подъезжает к железнодорожному переезду, обозначенному знаком «EXEMPT» (освобождён). Что требуется?","options":["Всё равно остановиться в пределах 15–50 футов от ближайшего рельса","Остановиться только если виден поезд","Водитель не обязан останавливаться на этом переезде","Остановиться и выставить предупреждающие треугольники перед переездом"],"explanation":"Кодекс Айовы 321.343 требует остановки для автобусов, автомобилей, перевозящих пассажиров за плату, и автомобилей с табличками HazMat, однако переезд, обозначенный официальным знаком «EXEMPT», не требует остановки. Источник: Кодекс Айовы 321.343; Руководство CDL Айовы."},"67":{"q":"После остановки на железнодорожном переезде что должен сделать водитель школьного автобуса в Айове, прежде чем продолжить движение через пути?","options":["Дважды подать звуковой сигнал и продолжить движение без задержки","Открыть входную дверь, посмотреть и прислушаться, нет ли поездов, и пересекать пути только когда это безопасно","Ждать полные 60 секунд независимо от условий","Включить жёлтые предупреждающие огни и медленно проехать"],"explanation":"Согласно Кодексу Айовы 321.343, после остановки в 15–50 футах от ближайшего рельса водитель школьного автобуса должен открыть входную дверь, посмотреть и прислушаться, нет ли приближающегося поезда, и не продолжать движение, пока это не станет безопасным. Источник: Кодекс Айовы 321.343."},"68":{"q":"На двухполосной автодороге Айовы школьный автобус останавливается, включает мигающие красные огни и выдвигает знак «Стоп» для высадки детей. Что должен сделать приближающийся водитель?","options":["Снизить скорость до 20 mph и проехать с осторожностью","Остановиться не ближе 15 футов от автобуса и оставаться на месте, пока знак «Стоп» не будет убран","Остановиться только если на проезжей части видны дети","Перестроиться в дальнюю полосу и медленно проехать мимо автобуса"],"explanation":"Кодекс Айовы 321.372 требует, чтобы автомобили, встречающие или обгоняющие остановившийся школьный автобус с мигающими красными огнями и выдвинутым знаком «Стоп», остановились не ближе 15 футов и оставались на месте, пока знак «Стоп» не будет убран и автобус снова не тронется. Источник: Кодекс Айовы 321.372."},"69":{"q":"Согласно закону Айовы о школьных автобусах, на какой дороге водитель, ВСТРЕЧАЮЩИЙ остановившийся школьный автобус, движущийся в противоположном направлении, может продолжить движение без остановки?","options":["На любой дороге с нанесённой осевой линией","На дороге с двумя или более полосами движения в каждом направлении","На любой дороге с установленной скоростью 55 mph или выше","На дороге с асфальтированными обочинами шириной не менее 8 футов"],"explanation":"Кодекс Айовы 321.372 предусматривает, что водитель на дороге с двумя или более полосами в каждом направлении не обязан останавливаться при ВСТРЕЧЕ со школьным автобусом, движущимся в противоположном направлении, даже если тот остановился. На неразделённых дорогах останавливаться должны все направления. Источник: Кодекс Айовы 321.372."},"70":{"q":"На дороге Айовы с двумя полосами в каждом направлении, разделённых разделительной полосой, школьный автобус останавливается на полосах противоположного направления с мигающими красными огнями. Водитель, движущийся в обратную сторону:","options":["Обязан остановиться, пока красные огни не погаснут","Обязан снизить скорость до 10 mph, но может продолжить движение","Не обязан останавливаться, поскольку на дороге две или более полосы в каждом направлении","Обязан остановиться только если ширина разделительной полосы менее 6 футов"],"explanation":"Исключение для разделённых дорог в Кодексе Айовы 321.372 зависит от количества полос: на дороге с двумя или более полосами в каждом направлении водители, встречающие остановившийся автобус противоположного направления, не обязаны останавливаться. Источник: Кодекс Айовы 321.372."},"71":{"q":"Школьный автобус движется по дороге Айовы с четырьмя или более полосами. В отношении учеников, которым нужно пересечь дорогу, автобус:","options":["Может высаживать или забирать их где угодно, пока включены красные огни","Не должен останавливаться для посадки или высадки учеников, которым нужно пересечь дорогу, кроме как в специально отведённых местах","Должен использовать левую полосу для их высадки","Может высаживать их только с 7 утра до 7 вечера"],"explanation":"Кодекс Айовы 321.372 запрещает школьному автобусу на дороге с четырьмя или более полосами останавливаться для посадки или высадки учеников, которым нужно пересечь дорогу, кроме как в специально отведённых остановках/местах с устройствами регулирования движения или регулировщиками. Источник: Кодекс Айовы 321.372."},"72":{"q":"Когда школьный автобус в Айове готовится остановиться для пассажиров, какие предупреждающие огни он должен включить перед активацией мигающих красных огней?","options":["Мигающие зелёные огни","Мигающие синие огни","Мигающие жёлтые (янтарные) предупреждающие огни","Белые проблесковые огни"],"explanation":"Закон Айовы и правила школьных перевозок Айовы требуют, чтобы водитель заранее перед остановкой включил мигающие жёлтые предупреждающие огни, а затем переключился на мигающие красные огни и выдвинул знак «Стоп» при остановке. Источник: Кодекс Айовы 321.372; Iowa Admin. Code 281-43."},"73":{"q":"Водитель CDL останавливает грузовик на ровной, прямой двухполосной дороге Айовы и должен выставить три требуемых предупреждающих треугольника. Правильное расположение:","options":["Один в 10 футах сзади, один в 100 футах сзади и один в 100 футах спереди","Один в 25 футах сзади, один в 250 футах сзади и один в 250 футах спереди","Один в 5 футах, один в 50 футах и один в 150 футах, все сзади","Все три в 200 футах сзади от автомобиля"],"explanation":"Айова следует федеральному правилу (49 CFR 392.22), которому учит Руководство CDL Айовы: на двухполосной дороге треугольники размещаются примерно в 10 футах сзади, 100 футах сзади и 100 футах впереди автомобиля. Источник: 49 CFR 392.22; Руководство CDL Айовы."},"74":{"q":"Согласно Руководству CDL Айовы, как скоро после остановки неисправного коммерческого автомобиля на проезжей части или обочине должны быть выставлены предупреждающие устройства (треугольники)?","options":["В течение 3 минут","В течение 10 минут","В течение 30 минут","В течение 1 часа"],"explanation":"Айова следует 49 CFR 392.22, требуя, чтобы водитель выставил необходимые предупреждающие устройства в течение 10 минут после остановки. Источник: 49 CFR 392.22; Руководство CDL Айовы."},"75":{"q":"Водитель CDL останавливается на дороге Айовы с односторонним движением или на разделённой дороге. Где должны находиться три предупреждающих треугольника?","options":["В 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта (сзади)","В 10 футах, 100 футах и 100 футах, один сзади и два спереди","Все три в 10 футах от автомобиля с каждой стороны","В 100 футах впереди, 100 футах сзади и один сбоку от кабины"],"explanation":"Айова следует 49 CFR 392.22: на дороге с односторонним движением или разделённой дороге треугольники размещаются в 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта. Источник: 49 CFR 392.22; Руководство CDL Айовы."},"76":{"q":"Общее правило Айовы «держись правее» (Кодекс Айовы 321.297) предписывает каким транспортным средствам двигаться по правой полосе?","options":["Только транспортным средствам, зарегистрированным как коммерческие автомобили","Только транспортным средствам, буксирующим прицепы","Любому транспортному средству, движущемуся медленнее обычной скорости потока, кроме случаев обгона или поворота налево","Только транспортным средствам с полной массой свыше 26,000 фунтов"],"explanation":"Кодекс Айовы 321.297 требует, чтобы любое транспортное средство, движущееся медленнее обычной скорости потока, использовало правую полосу, кроме случаев обгона или подготовки к повороту налево. В Айове нет специального запрета на левую полосу для грузовиков; правило применяется ко всему более медленному транспорту. Источник: Кодекс Айовы 321.297."},"77":{"q":"В Айове, прежде чем транспортное средство/груз потребует разрешения на негабаритную перевозку, законная максимальная ШИРИНА для движения по дорогам общего пользования составляет:","options":["8 футов 0 дюймов","8 футов 6 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Айова, в соответствии с федеральным стандартом, устанавливает законную максимальную ширину в 8 футов 6 дюймов; всё, что шире, требует разрешения на негабаритную перевозку. Источник: Iowa DOT Motor Carrier Services, Oversize/Overweight Permit Requirements; Кодекс Айовы гл. 321."},"78":{"q":"В Айове неделимый груз достигает высоты 13 футов 6 дюймов. Без разрешения эта высота является:","options":["Превышающей законный предел; разрешение требуется выше 13 футов 6 дюймов","Значительно ниже предела; законно до 16 футов","Превышающей предел; законный максимум составляет 12 футов","Законной только если груз не шире 8 футов"],"explanation":"Iowa DOT указывает законную максимальную высоту в 13 футов 6 дюймов; грузы, превышающие 13 футов 6 дюймов, требуют разрешения на негабаритную перевозку. Источник: Iowa DOT Oversize/Overweight Permit Requirements."},"79":{"q":"Согласно правилам Айовы о разрешениях на негабаритные перевозки, когда обычно разрешено перемещение негабаритного груза?","options":["Только с 9 утра до 3 дня в будние дни","Круглосуточно без ограничений по времени","С получаса до восхода солнца до получаса после заката","Только ночью, чтобы избежать движения"],"explanation":"Айова обычно разрешает перемещение негабаритного груза с получаса до восхода солнца до получаса после заката, семь дней в неделю, с ограничениями в определённые праздники и для очень крупных грузов. Источник: Iowa DOT Motor Carrier Services oversize/overweight permit rules."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Айове?","options":["Департамент транспорта Айовы (Iowa DOT)","Федеральное управление безопасности автоперевозчиков (FMCSA)","Департамент общественной безопасности Айовы","Управление транспортной безопасности (TSA)"],"explanation":"Удостоверения CDL в Айове выдаются Департаментом транспорта Айовы (Iowa DOT) — органом штата, отвечающим за выдачу водительских удостоверений. FMCSA устанавливает федеральные стандарты CDL, но не выдаёт удостоверения. Источник: Iowa DOT, Commercial Drivers / How to Get a CDL (iowadot.gov)."},"81":{"q":"Где заявитель может сдать тесты на знания и навыки CDL в Айове?","options":["В отдельных пунктах обслуживания водительских удостоверений Iowa DOT и казначейств округов (County Treasurer)","Только в единственной штаб-квартире Iowa DOT в городе Эймс","В любом полевом офисе FMCSA в штате","В любом местном отделении полиции в Айове"],"explanation":"Тестирование CDL в Айове проводится в отдельных пунктах выдачи водительских удостоверений Iowa DOT и казначейств округов; дополнительные пункты перечислены на странице CDL Testing Locations сайта Iowa DOT. Источник: Iowa DOT, CDL Testing (iowadot.gov)."},"82":{"q":"Каков общий минимальный возраст для получения CDL в Айове для вождения внутри штата (только в пределах Айовы)?","options":["18 лет","16 лет","21 год","25 лет"],"explanation":"Айова требует, чтобы заявителю на CDL было не менее 18 лет для коммерческого вождения в пределах Айовы (внутри штата). Для вождения через границы штатов (между штатами) требуется возраст 21 год. Источник: Iowa DOT, How to Get a CDL (iowadot.gov)."},"83":{"q":"Каков минимальный возраст, необходимый для управления коммерческим автомобилем в межштатных перевозках с CDL Айовы?","options":["21 год","18 лет","19 лет","23 года"],"explanation":"Согласно федеральному правилу, применяемому в Айове, водителю должно быть не менее 21 года для управления коммерческим автомобилем в межштатных перевозках; лица в возрасте 18–20 лет ограничены вождением внутри штата. Источник: Iowa DOT, How to Get a CDL; 49 CFR 391.11 (федеральный стандарт)."},"84":{"q":"Какой документ должен предоставить заявитель на CDL в Айове, чтобы подтвердить личность и законный статус при подаче заявления?","options":["Подтверждение полного имени, даты рождения, номера социального страхования (Social Security number) и гражданства или законного статуса","Только текущий счёт за коммунальные услуги на имя заявителя","Только подписанное письмо от текущего работодателя","Аттестат об окончании средней школы или сертификат GED"],"explanation":"Айова требует подтверждения полного юридического имени, даты рождения, номера социального страхования (Social Security number) и гражданства или законного постоянного проживания (например, свидетельство о рождении, паспорт или карту постоянного резидента), а также подтверждения проживания в Айове. Источник: Iowa DOT, How to Get a CDL (iowadot.gov)."},"85":{"q":"Перед тестированием каждый заявитель на CDL в Айове должен пройти «самосертификацию». Что означает самосертификация?","options":["Заявление в Iowa DOT о том, какая из четырёх категорий вождения описывает, как вы управляете коммерческим автомобилем","Подписание заявления о том, что у вас нет штрафов за нарушение ПДД","Обещание завершить обучение в течение одного года","Подтверждение того, что вы владеете автомобилем, на котором будете проходить тест"],"explanation":"Самосертификация — это заявление водителя в Iowa DOT о том, какая из четырёх категорий управления коммерческим автомобилем к нему относится; она определяет, должна ли в досье храниться справка медицинского эксперта. Источник: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"86":{"q":"Из скольких категорий самосертификации должен выбирать держатель CDL в Айове?","options":["Четыре","Две","Три","Шесть"],"explanation":"Существует четыре категории: межштатные без исключения (interstate non-excepted), межштатные с исключением (interstate excepted), внутриштатные без исключения (intrastate non-excepted) и внутриштатные с исключением (intrastate excepted). Источник: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"87":{"q":"Какая категория самосертификации ТРЕБУЕТ, чтобы в досье Iowa DOT хранилась действующая справка медицинского эксперта (Medical Examiner's Certificate)?","options":["Межштатные без исключения (interstate non-excepted)","Межштатные с исключением (interstate excepted)","Внутриштатные с исключением (intrastate excepted)","Внутриштатные без исключения (intrastate non-excepted)"],"explanation":"Только водители категории межштатные без исключения (interstate non-excepted) должны предоставлять и хранить действующую справку медицинского эксперта в досье Iowa DOT. Водители с исключением этого не делают, а водители категории внутриштатные без исключения должны иметь справку при себе, но не обязаны подавать её в штат. Источник: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"88":{"q":"Для водителя категории межштатные без исключения в Айове, как справка медицинского эксперта DOT подаётся в штат?","options":["Сертифицированный медицинский эксперт подаёт её электронно в национальный реестр/систему штата","Водитель отправляет бумажную копию по почте в FMCSA в Вашингтоне, округ Колумбия","Работодатель водителя отправляет её факсом в казначейство округа","Она автоматически передаётся из биллинговой программы врача"],"explanation":"В Айове сертифицированный медицинский эксперт подаёт справку электронно; результаты поступают через Национальный реестр сертифицированных медицинских экспертов (National Registry of Certified Medical Examiners) в штат. Водитель не подаёт её самостоятельно для статуса межштатные без исключения. Источник: Iowa DOT, Medical Cards & Certification."},"89":{"q":"Держатель CDL Айовы категории межштатные без исключения допускает истечение срока действия своей справки медицинского эксперта, не подав новую. Что происходит с CDL?","options":["Iowa DOT понижает CDL, лишая коммерческих привилегий после уведомления/льготного периода","Ничего не меняется, пока не истечёт срок действия самого CDL","CDL аннулируется навсегда в тот же день, когда истекает срок действия справки","Водитель автоматически переводится в категорию внутриштатные с исключением"],"explanation":"Если срок действия медицинской справки истекает, Iowa DOT устанавливает медицинский статус «не сертифицирован», направляет письменное уведомление и лишает привилегий управления коммерческим автомобилем (понижение), если действующая справка не получена в течение 60-дневного периода. Источник: Iowa Admin. Code r. 761-607.50."},"90":{"q":"Какой документ заявитель в Айове получает первым в процессе оформления CDL, до теста на навыки?","options":["Коммерческое ученическое разрешение (Commercial Learner's Permit, CLP)","Полное CDL без ограничений","Подтверждение на перевозку опасных материалов (hazmat)","Сертификат медицинского освобождения (waiver)"],"explanation":"После сдачи необходимых тестов на знания и выполнения требований по документам/медицине заявитель получает коммерческое ученическое разрешение (CLP), которое позволяет тренироваться под наблюдением перед тестом на навыки. Источник: Iowa DOT, How to Get a CDL; Commercial Learner Permits (iowadot.gov)."},"91":{"q":"Что должен сдать заявитель в Айове, чтобы получить коммерческое ученическое разрешение (CLP)?","options":["Соответствующий тест на знания CDL (письменный) и проверку зрения","Только трёхчастный тест на навыки","Дорожный тест на личном автомобиле","Проверку благонадёжности TSA для hazmat"],"explanation":"CLP выдаётся после того, как заявитель сдаёт соответствующие тесты на знания CDL и проверку зрения, а также предоставляет необходимые документы; тест на навыки сдаётся позже. Источник: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"92":{"q":"Как долго заявитель в Айове должен иметь коммерческое ученическое разрешение, прежде чем сдавать тест на навыки CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Айова применяет федеральное правило, требующее, чтобы CLP было на руках минимум 14 дней до того, как можно будет сдавать тест на навыки. Источник: Iowa DOT, How to Get a CDL / Commercial Learner Permits; 49 CFR 383.25."},"93":{"q":"Как долго действительно коммерческое ученическое разрешение (CLP) Айовы и можно ли его продлить?","options":["Действительно один год и не может быть продлено (необходимо получить новое CLP)","Действительно 180 дней и может быть продлено один раз","Действительно два года и продлевается ежегодно","Действительно 60 дней с неограниченным числом продлений"],"explanation":"CLP Айовы действительно один год с момента выдачи и не подлежит продлению; если срок истекает, заявитель должен подать заявление заново. Источник: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"94":{"q":"Для CLP, выданных 7 февраля 2022 года или позже, что должно быть пройдено и подтверждено, прежде чем заявитель в Айове сможет сдать тест на навыки CDL?","options":["Начальное обучение водителей (Entry-Level Driver Training, ELDT) у зарегистрированного поставщика обучения","Курс безопасного вождения в местном колледже","Минимум 160 часов неоплачиваемого времени за рулём","Второй тест на знания, сдаваемый минимум через 30 дней"],"explanation":"Начальное обучение водителей (ELDT) у поставщика, внесённого в реестр поставщиков обучения FMCSA (Training Provider Registry), должно быть пройдено и подтверждено до сдачи теста на навыки для CLP, выданных 7 февраля 2022 года или позже. Источник: Iowa DOT, How to Get a CDL; 49 CFR Part 380 Subpart F."},"95":{"q":"Где фиксируется прохождение ELDT, чтобы Iowa DOT мог это подтвердить перед назначением теста на навыки?","options":["В реестре поставщиков обучения FMCSA (Training Provider Registry, TPR)","На карточке CLP заявителя от руки","В бумажном журнале, который ведёт водитель","В базе данных Hazmat TSA"],"explanation":"Зарегистрированные поставщики загружают сертификацию ELDT в реестр поставщиков обучения FMCSA (Training Provider Registry); Iowa DOT проверяет эту запись до того, как можно будет назначить тест на навыки. Источник: Iowa DOT, How to Get a CDL; FMCSA Training Provider Registry (49 CFR Part 380)."},"96":{"q":"Тест на навыки CDL в Айове состоит из трёх частей. В каком списке они названы правильно?","options":["Предрейсовый осмотр транспортного средства, базовые навыки управления и вождение по дороге","Письменный экзамен, проверка зрения и проверка слуха","Викторина по пневмотормозам, викторина по hazmat и викторина по составным транспортным средствам","Только сдача задним ходом, только параллельная парковка и только перестроение на шоссе"],"explanation":"Тест на навыки в Айове состоит из трёх частей: предрейсовый осмотр транспортного средства, тест базовых навыков управления (манёвры и движение задним ходом вокруг конусов) и тест вождения по дороге. Источник: Iowa DOT, CDL Testing (iowadot.gov); Руководство CDL Айовы."},"97":{"q":"Во время части теста на навыки, посвящённой предрейсовому осмотру транспортного средства в Айове, что должен делать заявитель?","options":["Обойти транспортное средство и указать на каждый элемент или дотронуться до него, объясняя, что проверяется и зачем","Просто заявить, что транспортное средство в хорошем состоянии","Разобрать тормозную систему для экзаменатора","Вести транспортное средство по шоссе, описывая приборы"],"explanation":"При предрейсовом осмотре заявитель обходит транспортное средство, указывает на каждый элемент или дотрагивается до него и объясняет экзаменатору, что проверяется и зачем, чтобы показать, что транспортное средство безопасно для вождения. Источник: Iowa DOT, CDL Testing (iowadot.gov); Руководство CDL Айовы."},"98":{"q":"Каков типичный максимальный срок действия цикла продления CDL в Айове для большинства взрослых водителей?","options":["До 8 лет (короче для пожилых водителей, с ограничением около 80 лет)","Ровно 1 год для всех водителей","До 15 лет","Ровно 30 дней"],"explanation":"Водительские удостоверения Айовы, включая CDL, могут выдаваться на срок до 8 лет, с более короткими сроками для пожилых водителей и ограничением, чтобы документ не действовал дольше примерно 80-летия водителя. Источник: Кодекс Айовы 321.196; Iowa DOT, Renew a CDL."},"99":{"q":"При каждом продлении CDL в Айове, почему держатель подтверждения на перевозку опасных материалов (H) должен продлевать лично, а не онлайн?","options":["Они должны повторно сдать тест на знания hazmat и пройти оценку угроз/проверку благонадёжности TSA","Онлайн-продление никогда не доступно ни одному держателю CDL в Айове","Они должны навсегда отказаться от подтверждения","Они должны сначала пройти новый теоретический курс ELDT онлайн"],"explanation":"Держатели подтверждения hazmat должны повторно сдавать тест на знания hazmat и проходить оценку угроз безопасности TSA (проверку благонадёжности на основе отпечатков пальцев) при каждом продлении, поэтому они не могут продлевать онлайн и должны подавать заявление лично. Источник: Iowa DOT, Renew a CDL; 49 CFR 1572 (TSA)."}},"tr":{"0":{"q":"Iowa karayollarında, geniş yük (oversize) izni olmadan bir ticari aracın izin verilen azami genişliği nedir?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Iowa Code 321.454 bölümü, yük dahil olmak üzere bir aracın azami genişliğini 8 feet 6 inches (102 inches) olarak belirler. Bundan daha geniş olan her şey geniş yük (oversize) izni gerektirir. Kaynak: Iowa Code 321.454; Iowa DOT geniş/aşırı yük izin gereklilikleri."},"1":{"q":"Iowa karayollarında, izin olmadan bir araç ve yükün izin verilen azami yüksekliği nedir?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","14 feet 6 inches"],"explanation":"Iowa Code 321.456 bölümü, araç yüksekliğini 13 feet 6 inches ile sınırlar. Bundan daha yüksek yükler bir geniş yük (oversize) izni gerektirir. Kaynak: Iowa Code 321.456; Iowa DOT izin gereklilikleri."},"2":{"q":"Iowa karayollarında, çekici-yarı römork kombinasyonu olarak çalışan bir yarı römorkun izin olmadan izin verilen azami uzunluğu nedir?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"Iowa, çekici-yarı römork kombinasyonunda izin olmadan 53 feet uzunluğa kadar (yüklü veya boş) bir yarı römorka izin verir. İnşaat ekipmanı taşıyan alçak şasili (lowboy) römorklar 57 feet'e kadar olabilir. Kaynak: Iowa Code 321. bölüm; Iowa DOT izin gereklilikleri."},"3":{"q":"Iowa karayollarında, aşırı yük izni olmadan izin verilen azami toplam araç ağırlığı (gross vehicle weight) nedir?","options":["80,000 pounds","73,280 pounds","84,000 pounds","76,000 pounds"],"explanation":"Iowa Code 321.463 bölümü, federal sınırla uyumlu olarak azami toplam ağırlığı 80,000 pounds ile sınırlar. Bunu aşmak bir aşırı yük izni gerektirir. Kaynak: Iowa Code 321.463; Iowa DOT."},"4":{"q":"Iowa karayollarında tek bir aks üzerinde izin verilen azami ağırlık nedir?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Iowa Code 321.463 bölümü, tek bir aksı federal Interstate standardıyla aynı olan 20,000 pounds ile sınırlar. Kaynak: Iowa Code 321.463; Iowa DOT."},"5":{"q":"Iowa karayollarında bir tandem aks grubu üzerinde izin verilen azami ağırlık nedir?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Iowa Code 321.463 bölümü, bir tandem aksı federal standartla uyumlu olarak 34,000 pounds ile sınırlar. Kaynak: Iowa Code 321.463; Iowa DOT."},"6":{"q":"Iowa, iki veya daha fazla ardışık akstan oluşan herhangi bir grup üzerindeki azami toplam ağırlığı belirlemek için hangi yöntemi kullanır?","options":["Federal Köprü Formülü (Formül B)","Aks aralığından bağımsız olarak sabit 80,000 lb üst sınır","Yalnızca toplam lastik yük derecelendirmesi","Lastik genişliğinin her inch'i için 600-pounds kuralı"],"explanation":"Iowa, ardışık aks grupları üzerindeki ağırlığı aks sayısına (N) ve aralığa (L) göre sınırlamak için federal Köprü Formülünü (W = 500[(LN/(N-1)) + 12N + 36]) uygular. Kaynak: Iowa Code 321.463; 23 CFR 658.17; Iowa DOT."},"7":{"q":"Iowa'da uygulandığı şekliyle federal Köprü Formülünde, L ve N değişkenleri neyi temsil eder?","options":["L, grubun dış aksları arasındaki feet cinsinden mesafedir; N, gruptaki aks sayısıdır","L, pounds cinsinden yüktür; N, lastik sayısıdır","L, römorkun yasal uzunluğudur; N, net ağırlıktır","L, şerit genişliğidir; N, gereken izin sayısıdır"],"explanation":"W = 500[(LN/(N-1)) + 12N + 36] formülünde L, iki veya daha fazla ardışık akstan oluşan herhangi bir grubun en dıştaki aksları arasındaki feet cinsinden mesafedir ve N, o gruptaki aks sayısıdır. Kaynak: Iowa Code 321.463 tarafından kabul edilen 23 CFR 658.17."},"8":{"q":"Iowa'nın Interstate sistemindeki toplam ve aks ağırlık sınırları, eyaletin birincil (Interstate olmayan) karayollarındaki sınırlarla nasıl karşılaştırılır?","options":["80,000 lb toplam ve 20,000/34,000 lb aks sınırları aynıdır; belirli daha yüksek ağırlıklara yalnızca Interstate olmayan yollarda izin verilir","Interstate olmayan yollar yalnızca 73,280 lb toplam ağırlığa izin verir","Interstate 90,000 lb toplam ağırlığa izin verir","Interstate olmayan yollarda ağırlık sınırı yoktur"],"explanation":"Iowa'nın temel sınırları (80,000 lb toplam, 20,000 lb tek aks, 34,000 lb tandem) hem Interstate hem de birincil karayollarında geçerlidir. Interstate federal olarak 80,000 lb ile sınırlandırıldığından, ek ağırlığa ilişkin bazı yasal istisnalar yalnızca Interstate olmayan sistem için geçerlidir. Kaynak: Iowa Code 321.463; Iowa DOT."},"9":{"q":"Aralık gereksinimlerini karşılayan ayrık akslı (spread-axle) römorka sahip beş akslı bir Iowa canlı hayvan aracı, hangi yollarda daha yüksek bir toplam ağırlık taşıyabilir?","options":["Yalnızca Interstate olmayan (birincil) karayollarında, 86,000 pounds'a kadar","Yalnızca Interstate karayollarında, 86,000 pounds'a kadar","Interstate'ler dahil tüm karayollarında, 90,000 pounds'a kadar","Yalnızca çakıl ilçe yollarında, 80,000 pounds'a kadar"],"explanation":"Iowa Code 321.463 bölümü, beş akslı bir canlı hayvan aracının, birinci ve beşinci aks arasında en az 61 feet ve iki arka (ayrık) aks arasında en az 8 feet 1 inch olduğunda, Interstate olmayan karayollarında 86,000 lb toplam ağırlığa kadar çalışmasına izin verir. Bu, Interstate'te geçerli değildir. Kaynak: Iowa Code 321.463."},"10":{"q":"Iowa yasalarına göre, ham tarım ürünleri taşıyan bir araç, kayıtlı (tescil) toplam ağırlığını en fazla yüzde kaç oranında aşabilir?","options":["yüzde 25","yüzde 10","yüzde 15","yüzde 50"],"explanation":"Iowa, ham tarım ürünleri taşıyan kamyonların Iowa içindeyken kayıtlı ağırlıklarının yüzde 25 üzerine kadar çalışmasına izin verir (yine de aks ve Köprü Formülü sınırlarına tabidir). Kaynak: Iowa DOT motorlu taşıyıcı rehberi; Iowa Code 321. bölüm."},"11":{"q":"Bir yük için Iowa DOT geniş/aşırı yük izni ne zaman gereklidir?","options":["Yük bölünemez (nondivisible) olduğunda ve yasal boyut veya ağırlık sınırlarını aştığında","Araç 26,001 pounds'tan daha ağır olduğunda her zaman","Yalnızca araç bir eyalet sınırını geçtiğinde","Bir CDL sürücüsü karanlıktan sonra araç kullandığında her zaman"],"explanation":"İzin, yasal boyut veya ağırlık sınırlarını aşan bölünemez bir araç veya yük için verilir. Bir yük, ayrıştırılması değerini yok edecekse, amaçlanan kullanımını engelleyecekse veya parçalara ayrılması sekiz iş saatinden fazla gerektirecekse bölünemez olarak kabul edilir. Kaynak: Iowa DOT geniş/aşırı yük izin gereklilikleri; Iowa Code 321E. bölüm."},"12":{"q":"Bir yükün Iowa geniş/aşırı yük izni için uygun olacak şekilde \"bölünemez\" (nondivisible) olması ne anlama gelir?","options":["Değerini yok etmeden, kullanımını engellemeden veya parçalara ayrılması 8 iş saatinden fazla sürmeden makul şekilde yasal boyutlara/ağırlığa indirilemez","Kilitli bir konteynerde mühürlüdür","Tek bir taşıyıcıya aittir","Tam olarak 80,000 pounds ağırlığındadır"],"explanation":"Iowa, federal tanımları izleyerek, yasal sınırlara indirilmesi değerini yok edecekse, amaçlanan kullanımını engelleyecekse veya uygun ekipmanla parçalara ayrılması sekiz iş saatinden fazla gerektirecekse bir yükü bölünemez olarak kabul eder. Bölünebilir yüklere genellikle izin verilemez. Kaynak: Iowa DOT izin gereklilikleri; 23 CFR 658.5."},"13":{"q":"Bir taşıyıcı Iowa DOT geniş/aşırı yük iznine nasıl başvurur?","options":["Iowa DOT izin sistemi üzerinden çevrimiçi (ia.gotpermits.com) veya posta yoluyla","Yalnızca ilçe şerif ofisinde bizzat","Federal Motor Carrier Safety Administration'ı arayarak","Yalnızca aracın üreticisi aracılığıyla"],"explanation":"Iowa DOT geniş/aşırı yük izinleri, eyaletin izin portalı (ia.gotpermits.com) üzerinden çevrimiçi veya posta yoluyla alınır. İzinler yalnızca eyalet ve Interstate karayollarını kapsar; şehir veya ilçe yolları için ayrı izinler gereklidir. Kaynak: Iowa DOT geniş/aşırı yük izinleri."},"14":{"q":"Standart bir Iowa tek seferlik geniş/aşırı yük izni genellikle ne kadar süre geçerlidir?","options":["5 days","24 hours","30 days","1 year"],"explanation":"Standart bir Iowa tek seferlik (tek/gidiş-dönüş) izni 5 takvim günü geçerlidir. Çoklu sefer izinleri 60 days ve yıllık izinler 12 months geçerlidir. Kaynak: Iowa DOT geniş/aşırı yük izin türleri."},"15":{"q":"Bir Iowa DOT geniş/aşırı yük izni hangi yollarda seyahat yetkisi verir?","options":["Yalnızca eyalet ve Interstate karayolları; şehir ve ilçe yolları için ayrı izinler gereklidir","Tüm şehir caddeleri ve ilçe yolları dahil olmak üzere Iowa'daki tüm kamuya açık yollar","Yalnızca Interstate sistemi","Yalnızca özel taşıma yolları"],"explanation":"Iowa DOT izinleri, eyalet birincil ve Interstate karayolu sistemini kapsar. Şehir caddelerinde veya ilçe yollarında seyahat etmek için, bir taşıyıcının bu yerel yetki bölgelerinden ayrı izinler alması gerekir. Kaynak: Iowa DOT geniş/aşırı yük izin gereklilikleri."},"16":{"q":"Iowa karayollarında, geniş yük uyarı işaretleri ve köşe bayrakları genellikle araç ve yük hangi boyutları aştığında gereklidir?","options":["Uzunlukta 75 feet, genişlikte 8 feet 6 inches veya yükseklikte 14 feet 4 inches","Uzunlukta 40 feet veya genişlikte 8 feet","Uzunlukta 100 feet veya genişlikte 12 feet","Uzunlukta 53 feet veya genişlikte 10 feet"],"explanation":"Iowa, izinli bir araç ve yük 75 feet uzunluğu, 8 feet 6 inches genişliği ve/veya 14 feet 4 inches yüksekliği aştığında \"Oversize Load\" işaretleri ve bayraklar gerektirir. Kırmızı bayraklar (18-inch kare) yükün uç noktalarını işaretler. Kaynak: Iowa DOT/Iowa Admin. Code ch. 761-511 izin koşulları."},"17":{"q":"Bir geniş yük için, Iowa genellikle yaklaşık hangi genişlikte en az bir refakat (pilot) aracı gerektirmeye başlar?","options":["Yük 14 feet 6 inches'tan daha geniş olduğunda","Yük 8 feet 6 inches'tan daha geniş olduğunda","Yük 10 feet'ten daha geniş olduğunda","Iowa'da refakat araçları asla gerekli değildir"],"explanation":"Iowa'da, 14 feet 6 inches'tan daha geniş yükler genellikle en az bir refakat aracı gerektirir; yolun yarısından fazlasını kaplayan 14 feet 6 inches'a kadar olan yükler bunun yerine bir ön refakat aracı veya sarı (amber) uyarı ışıkları kullanabilir. Belirli güzergahlar daha katı gereklilikler getirebilir. Kaynak: Iowa DOT/Iowa Admin. Code ch. 761-511 izin koşulları."},"18":{"q":"Tipik Iowa izin koşulları altında, büyük bir geniş yük (7/24 seyahat için çok büyük olan) ne zaman hareket edebilir?","options":["Gün doğumundan yarım saat önce gün batımından yarım saat sonrasına kadar, Cumartesi ve Pazar günleri dahil, uygun güvenlik ekipmanıyla","Yalnızca gece yarısı ile sabah 4 arasında","Yalnızca hafta içi, asla hafta sonu veya tatil günlerinde değil","Günün herhangi bir saatinde, saat kısıtlaması olmadan"],"explanation":"Iowa izin koşulları, daha büyük geniş yüklerin gün doğumundan yarım saat önce gün batımından yarım saat sonrasına kadar, hafta sonları dahil, uygun aydınlatma/işaretleme ile seyahat etmesine izin verir. Daha küçük izinli yükler (belirlenen sınırlar dahilinde) sürekli (7/24) hareket edebilir. Kaynak: Iowa DOT/Iowa Admin. Code ch. 761-511 izin koşulları."},"19":{"q":"Iowa, yasal sınırların üzerinde ağırlıklarda hangi orman ile ilgili ürünün taşınması için özel olarak bir uzmanlık geniş/aşırı yük izni sunar?","options":["Ham orman ürünleri","Bitmiş mobilya","Kağıt para","Noel süsleri"],"explanation":"Iowa'nın uzmanlık izinleri arasında, (tarımsal varyanslar gibi) belirlenen koşullar altında standart sınırların üzerinde işlenmemiş orman ürünlerinin hasadını/taşınmasını karşılayan bir Raw Forest Products izni bulunur. Kaynak: Iowa DOT geniş/aşırı yük izin türleri."},"20":{"q":"Iowa kurallarına göre, çekilen ünite(ler)in GVWR'si 10,000 pounds'tan fazla olan ve 26,001 pounds veya daha fazla toplam kombinasyon ağırlık derecesine (GCWR) sahip bir kombinasyon aracını kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D (şoför)"],"explanation":"Iowa, çekilen ünitenin 10,000 lbs GVWR'yi aştığı, GCWR'si 26,001+ lbs olan kombinasyon araçları için bir Class A CDL düzenler. Kaynak: Iowa DOT CDL Manual / 761 IAC 607.16; Iowa DOT 'Driver's License Types, Restrictions, & Endorsements.'"},"21":{"q":"Bir Iowa sürücüsü, GVWR'si 30,000 pounds olan tek bir düz kamyon kullanıyor ve 8,000 pounds GVWR derecelendirmeli küçük bir römork çekiyor. Hangi CDL sınıfı gereklidir?","options":["Class C","Class A","Class B","CDL gerekli değildir"],"explanation":"Iowa'nın Class B CDL'si, 10,000 lbs GVWR'yi aşmayan bir ünitenin çekilmesi dahil olmak üzere, GVWR'si 26,001+ lbs olan tek bir aracı kapsar. Römork 10,001 lbs'nin altında olduğundan, bu Class A değil Class B'dir. Kaynak: Iowa DOT CDL Manual / Iowa DOT lisans türleri sayfası; 761 IAC 607.16."},"22":{"q":"Iowa'da, 26,001 lbs GVWR'nin altında olan ancak 16 veya daha fazla kişiyi (sürücü dahil) taşımak için tasarlanan ya da plakart gerektiren tehlikeli madde taşımak için kullanılan bir araç hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Class M"],"explanation":"Iowa'nın Class C CDL'si, Class A/B ağırlık eşiklerinin altındaki, ya 16+ kişi (sürücü dahil) taşıyan ya da plakart gerektiren tehlikeli madde taşıyan araçlar için geçerlidir. Kaynak: Iowa DOT 'Driver's License Types, Restrictions, & Endorsements'; 761 IAC 607.16."},"23":{"q":"Iowa'da, EYALET İÇİ (INTRASTATE) sürüş için (ticari araçları yalnızca Iowa içinde kullanmak) bir CDL almak için asgari yaş nedir?","options":["16 years old","18 years old","21 years old","19 years old"],"explanation":"Iowa, eyalet içi (Iowa içi) ticaret için 18 yaşında bir CDL'ye izin verir. Eyaletler arası sürüş 21 yaş gerektirir. Kaynak: Iowa DOT Commercial Drivers / Iowa Tax And Tags CDL Endorsements; Iowa tarafından kabul edilen FMCSA standardı."},"24":{"q":"Iowa'da, EYALETLER ARASI (INTERSTATE) ticarette (eyalet sınırlarını geçerek) ticari bir motorlu taşıt kullanmak için asgari yaş nedir?","options":["18 years old","19 years old","21 years old","20 years old"],"explanation":"Iowa, federal standardı izleyerek, sürücülerin eyaletler arası ticarette araç kullanmak veya tehlikeli madde taşımak için en az 21 yaşında olmasını gerektirir. 18-20 yaşındaki sürücüler eyalet içi çalışmayla sınırlıdır. Kaynak: Iowa DOT Commercial Drivers; Iowa'da uygulandığı şekliyle FMCSA 49 CFR 391.11."},"25":{"q":"Iowa, aracın plakartlanmasını gerektiren miktarlarda tehlikeli madde taşımak için hangi CDL onayını (endorsement) gerektirir?","options":["N onayı","H onayı","T onayı","X onayı"],"explanation":"Plakartlı tehlikeli madde taşımak için H (Hazardous Materials) onayı gereklidir. Kaynak: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual. (Not: bir X onayı, birleşik bir tank + tehlikeli madde onayını gösterir.)"},"26":{"q":"Yazılı bilgi testini geçmenin ötesinde, bir Iowa başvuru sahibinin HazMat (H) onayını almak (ve yenilemek) için karşılaması gereken ek federal gereklilik nedir?","options":["Tankerde ayrı bir yol becerisi testi","TSA parmak izine dayalı güvenlik tehdidi değerlendirmesi (geçmiş kontrolü)","En az iki yıllık CDL deneyimi","FMCSA'dan bir görme muafiyeti"],"explanation":"H onayı, HazMat bilgi testine ek olarak, ilk başvuruda ve her yenilemede parmak izine dayalı bir TSA güvenlik tehdidi değerlendirmesi gerektirir. Kaynak: Iowa Tax And Tags CDL Endorsements; Iowa'da kabul edilen TSA HazMat Endorsement Threat Assessment Program."},"27":{"q":"Bireysel derecelendirilmiş kapasitesi 119 gallon'dan fazla ve toplam derecelendirilmiş kapasitesi 1,000 gallon veya daha fazla olan bir tankta sıvı veya gaz taşıma olarak tanımlanan bir tank aracını kullanmak için hangi Iowa CDL onayı gereklidir?","options":["N (Tank)","H (HazMat)","T (İkili/Üçlü)","P (Yolcu)"],"explanation":"N (Tank) onayı, 119-gallon bireysel ve 1,000-gallon toplam kapasite eşiklerini karşılayan tank araçlarını kapsar ve Tanker bilgi sınavını geçmeyi gerektirir. Kaynak: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"28":{"q":"İkili veya üçlü römork çekmek için hangi Iowa CDL onayı gereklidir?","options":["P onayı","N onayı","T onayı","S onayı"],"explanation":"Double and Triple Trailers bilgi sınavını geçerek alınan T (İkili/Üçlü) onayı, birden fazla römork çekmek için gereklidir. Kaynak: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"29":{"q":"Iowa'da üçlü römorklarla ilgili olarak, T onayına sahip bir sürücü için hangi ifade doğrudur?","options":["Iowa yasaları, bir sakinin diğer eyaletlerde kullanım için T onayı alabilmesine rağmen, eyalet içinde üçlü römork kullanmayı yasaklar","Üçlü römorklar herhangi bir Iowa eyaletler arası karayolunda kullanılabilir","Üçlü römorklara yalnızca Iowa ücretli yollarında izin verilir","Iowa, üçlüler için ayrı bir 'Y' onayı gerektirir"],"explanation":"Iowa yasaları, eyalet içinde üçlü römork kullanımını yasaklar; ancak bir Iowa sakini, izin veren eyaletlerde üçlüleri yasal olarak kullanmak için yine de T onayı alabilir. Kaynak: Iowa Tax And Tags CDL Endorsements; Iowa Code Ch. 321 uzunluk/kombinasyon sınırları."},"30":{"q":"Sürücü dahil 16 veya daha fazla kişiyi taşımak için tasarlanmış bir aracı kullanmak için hangi Iowa CDL onayı gereklidir?","options":["S (Okul Otobüsü)","P (Yolcu)","N (Tank)","C (Şoför)"],"explanation":"P (Yolcu) onayı, sürücü dahil 16 veya daha fazla kişiyi taşımak için tasarlanmış araçlar için gereklidir. Yolcu bilgi testinin yanı sıra temsili bir araçta beceri testi gerektirir. Kaynak: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"31":{"q":"Iowa'da, bir okul otobüsünü yasal olarak kullanmak için bir sürücünün Okul Otobüsü (S) onayına ek olarak neye sahip olması gerekir?","options":["Yolcu (P) onayına","Tank (N) onayına","HazMat (H) onayına","Başka bir şeye gerek yok; S onayı tek başına yeterlidir"],"explanation":"Iowa, bir okul otobüsünü kullanmak için HEM Okul Otobüsü (S) HEM DE Yolcu (P) onaylarını gerektirir; P onayı tek başına okul otobüsü kullanımı için geçerli değildir. Kaynak: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"32":{"q":"Bir başvuru sahibi, CDL beceri (yol) testine girmesine izin verilmeden önce bir Iowa Commercial Learner's Permit (CLP) belgesini ne kadar süre elinde tutmalıdır?","options":["En az 7 days","En az 14 days","En az 30 days","En az 60 days"],"explanation":"Iowa'da uygulanan federal kural, beceri testine girmeden önce CLP'nin en az 14 days elde tutulmasını gerektirir. Kaynak: Iowa DOT Commercial Learner Permits (CLP) sayfası; 49 CFR 383.25."},"33":{"q":"Bir Iowa Commercial Learner's Permit (CLP) belgesinin geçerlilik süresi nedir?","options":["180 days, bir kez yenilenebilir","Düzenlenme tarihinden itibaren bir yıl, yenileme süresi olmadan","İki yıl, yenilenebilir","90 days, yenilenemez"],"explanation":"Bir Iowa CLP $12 tutarındadır ve düzenlenme tarihinden itibaren bir yıl, yenileme süresi olmaksızın geçerlidir. Kaynak: Iowa DOT Commercial Learner Permits (CLP) sayfası."},"34":{"q":"Bir başvuru sahibi, bir Iowa Commercial Learner's Permit (CLP) veya CDL için başvurmadan önce zaten neye sahip olmalıdır?","options":["Geçerli bir Iowa ticari olmayan sürücü belgesine","Federal bir TWIC kartına","İki yıllık askeri sürüş deneyimine","Bir Class M motosiklet belgesine"],"explanation":"Iowa, başvuru sahiplerinin bir CLP veya CDL için başvurmadan önce geçerli bir Iowa ticari olmayan sürücü belgesine sahip olmasını gerektirir. Kaynak: Iowa DOT Commercial Learner Permits (CLP) sayfası / Iowa Tax And Tags."},"35":{"q":"Iowa'da Entry-Level Driver Training (ELDT), test öncesinde hangi kurum aracılığıyla tamamlanmalıdır?","options":["Başvuru sahibinin seçtiği herhangi bir özel sürüş eğitmeni","FMCSA Training Provider Registry (TPR) listesinde yer alan bir sağlayıcı","Yerel ilçe veznedarı ofisi","Yalnızca Iowa State Patrol eğitim akademisi"],"explanation":"ELDT, FMCSA Training Provider Registry listesinde yer alan bir kurum tarafından sağlanmalıdır; gerekli eğitimi yalnızca kayıtlı sağlayıcılar verebilir. Kaynak: FMCSA Training Provider Registry; Iowa DOT Commercial Drivers (ELDT Iowa'da geçerlidir)."},"36":{"q":"ELDT (Entry-Level Driver Training), Iowa'da aşağıdakilerden hangisine ilk kez başvuranlar için gereklidir?","options":["Bir Class A veya Class B CDL ve ilk kez S, P veya H onayları","Yalnızca HazMat (H) onayı","Yalnızca İkili/Üçlü (T) onayı","Mevcut herhangi bir CDL'nin yenilenmesi"],"explanation":"ELDT, ilk kez Class A veya Class B CDL başvuranlar için, bir Class B-Class A yükseltmesi için ve ilk kez Okul Otobüsü (S), Yolcu (P) veya HazMat (H) onayları için (H için yalnızca teorik) gereklidir. Kaynak: FMCSA ELDT kuralı (7 Şubat 2022 tarihinde veya sonrasında alınan CLP); Iowa'da geçerlidir."},"37":{"q":"Eyaletler arası ticarette ticari bir araç kullanan ve federal fiziksel uygunluk kurallarından MUAF OLMAYAN bir Iowa CDL sahibi, hangi tıbbi kategoride kendi beyanda (self-certify) bulunmalıdır?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"Bir non-excepted interstate sürücü, bu şekilde kendi beyanda bulunmalı VE güncel bir Medical Examiner's Certificate belgesini Iowa DOT'ta dosyada tutmalıdır; bunu yapmamak bir düşürmeye (downgrade) yol açar. Kaynak: Iowa DOT Medical Cards & Certification; 761 IAC 607.50."},"38":{"q":"Hangi tıbbi kendi beyan kategorisi, Iowa DOT'a bir Medical Examiner's Certificate sunmayı GEREKTİRMEZ?","options":["Non-excepted interstate","Non-excepted intrastate","Dört kategorinin tümü bunu sunmalıdır","Yalnızca eyalet dışı sürücüler muaftır"],"explanation":"Yalnızca non-excepted interstate kategorisi, Medical Examiner's Certificate belgesini Iowa DOT'a sunmalıdır. Non-excepted intrastate sürücüler bunu yanlarında taşır ancak dosyalamak zorunda değildir ve excepted kategoriler hiçbir şeye ihtiyaç duymaz; eyalet içi (intrastate) kategoriler bir 'K' kısıtlaması alır. Kaynak: Iowa DOT Medical Cards & Certification; 761 IAC 607.50."},"39":{"q":"Iowa DOT, ilk kez bir CDL/CLP için başvururken bir başvuru sahibinin hangi belge setini sağlamasını gerektirir?","options":["Kimlik/yasal varlık kanıtı, Social Security numarası ve Iowa ikamet kanıtı","Yalnızca bir pasaport","Yalnızca bir askeri DD-214 formu","Yalnızca araç sigortası ve tescil kanıtı"],"explanation":"Iowa, kimlik ve ABD vatandaşlığı veya yasal varlık kanıtı, bir Social Security numarası ve Iowa ikametinin doğrulanmasını (örneğin, güncel Iowa adresli bir belge) gerektirir. Kaynak: Iowa DOT Commercial Learner Permits (CLP) sayfası; 761 IAC 607."},"40":{"q":"Iowa'da, bir kişinin yasal olarak ticari bir motorlu taşıt (CMV) kullanabileceği azami alkol konsantrasyonu nedir?","options":["0.04","0.08","0.02","0.05"],"explanation":"Iowa Code 321.208(1)(a), bir CMV'yi (321J.1'de tanımlandığı şekilde) 0.04 veya daha fazla alkol konsantrasyonuyla kullanan bir sürücüyü diskalifiye eder. Bu nedenle bir CMV için yasal sınır 0.04'ün altındadır; sıradan sürücülere uygulanan 0.08 sınırının yarısıdır. Kaynak: Iowa Code 321.208 / Iowa CDL Manual."},"41":{"q":"Iowa'nın zımni rıza (implied consent) yasası uyarınca, yasal bir talep sonrasında Chapter 321J kapsamında gerekli kimyasal testi yaptırmayı reddeden bir CDL sahibine ne olur?","options":["Bir alkol mahkumiyetiyle aynı şekilde büyük bir suç olarak değerlendirilir ve diskalifiye getirir","Reddetme anayasal bir hak olduğu için CDL'ye hiçbir şey olmaz","Diskalifiye olmadan yalnızca küçük bir hukuki para cezası uygulanır","Sürücü ilk reddetme için yazılı bir uyarı alır"],"explanation":"Iowa Code 321.208(2)(b) ve 321.208(13), Chapter 321J kapsamında kimyasal testi yaptırmayı reddetmeyi, bir OWI mahkumiyetiyle aynı diskalifiyeyi taşıyan büyük bir suç olarak değerlendirir. Kaynak: Iowa Code 321.208 / Iowa CDL Manual."},"42":{"q":"Plakartlı tehlikeli madde taşımazken, İLK büyük suç (OWI veya 0.04 ya da daha fazlasıyla bir CMV kullanmak gibi) için bir sürücü ne kadar süreyle CMV kullanmaktan diskalifiye edilir?","options":["1 year","3 years","60 days","Ömür boyu"],"explanation":"Iowa Code 321.208(1) ve (2), 0.04 veya daha fazla alkol konsantrasyonuyla araç kullanma, OWI veya test reddi gibi ilk büyük suç için bir yıllık CMV diskalifiyesi uygular. Kaynak: Iowa Code 321.208 (49 CFR 383.51'i yansıtır)."},"43":{"q":"İlk büyük bir suç (OWI veya 0.04 BAC gibi), sürücü plakartlı tehlikeli madde taşıyan bir CMV kullanırken meydana gelirse, diskalifiye ne kadar süreye çıkar?","options":["3 years","1 year","5 years","Ömür boyu"],"explanation":"Iowa Code 321.208(3), suç CMV 49 CFR 383.5 kapsamında plakart gerektiren tehlikeli madde taşırken meydana geldiğinde, ilk suç diskalifiyesini bir yıldan üç yıla yükseltir. Kaynak: Iowa Code 321.208."},"44":{"q":"İKİNCİ bir büyük suç (iki veya daha fazla ayrı olayda) işlemenin, ikinci bir OWI veya test reddi gibi, cezası nedir?","options":["Ömür boyu diskalifiye (daha sonra 10 yıla indirilebilir)","3 yıllık diskalifiye","1 yıllık diskalifiye","120 günlük diskalifiye"],"explanation":"Iowa Code 321.208(4), ayrı olaylardan kaynaklanan iki veya daha fazla büyük suç durumunda bir sürücüyü ömür boyu diskalifiye eder. Ömür boyu diskalifiye, departman kuralı ile 49 CFR 383.51'de öngörüldüğü şekilde 10 yıla indirilebilir. Kaynak: Iowa Code 321.208."},"45":{"q":"Bir CMV kullanırken üç yıllık bir süre içinde İKİ ciddi trafik ihlali biriktiren bir sürücü ne kadar süreyle diskalifiye edilir?","options":["60 days","120 days","30 days","1 year"],"explanation":"Iowa Code 321.208(8), herhangi bir üç yıllık süre içinde iki ciddi trafik ihlali için 60 günlük bir diskalifiye uygular. Kaynak: Iowa Code 321.208 / Iowa CDL Manual."},"46":{"q":"Bir CMV kullanırken üç yıllık bir süre içinde ÜÇ ciddi trafik ihlali biriktiren bir sürücü ne kadar süreyle diskalifiye edilir?","options":["120 days","60 days","180 days","1 year"],"explanation":"Iowa Code 321.208(8), herhangi bir üç yıllık süre içinde üç ciddi trafik ihlali için 120 günlük bir diskalifiye uygular. Birden fazla diskalifiye süresi art arda işler. Kaynak: Iowa Code 321.208."},"47":{"q":"Aşağıdakilerden hangisi Iowa'da bir CMV diskalifiyesine sayılan CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Yasal hız sınırının 15 mph veya daha fazla üzerinde hız yapmak","Yasal hız sınırının 5 mph üzerinde hız yapmak","Bir CMV'de park ihlali","Bir araç ağırlığı (aşırı yük) ihlali"],"explanation":"Iowa Code 321.208(7)(d), sınırın 15 mph veya daha fazla üzerinde hız yapmayı ciddi bir ihlal olarak listeler. Park ve araç ağırlığı ihlalleri, ciddi ihlal sayımından açıkça hariç tutulur. Kaynak: Iowa Code 321.208."},"48":{"q":"Iowa yasalarına göre, ticari bir motorlu taşıt kullanırken mesaj yazmak (texting) hangi tür CDL ihlali olarak kategorize edilir?","options":["Ciddi bir trafik ihlali","1 yıllık diskalifiye getiren büyük bir suç","Bir hizmet dışı (out-of-service) emri ihlali","Diskalifiye etkisi olmayan küçük bir ekipman ihlali"],"explanation":"Iowa Code 321.208(7)(i), bir CMV kullanırken mesaj yazmayı yasaklayan bir yasanın ihlalini, 60 günlük/120 günlük diskalifiyelere sayılan ciddi bir trafik ihlali olarak listeler. Kaynak: Iowa Code 321.208."},"49":{"q":"Bir CMV kullanırken, bir trafik kontrol yasasını ihlal ederek elde tutulan bir cep telefonu kullanmak, Iowa'da nasıl değerlendirilir:","options":["Diskalifiyeye sayılan ciddi bir trafik ihlali","Ömür boyu diskalifiye getiren büyük bir suç","CDL sonucu olmayan bir ihlal","Otomatik 1 yıllık diskalifiye"],"explanation":"Iowa Code 321.208(7)(j), bir CMV kullanırken elde tutulan bir cep telefonunun kullanımını kısıtlayan veya yasaklayan bir yasanın ihlalini, 60/120 günlük diskalifiye eşiklerine sayılan ciddi bir trafik ihlali olarak listeler. Kaynak: Iowa Code 321.208."},"50":{"q":"Bir hizmet dışı (out-of-service) emrinin İLK ihlali için (tehlikeli madde veya 16+ yolcu için tasarlanmış bir araç içermeyen), Iowa diskalifiye aralığı şudur:","options":["180 days'den az ve 1 year'dan fazla olmayan","60 days'den az ve 120 days'den fazla olmayan","30 days'den az ve 90 days'den fazla olmayan","2 years'dan az ve 5 years'dan fazla olmayan"],"explanation":"Iowa Code 321.208(10)(a), ilk hizmet dışı emri ihlalini 180 days'den az ve bir yıldan fazla olmayacak şekilde belirler. Kaynak: Iowa Code 321.208."},"51":{"q":"10 yıl içinde ayrı olaylarda bir hizmet dışı (out-of-service) emrinin İKİNCİ ihlali için (tehlikeli madde dışı), Iowa diskalifiye aralığı şudur:","options":["2 years'dan az ve 5 years'dan fazla olmayan","180 days'den az ve 1 year'dan fazla olmayan","1 year'dan az ve 3 years'dan fazla olmayan","Ömür boyu"],"explanation":"Iowa Code 321.208(10)(a), (10 yıllık bir süre içinde) ikinci bir hizmet dışı emri ihlalini iki yıldan az ve beş yıldan fazla olmayacak şekilde belirler. Kaynak: Iowa Code 321.208."},"52":{"q":"Plakartlı tehlikeli madde taşırken ya da 15'ten fazla yolcu taşımak için tasarlanmış bir CMV kullanırken işlenen bir hizmet dışı (out-of-service) emrinin ilk ihlali, hangi süreyle diskalifiyeyle sonuçlanır:","options":["1 year","180 days","3 years","60 days"],"explanation":"Iowa Code 321.208(10)(b), plakartlı tehlikeli madde taşırken veya 15'ten fazla yolcu (sürücü dahil) için tasarlanmış bir CMV kullanırken işlenen ilk hizmet dışı emri ihlali için bir yıllık diskalifiye uygular. Kaynak: Iowa Code 321.208."},"53":{"q":"Iowa'da bir CMV kullanırken işlenen İLK demiryolu-karayolu hemzemin geçit ihlali için bir sürücü ne kadar süreyle diskalifiye edilir?","options":["60 days","120 days","30 days","1 year"],"explanation":"Iowa Code 321.208(11)(a), bir CMV kullanırken işlenen ilk demiryolu hemzemin geçit ihlali (321.341 veya 321.343 kapsamında) için 60 günlük bir diskalifiye uygular. Kaynak: Iowa Code 321.208."},"54":{"q":"İlkinin üç yılı içinde, bir CMV'de İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlalinden mahkum edilen bir sürücü, hangi süreyle diskalifiye edilir:","options":["120 days","60 days","180 days","1 year"],"explanation":"Iowa Code 321.208(11)(b), ilkinin üç yılı içinde meydana gelen bir CMV'de ikinci bir demiryolu hemzemin geçit ihlali için 120 günlük bir diskalifiye uygular. Kaynak: Iowa Code 321.208."},"55":{"q":"İlkinin üç yılı içinde, bir CMV'de ÜÇÜNCÜ veya sonraki bir demiryolu-karayolu hemzemin geçit ihlalinden mahkum edilen bir sürücü, hangi süreyle diskalifiye edilir:","options":["1 year","120 days","60 days","180 days"],"explanation":"Iowa Code 321.208(11)(c), ilkinin üç yılı içinde meydana gelen bir CMV'de üçüncü veya sonraki bir demiryolu hemzemin geçit ihlali için bir yıllık bir diskalifiye uygular. Kaynak: Iowa Code 321.208."},"56":{"q":"Bir kontrollü maddenin üretimi, dağıtımı veya teslimini içeren bir suç işlerken ticari bir motorlu taşıt kullanmak, Iowa'da hangi CDL cezasıyla sonuçlanır?","options":["İndirim olasılığı olmaksızın ömür boyu diskalifiye","1 yıllık diskalifiye","3 yıllık diskalifiye","120 günlük diskalifiye"],"explanation":"Iowa Code 321.208(5), bir CMV bir kontrollü maddenin üretimi, dağıtımı veya teslimini içeren bir suçta kullanıldığında, 10 yıllık indirime tabi olmayan ömür boyu bir diskalifiye uygular. Kaynak: Iowa Code 321.208."},"57":{"q":"Iowa DOT, diskalifiye edici bir mahkumiyet kaydı aldığında, CMV diskalifiyesi yürürlüğe girmeden önce ne kadar önceden bildirimde bulunur?","options":["30 days","10 days","60 days","24 hours"],"explanation":"Iowa Code 321.208(12) ve (13), departmanın 30 günlük ön bildirim üzerine ön duruşma olmaksızın sürücüyü diskalifiye etmesini öngörür; diskalifiyenin yürürlük tarihi bildirimden 30 days sonradır. Kaynak: Iowa Code 321.208."},"58":{"q":"Bir uygulama görevlisi tarafından 0.04 veya daha fazla alkol konsantrasyonuna sahip olduğu tespit edilen bir CMV sürücüsü, diskalifiyeyle karşı karşıya kalmanın yanı sıra, derhal:","options":["24 hours hizmet dışı bırakılır","1 saatlik dinlenmeden sonra araç kullanmasına izin verilir","0.08'in altındaysa devam etmesine izin verilir","$25 ceza verilip araç kullanmak üzere serbest bırakılır"],"explanation":"Iowa'da kabul edilen federal kurallar (49 CFR 392.5), 0.04 veya daha fazla alkol konsantrasyonuna sahip herhangi bir sürücünün, Iowa Code 321.208 kapsamındaki resmi diskalifiyeden ayrı olarak, 24 hours hizmet dışı bırakılmasını gerektirir. Kaynak: 49 CFR 392.5 / Iowa CDL Manual."},"59":{"q":"İki ayrı olaydan kaynaklanan iki ayrı büyük suç mahkumiyeti, Iowa'da ömür boyu bir CDL diskalifiyesine yol açar. Iowa tarafından kabul edilen federal kural uyarınca, bu ömür boyu süre en az şu süreye indirilebilir:","options":["10 years","5 years","3 years","1 year"],"explanation":"Iowa Code 321.208(4), (iki veya daha fazla büyük suç için) ömür boyu bir diskalifiyeyi, 49 CFR 383.51'de öngörülen ve departman kuralı ile kabul edilen şekilde 10 yıllık bir diskalifiyeye indirilmeye tabi kılar. Kaynak: Iowa Code 321.208."},"60":{"q":"Iowa'nın \"Şerit Değiştir\" (Move Over) yasası uyarınca, kendi yönünüzde iki şeridi olan bir eyaletler arası otoyolda (interstate) seyrederken, ikaz lambaları yanan duran bir acil durum aracına yaklaştığınızda Iowa Code öncelikle ne yapmanızı gerektirir?","options":["Güvenliyse, duran araca bitişik olmayan bir şeride geçmek","Acil durum aracı ayrılana kadar banket üzerinde tamamen durmak","Korna çalıp aynı şeritte mevcut hızınızla geçmeye devam etmek","Sol bankete çekip bir kolluk görevlisinin geçmeniz için işaret etmesini beklemek"],"explanation":"Iowa Code 321.323A, sürücünün yönünde iki veya daha fazla şerit bulunan bir yolda, etkinleştirilmiş ikaz lambaları yanan duran bir araca yaklaşan sürücünün, güvenli ve yasal olduğunda o araca bitişik olmayan bir şeride geçmesini gerektirir. Kaynak: Iowa Code 321.323A; Iowa DOT 'Move Over or Slow Down.'"},"61":{"q":"Iowa'nın \"Şerit Değiştir\" (Move Over) yasası uyarınca, ikaz lambaları yanan duran bir araçtan uzağa şerit değiştirmek mümkün değilse veya güvenli değilse, bir Iowa sürücüsü ne yapmalıdır?","options":["Belirtilen hızı korumak ancak dörtlü flaşörleri açmak","Hızı, belirtilen hız sınırının altına düşürmek ve durmaya hazır olmak","Hızı, belirtilen hız sınırının tam olarak 20 mph altına düşürmek","Belirtilen hız sınırına bakılmaksızın 10 mph'a yavaşlamak"],"explanation":"Iowa Code 321.323A, şerit değiştirmenin mümkün, izinli veya güvenli olmadığı durumlarda sürücünün hızını, belirtilen hız sınırının altında makul ve uygun bir hıza düşürmesini ve durmaya hazır olmasını belirtir. Iowa, sabit bir mph azaltma miktarı BELİRLEMEZ. Kaynak: Iowa Code 321.323A; Iowa DOT."},"62":{"q":"Gerekli ikaz veya uyarı lambalarını gösterdiğinde, aşağıdaki duran araçlardan hangisi Iowa'nın \"Şerit Değiştir\" (Move Over) yasasının (Iowa Code 321.323A) kapsamındadır?","options":["Yalnızca kolluk ve itfaiye araçları","Yalnızca ambulanslar ve çekiciler","Bir katı atık veya geri dönüşüm toplama aracı","Yalnızca Iowa DOT'a ait araçlar"],"explanation":"Iowa Code 321.323A; duran yetkili acil durum araçlarını, çekme/kurtarma, bakım ve inşaat araçlarını, ikaz lambaları yanan katı atık veya geri dönüşüm toplama araçlarını ve dörtlü flaşörlerini sürekli olarak gösteren her türlü motorlu aracı kapsar. Kaynak: Iowa Code 321.323A; Iowa DOT."},"63":{"q":"Kırsal bir Iowa eyaletler arası otoyolunda (interstate), bir çekici-römork (tır) için geçerli olan azami hız sınırı nedir?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Iowa Code 321.285, eyaletler arası yol sisteminde hız sınırını tüm araç trafiği için 70 mph olarak belirler. Iowa, eyaletler arası otoyollarda kamyonlara ayrı, daha düşük bir hız sınırı uygulamaz. Kaynak: Iowa Code 321.285."},"64":{"q":"Iowa, eyaletler arası otoyollarda kamyonlar için binek otomobillerden daha düşük bir hız sınırı belirler mi?","options":["Evet, kamyonlar 65 mph ile sınırlıdır, otomobiller ise 70 mph gidebilir","Hayır, 70 mph'lik eyaletler arası sınır tüm araç trafiği için aynı şekilde geçerlidir","Evet, kamyonlar eyalet genelinde 60 mph ile sınırlıdır","Evet, 26.000 lbs üzerindeki kamyonlar 55 mph ile sınırlıdır"],"explanation":"\"Bölünmüş\" (split) hız sınırı olan bazı eyaletlerin aksine, Iowa Code 321.285, 70 mph'lik eyaletler arası azami sınırı tüm araç trafiğine uygular ve kamyonlar için ayrı bir belirtilmiş sınır yoktur. Kaynak: Iowa Code 321.285."},"65":{"q":"Ücret karşılığı yolcu taşıyan bir Iowa toplu taşıma otobüsü, hemzemin demiryolu geçidine yaklaşıyor. Sürücü nerede durmalıdır?","options":["En yakın raydan 15 fitten az ve 50 fitten fazla olmamak üzere","En yakın raydan 10 fitten az ve 25 fitten fazla olmamak üzere","En yakın raydan 25 fitten az ve 75 fitten fazla olmamak üzere","En yakın raydan 5 fit içinde"],"explanation":"Iowa Code 321.343, ücret karşılığı yolcu taşıyan bir aracın, okul otobüsünün veya plakartlı tehlikeli madde aracının, geçmeden önce en yakın raydan 50 fitten az ama 15 fitten fazla olmayacak şekilde durmasını gerektirir. Kaynak: Iowa Code 321.343."},"66":{"q":"Iowa'da plakartlı bir tehlikeli madde yükü taşıyan bir sürücü, üzerinde 'EXEMPT' (muaf) tabelası bulunan bir demiryolu geçidine ulaşır. Ne yapılması gerekir?","options":["Yine de en yakın raydan 15 ila 50 fit arasında durmak","Yalnızca bir tren görünürdeyse durmak","Sürücünün o geçitte durması gerekmez","Geçmeden önce durup uyarı üçgenleri yerleştirmek"],"explanation":"Iowa Code 321.343; otobüsler, ücret karşılığı yolcu taşıyan araçlar ve plakartlı tehlikeli madde araçları için durmayı gerektirir, ancak resmi bir 'EXEMPT' (muaf) tabelasıyla işaretlenmiş bir geçitte durulması gerekmez. Kaynak: Iowa Code 321.343; Iowa CDL Manual."},"67":{"q":"Bir demiryolu geçidinde durduktan sonra, bir Iowa okul otobüsü sürücüsü rayları geçmeden önce ne yapmalıdır?","options":["Kornayı iki kez çalıp gecikmeden geçmek","Giriş kapısını açmak, trenleri görmek ve dinlemek için bakmak, ardından yalnızca güvenliyse geçmek","Koşullara bakılmaksızın tam 60 saniye beklemek","Sarı uyarı lambalarını yakmak ve yavaşça geçmek"],"explanation":"Iowa Code 321.343 uyarınca, en yakın raydan 15 ila 50 fit uzaklıkta durduktan sonra okul otobüsü sürücüsü giriş kapısını açmalı, yaklaşan bir treni görmek ve dinlemek için bakmalı ve güvenli olana kadar geçmemelidir. Kaynak: Iowa Code 321.343."},"68":{"q":"İki şeritli bir Iowa karayolunda, bir okul otobüsü durur, kırmızı flaşörlü lambalarını yakar ve çocukları indirmek için 'dur' kolunu açar. Yaklaşan bir sürücü ne yapmalıdır?","options":["20 mph'a yavaşlayıp dikkatle geçmek","Otobüse 15 fitten daha yakın olmayacak şekilde durmak ve 'dur' kolu geri çekilene kadar durmaya devam etmek","Yalnızca yolda çocuklar görünürse durmak","En uzaktaki şeride geçip otobüsü yavaşça geçmek"],"explanation":"Iowa Code 321.372, kırmızı lambaları yanıp 'dur' kolu açık duran bir okul otobüsüyle karşılaşan veya onu geçen araçların, otobüse 15 fitten daha yakın olmayacak şekilde durmasını ve 'dur' kolu geri çekilip otobüs yeniden hareket edene kadar durmaya devam etmesini gerektirir. Kaynak: Iowa Code 321.372."},"69":{"q":"Iowa'nın okul otobüsü yasası uyarınca, ters yönde seyreden duran bir okul otobüsüyle KARŞILAŞAN bir sürücü, ne tür bir karayolunda durmadan devam edebilir?","options":["Boyalı orta çizgisi olan herhangi bir karayolu","Her yönde iki veya daha fazla seyir şeridi bulunan bir karayolu","Belirtilen hızı 55 mph veya daha yüksek olan herhangi bir karayolu","En az 8 fit genişliğinde asfalt bankete sahip bir karayolu"],"explanation":"Iowa Code 321.372, her yönde iki veya daha fazla şeridi olan bir karayolundaki bir sürücünün, ters yönde seyreden bir okul otobüsüyle KARŞILAŞTIĞINDA, otobüs durmuş olsa bile durmasının gerekmediğini öngörür. Bölünmemiş yollarda tüm yönlerin durması gerekir. Kaynak: Iowa Code 321.372."},"70":{"q":"Bir refüjle ayrılmış, her yönde iki şeridi olan bir Iowa karayolunda, bir okul otobüsü ters yöndeki şeritlerde kırmızı ışıkları yanarak durur. Diğer yönde seyreden bir sürücü:","options":["Kırmızı ışıklar sönene kadar durmak zorundadır","10 mph'a yavaşlamak zorundadır ancak devam edebilir","Yol her yönde iki veya daha fazla şeride sahip olduğu için durmak zorunda değildir","Yalnızca refüj 6 fitten daha darsa durmak zorundadır"],"explanation":"Iowa Code 321.372'nin bölünmüş karayolu istisnası, şerit sayısına bağlıdır: her yönde iki veya daha fazla şeridi olan bir karayolunda, ters yönde duran bir otobüsle karşılaşan sürücülerin durması gerekmez. Kaynak: Iowa Code 321.372."},"71":{"q":"Bir okul otobüsü, dört veya daha fazla şeritli bir Iowa karayolunda çalışıyor. Karayolunu geçmek zorunda olan öğrencilerle ilgili olarak otobüs:","options":["Kırmızı ışıklar yandığı sürece onları herhangi bir yerde indirip bindirebilir","Karayolunu geçmek zorunda olan öğrencileri, belirlenmiş noktalar dışında indirmek veya bindirmek için durmamalıdır","Onları indirmek için sol şeridi kullanmalıdır","Onları yalnızca sabah 7 ile akşam 7 arasında indirebilir"],"explanation":"Iowa Code 321.372, dört veya daha fazla şeritli bir karayolundaki bir okul otobüsünün, karayolunu geçmek zorunda olan öğrencileri indirmek veya bindirmek için durmasını yasaklar; bunun istisnası trafik kontrol cihazları veya görevlileri olan belirlenmiş duraklar/noktalardır. Kaynak: Iowa Code 321.372."},"72":{"q":"Bir Iowa okul otobüsü yolcular için durmaya hazırlanırken, kırmızı flaşörlü lambaları yakmadan önce hangi uyarı lambalarını göstermelidir?","options":["Yeşil flaşörlü lambalar","Mavi flaşörlü lambalar","Sarı (amber) flaşörlü uyarı lambaları","Beyaz strobe (çakar) lambalar"],"explanation":"Iowa yasası ve Iowa okul taşımacılığı kuralları, sürücünün durmadan önce sarı flaşörlü uyarı lambalarını göstermesini, ardından durakta kırmızı flaşörlü lambalara geçip 'dur' kolunu açmasını gerektirir. Kaynak: Iowa Code 321.372; Iowa Admin. Code 281-43."},"73":{"q":"Bir CDL sürücüsü, düz, dümdüz, iki şeritli bir Iowa karayolunda kamyonu durdurur ve gerekli olan üç uyarı üçgenini yerleştirmek zorundadır. Doğru yerleşim şudur:","options":["Biri arkaya 10 ft, biri arkaya 100 ft ve biri öne 100 ft mesafede","Biri arkaya 25 ft, biri arkaya 250 ft ve biri öne 250 ft mesafede","Biri 5 ft, biri 50 ft ve biri 150 ft mesafede, hepsi arkaya doğru","Üçü de aracın 200 ft arkasına yerleştirilir"],"explanation":"Iowa, Iowa CDL Manual'de öğretilen federal kurala (49 CFR 392.22) uyar: iki şeritli bir yolda üçgenleri aracın yaklaşık 10 ft arkasına, 100 ft arkasına ve 100 ft önüne yerleştirin. Kaynak: 49 CFR 392.22; Iowa CDL Manual."},"74":{"q":"Iowa CDL Manual'e göre, yolda veya bankette arızalanmış bir ticari motorlu aracı durdurduktan ne kadar süre sonra uyarı cihazları (üçgenler) yerleştirilmelidir?","options":["3 dakika içinde","10 dakika içinde","30 dakika içinde","1 saat içinde"],"explanation":"Iowa, sürücünün gerekli uyarı cihazlarını durduktan sonra 10 dakika içinde yerleştirmesini gerektiren 49 CFR 392.22'ye uyar. Kaynak: 49 CFR 392.22; Iowa CDL Manual."},"75":{"q":"Bir CDL sürücüsü, tek yönlü veya bölünmüş bir Iowa karayolunda durur. Üç uyarı üçgeni nereye yerleştirilir?","options":["Yaklaşan trafiğe (arkaya) doğru 10 ft, 100 ft ve 200 ft mesafede","10 ft, 100 ft ve 100 ft mesafede; biri arkaya, ikisi öne doğru","Üçü de aracın her iki tarafında 10 ft mesafede","100 ft önde, 100 ft arkada ve biri kabinin yanında"],"explanation":"Iowa, 49 CFR 392.22'ye uyar: tek yönlü veya bölünmüş bir karayolunda üçgenleri yaklaşan trafiğe doğru 10 ft, 100 ft ve 200 ft mesafede yerleştirin. Kaynak: 49 CFR 392.22; Iowa CDL Manual."},"76":{"q":"Iowa'nın genel 'sağda kal' kuralı (Iowa Code 321.297) hangi araçları sağ şeritte sürmeye yönlendirir?","options":["Yalnızca ticari motorlu araç olarak tescil edilmiş araçlar","Yalnızca römork çeken araçlar","Geçiş yaparken veya sola dönerken hariç, trafiğin normal hızından daha yavaş giden herhangi bir araç","Yalnızca brüt ağırlığı 26.000 pound üzerinde olan araçlar"],"explanation":"Iowa Code 321.297, trafiğin normal hızından daha yavaş giden herhangi bir aracın, geçiş yaparken veya sola dönüşe hazırlanırken hariç, sağ şeridi kullanmasını gerektirir. Iowa'nın kamyonlara özgü bir sol şerit yasağı yoktur; kural tüm yavaş trafiğe uygulanır. Kaynak: Iowa Code 321.297."},"77":{"q":"Iowa'da, bir araç/yük için aşırı boyut izni gerekmeden önce, kamuya açık karayollarında seyir için yasal azami GENİŞLİK şudur:","options":["8 fit 0 inç","8 fit 6 inç","9 fit 0 inç","10 fit 0 inç"],"explanation":"Iowa, federal standartla uyumlu olarak yasal azami genişliği 8 fit 6 inç olarak belirler; bundan daha geniş olan herhangi bir şey için aşırı boyut izni gerekir. Kaynak: Iowa DOT Motor Carrier Services, Oversize/Overweight Permit Requirements; Iowa Code ch. 321."},"78":{"q":"Iowa'da, bölünemez bir yük 13 fit 6 inç yüksekliğe ulaşır. İzin olmaksızın bu yükseklik:","options":["Yasal sınırın üzerindedir; 13 fit 6 inçin üzerinde izin gerekir","Sınırın oldukça altındadır; 16 fite kadar yasaldır","Sınırın üzerindedir; yasal azami 12 fittir","Yalnızca yük 8 fitten daha geniş değilse yasaldır"],"explanation":"Iowa DOT, yasal azami yüksekliği 13 fit 6 inç olarak listeler; 13 fit 6 inçi aşan yükler için aşırı boyut izni gerekir. Kaynak: Iowa DOT Oversize/Overweight Permit Requirements."},"79":{"q":"Iowa aşırı boyut izni kuralları uyarınca, aşırı boyutlu bir yükün hareketine genel olarak ne zaman izin verilir?","options":["Yalnızca hafta içi günlerde sabah 9 ile öğleden sonra 3 arasında","Zaman sınırı olmaksızın günde 24 saat","Gün doğumundan yarım saat önce ile gün batımından yarım saat sonrasına kadar","Trafikten kaçınmak için yalnızca geceleri"],"explanation":"Iowa, aşırı boyutlu yük hareketine genel olarak gün doğumundan yarım saat önce ile gün batımından yarım saat sonrasına kadar, haftanın yedi günü izin verir; bazı tatil günlerinde ve çok büyük yükler için kısıtlamalar vardır. Kaynak: Iowa DOT Motor Carrier Services oversize/overweight permit rules."},"80":{"q":"Iowa'da Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Iowa Ulaştırma Departmanı (Iowa DOT)","Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)","Iowa Kamu Güvenliği Departmanı","Ulaştırma Güvenliği İdaresi (TSA)"],"explanation":"Iowa CDL'leri, eyaletin sürücü belgelendirme kurumu olan Iowa Ulaştırma Departmanı (Iowa DOT) tarafından verilir. FMCSA federal CDL standartlarını belirler ancak belge vermez. Kaynak: Iowa DOT, Commercial Drivers / How to Get a CDL (iowadot.gov)."},"81":{"q":"Bir başvuru sahibi Iowa CDL bilgi ve beceri sınavlarını nerede girebilir?","options":["Seçilmiş Iowa DOT ve County Treasurer (İlçe Veznedarı) sürücü belgesi hizmet noktalarında","Yalnızca Ames'teki tek Iowa DOT genel merkezinde","Eyaletteki herhangi bir FMCSA saha ofisinde","Iowa'daki herhangi bir yerel polis departmanında"],"explanation":"Iowa CDL sınavları, seçilmiş Iowa DOT ve County Treasurer sürücü belgesi noktalarında yapılır; ek noktalar Iowa DOT CDL Testing Locations sayfasında listelenir. Kaynak: Iowa DOT, CDL Testing (iowadot.gov)."},"82":{"q":"Eyalet içi (yalnızca Iowa içinde) sürüş için bir Iowa CDL'si almanın genel asgari yaşı nedir?","options":["18 yaş","16 yaş","21 yaş","25 yaş"],"explanation":"Iowa, Iowa içinde (intrastate) ticari sürüş yapmak için bir CDL başvuru sahibinin en az 18 yaşında olmasını gerektirir. Eyalet sınırlarını geçerek sürüş (interstate) için 21 yaş gerekir. Kaynak: Iowa DOT, How to Get a CDL (iowadot.gov)."},"83":{"q":"Bir Iowa CDL'si ile eyaletler arası ticarette ticari motorlu araç kullanmak için gereken asgari yaş nedir?","options":["21 yaş","18 yaş","19 yaş","23 yaş"],"explanation":"Iowa'da uygulanan federal kural uyarınca, bir sürücünün eyaletler arası ticarette CMV kullanabilmesi için en az 21 yaşında olması gerekir; 18-20 yaş arası sürücüler eyalet içi sürüşle sınırlıdır. Kaynak: Iowa DOT, How to Get a CDL; 49 CFR 391.11 (federal standart)."},"84":{"q":"Bir Iowa CDL başvuru sahibi, başvuru sırasında kimliğini ve yasal statüsünü kanıtlamak için hangi belgeyi sunmalıdır?","options":["Tam ad, doğum tarihi, Sosyal Güvenlik numarası ve vatandaşlık veya yasal statü kanıtı","Yalnızca başvuru sahibinin adına olan güncel bir fatura","Yalnızca mevcut bir işverenden imzalı bir mektup","Bir lise diploması veya GED sertifikası"],"explanation":"Iowa; tam yasal ad, doğum tarihi, Sosyal Güvenlik numarası ve vatandaşlık veya yasal daimi ikamet kanıtının (örneğin doğum belgesi, pasaport veya daimi ikamet kartı) yanı sıra Iowa ikamet kanıtı gerektirir. Kaynak: Iowa DOT, How to Get a CDL (iowadot.gov)."},"85":{"q":"Sınavdan önce, her Iowa CDL başvuru sahibi 'öz beyanda' (self-certify) bulunmalıdır. Öz beyan ne anlama gelir?","options":["Bir CMV'yi nasıl kullandığınızı tanımlayan dört sürüş kategorisinden hangisinin geçerli olduğunu Iowa DOT'a beyan etmek","Hiçbir trafik cezanızın olmadığına dair bir beyan imzalamak","Eğitimi bir yıl içinde tamamlamayı taahhüt etmek","Sınava gireceğiniz aracın size ait olduğunu onaylamak"],"explanation":"Öz beyan, sürücünün kendisine hangi CMV kullanım kategorisinin uygun olduğunu Iowa DOT'a beyan etmesidir; bu, bir tıbbi muayene sertifikasının dosyada bulunması gerekip gerekmediğini belirler. Kaynak: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"86":{"q":"Bir Iowa CDL sahibinin arasından seçim yapması gereken kaç öz beyan kategorisi vardır?","options":["Dört","İki","Üç","Altı"],"explanation":"Dört kategori vardır: eyaletler arası muaf olmayan (interstate non-excepted), eyaletler arası muaf (interstate excepted), eyalet içi muaf olmayan (intrastate non-excepted) ve eyalet içi muaf (intrastate excepted). Kaynak: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"87":{"q":"Hangi öz beyan kategorisi, Iowa DOT'ta dosyada güncel bir Tıbbi Muayene Sertifikası bulunmasını GEREKTİRİR?","options":["Eyaletler arası muaf olmayan (interstate non-excepted)","Eyaletler arası muaf (interstate excepted)","Eyalet içi muaf (intrastate excepted)","Eyalet içi muaf olmayan (intrastate non-excepted)"],"explanation":"Yalnızca eyaletler arası muaf olmayan (interstate non-excepted) sürücüler, Iowa DOT'a güncel bir Tıbbi Muayene Sertifikası sunmak ve dosyada tutmak zorundadır. Muaf sürücüler bunu yapmaz ve eyalet içi muaf olmayan sürücüler kartı yanlarında taşımalıdır ancak eyalete dosyalamaları gerekmez. Kaynak: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"88":{"q":"Bir Iowa eyaletler arası muaf olmayan sürücüsü için, DOT Tıbbi Muayene Sertifikası eyalete nasıl sunulur?","options":["Sertifikalı tıbbi muayene uzmanı bunu ulusal sicil/eyalet sistemine elektronik olarak gönderir","Sürücü, Washington, D.C.'deki FMCSA'ya kağıt bir kopya postalar","Sürücünün işvereni bunu ilçe veznedarına fakslar","Doktorun faturalandırma yazılımından otomatik olarak aktarılır"],"explanation":"Iowa'da, sertifikalı tıbbi muayene uzmanı sertifikayı elektronik olarak gönderir; sonuçlar National Registry of Certified Medical Examiners aracılığıyla eyalete iletilir. Eyaletler arası muaf olmayan statü için sürücü bunu kendisi dosyalamaz. Kaynak: Iowa DOT, Medical Cards & Certification."},"89":{"q":"Bir Iowa eyaletler arası muaf olmayan CDL sahibi, yenisini dosyalamadan Tıbbi Muayene Sertifikasının süresinin dolmasına izin verir. CDL'ye ne olur?","options":["Iowa DOT, bir bildirim/ek süre döneminden sonra CDL'yi düşürerek ticari yetkileri kaldırır","CDL'nin kendisinin süresi dolana kadar hiçbir şey değişmez","CDL, kartın süresinin dolduğu gün kalıcı olarak iptal edilir","Sürücü otomatik olarak muaf eyalet içi kategorisine taşınır"],"explanation":"Tıbbi sertifikanın süresi dolarsa, Iowa DOT tıbbi durumu 'sertifikalı değil' (not certified) olarak ayarlar, yazılı bildirimde bulunur ve 60 günlük süre içinde güncel bir sertifika alınmazsa CMV yetkilerini kaldırır (düşürme). Kaynak: Iowa Admin. Code r. 761-607.50."},"90":{"q":"Bir Iowa başvuru sahibinin CDL sürecinde, beceri sınavından önce elde ettiği ilk belge nedir?","options":["Bir Ticari Öğrenici Belgesi (CLP)","Tam, kısıtlamasız bir CDL","Bir tehlikeli madde ek yetkisi","Bir tıbbi muafiyet sertifikası"],"explanation":"Gerekli bilgi sınav(lar)ını geçtikten ve belge/tıbbi gereklilikleri karşıladıktan sonra, başvuru sahibi, beceri sınavından önce gözetim altında pratik yapmaya izin veren bir Ticari Öğrenici Belgesi (CLP) alır. Kaynak: Iowa DOT, How to Get a CDL; Commercial Learner Permits (iowadot.gov)."},"91":{"q":"Bir Ticari Öğrenici Belgesi (CLP) verilebilmesi için bir Iowa başvuru sahibinin neyi geçmesi gerekir?","options":["İlgili CDL bilgi (yazılı) sınavı ve görme taraması","Yalnızca üç bölümlü beceri sınavı","Kendi özel arabalarında bir yol sınavı","Hazmat TSA güvenlik soruşturması"],"explanation":"Bir CLP, başvuru sahibi ilgili CDL bilgi sınav(lar)ını ve görme taramasını geçtikten ve gerekli belgeleri sunduktan sonra verilir; beceri sınavı daha sonra gelir. Kaynak: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"92":{"q":"Bir Iowa başvuru sahibinin CDL beceri sınavına girmeden önce bir Ticari Öğrenici Belgesini ne kadar süre elinde tutması gerekir?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Iowa, beceri sınavına girilmeden önce bir CLP'nin en az 14 gün elde tutulmasını gerektiren federal kuralı uygular. Kaynak: Iowa DOT, How to Get a CDL / Commercial Learner Permits; 49 CFR 383.25."},"93":{"q":"Bir Iowa Ticari Öğrenici Belgesi (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["Bir yıl geçerlidir ve yenilenemez (yeni bir CLP alınması gerekir)","180 gün geçerlidir ve bir kez yenilenebilir","İki yıl geçerlidir ve yıllık olarak yenilenebilir","60 gün geçerlidir ve sınırsız yenilenebilir"],"explanation":"Bir Iowa CLP'si veriliş tarihinden itibaren bir yıl geçerlidir ve yenilenemez; süresi dolarsa başvuru sahibi yeniden başvurmalıdır. Kaynak: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"94":{"q":"7 Şubat 2022 tarihinde veya sonrasında verilen CLP'ler için, bir Iowa başvuru sahibi CDL beceri sınavına girebilmeden önce neyin tamamlanması ve doğrulanması gerekir?","options":["Kayıtlı bir eğitim sağlayıcısından Giriş Seviyesi Sürücü Eğitimi (ELDT)","Bir community college'da bir savunmacı sürüş kursu","En az 160 saat ücretsiz yol süresi","En az 30 gün sonra girilen ikinci bir bilgi sınavı"],"explanation":"7 Şubat 2022 tarihinde veya sonrasında verilen CLP'ler için beceri sınavından önce, FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi'nin (ELDT) tamamlanması ve doğrulanması gerekir. Kaynak: Iowa DOT, How to Get a CDL; 49 CFR Part 380 Subpart F."},"95":{"q":"ELDT'nin tamamlanması, Iowa DOT'un bir beceri sınavı planlamadan önce bunu doğrulayabilmesi için nereye kaydedilir?","options":["FMCSA Training Provider Registry'de (TPR)","Başvuru sahibinin CLP kartına el yazısıyla","Sürücünün tuttuğu kağıt bir seyir defterinde","TSA Hazmat veritabanında"],"explanation":"Kayıtlı sağlayıcılar ELDT sertifikasyonunu FMCSA Training Provider Registry'ye yükler; Iowa DOT, beceri sınavı planlanmadan önce bu kaydı doğrular. Kaynak: Iowa DOT, How to Get a CDL; FMCSA Training Provider Registry (49 CFR Part 380)."},"96":{"q":"Iowa CDL beceri sınavı üç bölümden oluşur. Hangi liste bunları doğru şekilde adlandırır?","options":["Sürüş öncesi araç muayenesi, temel kontrol becerileri ve yol üzerinde sürüş","Yazılı sınav, görme testi ve işitme testi","Hava frenleri sınavı, hazmat sınavı ve kombinasyon sınavı","Yalnızca geri gitme, yalnızca paralel park etme ve yalnızca otoyola katılma"],"explanation":"Iowa beceri sınavının üç bölümü vardır: sürüş öncesi araç muayenesi, temel kontrol becerileri sınavı (manevralar ve koniler etrafında geri gitme) ve yol üzerinde sürüş sınavı. Kaynak: Iowa DOT, CDL Testing (iowadot.gov); Iowa CDL Manual."},"97":{"q":"Beceri sınavının Iowa sürüş öncesi araç muayenesi bölümünde, başvuru sahibinin ne yapması beklenir?","options":["Aracın etrafında yürümek ve her bir öğeyi işaret ederek veya dokunarak neyin neden kontrol edildiğini açıklamak","Aracın iyi durumda olduğunu basitçe belirtmek","Fren sistemini muayene memuru için sökmek","Göstergeleri tarif ederken aracı otoyolda sürmek"],"explanation":"Sürüş öncesi muayenede, başvuru sahibi aracın etrafında yürür, her bir öğeyi işaret eder veya ona dokunur ve aracın sürmek için güvenli olduğunu göstermek üzere muayene memuruna neyin neden kontrol edildiğini açıklar. Kaynak: Iowa DOT, CDL Testing (iowadot.gov); Iowa CDL Manual."},"98":{"q":"Çoğu yetişkin sürücü için bir Iowa CDL yenileme döngüsünün tipik azami geçerlilik süresi nedir?","options":["8 yıla kadar (yaşlı sürücüler için daha kısa, yaklaşık 80 yaş civarında sınırlanır)","Tüm sürücüler için tam olarak 1 yıl","15 yıla kadar","Tam olarak 30 gün"],"explanation":"CDL'ler dahil Iowa sürücü belgeleri 8 yıla kadar verilebilir; yaşlı sürücüler için daha kısa süreler vardır ve belgenin sürücünün yaklaşık 80. doğum gününü geçmemesi için bir sınır uygulanır. Kaynak: Iowa Code 321.196; Iowa DOT, Renew a CDL."},"99":{"q":"Her Iowa CDL yenilemesinde, tehlikeli madde (H) ek yetkisine sahip bir kişi neden çevrimiçi yerine bizzat yenileme yapmalıdır?","options":["Hazmat bilgi sınavını yeniden geçmeli ve bir TSA tehdit değerlendirmesi/güvenlik soruşturması tamamlamalıdır","Iowa'da hiçbir CDL sahibi için çevrimiçi yenileme asla mevcut değildir","Ek yetkiyi kalıcı olarak teslim etmelidir","Önce çevrimiçi yeni bir ELDT teori kursunu tamamlamalıdır"],"explanation":"Hazmat ek yetkisi sahipleri, her yenilemede hazmat bilgi sınavını yeniden geçmeli ve bir TSA güvenlik tehdit değerlendirmesi (parmak izi esaslı güvenlik soruşturması) tamamlamalıdır; bu nedenle çevrimiçi yenileme yapamazlar ve bizzat başvurmalıdırlar. Kaynak: Iowa DOT, Renew a CDL; 49 CFR 1572 (TSA)."}},"es":{"0":{"q":"¿Cuál es el ancho máximo legal de un vehículo comercial en las carreteras de Iowa sin un permiso de sobredimensión?","options":["8 pies 6 pulgadas","8 pies 0 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"La sección 321.454 del Código de Iowa establece el ancho máximo de un vehículo, incluida la carga, en 8 pies 6 pulgadas (102 inches). Cualquier cosa más ancha requiere un permiso de sobredimensión. Fuente: Iowa Code 321.454; requisitos de permisos de sobredimensión/sobrepeso del Iowa DOT."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo y su carga en las carreteras de Iowa sin un permiso?","options":["13 pies 6 pulgadas","13 pies 0 pulgadas","14 pies 0 pulgadas","14 pies 6 pulgadas"],"explanation":"La sección 321.456 del Código de Iowa limita la altura del vehículo a 13 pies 6 pulgadas. Las cargas más altas que esto requieren un permiso de sobredimensión. Fuente: Iowa Code 321.456; requisitos de permisos del Iowa DOT."},"2":{"q":"En las carreteras de Iowa, ¿cuál es la longitud máxima legal de un semirremolque que opera en una combinación tractor-semirremolque sin un permiso?","options":["53 pies","48 pies","57 pies","45 pies"],"explanation":"Iowa permite un semirremolque de hasta 53 pies de largo (cargado o vacío) en una combinación tractor-semirremolque sin un permiso. Los remolques de plataforma baja (lowboy) que transportan equipo de construcción pueden tener hasta 57 pies. Fuente: capítulo 321 del Iowa Code; requisitos de permisos del Iowa DOT."},"3":{"q":"¿Cuál es el peso bruto vehicular máximo permitido en las carreteras de Iowa sin un permiso de sobrepeso?","options":["80,000 pounds","73,280 pounds","84,000 pounds","76,000 pounds"],"explanation":"La sección 321.463 del Código de Iowa limita el peso bruto máximo a 80,000 pounds, en consonancia con el límite federal. Excederlo requiere un permiso de sobrepeso. Fuente: Iowa Code 321.463; Iowa DOT."},"4":{"q":"¿Cuál es el peso máximo permitido sobre un solo eje en las carreteras de Iowa?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"La sección 321.463 del Código de Iowa limita un solo eje a 20,000 pounds, lo mismo que el estándar federal de las carreteras interestatales (Interstate). Fuente: Iowa Code 321.463; Iowa DOT."},"5":{"q":"¿Cuál es el peso máximo permitido sobre un grupo de ejes en tándem en las carreteras de Iowa?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"La sección 321.463 del Código de Iowa limita un eje en tándem a 34,000 pounds, igualando el estándar federal. Fuente: Iowa Code 321.463; Iowa DOT."},"6":{"q":"¿Qué método utiliza Iowa para determinar el peso bruto máximo sobre cualquier grupo de dos o más ejes consecutivos?","options":["La Fórmula del Puente federal (Bridge Formula, Formula B)","Un límite fijo de 80,000 lb sin importar el espaciamiento","Únicamente la capacidad nominal de carga de los neumáticos","Una regla de 600 libras por pulgada de ancho de neumático"],"explanation":"Iowa aplica la Fórmula del Puente federal (W = 500[(LN/(N-1)) + 12N + 36]) para limitar el peso sobre grupos de ejes consecutivos en función del número de ejes (N) y el espaciamiento (L). Fuente: Iowa Code 321.463; 23 CFR 658.17; Iowa DOT."},"7":{"q":"En la Fórmula del Puente federal tal como se aplica en Iowa, ¿qué representan las variables L y N?","options":["L es la distancia en pies entre los ejes exteriores del grupo; N es el número de ejes del grupo","L es la carga en libras; N es el número de neumáticos","L es la longitud legal del remolque; N es el peso neto","L es el ancho del carril; N es el número de permisos requeridos"],"explanation":"En W = 500[(LN/(N-1)) + 12N + 36], L es la distancia en pies entre los ejes más exteriores de cualquier grupo de dos o más ejes consecutivos, y N es el número de ejes de ese grupo. Fuente: 23 CFR 658.17 según lo adoptado por el Iowa Code 321.463."},"8":{"q":"¿Cómo se comparan los límites de peso bruto y por eje de Iowa en el sistema interestatal (Interstate) con los de las carreteras principales (no interestatales) del estado?","options":["Los límites de 80,000 lb de peso bruto y 20,000/34,000 lb por eje son los mismos; ciertos pesos mayores se permiten únicamente en carreteras no interestatales","Las carreteras no interestatales permiten solo 73,280 lb de peso bruto","La interestatal permite 90,000 lb de peso bruto","No hay límites de peso en las carreteras no interestatales"],"explanation":"Los límites básicos de Iowa (80,000 lb de peso bruto, 20,000 lb por eje simple, 34,000 lb por tándem) se aplican tanto en las carreteras interestatales como en las principales. Algunas excepciones legales para peso adicional se aplican únicamente en el sistema no interestatal, ya que la interestatal tiene un tope federal de 80,000 lb. Fuente: Iowa Code 321.463; Iowa DOT."},"9":{"q":"Un vehículo de Iowa de cinco ejes para transporte de ganado, con un remolque de ejes separados (spread-axle) que cumple los requisitos de espaciamiento, puede transportar un peso bruto mayor ¿en qué carreteras?","options":["Únicamente en carreteras no interestatales (principales), hasta 86,000 pounds","Únicamente en carreteras interestatales, hasta 86,000 pounds","En todas las carreteras, incluidas las interestatales, hasta 90,000 pounds","Únicamente en caminos rurales de grava del condado, hasta 80,000 pounds"],"explanation":"La sección 321.463 del Código de Iowa permite que un vehículo de cinco ejes para transporte de ganado lleve hasta 86,000 lb de peso bruto en carreteras no interestatales cuando tiene al menos 61 feet entre el primer y el quinto eje y al menos 8 feet 1 inch entre los dos ejes traseros (separados). Esto no aplica en la interestatal. Fuente: Iowa Code 321.463."},"10":{"q":"Según la ley de Iowa, un vehículo que transporta productos agrícolas sin procesar puede exceder su peso bruto registrado (de registro) ¿hasta qué porcentaje?","options":["25 percent","10 percent","15 percent","50 percent"],"explanation":"Iowa permite que los camiones que transportan productos agrícolas sin procesar operen hasta un 25 percent por encima de su peso registrado mientras estén en Iowa (todavía sujetos a los límites por eje y de la Fórmula del Puente). Fuente: guía para transportistas motorizados del Iowa DOT; capítulo 321 del Iowa Code."},"11":{"q":"¿Cuándo se requiere un permiso de sobredimensión/sobrepeso del Iowa DOT para una carga?","options":["Cuando la carga es indivisible y excede los límites legales de tamaño o peso","Siempre que el vehículo pese más de 26,001 pounds","Solo cuando el vehículo cruza la línea estatal","Cada vez que un conductor con CDL opera después del anochecer"],"explanation":"Se emite un permiso para un vehículo o carga indivisible que excede los límites legales de tamaño o peso. Una carga se considera indivisible si separarla destruiría su valor, comprometería su uso previsto, o requeriría más de ocho horas de trabajo para desmontarla. Fuente: requisitos de permisos de sobredimensión/sobrepeso del Iowa DOT; capítulo 321E del Iowa Code."},"12":{"q":"¿Qué significa que una carga sea \"indivisible\" para que califique para un permiso de sobredimensión/sobrepeso de Iowa?","options":["No puede reducirse razonablemente a dimensiones/peso legales sin destruir su valor, comprometer su uso, o requerir más de 8 horas de trabajo para desmontarla","Está sellada en un contenedor con candado","Es propiedad de un solo transportista","Pesa exactamente 80,000 pounds"],"explanation":"Iowa, siguiendo las definiciones federales, trata una carga como indivisible cuando reducirla a los límites legales destruiría su valor, comprometería su uso previsto, o requeriría más de ocho horas de trabajo para desmontarla con el equipo adecuado. Las cargas divisibles, por lo general, no pueden ser objeto de permiso. Fuente: requisitos de permisos del Iowa DOT; 23 CFR 658.5."},"13":{"q":"¿Cómo solicita un transportista un permiso de sobredimensión/sobrepeso del Iowa DOT?","options":["En línea a través del sistema de permisos del Iowa DOT (ia.gotpermits.com) o por correo","Solo en persona en la oficina del alguacil del condado","Llamando a la Federal Motor Carrier Safety Administration","Únicamente a través del fabricante del vehículo"],"explanation":"Los permisos de sobredimensión/sobrepeso del Iowa DOT se obtienen en línea a través del portal de permisos del estado (ia.gotpermits.com) o por correo. Los permisos cubren únicamente las carreteras estatales e interestatales; se necesitan permisos separados para los caminos municipales o del condado. Fuente: permisos de sobredimensión/sobrepeso del Iowa DOT."},"14":{"q":"Un permiso estándar de sobredimensión/sobrepeso de viaje único de Iowa normalmente es válido ¿por cuánto tiempo?","options":["5 days","24 hours","30 days","1 year"],"explanation":"Un permiso estándar de viaje único (viaje sencillo/de ida y vuelta) de Iowa es válido por 5 días calendario. Los permisos de viajes múltiples duran 60 days y los permisos anuales 12 months. Fuente: tipos de permisos de sobredimensión/sobrepeso del Iowa DOT."},"15":{"q":"Un permiso de sobredimensión/sobrepeso del Iowa DOT autoriza el tránsito ¿en qué vías?","options":["Únicamente en carreteras estatales e interestatales; se necesitan permisos separados para caminos municipales y del condado","En todos los caminos públicos de Iowa, incluidas todas las calles municipales y caminos del condado","Únicamente en el sistema interestatal","Únicamente en caminos privados de acarreo"],"explanation":"Los permisos del Iowa DOT cubren el sistema de carreteras principales estatales e interestatales. Para transitar por calles municipales o caminos del condado, un transportista debe obtener permisos separados de esas jurisdicciones locales. Fuente: requisitos de permisos de sobredimensión/sobrepeso del Iowa DOT."},"16":{"q":"En las carreteras de Iowa, las señales de advertencia de carga sobredimensionada y las banderas en las esquinas generalmente se requieren una vez que el vehículo y la carga exceden ¿qué dimensiones?","options":["75 feet de longitud, 8 feet 6 inches de ancho, o 14 feet 4 inches de altura","40 feet de longitud u 8 feet de ancho","100 feet de longitud o 12 feet de ancho","53 feet de longitud o 10 feet de ancho"],"explanation":"Iowa requiere señales y banderas de \"Oversize Load\" cuando un vehículo y su carga con permiso exceden 75 feet de longitud, 8 feet 6 inches de ancho, y/o 14 feet 4 inches de altura. Banderas rojas (cuadradas de 18 inches) marcan los extremos de la carga. Fuente: condiciones de permisos del Iowa DOT/Iowa Admin. Code ch. 761-511."},"17":{"q":"Para una carga sobredimensionada, ¿a partir de qué ancho aproximadamente comienza Iowa generalmente a requerir al menos un vehículo escolta (piloto)?","options":["Cuando la carga es más ancha que 14 feet 6 inches","Cuando la carga es más ancha que 8 feet 6 inches","Cuando la carga es más ancha que 10 feet","Nunca se requieren escoltas en Iowa"],"explanation":"En Iowa, las cargas de más de 14 feet 6 inches de ancho generalmente requieren al menos un vehículo escolta; las cargas de hasta 14 feet 6 inches que ocupan más de la mitad de la vía pueden, en cambio, usar un escolta delantero o luces de advertencia ámbar. Ciertas rutas pueden imponer requisitos más estrictos. Fuente: condiciones de permisos del Iowa DOT/Iowa Admin. Code ch. 761-511."},"18":{"q":"Bajo las condiciones típicas de los permisos de Iowa, ¿cuándo puede circular una carga sobredimensionada grande (demasiado grande para circular 24/7)?","options":["Desde media hora antes del amanecer hasta media hora después del atardecer, incluidos sábados y domingos, con el equipo de seguridad adecuado","Únicamente entre la medianoche y las 4 a.m.","Únicamente entre semana, nunca los fines de semana ni los días festivos","En cualquier momento, sin restricción de hora del día"],"explanation":"Las condiciones de los permisos de Iowa permiten que las cargas sobredimensionadas más grandes circulen desde media hora antes del amanecer hasta media hora después del atardecer, incluidos los fines de semana, con la iluminación/señalización adecuada. Las cargas con permiso más pequeñas (dentro de los límites establecidos) pueden circular de forma continua (24/7). Fuente: condiciones de permisos del Iowa DOT/Iowa Admin. Code ch. 761-511."},"19":{"q":"Iowa ofrece un permiso especializado de sobredimensión/sobrepeso específicamente para transportar ¿qué producto forestal a pesos superiores a los legales?","options":["Productos forestales sin procesar","Muebles terminados","Papel moneda","Adornos navideños"],"explanation":"Entre los permisos especializados de Iowa está el permiso de Productos Forestales Sin Procesar (Raw Forest Products), que (al igual que las excepciones agrícolas) acomoda la cosecha/transporte de productos forestales no procesados por encima de los límites estándar bajo condiciones establecidas. Fuente: tipos de permisos de sobredimensión/sobrepeso del Iowa DOT."},"20":{"q":"Según las reglas de Iowa, ¿qué clase de CDL se requiere para operar un vehículo combinado con una clasificación de peso bruto combinado (GCWR) de 26,001 pounds o más, donde la(s) unidad(es) remolcada(s) tienen un GVWR de más de 10,000 pounds?","options":["Clase A","Clase B","Clase C","Clase D (chofer)"],"explanation":"Iowa emite una CDL de Clase A para vehículos combinados con un GCWR de 26,001+ lbs donde la unidad remolcada excede 10,000 lbs de GVWR. Fuente: Iowa DOT CDL Manual / 761 IAC 607.16; 'Driver's License Types, Restrictions, & Endorsements' del Iowa DOT."},"21":{"q":"Un conductor de Iowa opera un camión rígido de una sola unidad con un GVWR de 30,000 pounds y remolca un pequeño remolque con clasificación de 8,000 pounds de GVWR. ¿Qué clase de CDL se requiere?","options":["Clase C","Clase A","Clase B","No se requiere CDL"],"explanation":"La CDL de Clase B de Iowa cubre un solo vehículo con un GVWR de 26,001+ lbs, incluido remolcar una unidad que no exceda 10,000 lbs de GVWR. Dado que el remolque es de menos de 10,001 lbs, esto es Clase B, no Clase A. Fuente: Iowa DOT CDL Manual / página de tipos de licencias del Iowa DOT; 761 IAC 607.16."},"22":{"q":"En Iowa, un vehículo que tiene menos de 26,001 lbs de GVWR pero que está diseñado para transportar 16 o más personas (incluido el conductor), o que se usa para transportar materiales peligrosos con placas (placarded), requiere ¿qué clase de CDL?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"La CDL de Clase C de Iowa aplica a vehículos por debajo de los umbrales de peso de Clase A/B que ya sea transportan 16+ personas (incluido el conductor) o transportan materiales peligrosos que requieren placas. Fuente: 'Driver's License Types, Restrictions, & Endorsements' del Iowa DOT; 761 IAC 607.16."},"23":{"q":"En Iowa, ¿cuál es la edad mínima para obtener una CDL para conducir INTRAESTATAL (operar vehículos comerciales únicamente dentro de Iowa)?","options":["16 años","18 años","21 años","19 años"],"explanation":"Iowa permite una CDL para el comercio intraestatal (dentro de Iowa) a los 18 años. Conducir interestatal requiere tener 21 años. Fuente: Iowa DOT Commercial Drivers / Iowa Tax And Tags CDL Endorsements; estándar de la FMCSA adoptado por Iowa."},"24":{"q":"En Iowa, ¿cuál es la edad mínima para operar un vehículo motorizado comercial en el comercio INTERESTATAL (cruzando líneas estatales)?","options":["18 años","19 años","21 años","20 años"],"explanation":"Iowa, siguiendo el estándar federal, exige que los conductores tengan al menos 21 años para conducir en el comercio interestatal o para transportar materiales peligrosos. Los conductores de 18 a 20 años están limitados a la operación intraestatal. Fuente: Iowa DOT Commercial Drivers; FMCSA 49 CFR 391.11 según se aplica en Iowa."},"25":{"q":"¿Qué endoso de CDL requiere Iowa para transportar materiales peligrosos en cantidades que exigen que el vehículo lleve placas (placarded)?","options":["Endoso N","Endoso H","Endoso T","Endoso X"],"explanation":"El endoso H (HazMat, materiales peligrosos) se requiere para transportar HazMat con placas. Fuente: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual. (Nota: un endoso X indica un endoso combinado de tanque + HazMat.)"},"26":{"q":"Además de aprobar el examen escrito de conocimientos, ¿qué requisito federal adicional debe cumplir un solicitante de Iowa para obtener (y renovar) el endoso de HazMat (H)?","options":["Un examen de habilidades de manejo por separado en un camión cisterna","Una evaluación de amenazas a la seguridad basada en huellas dactilares de la TSA (verificación de antecedentes)","Un mínimo de dos años de experiencia con CDL","Una exención de visión de la FMCSA"],"explanation":"El endoso H requiere una evaluación de amenazas a la seguridad de la TSA basada en huellas dactilares en la solicitud inicial y nuevamente en cada renovación, además del examen de conocimientos de HazMat. Fuente: Iowa Tax And Tags CDL Endorsements; TSA HazMat Endorsement Threat Assessment Program adoptado en Iowa."},"27":{"q":"¿Qué endoso de CDL de Iowa se requiere para conducir un vehículo cisterna (tank vehicle), definido como el transporte de líquidos o gases en un tanque con una capacidad nominal individual de más de 119 gallons y una capacidad nominal agregada de 1,000 gallons o más?","options":["N (Tanque)","H (HazMat)","T (Dobles/Triples)","P (Pasajeros)"],"explanation":"El endoso N (Tanque) cubre los vehículos cisterna que cumplen los umbrales de capacidad de 119 gallons individual y 1,000 gallons agregada, y requiere aprobar el examen de conocimientos de camión cisterna (Tanker). Fuente: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"28":{"q":"¿Qué endoso de CDL de Iowa se requiere para arrastrar remolques dobles o triples?","options":["Endoso P","Endoso N","Endoso T","Endoso S"],"explanation":"El endoso T (Dobles/Triples), obtenido al aprobar el examen de conocimientos de Remolques Dobles y Triples, se requiere para arrastrar varios remolques. Fuente: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"29":{"q":"Respecto a los remolques triples en Iowa, ¿qué afirmación es correcta para un conductor que posee el endoso T?","options":["La ley de Iowa prohíbe operar remolques triples dentro del estado, aunque un residente puede obtener el endoso T para usarlo en otros estados","Los remolques triples pueden operarse en cualquier carretera interestatal de Iowa","Los remolques triples se permiten únicamente en las carreteras de peaje de Iowa","Iowa exige un endoso 'Y' separado para los triples"],"explanation":"La ley de Iowa prohíbe la operación de remolques triples dentro del estado; sin embargo, un residente de Iowa puede aun así obtener el endoso T para operar triples legalmente en estados que los permiten. Fuente: Iowa Tax And Tags CDL Endorsements; límites de longitud/combinación del Iowa Code Ch. 321."},"30":{"q":"¿Qué endoso de CDL de Iowa se requiere para conducir un vehículo diseñado para transportar 16 o más personas, incluido el conductor?","options":["S (Autobús Escolar)","P (Pasajeros)","N (Tanque)","C (Chofer)"],"explanation":"El endoso P (Pasajeros) se requiere para vehículos diseñados para transportar 16 o más personas, incluido el conductor. Requiere el examen de conocimientos de pasajeros más un examen de habilidades en un vehículo representativo. Fuente: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"31":{"q":"En Iowa, ¿qué debe poseer un conductor además del endoso de Autobús Escolar (S) para poder operar legalmente un autobús escolar?","options":["El endoso de Pasajeros (P)","El endoso de Tanque (N)","El endoso de HazMat (H)","Nada más; el endoso S por sí solo es suficiente"],"explanation":"Iowa exige AMBOS endosos, el de Autobús Escolar (S) y el de Pasajeros (P), para operar un autobús escolar; el endoso P por sí solo no es válido para la operación de autobuses escolares. Fuente: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual."},"32":{"q":"¿Cuánto tiempo debe poseer un solicitante un Permiso de Aprendiz Comercial (CLP) de Iowa antes de que se le permita tomar el examen de habilidades (de manejo) de la CDL?","options":["Al menos 7 days","Al menos 14 days","Al menos 30 days","Al menos 60 days"],"explanation":"La regla federal, aplicada en Iowa, exige poseer el CLP por un mínimo de 14 days antes de tomar el examen de habilidades. Fuente: página de Commercial Learner Permits (CLP) del Iowa DOT; 49 CFR 383.25."},"33":{"q":"¿Cuál es el período de validez de un Permiso de Aprendiz Comercial (CLP) de Iowa?","options":["180 days, renovable una vez","Un año desde la emisión, sin período de renovación","Dos años, renovable","90 days, no renovable"],"explanation":"Un CLP de Iowa cuesta $12 y es válido por un año a partir de la fecha de emisión, sin período de renovación. Fuente: página de Commercial Learner Permits (CLP) del Iowa DOT."},"34":{"q":"¿Qué debe poseer ya un solicitante antes de solicitar un Permiso de Aprendiz Comercial (CLP) o una CDL de Iowa?","options":["Una licencia de conducir no comercial de Iowa válida","Una tarjeta TWIC federal","Dos años de experiencia de manejo militar","Una licencia de motocicleta de Clase M"],"explanation":"Iowa exige que los solicitantes posean una licencia de conducir no comercial de Iowa válida antes de solicitar un CLP o una CDL. Fuente: página de Commercial Learner Permits (CLP) del Iowa DOT / Iowa Tax And Tags."},"35":{"q":"La Capacitación de Conductores de Nivel Inicial (ELDT) en Iowa debe completarse a través de ¿qué entidad antes de hacer el examen?","options":["Cualquier instructor de manejo privado a elección del solicitante","Un proveedor incluido en el Training Provider Registry (TPR) de la FMCSA","La oficina del tesorero local del condado","Únicamente la academia de capacitación de la Iowa State Patrol"],"explanation":"La ELDT debe ser impartida por una entidad incluida en el Training Provider Registry de la FMCSA; solo los proveedores registrados pueden impartir la capacitación requerida. Fuente: FMCSA Training Provider Registry; Iowa DOT Commercial Drivers (la ELDT aplica en Iowa)."},"36":{"q":"La ELDT (Capacitación de Conductores de Nivel Inicial) se requiere para solicitantes por primera vez de ¿cuál de los siguientes en Iowa?","options":["Una CDL de Clase A o Clase B, y los endosos S, P o H por primera vez","Únicamente el endoso de HazMat (H)","Únicamente el endoso de Dobles/Triples (T)","Renovaciones de cualquier CDL existente"],"explanation":"La ELDT se requiere para los solicitantes de CDL de Clase A o Clase B por primera vez, para un ascenso de Clase B a Clase A, y para los endosos de Autobús Escolar (S), Pasajeros (P) o HazMat (H) por primera vez (solo teoría para el H). Fuente: regla ELDT de la FMCSA (CLP obtenido en o después del 7 de febrero de 2022); aplica en Iowa."},"37":{"q":"Un titular de CDL de Iowa que conduce un vehículo comercial en el comercio interestatal y que NO está exento de las reglas federales de calificación física debe autocertificarse en ¿qué categoría médica?","options":["Interestatal exceptuado (excepted interstate)","Interestatal no exceptuado (non-excepted interstate)","Intraestatal no exceptuado (non-excepted intrastate)","Intraestatal exceptuado (excepted intrastate)"],"explanation":"Un conductor interestatal no exceptuado (non-excepted interstate) debe autocertificarse como tal Y mantener un Medical Examiner's Certificate vigente archivado en el Iowa DOT; no hacerlo conduce a una degradación de la licencia. Fuente: Iowa DOT Medical Cards & Certification; 761 IAC 607.50."},"38":{"q":"¿Qué categoría de autocertificación médica NO requiere presentar un Medical Examiner's Certificate al Iowa DOT?","options":["Interestatal no exceptuado (non-excepted interstate)","Intraestatal no exceptuado (non-excepted intrastate)","Las cuatro categorías deben presentarlo","Solo los conductores de fuera del estado están exentos"],"explanation":"Solo la categoría interestatal no exceptuada (non-excepted interstate) debe presentar el Medical Examiner's Certificate al Iowa DOT. Los conductores intraestatales no exceptuados lo portan pero no necesitan presentarlo, y las categorías exceptuadas no necesitan ninguno; las categorías intraestatales reciben una restricción 'K'. Fuente: Iowa DOT Medical Cards & Certification; 761 IAC 607.50."},"39":{"q":"¿Qué conjunto de documentos exige el Iowa DOT que un solicitante presente al solicitar por primera vez una CDL/CLP?","options":["Prueba de identidad/presencia legal, número de Seguro Social, y residencia en Iowa","Únicamente un pasaporte","Únicamente un formulario militar DD-214","Únicamente prueba de seguro y registro del vehículo"],"explanation":"Iowa exige prueba de identidad y de ciudadanía estadounidense o presencia legal, un número de Seguro Social, y verificación de residencia en Iowa (por ejemplo, una licencia vigente con domicilio en Iowa). Fuente: página de Commercial Learner Permits (CLP) del Iowa DOT; 761 IAC 607."},"40":{"q":"En Iowa, ¿cuál es la concentración máxima de alcohol que una persona puede tener y aun así operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.04","0.08","0.02","0.05"],"explanation":"El Iowa Code 321.208(1)(a) descalifica a un conductor que opera un CMV con una concentración de alcohol (según se define en 321J.1) de 0.04 o más. Por lo tanto, el límite legal para un CMV es inferior a 0.04, la mitad del límite de 0.08 que aplica a los conductores comunes. Fuente: Iowa Code 321.208 / Iowa CDL Manual."},"41":{"q":"Bajo la ley de consentimiento implícito de Iowa, ¿qué le sucede a un titular de CDL que se niega a someterse a las pruebas químicas requeridas bajo el Capítulo 321J después de una solicitud legal?","options":["Se trata como una infracción grave (major offense), igual que una condena por alcohol, y conlleva la descalificación","No le sucede nada a la CDL porque negarse es un derecho constitucional","Solo se impone una pequeña multa civil sin descalificación","El conductor recibe una advertencia por escrito por una primera negativa"],"explanation":"El Iowa Code 321.208(2)(b) y 321.208(13) tratan la negativa a someterse a las pruebas químicas bajo el Capítulo 321J como una infracción grave (major offense), que conlleva la misma descalificación que una condena por OWI. Fuente: Iowa Code 321.208 / Iowa CDL Manual."},"42":{"q":"¿Por cuánto tiempo se descalifica a un conductor para operar un CMV por una PRIMERA infracción grave (major offense) (como OWI o conducir un CMV con 0.04 o más) cuando NO transporta materiales peligrosos con placas (placarded)?","options":["1 year","3 years","60 days","De por vida"],"explanation":"El Iowa Code 321.208(1) y (2) imponen una descalificación de CMV de un año por una primera infracción grave (major offense), como operar con una concentración de alcohol de 0.04 o más, OWI, o negativa a la prueba. Fuente: Iowa Code 321.208 (refleja 49 CFR 383.51)."},"43":{"q":"Si una primera infracción grave (major offense) (como OWI o 0.04 BAC) ocurre mientras el conductor opera un CMV que transporta materiales peligrosos con placas (placarded), la descalificación aumenta ¿a cuánto tiempo?","options":["3 years","1 year","5 years","De por vida"],"explanation":"El Iowa Code 321.208(3) eleva la descalificación por primera infracción de un año a tres años cuando la infracción ocurre mientras el CMV transporta materiales peligrosos que requieren placas bajo 49 CFR 383.5. Fuente: Iowa Code 321.208."},"44":{"q":"¿Cuál es la sanción por cometer una SEGUNDA infracción grave (major offense) (en dos o más incidentes separados), como un segundo OWI o negativa a la prueba?","options":["Descalificación de por vida (que posteriormente puede reducirse a 10 years)","Descalificación de 3 years","Descalificación de 1 year","Descalificación de 120 days"],"explanation":"El Iowa Code 321.208(4) descalifica a un conductor de por vida tras dos o más infracciones graves (major offenses) provenientes de incidentes separados. La descalificación de por vida puede reducirse a 10 years según lo dispuesto en 49 CFR 383.51 por regla del departamento. Fuente: Iowa Code 321.208."},"45":{"q":"¿Por cuánto tiempo se descalifica a un conductor por acumular DOS infracciones de tránsito graves (serious traffic violations) mientras opera un CMV dentro de un período de tres años?","options":["60 days","120 days","30 days","1 year"],"explanation":"El Iowa Code 321.208(8) impone una descalificación de 60 days por dos infracciones de tránsito graves (serious traffic violations) dentro de cualquier período de tres años. Fuente: Iowa Code 321.208 / Iowa CDL Manual."},"46":{"q":"¿Por cuánto tiempo se descalifica a un conductor por acumular TRES infracciones de tránsito graves (serious traffic violations) mientras opera un CMV dentro de un período de tres años?","options":["120 days","60 days","180 days","1 year"],"explanation":"El Iowa Code 321.208(8) impone una descalificación de 120 days por tres infracciones de tránsito graves (serious traffic violations) dentro de cualquier período de tres años. Los múltiples períodos de descalificación corren de forma consecutiva. Fuente: Iowa Code 321.208."},"47":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE (serious traffic violation) que cuenta para una descalificación de CMV en Iowa?","options":["Exceso de velocidad de 15 mph o más por encima del límite legal de velocidad","Exceso de velocidad de 5 mph por encima del límite legal de velocidad","Una infracción de estacionamiento en un CMV","Una infracción de peso del vehículo (sobrepeso)"],"explanation":"El Iowa Code 321.208(7)(d) incluye el exceso de velocidad de 15 mph o más por encima del límite como una infracción grave. Las infracciones de estacionamiento y de peso del vehículo están expresamente excluidas del conteo de infracciones graves. Fuente: Iowa Code 321.208."},"48":{"q":"Según la ley de Iowa, enviar mensajes de texto mientras se conduce un vehículo motorizado comercial se clasifica ¿como qué tipo de infracción de CDL?","options":["Una infracción de tránsito grave (serious traffic violation)","Una infracción grave (major offense) que conlleva una descalificación de 1 year","Una violación de una orden de fuera de servicio (out-of-service order)","Una infracción menor de equipo sin efecto de descalificación"],"explanation":"El Iowa Code 321.208(7)(i) incluye violar una ley que prohíbe enviar mensajes de texto mientras se conduce un CMV como una infracción de tránsito grave (serious traffic violation), que cuenta para las descalificaciones de 60 days/120 days. Fuente: Iowa Code 321.208."},"49":{"q":"Usar un teléfono móvil de mano mientras se conduce un CMV, en violación de una ley de control de tránsito, se trata en Iowa como:","options":["Una infracción de tránsito grave (serious traffic violation) que cuenta para la descalificación","Una infracción grave (major offense) con descalificación de por vida","Una infracción sin consecuencia para la CDL","Una descalificación automática de 1 year"],"explanation":"El Iowa Code 321.208(7)(j) incluye violar una ley que restringe o prohíbe el uso de un teléfono móvil de mano mientras se conduce un CMV como una infracción de tránsito grave (serious traffic violation), que cuenta para los umbrales de descalificación de 60/120 days. Fuente: Iowa Code 321.208."},"50":{"q":"Para una PRIMERA violación de una orden de fuera de servicio (out-of-service order) (que no involucre HazMat ni un vehículo diseñado para 16+ pasajeros), el rango de descalificación de Iowa es:","options":["No menos de 180 days y no más de 1 year","No menos de 60 days y no más de 120 days","No menos de 30 days y no más de 90 days","No menos de 2 years y no más de 5 years"],"explanation":"El Iowa Code 321.208(10)(a) fija la primera violación de una orden de fuera de servicio en no menos de 180 days y no más de un año. Fuente: Iowa Code 321.208."},"51":{"q":"Para una SEGUNDA violación de una orden de fuera de servicio (out-of-service order) en incidentes separados dentro de 10 years (sin HazMat), el rango de descalificación de Iowa es:","options":["No menos de 2 years y no más de 5 years","No menos de 180 days y no más de 1 year","No menos de 1 year y no más de 3 years","De por vida"],"explanation":"El Iowa Code 321.208(10)(a) fija una segunda violación de una orden de fuera de servicio (dentro de un período de 10 years) en no menos de dos años y no más de cinco años. Fuente: Iowa Code 321.208."},"52":{"q":"Una primera violación de una orden de fuera de servicio (out-of-service order) cometida mientras se transportan materiales peligrosos con placas (placarded), o mientras se opera un CMV diseñado para transportar más de 15 pasajeros, resulta en una descalificación de:","options":["1 year","180 days","3 years","60 days"],"explanation":"El Iowa Code 321.208(10)(b) impone una descalificación de un año por una primera violación de una orden de fuera de servicio cuando se transporta HazMat con placas u se opera un CMV diseñado para más de 15 pasajeros (conductor incluido). Fuente: Iowa Code 321.208."},"53":{"q":"¿Por cuánto tiempo se descalifica a un conductor por una PRIMERA violación de cruce a nivel de ferrocarril y carretera (railroad-highway grade crossing) cometida mientras opera un CMV en Iowa?","options":["60 days","120 days","30 days","1 year"],"explanation":"El Iowa Code 321.208(11)(a) impone una descalificación de 60 days por una primera violación de cruce a nivel de ferrocarril (bajo 321.341 o 321.343) cometida mientras se opera un CMV. Fuente: Iowa Code 321.208."},"54":{"q":"Un conductor condenado por una SEGUNDA violación de cruce a nivel de ferrocarril y carretera (railroad-highway grade crossing) en un CMV, dentro de los tres años posteriores a la primera, es descalificado por:","options":["120 days","60 days","180 days","1 year"],"explanation":"El Iowa Code 321.208(11)(b) impone una descalificación de 120 days por una segunda violación de cruce a nivel de ferrocarril en un CMV que ocurra dentro de los tres años posteriores a la primera. Fuente: Iowa Code 321.208."},"55":{"q":"Un conductor condenado por una TERCERA o subsiguiente violación de cruce a nivel de ferrocarril y carretera (railroad-highway grade crossing) en un CMV, dentro de los tres años posteriores a la primera, es descalificado por:","options":["1 year","120 days","60 days","180 days"],"explanation":"El Iowa Code 321.208(11)(c) impone una descalificación de un año por una tercera o subsiguiente violación de cruce a nivel de ferrocarril en un CMV que ocurra dentro de los tres años posteriores a la primera. Fuente: Iowa Code 321.208."},"56":{"q":"Usar un vehículo motorizado comercial en la comisión de un delito grave (felony) que involucre la fabricación, distribución o suministro de una sustancia controlada resulta en ¿qué sanción de CDL en Iowa?","options":["Descalificación de por vida sin posibilidad de reducción","Descalificación de 1 year","Descalificación de 3 years","Descalificación de 120 days"],"explanation":"El Iowa Code 321.208(5) impone una descalificación de por vida, no sujeta a la reducción de 10 years, cuando se usa un CMV en un delito grave (felony) que involucra la fabricación, distribución o suministro de una sustancia controlada. Fuente: Iowa Code 321.208."},"57":{"q":"Cuando el Iowa DOT recibe un registro de una condena descalificante, ¿cuánta notificación anticipada da antes de que la descalificación de CMV entre en vigor?","options":["30 days","10 days","60 days","24 hours"],"explanation":"El Iowa Code 321.208(12) y (13) disponen que el departamento descalifica al conductor sin una audiencia preliminar con 30 days de notificación anticipada; la fecha de entrada en vigor de la descalificación es 30 days después de la notificación. Fuente: Iowa Code 321.208."},"58":{"q":"Un conductor de CMV a quien un oficial de cumplimiento de la ley determina que tiene una concentración de alcohol de 0.04 o más, además de enfrentar la descalificación, queda de inmediato:","options":["Puesto fuera de servicio (out of service) por 24 hours","Autorizado a conducir tras un descanso de 1 hour","Autorizado a continuar si está por debajo de 0.08","Multado con $25 y liberado para conducir"],"explanation":"Las reglas federales adoptadas en Iowa (49 CFR 392.5) exigen que cualquier conductor con una concentración de alcohol de 0.04 o mayor sea puesto fuera de servicio por 24 hours, de forma separada a la descalificación formal bajo el Iowa Code 321.208. Fuente: 49 CFR 392.5 / Iowa CDL Manual."},"59":{"q":"Dos condenas separadas por infracciones graves (major offenses) que surjan de dos incidentes separados conducen a una descalificación de CDL de por vida en Iowa. Bajo la regla federal adoptada por Iowa, este período de por vida puede reducirse a un mínimo de:","options":["10 years","5 years","3 years","1 year"],"explanation":"El Iowa Code 321.208(4) hace que una descalificación de por vida (por dos o más infracciones graves) esté sujeta a reducción a una descalificación de 10 years según lo dispuesto en 49 CFR 383.51 y adoptado por regla del departamento. Fuente: Iowa Code 321.208."},"60":{"q":"Bajo la ley de Iowa de \"cambiar de carril\" (Move Over), cuando te acercas a un vehículo de emergencia detenido con sus luces intermitentes encendidas mientras conduces en una interestatal con dos carriles en tu dirección, ¿qué exige primero el Código de Iowa que hagas?","options":["Cambiarte a un carril que no sea contiguo al vehículo detenido si es seguro hacerlo","Detenerte por completo en el acotamiento hasta que el vehículo de emergencia se retire","Tocar la bocina y seguir de largo en el mismo carril a tu velocidad actual","Orillarte al acotamiento izquierdo y esperar a que un agente del orden te haga señas para avanzar"],"explanation":"El Código de Iowa 321.323A exige que un conductor que se aproxima a un vehículo detenido con luces intermitentes activadas, en una vía con dos o más carriles en la dirección del conductor, realice un cambio de carril hacia un carril que no sea contiguo a ese vehículo cuando sea seguro y legal. Fuente: Código de Iowa 321.323A; Iowa DOT \"Move Over or Slow Down\"."},"61":{"q":"Bajo la ley de Iowa de \"cambiar de carril\" (Move Over), si cambiar de carril para alejarte de un vehículo detenido que muestra luces intermitentes es imposible o inseguro, ¿qué debe hacer un conductor en Iowa?","options":["Mantener la velocidad señalizada pero encender las luces de emergencia","Reducir la velocidad por debajo del límite de velocidad señalizado y estar preparado para detenerse","Reducir la velocidad a exactamente 20 mph por debajo del límite de velocidad señalizado","Bajar a 10 mph sin importar el límite de velocidad señalizado"],"explanation":"El Código de Iowa 321.323A establece que cuando un cambio de carril es imposible, está prohibido o es inseguro, el conductor debe reducir la velocidad a una velocidad razonable y adecuada que sea menor que el límite de velocidad señalizado y estar preparado para detenerse. Iowa NO establece una reducción fija en mph. Fuente: Código de Iowa 321.323A; Iowa DOT."},"62":{"q":"¿Cuál de estos vehículos detenidos, cuando muestra sus luces intermitentes o de advertencia requeridas, está cubierto por la ley de Iowa de \"cambiar de carril\" (Código de Iowa 321.323A)?","options":["Solo vehículos de la policía y de bomberos","Solo ambulancias y grúas","Un vehículo de recolección de residuos sólidos o de reciclaje","Solo vehículos propiedad del Iowa DOT"],"explanation":"El Código de Iowa 321.323A cubre vehículos de emergencia autorizados detenidos, vehículos de remolque/recuperación, de mantenimiento y construcción, vehículos de recolección de residuos sólidos o reciclaje con luces intermitentes, y cualquier vehículo motorizado que muestre de forma continua sus luces de emergencia. Fuente: Código de Iowa 321.323A; Iowa DOT."},"63":{"q":"En una carretera interestatal rural de Iowa, ¿cuál es el límite de velocidad máximo que aplica a un tractocamión con remolque?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"El Código de Iowa 321.285 fija el límite de velocidad en el sistema de carreteras interestatales en 70 mph para todo el tránsito vehicular. Iowa no impone un límite de velocidad menor por separado para camiones en las interestatales. Fuente: Código de Iowa 321.285."},"64":{"q":"¿Establece Iowa un límite de velocidad interestatal más bajo para los camiones que para los autos de pasajeros?","options":["Sí, los camiones están limitados a 65 mph mientras que los autos pueden circular a 70 mph","No, el límite interestatal de 70 mph aplica por igual a todo el tránsito vehicular","Sí, los camiones están limitados a 60 mph en todo el estado","Sí, los camiones de más de 26,000 lbs están limitados a 55 mph"],"explanation":"A diferencia de algunos estados con límites de velocidad \"divididos\", el Código de Iowa 321.285 aplica el máximo interestatal de 70 mph a todo el tránsito vehicular, sin un límite señalizado por separado para camiones. Fuente: Código de Iowa 321.285."},"65":{"q":"Un autobús de transporte público de Iowa que lleva pasajeros a cambio de pago se acerca a un cruce a nivel de ferrocarril. ¿Dónde debe detenerse el conductor?","options":["A no menos de 15 pies y no más de 50 pies del riel más cercano","A no menos de 10 pies y no más de 25 pies del riel más cercano","A no menos de 25 pies y no más de 75 pies del riel más cercano","A 5 pies del riel más cercano"],"explanation":"El Código de Iowa 321.343 exige que un vehículo que lleva pasajeros a cambio de pago, un autobús escolar o un vehículo con materiales peligrosos rotulado se detenga a no más de 50 pies pero no menos de 15 pies del riel más cercano antes de cruzar. Fuente: Código de Iowa 321.343."},"66":{"q":"Un conductor que transporta una carga rotulada de material peligroso en Iowa llega a un cruce de ferrocarril señalizado con un letrero \"EXEMPT\". ¿Qué se requiere?","options":["Detenerse de todos modos a entre 15 y 50 pies del riel más cercano","Detenerse solo si hay un tren a la vista","El conductor no está obligado a detenerse en ese cruce","Detenerse y colocar triángulos de advertencia antes de cruzar"],"explanation":"El Código de Iowa 321.343 exige la parada para autobuses, vehículos de pasajeros a cambio de pago y vehículos con materiales peligrosos rotulados, pero un cruce señalizado con un letrero oficial \"EXEMPT\" no requiere detenerse. Fuente: Código de Iowa 321.343; Manual CDL de Iowa."},"67":{"q":"Después de detenerse en un cruce de ferrocarril, ¿qué debe hacer el conductor de un autobús escolar de Iowa antes de continuar por las vías?","options":["Tocar la bocina dos veces y avanzar sin demora","Abrir la puerta de entrada, mirar y escuchar si vienen trenes, y cruzar solo cuando sea seguro","Esperar 60 segundos completos sin importar las condiciones","Activar las luces de advertencia ámbar y cruzar despacio"],"explanation":"Según el Código de Iowa 321.343, después de detenerse a entre 15 y 50 pies del riel más cercano, el conductor del autobús escolar debe abrir la puerta de entrada, mirar y escuchar si se aproxima un tren, y no continuar hasta que sea seguro. Fuente: Código de Iowa 321.343."},"68":{"q":"En una carretera de dos carriles de Iowa, un autobús escolar se detiene, activa sus luces rojas intermitentes y extiende su brazo de alto para bajar a los niños. ¿Qué debe hacer un automovilista que se aproxima?","options":["Reducir a 20 mph y pasar con precaución","Detenerse a no menos de 15 pies del autobús y permanecer detenido hasta que el brazo de alto se retraiga","Detenerse solo si hay niños visibles en la vía","Cambiarse al carril más lejano y pasar el autobús despacio"],"explanation":"El Código de Iowa 321.372 exige que los vehículos que se encuentren o rebasen a un autobús escolar detenido con las luces rojas intermitentes y el brazo de alto extendido se detengan a no menos de 15 pies y permanezcan detenidos hasta que el brazo de alto se retraiga y el autobús vuelva a moverse. Fuente: Código de Iowa 321.372."},"69":{"q":"Bajo la ley de autobuses escolares de Iowa, ¿en qué tipo de carretera puede un conductor que SE ENCUENTRA con un autobús escolar detenido que circula en sentido contrario continuar sin detenerse?","options":["Cualquier carretera con una línea central pintada","Una carretera que proporcione dos o más carriles de circulación en cada dirección","Cualquier carretera con una velocidad señalizada de 55 mph o más","Una carretera con acotamientos pavimentados de al menos 8 pies de ancho"],"explanation":"El Código de Iowa 321.372 dispone que un conductor en una carretera con dos o más carriles en cada dirección no necesita detenerse al ENCONTRARSE con un autobús escolar que circula en sentido contrario, aunque esté detenido. En vías no divididas, todas las direcciones deben detenerse. Fuente: Código de Iowa 321.372."},"70":{"q":"En una carretera de Iowa con dos carriles en cada dirección separados por un camellón, un autobús escolar se detiene en los carriles de sentido contrario con sus luces rojas intermitentes encendidas. Un conductor que circula en el otro sentido está:","options":["Obligado a detenerse hasta que las luces rojas se apaguen","Obligado a reducir a 10 mph pero puede continuar","No obligado a detenerse porque la vía tiene dos o más carriles en cada dirección","Obligado a detenerse solo si el camellón mide menos de 6 pies de ancho"],"explanation":"La excepción de carretera dividida del Código de Iowa 321.372 depende del número de carriles: en una carretera con dos o más carriles en cada dirección, los conductores que se encuentran con un autobús detenido en sentido contrario no necesitan detenerse. Fuente: Código de Iowa 321.372."},"71":{"q":"Un autobús escolar circula en una carretera de Iowa con cuatro o más carriles. Respecto a los alumnos que deben cruzar la carretera, el autobús:","options":["Puede subirlos o bajarlos en cualquier lugar siempre que las luces rojas estén encendidas","No debe detenerse para subir o bajar alumnos que deban cruzar la carretera, salvo en puntos designados","Debe usar el carril izquierdo para bajarlos","Solo puede bajarlos entre las 7 a.m. y las 7 p.m."],"explanation":"El Código de Iowa 321.372 prohíbe que un autobús escolar en una carretera de cuatro o más carriles se detenga para subir o bajar alumnos que deban cruzar la carretera, salvo en paradas/puntos designados con dispositivos de control de tránsito o agentes. Fuente: Código de Iowa 321.372."},"72":{"q":"Cuando un autobús escolar de Iowa se prepara para detenerse a recoger pasajeros, ¿qué luces de advertencia debe mostrar antes de activar las luces rojas intermitentes?","options":["Luces intermitentes verdes","Luces intermitentes azules","Luces de advertencia intermitentes ámbar (amarillas)","Luces estroboscópicas blancas"],"explanation":"La ley de Iowa y las normas de transporte escolar de Iowa exigen que el conductor muestre luces de advertencia intermitentes ámbar antes de la parada, y luego cambie a luces rojas intermitentes y extienda el brazo de alto en la parada. Fuente: Código de Iowa 321.372; Iowa Admin. Code 281-43."},"73":{"q":"Un conductor con CDL detiene un camión en una carretera de dos carriles de Iowa, recta y a nivel, y debe colocar los tres triángulos de advertencia requeridos. La colocación correcta es:","options":["Uno a 10 ft hacia atrás, uno a 100 ft hacia atrás y uno a 100 ft hacia adelante","Uno a 25 ft hacia atrás, uno a 250 ft hacia atrás y uno a 250 ft hacia adelante","Uno a 5 ft, uno a 50 ft y uno a 150 ft, todos hacia atrás","Los tres colocados a 200 ft hacia atrás del vehículo"],"explanation":"Iowa sigue la norma federal (49 CFR 392.22) que se enseña en el Manual CDL de Iowa: en una vía de dos carriles, coloca los triángulos a aproximadamente 10 ft detrás, 100 ft detrás y 100 ft delante del vehículo. Fuente: 49 CFR 392.22; Manual CDL de Iowa."},"74":{"q":"Según el Manual CDL de Iowa, ¿en cuánto tiempo después de detener un vehículo motorizado comercial averiado en la vía o el acotamiento deben colocarse los dispositivos de advertencia (triángulos)?","options":["Dentro de 3 minutos","Dentro de 10 minutos","Dentro de 30 minutos","Dentro de 1 hora"],"explanation":"Iowa sigue el 49 CFR 392.22, que exige que el conductor coloque los dispositivos de advertencia requeridos dentro de los 10 minutos de haberse detenido. Fuente: 49 CFR 392.22; Manual CDL de Iowa."},"75":{"q":"Un conductor con CDL se detiene en una carretera de un solo sentido o dividida de Iowa. ¿Dónde van los tres triángulos de advertencia?","options":["A 10 ft, 100 ft y 200 ft en dirección al tránsito que se aproxima (hacia atrás)","A 10 ft, 100 ft y 100 ft, uno hacia atrás y dos hacia adelante","Los tres a 10 ft del vehículo en cada lado","A 100 ft adelante, 100 ft atrás y uno junto a la cabina"],"explanation":"Iowa sigue el 49 CFR 392.22: en una carretera de un solo sentido o dividida, coloca los triángulos a 10 ft, 100 ft y 200 ft en dirección al tránsito que se aproxima. Fuente: 49 CFR 392.22; Manual CDL de Iowa."},"76":{"q":"La regla general de Iowa de \"mantenerse a la derecha\" (Código de Iowa 321.297) ordena a qué vehículos circular en el carril derecho?","options":["Solo vehículos registrados como vehículos motorizados comerciales","Solo vehículos que remolcan tráileres","Cualquier vehículo que circule más lento que la velocidad normal del tránsito, salvo al rebasar o girar a la izquierda","Solo vehículos de más de 26,000 libras de peso bruto"],"explanation":"El Código de Iowa 321.297 exige que cualquier vehículo que circule más lento que la velocidad normal del tránsito use el carril derecho, salvo al rebasar o al prepararse para un giro a la izquierda. Iowa no tiene una prohibición del carril izquierdo específica para camiones; la regla aplica a todo el tránsito más lento. Fuente: Código de Iowa 321.297."},"77":{"q":"En Iowa, antes de que un vehículo/carga requiera un permiso de sobredimensión, el ANCHO máximo legal para circular en las vías públicas es:","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"Iowa, en consonancia con el estándar federal, fija el ancho máximo legal en 8 pies 6 pulgadas; cualquier cosa más ancha necesita un permiso de sobredimensión. Fuente: Iowa DOT Motor Carrier Services, Oversize/Overweight Permit Requirements; Código de Iowa cap. 321."},"78":{"q":"En Iowa, una carga indivisible alcanza 13 pies 6 pulgadas de altura. Sin un permiso, esta altura es:","options":["Superior al límite legal; se requiere un permiso por encima de 13 pies 6 pulgadas","Muy por debajo del límite; legal hasta 16 pies","Superior al límite; el máximo legal es 12 pies","Legal solo si la carga no es más ancha que 8 pies"],"explanation":"El Iowa DOT indica que la altura máxima legal es 13 pies 6 pulgadas; las cargas que excedan 13 pies 6 pulgadas requieren un permiso de sobredimensión. Fuente: Iowa DOT Oversize/Overweight Permit Requirements."},"79":{"q":"Bajo las reglas de permisos de sobredimensión de Iowa, ¿cuándo se permite generalmente el movimiento de una carga sobredimensionada?","options":["Solo entre las 9 a.m. y las 3 p.m. en días laborables","Las 24 horas del día sin límites de tiempo","Desde media hora antes del amanecer hasta media hora después del atardecer","Solo de noche para evitar el tránsito"],"explanation":"Iowa generalmente permite el movimiento de cargas sobredimensionadas desde media hora antes del amanecer hasta media hora después del atardecer, los siete días de la semana, con restricciones en ciertos días feriados y para cargas muy grandes. Fuente: Iowa DOT Motor Carrier Services, reglas de permisos de sobredimensión/sobrepeso."},"80":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Iowa?","options":["El Departamento de Transporte de Iowa (Iowa DOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Seguridad Pública de Iowa","La Administración de Seguridad en el Transporte (TSA)"],"explanation":"Las CDL de Iowa son emitidas por el Departamento de Transporte de Iowa (Iowa DOT), la agencia estatal de licencias de conducir. La FMCSA establece los estándares federales de la CDL pero no emite licencias. Fuente: Iowa DOT, Commercial Drivers / How to Get a CDL (iowadot.gov)."},"81":{"q":"¿Dónde puede un solicitante presentar los exámenes de conocimientos y de habilidades de la CDL de Iowa?","options":["En ubicaciones seleccionadas de servicio de licencias de conducir del Iowa DOT y del Tesorero del Condado (County Treasurer)","Solo en la única sede del Iowa DOT en Ames","En cualquier oficina regional de la FMCSA en el estado","En cualquier departamento de policía local de Iowa"],"explanation":"Las pruebas de la CDL de Iowa se administran en ubicaciones seleccionadas de licencias de conducir del Iowa DOT y del Tesorero del Condado; los sitios adicionales se listan en la página de CDL Testing Locations del Iowa DOT. Fuente: Iowa DOT, CDL Testing (iowadot.gov)."},"82":{"q":"¿Cuál es la edad mínima general para obtener una CDL de Iowa para conducción intraestatal (solo dentro de Iowa)?","options":["18 años","16 años","21 años","25 años"],"explanation":"Iowa exige que el solicitante de una CDL tenga al menos 18 años para conducir comercialmente dentro de Iowa (intraestatal). Conducir cruzando líneas estatales (interestatal) requiere tener 21 años. Fuente: Iowa DOT, How to Get a CDL (iowadot.gov)."},"83":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo motorizado comercial en comercio interestatal con una CDL de Iowa?","options":["21 años","18 años","19 años","23 años"],"explanation":"Bajo la norma federal aplicada en Iowa, un conductor debe tener al menos 21 años para operar un CMV en comercio interestatal; los de 18 a 20 años están limitados a la conducción intraestatal. Fuente: Iowa DOT, How to Get a CDL; 49 CFR 391.11 (estándar federal)."},"84":{"q":"¿Qué documento debe presentar un solicitante de la CDL de Iowa para comprobar su identidad y estatus legal al hacer la solicitud?","options":["Comprobante de nombre completo, fecha de nacimiento, número de Seguro Social y ciudadanía o estatus legal","Solo un recibo de servicios públicos vigente a nombre del solicitante","Solo una carta firmada de un empleador actual","Un diploma de preparatoria o certificado GED"],"explanation":"Iowa exige comprobante de nombre legal completo, fecha de nacimiento, número de Seguro Social y ciudadanía o residencia permanente legal (por ejemplo, acta de nacimiento, pasaporte o tarjeta de residente permanente), además de comprobante de residencia en Iowa. Fuente: Iowa DOT, How to Get a CDL (iowadot.gov)."},"85":{"q":"Antes de presentar el examen, todo solicitante de la CDL de Iowa debe \"autocertificarse\". ¿Qué significa la autocertificación?","options":["Declarar al Iowa DOT cuál de cuatro categorías de conducción describe cómo operas un CMV","Firmar una declaración de que no tienes multas de tránsito","Prometer completar la capacitación dentro de un año","Certificar que eres dueño del vehículo en el que harás el examen"],"explanation":"La autocertificación es la declaración del conductor al Iowa DOT sobre cuál de las cuatro categorías de operación de CMV le aplica; determina si debe constar en el archivo un certificado de examinador médico. Fuente: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"86":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un titular de la CDL de Iowa?","options":["Cuatro","Dos","Tres","Seis"],"explanation":"Hay cuatro categorías: interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado e intraestatal exceptuado. Fuente: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"87":{"q":"¿Cuál categoría de autocertificación REQUIERE que conste en el archivo del Iowa DOT un Certificado de Examinador Médico vigente?","options":["Interestatal no exceptuado","Interestatal exceptuado","Intraestatal exceptuado","Intraestatal no exceptuado"],"explanation":"Solo los conductores interestatales no exceptuados deben presentar y mantener un Certificado de Examinador Médico vigente en el archivo del Iowa DOT. Los conductores exceptuados no lo hacen, y los conductores intraestatales no exceptuados deben portar la tarjeta pero no es necesario que la presenten ante el estado. Fuente: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"88":{"q":"Para un conductor interestatal no exceptuado de Iowa, ¿cómo se presenta ante el estado el Certificado de Examinador Médico del DOT?","options":["El examinador médico certificado lo presenta electrónicamente al registro nacional/sistema estatal","El conductor envía por correo una copia en papel a la FMCSA en Washington, D.C.","El empleador del conductor lo envía por fax al tesorero del condado","Se transfiere automáticamente desde el software de facturación del médico"],"explanation":"En Iowa, el examinador médico certificado presenta el certificado de forma electrónica; los resultados fluyen a través del National Registry of Certified Medical Examiners hacia el estado. El conductor no lo presenta por sí mismo para el estatus interestatal no exceptuado. Fuente: Iowa DOT, Medical Cards & Certification."},"89":{"q":"Un titular de CDL de Iowa interestatal no exceptuado deja que su Certificado de Examinador Médico expire sin presentar uno nuevo. ¿Qué le pasa a la CDL?","options":["El Iowa DOT degrada la CDL, retirando los privilegios comerciales después de un aviso/periodo de gracia","Nada cambia hasta que la CDL en sí expire","La CDL se revoca permanentemente el mismo día en que la tarjeta expira","El conductor pasa automáticamente a la categoría intraestatal exceptuado"],"explanation":"Si el certificado médico caduca, el Iowa DOT fija el estatus médico como \"no certificado\", da aviso por escrito y retira los privilegios de CMV (degradación) si no se recibe un certificado vigente dentro del periodo de 60 días. Fuente: Iowa Admin. Code r. 761-607.50."},"90":{"q":"¿Cuál es la primera credencial que obtiene un solicitante de Iowa en el proceso de la CDL, antes del examen de habilidades?","options":["Un Permiso de Aprendiz Comercial (CLP)","Una CDL completa sin restricciones","Un endoso de materiales peligrosos","Un certificado de exención médica"],"explanation":"Después de aprobar el o los exámenes de conocimientos requeridos y cumplir con los requisitos de documentos/médicos, el solicitante recibe un Permiso de Aprendiz Comercial (CLP), que permite practicar bajo supervisión antes del examen de habilidades. Fuente: Iowa DOT, How to Get a CDL; Commercial Learner Permits (iowadot.gov)."},"91":{"q":"¿Qué debe aprobar un solicitante de Iowa para que se le emita un Permiso de Aprendiz Comercial (CLP)?","options":["El examen de conocimientos (escrito) de la CDL aplicable y el examen de la vista","Solo el examen de habilidades de tres partes","Un examen de manejo en su auto personal","La verificación de antecedentes de la TSA para hazmat"],"explanation":"Un CLP se emite después de que el solicitante aprueba el o los exámenes de conocimientos aplicables de la CDL y el examen de la vista, y presenta los documentos requeridos; el examen de habilidades viene después. Fuente: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"92":{"q":"¿Cuánto tiempo debe tener un solicitante de Iowa un Permiso de Aprendiz Comercial antes de presentar el examen de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Iowa aplica la norma federal que exige tener un CLP durante un mínimo de 14 días antes de poder presentar el examen de habilidades. Fuente: Iowa DOT, How to Get a CDL / Commercial Learner Permits; 49 CFR 383.25."},"93":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Iowa, y puede renovarse?","options":["Válido por un año y no puede renovarse (debe obtenerse un nuevo CLP)","Válido por 180 días y puede renovarse una vez","Válido por dos años y renovable anualmente","Válido por 60 días con renovaciones ilimitadas"],"explanation":"Un CLP de Iowa es válido por un año a partir de su emisión y no es renovable; si expira, el solicitante debe volver a presentar la solicitud. Fuente: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"94":{"q":"Para los CLP emitidos en o después del 7 de febrero de 2022, ¿qué debe completarse y verificarse antes de que un solicitante de Iowa pueda presentar el examen de habilidades de la CDL?","options":["Capacitación para Conductores de Nivel Inicial (ELDT) de un proveedor de capacitación registrado","Un curso de manejo defensivo en un colegio comunitario","Un mínimo de 160 horas de tiempo de manejo no remunerado","Un segundo examen de conocimientos presentado al menos 30 días después"],"explanation":"La Capacitación para Conductores de Nivel Inicial (ELDT) de un proveedor listado en el Training Provider Registry de la FMCSA debe completarse y verificarse antes del examen de habilidades para los CLP emitidos en o después del 7 de febrero de 2022. Fuente: Iowa DOT, How to Get a CDL; 49 CFR Part 380 Subpart F."},"95":{"q":"¿Dónde se registra la finalización de la ELDT para que el Iowa DOT pueda verificarla antes de programar un examen de habilidades?","options":["En el Training Provider Registry (TPR) de la FMCSA","A mano en la tarjeta del CLP del solicitante","En una bitácora de papel que lleva el conductor","En la base de datos de Hazmat de la TSA"],"explanation":"Los proveedores registrados cargan la certificación de la ELDT en el Training Provider Registry de la FMCSA; el Iowa DOT verifica ese registro antes de que pueda programarse el examen de habilidades. Fuente: Iowa DOT, How to Get a CDL; FMCSA Training Provider Registry (49 CFR Part 380)."},"96":{"q":"El examen de habilidades de la CDL de Iowa consta de tres partes. ¿Qué lista las nombra correctamente?","options":["Inspección previa al viaje del vehículo, habilidades básicas de control y manejo en la vía","Examen escrito, examen de la vista y examen de audición","Cuestionario de frenos de aire, cuestionario de hazmat y cuestionario de combinación","Solo reversa, solo estacionamiento en paralelo y solo incorporación a la autopista"],"explanation":"El examen de habilidades de Iowa tiene tres partes: la inspección previa al viaje del vehículo, el examen de habilidades básicas de control (maniobras y reversa entre conos) y el examen de manejo en la vía. Fuente: Iowa DOT, CDL Testing (iowadot.gov); Manual CDL de Iowa."},"97":{"q":"Durante la parte de inspección previa al viaje del vehículo en el examen de habilidades de Iowa, ¿qué se espera que haga el solicitante?","options":["Caminar alrededor del vehículo y señalar o tocar cada elemento mientras explica qué se revisa y por qué","Simplemente declarar que el vehículo está en buenas condiciones","Desarmar el sistema de frenos para el examinador","Manejar el vehículo en la autopista mientras describe los indicadores"],"explanation":"En la inspección previa al viaje, el solicitante camina alrededor del vehículo, señala o toca cada elemento y explica al examinador qué se revisa y por qué, para demostrar que el vehículo es seguro para manejar. Fuente: Iowa DOT, CDL Testing (iowadot.gov); Manual CDL de Iowa."},"98":{"q":"¿Cuál es el periodo de validez máximo típico de un ciclo de renovación de la CDL de Iowa para la mayoría de los conductores adultos?","options":["Hasta 8 años (menos para conductores mayores, con un tope cerca de los 80 años de edad)","Exactamente 1 año para todos los conductores","Hasta 15 años","Exactamente 30 días"],"explanation":"Las licencias de conducir de Iowa, incluidas las CDL, pueden emitirse por hasta 8 años, con plazos más cortos para conductores mayores y un tope para que la credencial no se extienda más allá de aproximadamente el cumpleaños número 80 del conductor. Fuente: Código de Iowa 321.196; Iowa DOT, Renew a CDL."},"99":{"q":"En cada renovación de la CDL de Iowa, ¿por qué un titular de un endoso de materiales peligrosos (H) debe renovar en persona en lugar de en línea?","options":["Debe volver a presentar el examen de conocimientos de hazmat y completar una evaluación de amenazas/verificación de antecedentes de la TSA","La renovación en línea nunca está disponible para ningún titular de CDL en Iowa","Debe entregar el endoso de forma permanente","Debe completar primero un nuevo curso teórico de ELDT en línea"],"explanation":"Los titulares del endoso de hazmat deben volver a presentar el examen de conocimientos de hazmat y completar una evaluación de amenazas de seguridad de la TSA (verificación de antecedentes basada en huellas dactilares) en cada renovación, por lo que no pueden renovar en línea y deben solicitarlo en persona. Fuente: Iowa DOT, Renew a CDL; 49 CFR 1572 (TSA)."}},"hi":{"0":{"q":"ओवरसाइज़ परमिट के बिना आयोवा के राजमार्गों पर किसी वाणिज्यिक वाहन की अधिकतम कानूनी चौड़ाई क्या है?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Iowa Code की धारा 321.454 लोड सहित किसी वाहन की अधिकतम चौड़ाई 8 feet 6 inches (102 inches) निर्धारित करती है। इससे अधिक चौड़ी किसी भी चीज़ के लिए ओवरसाइज़ परमिट आवश्यक है। स्रोत: Iowa Code 321.454; Iowa DOT ओवरसाइज़/ओवरवेट परमिट आवश्यकताएँ।"},"1":{"q":"परमिट के बिना आयोवा के राजमार्गों पर किसी वाहन और लोड की अधिकतम कानूनी ऊँचाई क्या है?","options":["13 feet 6 inches","13 feet 0 inches","14 feet 0 inches","14 feet 6 inches"],"explanation":"Iowa Code की धारा 321.456 वाहन की ऊँचाई 13 feet 6 inches तक सीमित करती है। इससे ऊँचे लोड के लिए ओवरसाइज़ परमिट आवश्यक है। स्रोत: Iowa Code 321.456; Iowa DOT परमिट आवश्यकताएँ।"},"2":{"q":"आयोवा के राजमार्गों पर, परमिट के बिना ट्रैक्टर-सेमीट्रेलर संयोजन में संचालित किसी सेमीट्रेलर की अधिकतम कानूनी लंबाई क्या है?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"आयोवा परमिट के बिना ट्रैक्टर-सेमीट्रेलर संयोजन में किसी सेमीट्रेलर को 53 feet तक लंबा (लदा हुआ या खाली) होने की अनुमति देता है। निर्माण उपकरण ढोने वाले लोबॉय ट्रेलर 57 feet तक हो सकते हैं। स्रोत: Iowa Code chapter 321; Iowa DOT परमिट आवश्यकताएँ।"},"3":{"q":"ओवरवेट परमिट के बिना आयोवा के राजमार्गों पर अनुमत अधिकतम सकल वाहन वज़न क्या है?","options":["80,000 pounds","73,280 pounds","84,000 pounds","76,000 pounds"],"explanation":"Iowa Code की धारा 321.463 अधिकतम सकल वज़न को 80,000 pounds तक सीमित करती है, जो संघीय सीमा के अनुरूप है। इससे अधिक होने पर ओवरवेट परमिट आवश्यक है। स्रोत: Iowa Code 321.463; Iowa DOT।"},"4":{"q":"आयोवा के राजमार्गों पर एकल एक्सल पर अनुमत अधिकतम वज़न क्या है?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Iowa Code की धारा 321.463 एकल एक्सल को 20,000 pounds तक सीमित करती है, जो संघीय Interstate मानक के समान है। स्रोत: Iowa Code 321.463; Iowa DOT।"},"5":{"q":"आयोवा के राजमार्गों पर टैंडम एक्सल समूह पर अनुमत अधिकतम वज़न क्या है?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Iowa Code की धारा 321.463 किसी टैंडम एक्सल को 34,000 pounds तक सीमित करती है, जो संघीय मानक से मेल खाता है। स्रोत: Iowa Code 321.463; Iowa DOT।"},"6":{"q":"आयोवा दो या अधिक लगातार एक्सलों के किसी भी समूह पर अधिकतम सकल वज़न निर्धारित करने के लिए किस विधि का उपयोग करता है?","options":["संघीय Bridge Formula (Formula B)","स्पेसिंग की परवाह किए बिना एक समान 80,000 lb की सीमा","केवल कुल टायर-लोड रेटिंग","600-pounds-per-inch-of-tire-width का नियम"],"explanation":"आयोवा एक्सलों की संख्या (N) और स्पेसिंग (L) के आधार पर लगातार एक्सलों के समूहों पर वज़न सीमित करने के लिए संघीय Bridge Formula (W = 500[(LN/(N-1)) + 12N + 36]) लागू करता है। स्रोत: Iowa Code 321.463; 23 CFR 658.17; Iowa DOT।"},"7":{"q":"आयोवा में लागू संघीय Bridge Formula में, चर L और N क्या दर्शाते हैं?","options":["L समूह के बाहरी एक्सलों के बीच की दूरी feet में है; N समूह में एक्सलों की संख्या है","L pounds में लोड है; N टायरों की संख्या है","L ट्रेलर की कानूनी लंबाई है; N शुद्ध वज़न है","L लेन की चौड़ाई है; N आवश्यक परमिटों की संख्या है"],"explanation":"W = 500[(LN/(N-1)) + 12N + 36] में, L दो या अधिक लगातार एक्सलों के किसी भी समूह के सबसे बाहरी एक्सलों के बीच की दूरी feet में है, और N उस समूह में एक्सलों की संख्या है। स्रोत: 23 CFR 658.17 जैसा कि Iowa Code 321.463 द्वारा अपनाया गया है।"},"8":{"q":"Interstate प्रणाली पर आयोवा की सकल और एक्सल वज़न सीमाएँ राज्य के प्राथमिक (गैर-Interstate) राजमार्गों की तुलना में कैसी हैं?","options":["80,000 lb सकल और 20,000/34,000 lb एक्सल सीमाएँ समान हैं; कुछ अधिक वज़न केवल गैर-Interstate सड़कों पर अनुमत हैं","गैर-Interstate सड़कें केवल 73,280 lb सकल की अनुमति देती हैं","Interstate 90,000 lb सकल की अनुमति देता है","गैर-Interstate सड़कों पर कोई वज़न सीमा नहीं है"],"explanation":"आयोवा की मूल सीमाएँ (80,000 lb सकल, 20,000 lb एकल, 34,000 lb टैंडम) Interstate और प्राथमिक दोनों राजमार्गों पर लागू होती हैं। अतिरिक्त वज़न के लिए कुछ वैधानिक अपवाद केवल गैर-Interstate प्रणाली पर लागू होते हैं, क्योंकि Interstate संघीय रूप से 80,000 lb पर सीमित है। स्रोत: Iowa Code 321.463; Iowa DOT।"},"9":{"q":"स्पेसिंग आवश्यकताओं को पूरा करने वाले स्प्रेड-एक्सल ट्रेलर वाला एक आयोवा पाँच-एक्सल पशुधन वाहन किन सड़कों पर अधिक सकल वज़न ले जा सकता है?","options":["केवल गैर-Interstate (प्राथमिक) राजमार्ग, 86,000 pounds तक","केवल Interstate राजमार्ग, 86,000 pounds तक","Interstate सहित सभी राजमार्ग, 90,000 pounds तक","केवल बजरी वाली काउंटी सड़कें, 80,000 pounds तक"],"explanation":"Iowa Code की धारा 321.463 एक पाँच-एक्सल पशुधन वाहन को गैर-Interstate राजमार्गों पर 86,000 lb सकल तक की अनुमति देती है जब पहले और पाँचवें एक्सल के बीच कम से कम 61 feet और दो पिछले (स्प्रेड) एक्सलों के बीच कम से कम 8 feet 1 inch हो। यह Interstate पर लागू नहीं होता। स्रोत: Iowa Code 321.463।"},"10":{"q":"आयोवा कानून के तहत, कच्चे कृषि उत्पाद ढोने वाला वाहन अपने पंजीकृत (रजिस्ट्रेशन) सकल वज़न से अधिकतम कितने प्रतिशत तक अधिक हो सकता है?","options":["25 percent","10 percent","15 percent","50 percent"],"explanation":"आयोवा कच्चे कृषि उत्पाद परिवहन करने वाले ट्रकों को आयोवा में रहते हुए अपने पंजीकृत वज़न से 25 percent तक अधिक संचालित करने की अनुमति देता है (फिर भी एक्सल और Bridge Formula सीमाओं के अधीन)। स्रोत: Iowa DOT मोटर कैरियर मार्गदर्शन; Iowa Code chapter 321।"},"11":{"q":"किसी लोड के लिए Iowa DOT ओवरसाइज़/ओवरवेट परमिट कब आवश्यक होता है?","options":["जब लोड अविभाज्य हो और कानूनी आकार या वज़न सीमाओं से अधिक हो","जब भी वाहन का वज़न 26,001 pounds से अधिक हो","केवल जब वाहन राज्य की सीमा पार करे","जब भी कोई CDL चालक अंधेरे के बाद संचालन करे"],"explanation":"किसी अविभाज्य वाहन या लोड के लिए परमिट जारी किया जाता है जो वैधानिक आकार या वज़न सीमाओं से अधिक हो। किसी लोड को अविभाज्य माना जाता है यदि उसे अलग करने से उसका मूल्य नष्ट हो जाए, उसके इच्छित उपयोग से समझौता हो, या उसे तोड़ने में आठ कार्य घंटों से अधिक लगें। स्रोत: Iowa DOT ओवरसाइज़/ओवरवेट परमिट आवश्यकताएँ; Iowa Code chapter 321E।"},"12":{"q":"किसी लोड के \"अविभाज्य\" होने का क्या अर्थ है जिससे वह आयोवा ओवरसाइज़/ओवरवेट परमिट के लिए योग्य हो जाता है?","options":["इसे इसके मूल्य को नष्ट किए, इसके उपयोग से समझौता किए, या तोड़ने में 8 कार्य घंटों से अधिक लिए बिना कानूनी आयामों/वज़न तक उचित रूप से कम नहीं किया जा सकता","यह एक बंद कंटेनर में सीलबंद है","यह एक ही कैरियर के स्वामित्व में है","इसका वज़न ठीक 80,000 pounds है"],"explanation":"आयोवा, संघीय परिभाषाओं का पालन करते हुए, किसी लोड को अविभाज्य मानता है जब उसे कानूनी सीमाओं तक कम करने से उसका मूल्य नष्ट हो जाए, उसके इच्छित उपयोग से समझौता हो, या उचित उपकरण के साथ तोड़ने में आठ कार्य घंटों से अधिक लगें। विभाज्य लोड को आम तौर पर परमिट नहीं दिया जा सकता। स्रोत: Iowa DOT परमिट आवश्यकताएँ; 23 CFR 658.5।"},"13":{"q":"कोई कैरियर Iowa DOT ओवरसाइज़/ओवरवेट परमिट के लिए कैसे आवेदन करता है?","options":["Iowa DOT परमिट प्रणाली (ia.gotpermits.com) के माध्यम से ऑनलाइन या डाक द्वारा","केवल काउंटी शेरिफ़ के कार्यालय में व्यक्तिगत रूप से","Federal Motor Carrier Safety Administration को कॉल करके","केवल वाहन के निर्माता के माध्यम से"],"explanation":"Iowa DOT ओवरसाइज़/ओवरवेट परमिट राज्य के परमिट पोर्टल (ia.gotpermits.com) के माध्यम से ऑनलाइन या डाक द्वारा प्राप्त किए जाते हैं। परमिट केवल राज्य और Interstate राजमार्गों को कवर करते हैं; शहर या काउंटी सड़कों के लिए अलग परमिट आवश्यक हैं। स्रोत: Iowa DOT ओवरसाइज़/ओवरवेट परमिट।"},"14":{"q":"एक मानक आयोवा एकल-यात्रा ओवरसाइज़/ओवरवेट परमिट आमतौर पर कितने समय के लिए वैध होता है?","options":["5 days","24 hours","30 days","1 year"],"explanation":"एक मानक आयोवा एकल-यात्रा (एकल/राउंड ट्रिप) परमिट 5 कैलेंडर दिनों के लिए वैध होता है। मल्टी-ट्रिप परमिट 60 days चलते हैं और वार्षिक परमिट 12 months। स्रोत: Iowa DOT ओवरसाइज़/ओवरवेट परमिट प्रकार।"},"15":{"q":"एक Iowa DOT ओवरसाइज़/ओवरवेट परमिट किन सड़कों पर यात्रा को अधिकृत करता है?","options":["केवल राज्य और Interstate राजमार्ग; शहर और काउंटी सड़कों के लिए अलग परमिट आवश्यक हैं","आयोवा की सभी सार्वजनिक सड़कें, जिसमें सभी शहर की गलियाँ और काउंटी सड़कें शामिल हैं","केवल Interstate प्रणाली","केवल निजी ढुलाई सड़कें"],"explanation":"Iowa DOT परमिट राज्य प्राथमिक और Interstate राजमार्ग प्रणाली को कवर करते हैं। शहर की गलियों या काउंटी सड़कों पर यात्रा करने के लिए, किसी कैरियर को उन स्थानीय क्षेत्राधिकारों से अलग परमिट प्राप्त करना होगा। स्रोत: Iowa DOT ओवरसाइज़/ओवरवेट परमिट आवश्यकताएँ।"},"16":{"q":"आयोवा के राजमार्गों पर, ओवरसाइज़-लोड चेतावनी संकेत और कोने के झंडे आम तौर पर तब आवश्यक होते हैं जब वाहन और लोड किन आयामों से अधिक हो जाते हैं?","options":["लंबाई में 75 feet, चौड़ाई में 8 feet 6 inches, या ऊँचाई में 14 feet 4 inches","लंबाई में 40 feet या चौड़ाई में 8 feet","लंबाई में 100 feet या चौड़ाई में 12 feet","लंबाई में 53 feet या चौड़ाई में 10 feet"],"explanation":"आयोवा को \"Oversize Load\" संकेत और झंडे तब आवश्यक होते हैं जब कोई परमिट प्राप्त वाहन और लोड लंबाई में 75 feet, चौड़ाई में 8 feet 6 inches, और/या ऊँचाई में 14 feet 4 inches से अधिक हो जाए। लाल झंडे (18-inch वर्ग) लोड की सीमाओं को चिह्नित करते हैं। स्रोत: Iowa DOT/Iowa Admin. Code ch. 761-511 परमिट शर्तें।"},"17":{"q":"किसी ओवरसाइज़ लोड के लिए, लगभग किस चौड़ाई पर आयोवा आम तौर पर कम से कम एक एस्कॉर्ट (पायलट) वाहन की माँग करना शुरू करता है?","options":["जब लोड 14 feet 6 inches से अधिक चौड़ा हो","जब लोड 8 feet 6 inches से अधिक चौड़ा हो","जब लोड 10 feet से अधिक चौड़ा हो","आयोवा में एस्कॉर्ट कभी आवश्यक नहीं होते"],"explanation":"आयोवा में, 14 feet 6 inches से अधिक चौड़े लोड के लिए आम तौर पर कम से कम एक एस्कॉर्ट वाहन आवश्यक होता है; 14 feet 6 inches तक के लोड जो सड़क के आधे से अधिक हिस्से पर कब्जा करते हैं, इसके बजाय एक फ्रंट एस्कॉर्ट या एम्बर चेतावनी लाइट का उपयोग कर सकते हैं। विशिष्ट मार्ग सख्त आवश्यकताएँ लगा सकते हैं। स्रोत: Iowa DOT/Iowa Admin. Code ch. 761-511 परमिट शर्तें।"},"18":{"q":"सामान्य आयोवा परमिट शर्तों के तहत, कोई बड़ा ओवरसाइज़ लोड (जो 24/7 यात्रा के लिए बहुत बड़ा हो) कब चल सकता है?","options":["सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक, शनिवार और रविवार सहित, उचित सुरक्षा उपकरण के साथ","केवल आधी रात और सुबह 4 बजे के बीच","केवल सप्ताह के कार्यदिवसों पर, कभी सप्ताहांत या छुट्टियों पर नहीं","बिना किसी दिन-के-समय प्रतिबंध के किसी भी समय"],"explanation":"आयोवा परमिट शर्तें बड़े ओवरसाइज़ लोड को सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक, सप्ताहांत सहित, उचित लाइटिंग/मार्किंग के साथ यात्रा करने की अनुमति देती हैं। छोटे परमिट प्राप्त लोड (निर्धारित सीमाओं के भीतर) लगातार (24/7) चल सकते हैं। स्रोत: Iowa DOT/Iowa Admin. Code ch. 761-511 परमिट शर्तें।"},"19":{"q":"आयोवा विशेष रूप से किस वन-संबंधी वस्तु को कानूनी सीमा से अधिक वज़न पर ढोने के लिए एक विशेष ओवरसाइज़/ओवरवेट परमिट प्रदान करता है?","options":["कच्चे वन उत्पाद","तैयार फर्नीचर","कागज़ी मुद्रा","क्रिसमस सजावट"],"explanation":"आयोवा के विशेष परमिटों में एक Raw Forest Products परमिट है, जो (कृषि छूटों की तरह) निर्धारित शर्तों के तहत मानक सीमाओं से अधिक अप्रसंस्कृत वन उत्पादों की कटाई/ढुलाई को समायोजित करता है। स्रोत: Iowa DOT ओवरसाइज़/ओवरवेट परमिट प्रकार।"},"20":{"q":"आयोवा नियमों के तहत, 26,001 pounds या अधिक के सकल संयोजन वज़न रेटिंग (GCWR) वाले संयोजन वाहन को संचालित करने के लिए, जहाँ खींचे जाने वाले यूनिट(ओं) का GVWR 10,000 pounds से अधिक हो, कौन-सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","Class D (chauffeur)"],"explanation":"आयोवा 26,001+ lbs के GCWR वाले संयोजन वाहनों के लिए Class A CDL जारी करता है जहाँ खींचा जाने वाला यूनिट 10,000 lbs GVWR से अधिक हो। स्रोत: Iowa DOT CDL Manual / 761 IAC 607.16; Iowa DOT 'Driver's License Types, Restrictions, & Endorsements.'"},"21":{"q":"एक आयोवा चालक 30,000 pounds GVWR वाला एक एकल सीधा ट्रक संचालित करता है और 8,000 pounds GVWR रेटेड एक छोटा ट्रेलर खींचता है। कौन-सा CDL वर्ग आवश्यक है?","options":["Class C","Class A","Class B","किसी CDL की आवश्यकता नहीं है"],"explanation":"आयोवा का Class B CDL 26,001+ lbs के GVWR वाले एकल वाहन को कवर करता है, जिसमें 10,000 lbs GVWR से अधिक नहीं वाले यूनिट को खींचना शामिल है। चूँकि ट्रेलर 10,001 lbs से कम है, यह Class B है, Class A नहीं। स्रोत: Iowa DOT CDL Manual / Iowa DOT लाइसेंस प्रकार पृष्ठ; 761 IAC 607.16।"},"22":{"q":"आयोवा में, ऐसा वाहन जो 26,001 lbs GVWR से कम है लेकिन 16 या अधिक लोगों (चालक सहित) को परिवहन करने के लिए डिज़ाइन किया गया है, या प्लेकार्ड वाली खतरनाक सामग्री ले जाने के लिए उपयोग किया जाता है, उसके लिए कौन-सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","Class M"],"explanation":"आयोवा का Class C CDL उन वाहनों पर लागू होता है जो Class A/B वज़न सीमा से नीचे हैं और या तो 16+ व्यक्तियों (चालक सहित) को ले जाते हैं या प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन करते हैं। स्रोत: Iowa DOT 'Driver's License Types, Restrictions, & Endorsements'; 761 IAC 607.16।"},"23":{"q":"आयोवा में, INTRASTATE ड्राइविंग (केवल आयोवा के भीतर वाणिज्यिक वाहन संचालित करना) के लिए CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 years old","18 years old","21 years old","19 years old"],"explanation":"आयोवा 18 वर्ष की आयु में intrastate (आयोवा के भीतर) वाणिज्य के लिए CDL की अनुमति देता है। Interstate ड्राइविंग के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Iowa DOT Commercial Drivers / Iowa Tax And Tags CDL Endorsements; आयोवा द्वारा अपनाया गया FMCSA मानक।"},"24":{"q":"आयोवा में, INTERSTATE वाणिज्य (राज्य की सीमाएँ पार करना) में किसी वाणिज्यिक मोटर वाहन को संचालित करने की न्यूनतम आयु क्या है?","options":["18 years old","19 years old","21 years old","20 years old"],"explanation":"आयोवा, संघीय मानक का पालन करते हुए, चालकों को interstate वाणिज्य में ड्राइविंग करने या खतरनाक सामग्री परिवहन करने के लिए कम से कम 21 वर्ष का होना आवश्यक करता है। 18-20 वर्ष के चालक intrastate संचालन तक सीमित हैं। स्रोत: Iowa DOT Commercial Drivers; आयोवा में लागू FMCSA 49 CFR 391.11।"},"25":{"q":"वाहन को प्लेकार्ड किए जाने की आवश्यकता वाली मात्रा में खतरनाक सामग्री परिवहन के लिए आयोवा किस CDL एंडोर्समेंट की माँग करता है?","options":["N endorsement","H endorsement","T endorsement","X endorsement"],"explanation":"प्लेकार्ड वाली हैज़मैट ढोने के लिए H (Hazardous Materials) एंडोर्समेंट आवश्यक है। स्रोत: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual। (नोट: X एंडोर्समेंट संयुक्त टैंक + हैज़मैट एंडोर्समेंट को दर्शाता है।)"},"26":{"q":"लिखित ज्ञान परीक्षा पास करने के अलावा, HazMat (H) एंडोर्समेंट प्राप्त करने (और नवीनीकृत करने) के लिए किसी आयोवा आवेदक को कौन-सी अतिरिक्त संघीय आवश्यकता पूरी करनी होगी?","options":["एक टैंकर में एक अलग रोड स्किल्स टेस्ट","एक TSA फिंगरप्रिंट-आधारित सुरक्षा खतरा मूल्यांकन (पृष्ठभूमि जाँच)","न्यूनतम दो वर्ष का CDL अनुभव","FMCSA से एक दृष्टि छूट"],"explanation":"H एंडोर्समेंट के लिए HazMat ज्ञान परीक्षा के अलावा, प्रारंभिक आवेदन पर और प्रत्येक नवीनीकरण पर फिर से एक फिंगरप्रिंट-आधारित TSA सुरक्षा खतरा मूल्यांकन आवश्यक है। स्रोत: Iowa Tax And Tags CDL Endorsements; आयोवा में अपनाया गया TSA HazMat Endorsement Threat Assessment Program।"},"27":{"q":"किसी टैंक वाहन को चलाने के लिए कौन-सा आयोवा CDL एंडोर्समेंट आवश्यक है, जिसे एक टैंक में 119 gallons से अधिक की व्यक्तिगत रेटेड क्षमता और 1,000 gallons या अधिक की कुल रेटेड क्षमता वाले तरल या गैस के परिवहन के रूप में परिभाषित किया गया है?","options":["N (Tank)","H (HazMat)","T (Doubles/Triples)","P (Passenger)"],"explanation":"N (Tank) एंडोर्समेंट 119-gallon व्यक्तिगत और 1,000-gallon कुल क्षमता सीमा को पूरा करने वाले टैंक वाहनों को कवर करता है, और इसके लिए Tanker ज्ञान परीक्षा पास करना आवश्यक है। स्रोत: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual।"},"28":{"q":"डबल या ट्रिपल ट्रेलर खींचने के लिए कौन-सा आयोवा CDL एंडोर्समेंट आवश्यक है?","options":["P endorsement","N endorsement","T endorsement","S endorsement"],"explanation":"T (Doubles/Triples) एंडोर्समेंट, जो Double and Triple Trailers ज्ञान परीक्षा पास करके प्राप्त किया जाता है, कई ट्रेलर खींचने के लिए आवश्यक है। स्रोत: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual।"},"29":{"q":"आयोवा में ट्रिपल ट्रेलरों के संबंध में, T एंडोर्समेंट रखने वाले चालक के लिए कौन-सा कथन सही है?","options":["आयोवा कानून राज्य के भीतर ट्रिपल ट्रेलर संचालित करने पर रोक लगाता है, भले ही कोई निवासी अन्य राज्यों में उपयोग के लिए T एंडोर्समेंट प्राप्त कर सकता है","ट्रिपल ट्रेलर किसी भी आयोवा interstate राजमार्ग पर संचालित किए जा सकते हैं","ट्रिपल ट्रेलर केवल आयोवा टोल सड़कों पर अनुमत हैं","आयोवा ट्रिपल के लिए एक अलग 'Y' एंडोर्समेंट की माँग करता है"],"explanation":"आयोवा कानून राज्य के भीतर ट्रिपल-ट्रेलर संचालन पर रोक लगाता है; हालाँकि, कोई आयोवा निवासी अभी भी उन राज्यों में कानूनी रूप से ट्रिपल संचालित करने के लिए T एंडोर्समेंट प्राप्त कर सकता है जो उन्हें अनुमति देते हैं। स्रोत: Iowa Tax And Tags CDL Endorsements; Iowa Code Ch. 321 लंबाई/संयोजन सीमाएँ।"},"30":{"q":"चालक सहित 16 या अधिक लोगों को परिवहन करने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए कौन-सा आयोवा CDL एंडोर्समेंट आवश्यक है?","options":["S (School Bus)","P (Passenger)","N (Tank)","C (Chauffeur)"],"explanation":"चालक सहित 16 या अधिक व्यक्तियों को ले जाने के लिए डिज़ाइन किए गए वाहनों के लिए P (Passenger) एंडोर्समेंट आवश्यक है। इसके लिए यात्री ज्ञान परीक्षा के साथ-साथ एक प्रतिनिधि वाहन में स्किल्स परीक्षण आवश्यक है। स्रोत: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual।"},"31":{"q":"आयोवा में, किसी स्कूल बस को कानूनी रूप से संचालित करने के लिए किसी चालक को School Bus (S) एंडोर्समेंट के अलावा क्या रखना चाहिए?","options":["Passenger (P) एंडोर्समेंट","Tank (N) एंडोर्समेंट","HazMat (H) एंडोर्समेंट","और कुछ नहीं; अकेले S एंडोर्समेंट पर्याप्त है"],"explanation":"आयोवा को स्कूल बस संचालित करने के लिए School Bus (S) और Passenger (P) दोनों एंडोर्समेंट आवश्यक हैं; अकेले P एंडोर्समेंट स्कूल बस संचालन के लिए वैध नहीं है। स्रोत: Iowa Tax And Tags CDL Endorsements; Iowa DOT CDL Manual।"},"32":{"q":"CDL स्किल्स (रोड) टेस्ट देने की अनुमति मिलने से पहले किसी आवेदक को आयोवा Commercial Learner's Permit (CLP) कितने समय तक रखना होगा?","options":["कम से कम 7 days","कम से कम 14 days","कम से कम 30 days","कम से कम 60 days"],"explanation":"संघीय नियम, जो आयोवा में लागू है, स्किल्स टेस्ट देने से पहले CLP को कम से कम 14 days रखना आवश्यक करता है। स्रोत: Iowa DOT Commercial Learner Permits (CLP) पृष्ठ; 49 CFR 383.25।"},"33":{"q":"एक आयोवा Commercial Learner's Permit (CLP) की वैधता अवधि क्या है?","options":["180 days, एक बार नवीकरणीय","जारी होने की तिथि से एक वर्ष, बिना किसी नवीकरण अवधि के","दो वर्ष, नवीकरणीय","90 days, गैर-नवीकरणीय"],"explanation":"एक आयोवा CLP की लागत $12 है और यह जारी होने की तिथि से एक वर्ष के लिए वैध है, बिना किसी नवीकरण अवधि के। स्रोत: Iowa DOT Commercial Learner Permits (CLP) पृष्ठ।"},"34":{"q":"आयोवा Commercial Learner's Permit (CLP) या CDL के लिए आवेदन करने से पहले किसी आवेदक के पास पहले से क्या होना चाहिए?","options":["एक वैध आयोवा गैर-वाणिज्यिक ड्राइवर लाइसेंस","एक संघीय TWIC कार्ड","दो वर्ष का सैन्य ड्राइविंग अनुभव","एक Class M मोटरसाइकिल लाइसेंस"],"explanation":"आयोवा को आवेदकों को CLP या CDL के लिए आवेदन करने से पहले एक वैध आयोवा गैर-वाणिज्यिक ड्राइवर लाइसेंस रखने की आवश्यकता है। स्रोत: Iowa DOT Commercial Learner Permits (CLP) पृष्ठ / Iowa Tax And Tags।"},"35":{"q":"आयोवा में परीक्षण से पहले Entry-Level Driver Training (ELDT) किस संस्था के माध्यम से पूरा किया जाना चाहिए?","options":["आवेदक की पसंद का कोई भी निजी ड्राइविंग प्रशिक्षक","FMCSA Training Provider Registry (TPR) पर सूचीबद्ध एक प्रदाता","स्थानीय काउंटी ट्रेज़रर का कार्यालय","केवल Iowa State Patrol प्रशिक्षण अकादमी"],"explanation":"ELDT FMCSA Training Provider Registry पर सूचीबद्ध संस्था द्वारा प्रदान किया जाना चाहिए; केवल पंजीकृत प्रदाता ही आवश्यक प्रशिक्षण दे सकते हैं। स्रोत: FMCSA Training Provider Registry; Iowa DOT Commercial Drivers (ELDT आयोवा में लागू होता है)।"},"36":{"q":"ELDT (Entry-Level Driver Training) आयोवा में निम्नलिखित में से किसके पहली बार आवेदकों के लिए आवश्यक है?","options":["एक Class A या Class B CDL, और पहली बार S, P, या H एंडोर्समेंट","केवल HazMat (H) एंडोर्समेंट","केवल Doubles/Triples (T) एंडोर्समेंट","किसी भी मौजूदा CDL का नवीनीकरण"],"explanation":"ELDT पहली बार के Class A या Class B CDL आवेदकों के लिए, Class B-से-Class A उन्नयन के लिए, और पहली बार के School Bus (S), Passenger (P), या HazMat (H) एंडोर्समेंट के लिए आवश्यक है (H के लिए केवल सिद्धांत)। स्रोत: FMCSA ELDT नियम (CLP Feb 7, 2022 को या उसके बाद प्राप्त); आयोवा में लागू।"},"37":{"q":"एक आयोवा CDL धारक जो interstate वाणिज्य में एक वाणिज्यिक वाहन चलाता है और संघीय शारीरिक-योग्यता नियमों से छूट प्राप्त नहीं है, उसे किस चिकित्सा श्रेणी में स्व-प्रमाणन करना चाहिए?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"एक non-excepted interstate चालक को इस रूप में स्व-प्रमाणन करना चाहिए और Iowa DOT के पास एक वर्तमान Medical Examiner's Certificate फ़ाइल में रखना चाहिए; ऐसा न करने पर डाउनग्रेड हो जाता है। स्रोत: Iowa DOT Medical Cards & Certification; 761 IAC 607.50।"},"38":{"q":"किस चिकित्सा स्व-प्रमाणन श्रेणी को Iowa DOT को Medical Examiner's Certificate जमा करने की आवश्यकता नहीं है?","options":["Non-excepted interstate","Non-excepted intrastate","सभी चार श्रेणियों को इसे जमा करना होगा","केवल राज्य से बाहर के चालकों को छूट है"],"explanation":"केवल non-excepted interstate श्रेणी को Iowa DOT को Medical Examiner's Certificate जमा करना होगा। Non-excepted intrastate चालक इसे साथ रखते हैं लेकिन फ़ाइल करने की आवश्यकता नहीं है, और excepted श्रेणियों को किसी की आवश्यकता नहीं है; intrastate श्रेणियों को 'K' प्रतिबंध मिलता है। स्रोत: Iowa DOT Medical Cards & Certification; 761 IAC 607.50।"},"39":{"q":"पहली बार CDL/CLP के लिए आवेदन करते समय Iowa DOT किसी आवेदक से कौन-सा दस्तावेज़ समूह प्रदान करने की माँग करता है?","options":["पहचान/वैध उपस्थिति का प्रमाण, Social Security number, और आयोवा निवास","केवल एक पासपोर्ट","केवल एक सैन्य DD-214 फॉर्म","केवल वाहन बीमा और पंजीकरण का प्रमाण"],"explanation":"आयोवा को पहचान और अमेरिकी नागरिकता या वैध उपस्थिति का प्रमाण, एक Social Security number, और आयोवा निवास का सत्यापन (जैसे, वर्तमान आयोवा-पते वाला लाइसेंस) आवश्यक है। स्रोत: Iowa DOT Commercial Learner Permits (CLP) पृष्ठ; 761 IAC 607।"},"40":{"q":"आयोवा में, किसी व्यक्ति की अधिकतम अल्कोहल सांद्रता क्या हो सकती है और फिर भी वह कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) संचालित कर सके?","options":["0.04","0.08","0.02","0.05"],"explanation":"Iowa Code 321.208(1)(a) किसी ऐसे चालक को अयोग्य घोषित करता है जो 0.04 या अधिक की अल्कोहल सांद्रता (जैसा कि 321J.1 में परिभाषित है) के साथ CMV संचालित करता है। इसलिए CMV के लिए कानूनी सीमा 0.04 से नीचे है, जो सामान्य चालकों पर लागू 0.08 सीमा की आधी है। स्रोत: Iowa Code 321.208 / Iowa CDL Manual।"},"41":{"q":"आयोवा के implied consent कानून के तहत, किसी CDL धारक के साथ क्या होता है जो वैध अनुरोध के बाद Chapter 321J के तहत आवश्यक रासायनिक परीक्षण कराने से इनकार करता है?","options":["इसे एक प्रमुख अपराध माना जाता है, अल्कोहल दोषसिद्धि के समान, और इससे अयोग्यता आती है","CDL के साथ कुछ नहीं होता क्योंकि इनकार एक संवैधानिक अधिकार है","बिना किसी अयोग्यता के केवल एक छोटा नागरिक जुर्माना लगाया जाता है","पहली बार इनकार के लिए चालक को एक लिखित चेतावनी मिलती है"],"explanation":"Iowa Code 321.208(2)(b) और 321.208(13) Chapter 321J के तहत रासायनिक परीक्षण कराने से इनकार को एक प्रमुख अपराध मानते हैं, जो एक OWI दोषसिद्धि के समान अयोग्यता लाता है। स्रोत: Iowa Code 321.208 / Iowa CDL Manual।"},"42":{"q":"प्लेकार्ड वाली खतरनाक सामग्री न ढोते समय, पहले प्रमुख अपराध (जैसे OWI या 0.04 या अधिक के साथ CMV चलाना) के लिए किसी चालक को CMV संचालित करने से कितने समय तक अयोग्य ठहराया जाता है?","options":["1 year","3 years","60 days","आजीवन"],"explanation":"Iowa Code 321.208(1) और (2) पहले प्रमुख अपराध जैसे 0.04 या अधिक की अल्कोहल सांद्रता के साथ संचालन, OWI, या परीक्षण से इनकार के लिए एक वर्ष की CMV अयोग्यता लगाते हैं। स्रोत: Iowa Code 321.208 (49 CFR 383.51 को प्रतिबिंबित करता है)।"},"43":{"q":"यदि कोई पहला प्रमुख अपराध (जैसे OWI या 0.04 BAC) तब होता है जब चालक प्लेकार्ड वाली खतरनाक सामग्री परिवहन करने वाला CMV संचालित कर रहा हो, तो अयोग्यता कितने समय तक बढ़ जाती है?","options":["3 years","1 year","5 years","आजीवन"],"explanation":"Iowa Code 321.208(3) पहले-अपराध की अयोग्यता को एक वर्ष से बढ़ाकर तीन वर्ष कर देता है जब अपराध तब होता है जब CMV 49 CFR 383.5 के तहत प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री परिवहन कर रहा हो। स्रोत: Iowa Code 321.208।"},"44":{"q":"दूसरा प्रमुख अपराध (दो या अधिक अलग-अलग घटनाओं में) करने के लिए, जैसे दूसरा OWI या परीक्षण से इनकार, क्या दंड है?","options":["आजीवन अयोग्यता (जिसे बाद में 10 years तक कम किया जा सकता है)","3-year अयोग्यता","1-year अयोग्यता","120-day अयोग्यता"],"explanation":"Iowa Code 321.208(4) अलग-अलग घटनाओं से दो या अधिक प्रमुख अपराधों पर किसी चालक को आजीवन के लिए अयोग्य ठहराता है। आजीवन अयोग्यता को विभाग के नियम द्वारा 49 CFR 383.51 में दिए गए अनुसार 10 years तक कम किया जा सकता है। स्रोत: Iowa Code 321.208।"},"45":{"q":"तीन-वर्ष की अवधि के भीतर CMV संचालित करते समय दो गंभीर यातायात उल्लंघन जमा करने के लिए किसी चालक को कितने समय तक अयोग्य ठहराया जाता है?","options":["60 days","120 days","30 days","1 year"],"explanation":"Iowa Code 321.208(8) किसी भी तीन-वर्ष की अवधि के भीतर दो गंभीर यातायात उल्लंघनों के लिए 60-day की अयोग्यता लगाता है। स्रोत: Iowa Code 321.208 / Iowa CDL Manual।"},"46":{"q":"तीन-वर्ष की अवधि के भीतर CMV संचालित करते समय तीन गंभीर यातायात उल्लंघन जमा करने के लिए किसी चालक को कितने समय तक अयोग्य ठहराया जाता है?","options":["120 days","60 days","180 days","1 year"],"explanation":"Iowa Code 321.208(8) किसी भी तीन-वर्ष की अवधि के भीतर तीन गंभीर यातायात उल्लंघनों के लिए 120-day की अयोग्यता लगाता है। एकाधिक अयोग्यता अवधियाँ लगातार चलती हैं। स्रोत: Iowa Code 321.208।"},"47":{"q":"निम्नलिखित में से कौन-सा आयोवा में CMV अयोग्यता की ओर गिने जाने वाले एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत है?","options":["कानूनी गति सीमा से 15 mph या अधिक तेज़ गति","कानूनी गति सीमा से 5 mph तेज़ गति","CMV में एक पार्किंग उल्लंघन","एक वाहन वज़न (ओवरवेट) उल्लंघन"],"explanation":"Iowa Code 321.208(7)(d) सीमा से 15 mph या अधिक तेज़ गति को एक गंभीर उल्लंघन के रूप में सूचीबद्ध करता है। पार्किंग और वाहन वज़न उल्लंघनों को गंभीर-उल्लंघन गणना से स्पष्ट रूप से बाहर रखा गया है। स्रोत: Iowa Code 321.208।"},"48":{"q":"आयोवा कानून के तहत, किसी वाणिज्यिक मोटर वाहन को चलाते समय टेक्स्टिंग करना किस प्रकार के CDL उल्लंघन के रूप में वर्गीकृत है?","options":["एक गंभीर यातायात उल्लंघन","1-year अयोग्यता लाने वाला एक प्रमुख अपराध","एक out-of-service order उल्लंघन","बिना किसी अयोग्यता प्रभाव वाला एक मामूली उपकरण उल्लंघन"],"explanation":"Iowa Code 321.208(7)(i) CMV चलाते समय टेक्स्टिंग पर रोक लगाने वाले कानून का उल्लंघन करने को एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध करता है, जो 60-day/120-day की अयोग्यताओं की ओर गिना जाता है। स्रोत: Iowa Code 321.208।"},"49":{"q":"यातायात-नियंत्रण कानून के उल्लंघन में, CMV चलाते समय हैंड-हेल्ड मोबाइल टेलीफ़ोन का उपयोग करना, आयोवा में किस रूप में माना जाता है:","options":["अयोग्यता की ओर गिने जाने वाला एक गंभीर यातायात उल्लंघन","आजीवन अयोग्यता वाला एक प्रमुख अपराध","बिना किसी CDL परिणाम वाला एक उल्लंघन","एक स्वचालित 1-year अयोग्यता"],"explanation":"Iowa Code 321.208(7)(j) CMV चलाते समय हैंड-हेल्ड मोबाइल टेलीफ़ोन के उपयोग को प्रतिबंधित या निषिद्ध करने वाले कानून का उल्लंघन करने को एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध करता है, जो 60/120-day की अयोग्यता सीमाओं की ओर गिना जाता है। स्रोत: Iowa Code 321.208।"},"50":{"q":"किसी out-of-service order के पहले उल्लंघन (हैज़मैट या 16+ यात्रियों के लिए डिज़ाइन किए गए वाहन से असंबंधित) के लिए, आयोवा अयोग्यता सीमा है:","options":["180 days से कम नहीं और 1 year से अधिक नहीं","60 days से कम नहीं और 120 days से अधिक नहीं","30 days से कम नहीं और 90 days से अधिक नहीं","2 years से कम नहीं और 5 years से अधिक नहीं"],"explanation":"Iowa Code 321.208(10)(a) पहले out-of-service order उल्लंघन को 180 days से कम नहीं और एक वर्ष से अधिक नहीं निर्धारित करता है। स्रोत: Iowa Code 321.208।"},"51":{"q":"10 वर्षों के भीतर अलग-अलग घटनाओं में किसी out-of-service order के दूसरे उल्लंघन (गैर-हैज़मैट) के लिए, आयोवा अयोग्यता सीमा है:","options":["2 years से कम नहीं और 5 years से अधिक नहीं","180 days से कम नहीं और 1 year से अधिक नहीं","1 year से कम नहीं और 3 years से अधिक नहीं","आजीवन"],"explanation":"Iowa Code 321.208(10)(a) दूसरे out-of-service order उल्लंघन (10-वर्ष की अवधि के भीतर) को 2 years से कम नहीं और 5 years से अधिक नहीं निर्धारित करता है। स्रोत: Iowa Code 321.208।"},"52":{"q":"प्लेकार्ड वाली खतरनाक सामग्री परिवहन करते समय, या 15 से अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए CMV को संचालित करते समय किए गए out-of-service order के पहले उल्लंघन का परिणाम अयोग्यता है:","options":["1 year","180 days","3 years","60 days"],"explanation":"Iowa Code 321.208(10)(b) प्लेकार्ड वाली हैज़मैट ढोते समय या 15 से अधिक यात्रियों (चालक सहित) के लिए डिज़ाइन किए गए CMV को संचालित करते समय किए गए पहले out-of-service order उल्लंघन के लिए एक वर्ष की अयोग्यता लगाता है। स्रोत: Iowa Code 321.208।"},"53":{"q":"आयोवा में CMV संचालित करते समय किए गए पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए किसी चालक को कितने समय तक अयोग्य ठहराया जाता है?","options":["60 days","120 days","30 days","1 year"],"explanation":"Iowa Code 321.208(11)(a) CMV संचालित करते समय किए गए पहले रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन (321.341 या 321.343 के तहत) के लिए 60-day की अयोग्यता लगाता है। स्रोत: Iowa Code 321.208।"},"54":{"q":"पहले के तीन वर्षों के भीतर, CMV में दूसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए दोषी पाए गए चालक को अयोग्य ठहराया जाता है:","options":["120 days","60 days","180 days","1 year"],"explanation":"Iowa Code 321.208(11)(b) पहले के तीन वर्षों के भीतर होने वाले CMV में दूसरे रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए 120-day की अयोग्यता लगाता है। स्रोत: Iowa Code 321.208।"},"55":{"q":"पहले के तीन वर्षों के भीतर, CMV में तीसरे या बाद के रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए दोषी पाए गए चालक को अयोग्य ठहराया जाता है:","options":["1 year","120 days","60 days","180 days"],"explanation":"Iowa Code 321.208(11)(c) पहले के तीन वर्षों के भीतर होने वाले CMV में तीसरे या बाद के रेलमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए एक वर्ष की अयोग्यता लगाता है। स्रोत: Iowa Code 321.208।"},"56":{"q":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े एक गंभीर अपराध (फेलोनी) के आयोजन में किसी वाणिज्यिक मोटर वाहन का उपयोग करने का आयोवा में क्या CDL दंड होता है?","options":["कमी की कोई संभावना के बिना आजीवन अयोग्यता","1-year अयोग्यता","3-year अयोग्यता","120-day अयोग्यता"],"explanation":"Iowa Code 321.208(5) आजीवन अयोग्यता लगाता है, जो 10-वर्ष की कमी के अधीन नहीं है, जब किसी CMV का उपयोग एक नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े एक गंभीर अपराध में किया जाता है। स्रोत: Iowa Code 321.208।"},"57":{"q":"जब Iowa DOT को किसी अयोग्यता-योग्य दोषसिद्धि का रिकॉर्ड मिलता है, तो CMV अयोग्यता प्रभावी होने से पहले वह कितनी अग्रिम सूचना देता है?","options":["30 days","10 days","60 days","24 hours"],"explanation":"Iowa Code 321.208(12) और (13) प्रावधान करते हैं कि विभाग 30 days की अग्रिम सूचना पर बिना प्रारंभिक सुनवाई के चालक को अयोग्य ठहराता है; अयोग्यता की प्रभावी तिथि सूचना के 30 days बाद होती है। स्रोत: Iowa Code 321.208।"},"58":{"q":"एक प्रवर्तन अधिकारी द्वारा 0.04 या अधिक की अल्कोहल सांद्रता पाए जाने वाला एक CMV चालक, अयोग्यता का सामना करने के अलावा, तुरंत:","options":["24 hours के लिए out of service रखा जाता है","1-hour के आराम के बाद ड्राइव करने की अनुमति दी जाती है","0.08 से कम होने पर जारी रखने की अनुमति दी जाती है","$25 का जुर्माना लगाकर ड्राइव करने के लिए छोड़ा जाता है"],"explanation":"आयोवा में अपनाए गए संघीय नियम (49 CFR 392.5) किसी भी चालक को जिसकी अल्कोहल सांद्रता 0.04 या अधिक है, Iowa Code 321.208 के तहत औपचारिक अयोग्यता से अलग, 24 hours के लिए out of service रखे जाने की आवश्यकता करते हैं। स्रोत: 49 CFR 392.5 / Iowa CDL Manual।"},"59":{"q":"दो अलग-अलग घटनाओं से उत्पन्न दो अलग-अलग प्रमुख-अपराध दोषसिद्धियाँ आयोवा में एक आजीवन CDL अयोग्यता की ओर ले जाती हैं। आयोवा द्वारा अपनाए गए संघीय नियम के तहत, इस आजीवन अवधि को कम से कम कितने समय तक कम किया जा सकता है:","options":["10 years","5 years","3 years","1 year"],"explanation":"Iowa Code 321.208(4) एक आजीवन अयोग्यता (दो या अधिक प्रमुख अपराधों के लिए) को 49 CFR 383.51 में दिए गए और विभाग के नियम द्वारा अपनाए गए अनुसार 10-वर्ष की अयोग्यता तक कम करने के अधीन बनाता है। स्रोत: Iowa Code 321.208।"},"60":{"q":"आयोवा के 'मूव ओवर' कानून के तहत, जब आप किसी ऐसे इंटरस्टेट पर गाड़ी चला रहे हों जिसमें आपकी दिशा में दो लेन हों और आप एक रुके हुए आपातकालीन वाहन के पास पहुँचें जिसकी फ्लैशिंग लाइटें चालू हों, तो आयोवा कोड के अनुसार आपको सबसे पहले क्या करना आवश्यक है?","options":["यदि ऐसा करना सुरक्षित हो तो उस रुके हुए वाहन से सटी हुई लेन को छोड़कर किसी दूसरी लेन में चले जाएँ","जब तक आपातकालीन वाहन वहाँ से न चला जाए, तब तक शोल्डर पर पूरी तरह रुक जाएँ","अपना हॉर्न बजाएँ और उसी लेन में अपनी मौजूदा गति से आगे बढ़ते रहें","बाईं शोल्डर पर रुक जाएँ और किसी शांति अधिकारी (peace officer) के इशारे का इंतजार करें"],"explanation":"आयोवा कोड 321.323A के अनुसार, यदि कोई चालक ऐसे मार्ग पर किसी रुके हुए वाहन के पास पहुँचता है जिसकी फ्लैशिंग लाइटें चालू हों और जिस मार्ग पर चालक की दिशा में दो या अधिक लेन हों, तो जब ऐसा करना सुरक्षित और वैध हो, तो उसे उस वाहन से सटी हुई लेन को छोड़कर किसी दूसरी लेन में जाना आवश्यक है। स्रोत: आयोवा कोड 321.323A; Iowa DOT 'Move Over or Slow Down.'"},"61":{"q":"आयोवा के 'मूव ओवर' कानून के तहत, यदि किसी ऐसे रुके हुए वाहन से दूर लेन बदलना असंभव या असुरक्षित हो जिसकी फ्लैशिंग लाइटें चालू हों, तो आयोवा के चालक को क्या करना चाहिए?","options":["निर्धारित गति बनाए रखें लेकिन हैज़र्ड फ्लैशर्स चालू कर दें","गति को निर्धारित गति सीमा से कम कर दें और रुकने के लिए तैयार रहें","गति को निर्धारित गति सीमा से ठीक 20 mph कम कर दें","निर्धारित गति सीमा चाहे जो भी हो, गति को घटाकर 10 mph कर दें"],"explanation":"आयोवा कोड 321.323A में कहा गया है कि जब लेन बदलना असंभव, प्रतिबंधित या असुरक्षित हो, तो चालक को गति को घटाकर एक उचित और उपयुक्त गति तक लाना चाहिए जो निर्धारित गति सीमा से कम हो, और रुकने के लिए तैयार रहना चाहिए। आयोवा किसी निश्चित mph की कमी निर्धारित नहीं करता। स्रोत: आयोवा कोड 321.323A; Iowa DOT."},"62":{"q":"इनमें से कौन-सा रुका हुआ वाहन, जब अपनी आवश्यक फ्लैशिंग या चेतावनी लाइटें दिखा रहा हो, आयोवा के 'मूव ओवर' कानून (आयोवा कोड 321.323A) के अंतर्गत आता है?","options":["केवल कानून प्रवर्तन और अग्निशमन वाहन","केवल एम्बुलेंस और टो ट्रक","ठोस अपशिष्ट या रीसाइक्लिंग संग्रह वाहन","केवल Iowa DOT के स्वामित्व वाले वाहन"],"explanation":"आयोवा कोड 321.323A में रुके हुए अधिकृत आपातकालीन वाहन, टो/रिकवरी वाहन, रखरखाव और निर्माण वाहन, फ्लैशिंग लाइटों वाले ठोस अपशिष्ट या रीसाइक्लिंग संग्रह वाहन, और कोई भी ऐसा मोटर वाहन शामिल है जो लगातार अपने हैज़र्ड लैंप दिखा रहा हो। स्रोत: आयोवा कोड 321.323A; Iowa DOT."},"63":{"q":"आयोवा के किसी ग्रामीण इंटरस्टेट राजमार्ग पर, एक ट्रैक्टर-ट्रेलर पर लागू होने वाली अधिकतम गति सीमा क्या है?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"आयोवा कोड 321.285 इंटरस्टेट मार्ग प्रणाली पर सभी वाहन यातायात के लिए गति सीमा 70 mph निर्धारित करता है। आयोवा इंटरस्टेट पर ट्रकों के लिए अलग, कम गति सीमा लागू नहीं करता। स्रोत: आयोवा कोड 321.285."},"64":{"q":"क्या आयोवा यात्री कारों की तुलना में ट्रकों के लिए कम इंटरस्टेट गति सीमा निर्धारित करता है?","options":["हाँ, ट्रक 65 mph तक सीमित हैं जबकि कारें 70 mph चल सकती हैं","नहीं, 70 mph की इंटरस्टेट सीमा सभी वाहन यातायात पर समान रूप से लागू होती है","हाँ, ट्रक पूरे राज्य में 60 mph तक सीमित हैं","हाँ, 26,000 lbs से अधिक के ट्रक 55 mph तक सीमित हैं"],"explanation":"'विभाजित' गति सीमा वाले कुछ राज्यों के विपरीत, आयोवा कोड 321.285 सभी वाहन यातायात पर 70 mph की इंटरस्टेट अधिकतम सीमा लागू करता है, ट्रकों के लिए कोई अलग निर्धारित सीमा नहीं है। स्रोत: आयोवा कोड 321.285."},"65":{"q":"किराये पर यात्रियों को ले जाने वाली आयोवा की एक ट्रांज़िट बस एक रेलरोड ग्रेड क्रॉसिंग के पास पहुँचती है। चालक को कहाँ रुकना चाहिए?","options":["निकटतम रेल से 15 फ़ीट से कम नहीं और 50 फ़ीट से अधिक नहीं","निकटतम रेल से 10 फ़ीट से कम नहीं और 25 फ़ीट से अधिक नहीं","निकटतम रेल से 25 फ़ीट से कम नहीं और 75 फ़ीट से अधिक नहीं","निकटतम रेल के 5 फ़ीट के भीतर"],"explanation":"आयोवा कोड 321.343 के अनुसार किराये पर यात्रियों को ले जाने वाले वाहन, स्कूल बस, या प्लेकार्ड लगे खतरनाक-सामग्री वाहन को क्रॉसिंग से पहले निकटतम रेल से 50 फ़ीट के भीतर लेकिन 15 फ़ीट से कम नहीं की दूरी पर रुकना आवश्यक है। स्रोत: आयोवा कोड 321.343."},"66":{"q":"आयोवा में खतरनाक सामग्री का प्लेकार्ड लगा भार ढोने वाला एक चालक एक रेलरोड क्रॉसिंग पर पहुँचता है जिस पर 'EXEMPT' का चिन्ह लगा है। क्या आवश्यक है?","options":["फिर भी निकटतम रेल से 15 से 50 फ़ीट के भीतर रुकें","केवल तभी रुकें जब कोई ट्रेन दिखाई दे","उस क्रॉसिंग पर चालक के लिए रुकना आवश्यक नहीं है","क्रॉसिंग से पहले रुकें और चेतावनी त्रिकोण लगाएँ"],"explanation":"आयोवा कोड 321.343 बसों, किराये पर यात्री ले जाने वाले वाहनों, और प्लेकार्ड लगे HazMat वाहनों के लिए रुकना आवश्यक करता है, लेकिन जिस क्रॉसिंग पर आधिकारिक 'EXEMPT' चिन्ह लगा हो, वहाँ रुकना आवश्यक नहीं है। स्रोत: आयोवा कोड 321.343; Iowa CDL Manual."},"67":{"q":"किसी रेलरोड क्रॉसिंग पर रुकने के बाद, पटरियों को पार करने से पहले आयोवा के स्कूल बस चालक को क्या करना चाहिए?","options":["हॉर्न दो बार बजाएँ और बिना देरी के आगे बढ़ें","प्रवेश द्वार खोलें, ट्रेनों के लिए देखें और सुनें, फिर तभी पार करें जब सुरक्षित हो","परिस्थितियों चाहे जो भी हों, पूरे 60 सेकंड प्रतीक्षा करें","एम्बर चेतावनी लैंप चालू करें और धीरे-धीरे पार करें"],"explanation":"आयोवा कोड 321.343 के अनुसार, निकटतम रेल से 15 से 50 फ़ीट की दूरी पर रुकने के बाद स्कूल बस चालक को प्रवेश द्वार खोलना चाहिए, आती हुई ट्रेन के लिए देखना और सुनना चाहिए, और तब तक आगे नहीं बढ़ना चाहिए जब तक यह सुरक्षित न हो। स्रोत: आयोवा कोड 321.343."},"68":{"q":"आयोवा के एक दो-लेन राजमार्ग पर, एक स्कूल बस रुकती है, अपने फ्लैशिंग लाल लैंप चालू करती है, और बच्चों को उतारने के लिए अपना स्टॉप आर्म फैलाती है। पास आ रहे वाहन चालक को क्या करना चाहिए?","options":["गति घटाकर 20 mph करें और सावधानी से आगे निकलें","बस से 15 फ़ीट से कम दूरी पर न रुकें और जब तक स्टॉप आर्म वापस न ले लिया जाए तब तक रुके रहें","केवल तभी रुकें जब बच्चे सड़क पर दिखाई दें","दूर वाली लेन में चले जाएँ और बस को धीरे-धीरे पार करें"],"explanation":"आयोवा कोड 321.372 के अनुसार जिन वाहनों के सामने या जो किसी रुकी हुई स्कूल बस को ओवरटेक कर रहे हों, जिसके लाल लैंप फ्लैश हो रहे हों और स्टॉप आर्म फैला हो, उन्हें 15 फ़ीट से कम दूरी पर नहीं रुकना चाहिए और तब तक रुके रहना चाहिए जब तक स्टॉप आर्म वापस न ले लिया जाए और बस फिर से चलने न लगे। स्रोत: आयोवा कोड 321.372."},"69":{"q":"आयोवा के स्कूल बस कानून के तहत, किस प्रकार के राजमार्ग पर एक चालक जो विपरीत दिशा में चल रही एक रुकी हुई स्कूल बस के सामने (MEETS) आता है, बिना रुके आगे बढ़ सकता है?","options":["कोई भी राजमार्ग जिसमें बीच में रंगी हुई रेखा हो","ऐसा राजमार्ग जिसमें प्रत्येक दिशा में दो या अधिक यात्रा लेन हों","कोई भी राजमार्ग जिसकी निर्धारित गति 55 mph या उससे अधिक हो","ऐसा राजमार्ग जिसकी पक्की शोल्डर कम से कम 8 फ़ीट चौड़ी हो"],"explanation":"आयोवा कोड 321.372 प्रावधान करता है कि प्रत्येक दिशा में दो या अधिक लेन वाले राजमार्ग पर चालक को विपरीत दिशा में चल रही स्कूल बस के सामने आने (MEETING) पर रुकने की आवश्यकता नहीं है, भले ही वह रुकी हुई हो। अविभाजित सड़कों पर, सभी दिशाओं को रुकना चाहिए। स्रोत: आयोवा कोड 321.372."},"70":{"q":"आयोवा के एक राजमार्ग पर, जिसमें प्रत्येक दिशा में दो लेन हों और जो एक मीडियन से अलग हों, एक स्कूल बस विपरीत-दिशा वाली लेन में अपनी लाल लाइटें फ्लैश करते हुए रुकती है। दूसरी दिशा में चल रहा चालक:","options":["लाल लाइटें बंद होने तक रुकने के लिए आवश्यक है","गति घटाकर 10 mph करने के लिए आवश्यक है लेकिन आगे बढ़ सकता है","रुकने के लिए आवश्यक नहीं है क्योंकि सड़क में प्रत्येक दिशा में दो या अधिक लेन हैं","केवल तभी रुकने के लिए आवश्यक है जब मीडियन 6 फ़ीट से कम चौड़ा हो"],"explanation":"आयोवा कोड 321.372 का विभाजित-राजमार्ग अपवाद लेन की संख्या पर निर्भर करता है: प्रत्येक दिशा में दो या अधिक लेन वाले राजमार्ग पर, विपरीत-दिशा में रुकी हुई बस के सामने आने वाले चालकों को रुकने की आवश्यकता नहीं है। स्रोत: आयोवा कोड 321.372."},"71":{"q":"एक स्कूल बस आयोवा के ऐसे राजमार्ग पर चल रही है जिसमें चार या अधिक लेन हैं। ऐसे विद्यार्थियों के संबंध में जिन्हें राजमार्ग पार करना है, बस:","options":["जब तक लाल लाइटें चालू हों, तब तक उन्हें कहीं भी चढ़ा या उतार सकती है","जिन विद्यार्थियों को राजमार्ग पार करना है, उन्हें चढ़ाने या उतारने के लिए निर्धारित स्थानों को छोड़कर कहीं नहीं रुकेगी","उन्हें उतारने के लिए बाईं लेन का उपयोग करना चाहिए","उन्हें केवल सुबह 7 बजे से शाम 7 बजे के बीच ही उतार सकती है"],"explanation":"आयोवा कोड 321.372 चार या अधिक लेन वाले राजमार्ग पर किसी स्कूल बस को ऐसे विद्यार्थियों को चढ़ाने या उतारने के लिए रुकने से रोकता है जिन्हें राजमार्ग पार करना है, सिवाय यातायात-नियंत्रण उपकरणों या अधिकारियों वाले निर्धारित स्टॉप/स्थानों के। स्रोत: आयोवा कोड 321.372."},"72":{"q":"जब आयोवा की एक स्कूल बस यात्रियों के लिए रुकने की तैयारी कर रही हो, तो लाल फ्लैशिंग लैंप चालू करने से पहले उसे कौन-से चेतावनी लैंप दिखाने चाहिए?","options":["हरे फ्लैशिंग लैंप","नीले फ्लैशिंग लैंप","एम्बर (पीले) फ्लैशिंग चेतावनी लैंप","सफ़ेद स्ट्रोब लैंप"],"explanation":"आयोवा कानून और आयोवा स्कूल परिवहन नियमों के अनुसार चालक को रुकने से पहले एम्बर फ्लैशिंग चेतावनी लैंप दिखाने चाहिए, फिर रुकने पर लाल फ्लैशिंग लैंप पर स्विच करना चाहिए और स्टॉप आर्म फैलाना चाहिए। स्रोत: आयोवा कोड 321.372; Iowa Admin. Code 281-43."},"73":{"q":"एक CDL चालक आयोवा के एक समतल, सीधे दो-लेन राजमार्ग पर एक ट्रक रोकता है और उसे तीन आवश्यक चेतावनी त्रिकोण लगाने हैं। सही स्थान है:","options":["एक पीछे की ओर 10 ft पर, एक पीछे की ओर 100 ft पर, और एक आगे की ओर 100 ft पर","एक पीछे की ओर 25 ft पर, एक पीछे की ओर 250 ft पर, और एक आगे की ओर 250 ft पर","एक 5 ft पर, एक 50 ft पर, और एक 150 ft पर, सभी पीछे की ओर","तीनों वाहन के 200 ft पीछे रखे गए"],"explanation":"आयोवा संघीय नियम (49 CFR 392.22) का पालन करता है जो Iowa CDL Manual में सिखाया गया है: दो-लेन सड़क पर त्रिकोण वाहन के लगभग 10 ft पीछे, 100 ft पीछे, और 100 ft आगे रखें। स्रोत: 49 CFR 392.22; Iowa CDL Manual."},"74":{"q":"Iowa CDL Manual के अनुसार, किसी सड़क या शोल्डर पर एक खराब वाणिज्यिक मोटर वाहन को रोकने के बाद चेतावनी उपकरण (त्रिकोण) कितनी जल्दी लगाए जाने चाहिए?","options":["3 मिनट के भीतर","10 मिनट के भीतर","30 मिनट के भीतर","1 घंटे के भीतर"],"explanation":"आयोवा 49 CFR 392.22 का पालन करता है, जिसके अनुसार चालक को रुकने के 10 मिनट के भीतर आवश्यक चेतावनी उपकरण लगाने चाहिए। स्रोत: 49 CFR 392.22; Iowa CDL Manual."},"75":{"q":"एक CDL चालक आयोवा के एक वन-वे या विभाजित राजमार्ग पर रुकता है। तीन चेतावनी त्रिकोण कहाँ लगने चाहिए?","options":["आती हुई यातायात (पीछे) की ओर 10 ft, 100 ft, और 200 ft पर","10 ft, 100 ft, और 100 ft, एक पीछे की ओर और दो आगे की ओर","तीनों वाहन से प्रत्येक ओर 10 ft पर","100 ft आगे, 100 ft पीछे, और एक कैब के बगल में"],"explanation":"आयोवा 49 CFR 392.22 का पालन करता है: वन-वे या विभाजित राजमार्ग पर, त्रिकोण आती हुई यातायात की ओर 10 ft, 100 ft, और 200 ft पर रखें। स्रोत: 49 CFR 392.22; Iowa CDL Manual."},"76":{"q":"आयोवा का सामान्य 'दाएँ रहो' नियम (आयोवा कोड 321.297) किन वाहनों को दाईं ओर की लेन में चलने का निर्देश देता है?","options":["केवल वाणिज्यिक मोटर वाहन के रूप में पंजीकृत वाहन","केवल ट्रेलर खींचने वाले वाहन","कोई भी वाहन जो यातायात की सामान्य गति से धीमा चल रहा हो, सिवाय जब वह आगे निकल रहा हो या बाएँ मुड़ रहा हो","केवल 26,000 पाउंड सकल वजन से अधिक के वाहन"],"explanation":"आयोवा कोड 321.297 के अनुसार यातायात की सामान्य गति से धीमे चल रहे किसी भी वाहन को दाईं ओर की लेन का उपयोग करना आवश्यक है, सिवाय जब वह आगे निकल रहा हो या बाएँ मुड़ने की तैयारी कर रहा हो। आयोवा में ट्रकों के लिए कोई विशिष्ट बाईं-लेन प्रतिबंध नहीं है; यह नियम सभी धीमे यातायात पर लागू होता है। स्रोत: आयोवा कोड 321.297."},"77":{"q":"आयोवा में, किसी वाहन/भार को ओवरसाइज़ परमिट की आवश्यकता होने से पहले, सार्वजनिक राजमार्गों पर यात्रा के लिए कानूनी अधिकतम चौड़ाई है:","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"आयोवा, संघीय मानक के अनुरूप, कानूनी अधिकतम चौड़ाई 8 feet 6 inches निर्धारित करता है; इससे अधिक चौड़ी किसी भी चीज़ के लिए ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: Iowa DOT Motor Carrier Services, Oversize/Overweight Permit Requirements; आयोवा कोड अध्याय 321."},"78":{"q":"आयोवा में, एक अविभाज्य (indivisible) भार की ऊँचाई 13 feet 6 inches तक पहुँच जाती है। बिना परमिट के, यह ऊँचाई है:","options":["कानूनी सीमा से अधिक; 13 feet 6 inches से ऊपर परमिट आवश्यक है","सीमा से काफी कम; 16 feet तक कानूनी","सीमा से अधिक; कानूनी अधिकतम 12 feet है","केवल तभी कानूनी जब भार 8 feet से अधिक चौड़ा न हो"],"explanation":"Iowa DOT कानूनी अधिकतम ऊँचाई 13 feet 6 inches के रूप में सूचीबद्ध करता है; 13 feet 6 inches से अधिक के भार के लिए ओवरसाइज़ परमिट आवश्यक है। स्रोत: Iowa DOT Oversize/Overweight Permit Requirements."},"79":{"q":"आयोवा के ओवरसाइज़-परमिट नियमों के तहत, ओवरसाइज़ भार की आवाजाही आमतौर पर कब अनुमत है?","options":["केवल कार्यदिवसों में सुबह 9 बजे से दोपहर 3 बजे के बीच","दिन में 24 घंटे, बिना किसी समय सीमा के","सूर्योदय से आधा घंटा पहले से लेकर सूर्यास्त के आधा घंटा बाद तक","केवल रात में, यातायात से बचने के लिए"],"explanation":"आयोवा आमतौर पर ओवरसाइज़-भार की आवाजाही की अनुमति सूर्योदय से आधा घंटा पहले से लेकर सूर्यास्त के आधा घंटा बाद तक, सप्ताह के सातों दिन देता है, जिसमें कुछ छुट्टियों पर और बहुत बड़े भारों के लिए प्रतिबंध होते हैं। स्रोत: Iowa DOT Motor Carrier Services oversize/overweight permit rules."},"80":{"q":"आयोवा में वाणिज्यिक चालक लाइसेंस (CDL) कौन-सी एजेंसी जारी करती है?","options":["आयोवा परिवहन विभाग (Iowa DOT)","संघीय मोटर वाहक सुरक्षा प्रशासन (FMCSA)","आयोवा सार्वजनिक सुरक्षा विभाग","परिवहन सुरक्षा प्रशासन (TSA)"],"explanation":"आयोवा CDL आयोवा परिवहन विभाग (Iowa DOT) द्वारा जारी किए जाते हैं, जो राज्य की चालक लाइसेंसिंग एजेंसी है। FMCSA संघीय CDL मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता। स्रोत: Iowa DOT, Commercial Drivers / How to Get a CDL (iowadot.gov)."},"81":{"q":"एक आवेदक आयोवा CDL ज्ञान और कौशल परीक्षण कहाँ दे सकता है?","options":["चुनिंदा Iowa DOT और County Treasurer चालक लाइसेंस सेवा स्थानों पर","केवल एम्स (Ames) में एकमात्र Iowa DOT मुख्यालय पर","राज्य के किसी भी FMCSA फ़ील्ड कार्यालय पर","आयोवा के किसी भी स्थानीय पुलिस विभाग पर"],"explanation":"आयोवा CDL परीक्षण चुनिंदा Iowa DOT और County Treasurer चालक लाइसेंस स्थानों पर आयोजित किया जाता है; अतिरिक्त स्थान Iowa DOT CDL Testing Locations पृष्ठ पर सूचीबद्ध हैं। स्रोत: Iowa DOT, CDL Testing (iowadot.gov)."},"82":{"q":"इंट्रास्टेट (केवल-आयोवा-के-भीतर) ड्राइविंग के लिए आयोवा CDL प्राप्त करने हेतु सामान्य न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"आयोवा में आयोवा के भीतर (इंट्रास्टेट) वाणिज्यिक रूप से गाड़ी चलाने के लिए CDL आवेदक का कम से कम 18 वर्ष का होना आवश्यक है। राज्य की सीमाओं के पार (इंटरस्टेट) गाड़ी चलाने के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Iowa DOT, How to Get a CDL (iowadot.gov)."},"83":{"q":"आयोवा CDL के साथ इंटरस्टेट वाणिज्य में वाणिज्यिक मोटर वाहन चलाने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","23 वर्ष"],"explanation":"आयोवा में लागू संघीय नियम के तहत, इंटरस्टेट वाणिज्य में CMV चलाने के लिए चालक का कम से कम 21 वर्ष का होना आवश्यक है; 18 से 20 वर्ष के लोग केवल इंट्रास्टेट ड्राइविंग तक सीमित हैं। स्रोत: Iowa DOT, How to Get a CDL; 49 CFR 391.11 (संघीय मानक)."},"84":{"q":"आवेदन करते समय पहचान और कानूनी स्थिति साबित करने के लिए आयोवा CDL आवेदक को कौन-सा दस्तावेज़ प्रदान करना चाहिए?","options":["पूरे नाम, जन्म तिथि, सोशल सिक्योरिटी नंबर, और नागरिकता या कानूनी स्थिति का प्रमाण","केवल आवेदक के नाम पर एक मौजूदा यूटिलिटी बिल","केवल किसी मौजूदा नियोक्ता का एक हस्ताक्षरित पत्र","एक हाई स्कूल डिप्लोमा या GED प्रमाणपत्र"],"explanation":"आयोवा को पूरे कानूनी नाम, जन्म तिथि, सोशल सिक्योरिटी नंबर, और नागरिकता या कानूनी स्थायी निवास (जैसे, जन्म प्रमाणपत्र, पासपोर्ट, या स्थायी निवासी कार्ड) के प्रमाण के साथ-साथ आयोवा निवास के प्रमाण की आवश्यकता होती है। स्रोत: Iowa DOT, How to Get a CDL (iowadot.gov)."},"85":{"q":"परीक्षण से पहले, प्रत्येक आयोवा CDL आवेदक को 'स्व-प्रमाणन' (self-certify) करना चाहिए। स्व-प्रमाणन का क्या अर्थ है?","options":["Iowa DOT को यह घोषित करना कि चार ड्राइविंग श्रेणियों में से कौन-सी यह वर्णन करती है कि आप CMV कैसे चलाते हैं","एक बयान पर हस्ताक्षर करना कि आपके पास कोई ट्रैफ़िक टिकट नहीं है","एक वर्ष के भीतर प्रशिक्षण पूरा करने का वादा करना","यह प्रमाणित करना कि जिस वाहन में आप परीक्षण देंगे वह आपका है"],"explanation":"स्व-प्रमाणन Iowa DOT को चालक की यह घोषणा है कि CMV संचालन की चार श्रेणियों में से कौन-सी उन पर लागू होती है; यह निर्धारित करता है कि क्या किसी चिकित्सा परीक्षक के प्रमाणपत्र को फाइल पर रखा जाना चाहिए। स्रोत: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"86":{"q":"आयोवा CDL धारक को कितनी स्व-प्रमाणन श्रेणियों में से चुनना होता है?","options":["चार","दो","तीन","छह"],"explanation":"चार श्रेणियाँ हैं: इंटरस्टेट non-excepted, इंटरस्टेट excepted, इंट्रास्टेट non-excepted, और इंट्रास्टेट excepted। स्रोत: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"87":{"q":"किस स्व-प्रमाणन श्रेणी के लिए Iowa DOT के पास एक मौजूदा चिकित्सा परीक्षक प्रमाणपत्र (Medical Examiner's Certificate) फाइल पर होना आवश्यक है?","options":["इंटरस्टेट non-excepted","इंटरस्टेट excepted","इंट्रास्टेट excepted","इंट्रास्टेट non-excepted"],"explanation":"केवल इंटरस्टेट non-excepted चालकों को Iowa DOT के पास एक मौजूदा Medical Examiner's Certificate जमा करना और रखना आवश्यक है। Excepted चालकों को ऐसा नहीं करना पड़ता, और इंट्रास्टेट non-excepted चालकों को कार्ड साथ रखना चाहिए लेकिन उसे राज्य के पास फाइल करने की आवश्यकता नहीं है। स्रोत: Iowa DOT, Medical Cards & Certification; Iowa Admin. Code r. 761-607.50."},"88":{"q":"एक आयोवा इंटरस्टेट non-excepted चालक के लिए, DOT Medical Examiner's Certificate राज्य को कैसे जमा किया जाता है?","options":["प्रमाणित चिकित्सा परीक्षक इसे इलेक्ट्रॉनिक रूप से राष्ट्रीय रजिस्ट्री/राज्य प्रणाली में जमा करता है","चालक FMCSA को वॉशिंगटन, D.C. में एक कागज़ी प्रति डाक से भेजता है","चालक का नियोक्ता इसे काउंटी ट्रेज़रर को फ़ैक्स करता है","यह डॉक्टर के बिलिंग सॉफ़्टवेयर से स्वचालित रूप से स्थानांतरित हो जाता है"],"explanation":"आयोवा में, प्रमाणित चिकित्सा परीक्षक प्रमाणपत्र को इलेक्ट्रॉनिक रूप से जमा करता है; परिणाम National Registry of Certified Medical Examiners के माध्यम से राज्य तक पहुँचते हैं। चालक इंटरस्टेट non-excepted स्थिति के लिए इसे स्वयं फाइल नहीं करता। स्रोत: Iowa DOT, Medical Cards & Certification."},"89":{"q":"एक आयोवा इंटरस्टेट non-excepted CDL धारक नई प्रति फाइल किए बिना अपने Medical Examiner's Certificate को समाप्त (expire) होने देता है। CDL का क्या होता है?","options":["Iowa DOT एक सूचना/छूट अवधि के बाद CDL को डाउनग्रेड कर देता है, वाणिज्यिक विशेषाधिकार हटा देता है","जब तक CDL स्वयं समाप्त नहीं हो जाता, तब तक कुछ नहीं बदलता","जिस दिन कार्ड समाप्त होता है उसी दिन CDL स्थायी रूप से रद्द कर दिया जाता है","चालक स्वचालित रूप से excepted इंट्रास्टेट श्रेणी में चला जाता है"],"explanation":"यदि चिकित्सा प्रमाणपत्र की अवधि समाप्त हो जाती है, तो Iowa DOT चिकित्सा स्थिति को 'not certified' पर सेट कर देता है, लिखित सूचना देता है, और यदि 60-दिन की अवधि के भीतर एक मौजूदा प्रमाणपत्र प्राप्त नहीं होता है तो CMV विशेषाधिकार हटा देता है (डाउनग्रेड)। स्रोत: Iowa Admin. Code r. 761-607.50."},"90":{"q":"CDL प्रक्रिया में, कौशल परीक्षण से पहले, एक आयोवा आवेदक को सबसे पहले कौन-सा क्रेडेंशियल प्राप्त होता है?","options":["एक वाणिज्यिक शिक्षार्थी परमिट (CLP)","एक पूर्ण अप्रतिबंधित CDL","एक खतरनाक सामग्री समर्थन (endorsement)","एक चिकित्सा छूट प्रमाणपत्र"],"explanation":"आवश्यक ज्ञान परीक्षण पास करने और दस्तावेज़/चिकित्सा आवश्यकताओं को पूरा करने के बाद, आवेदक को एक वाणिज्यिक शिक्षार्थी परमिट (CLP) प्राप्त होता है, जो कौशल परीक्षण से पहले पर्यवेक्षित अभ्यास की अनुमति देता है। स्रोत: Iowa DOT, How to Get a CDL; Commercial Learner Permits (iowadot.gov)."},"91":{"q":"वाणिज्यिक शिक्षार्थी परमिट (CLP) जारी किए जाने के लिए एक आयोवा आवेदक को क्या पास करना चाहिए?","options":["लागू CDL ज्ञान (लिखित) परीक्षण और दृष्टि जाँच (vision screening)","केवल तीन-भाग वाला कौशल परीक्षण","उनकी निजी कार में एक रोड टेस्ट","हैज़मैट TSA पृष्ठभूमि जाँच"],"explanation":"CLP तब जारी किया जाता है जब आवेदक लागू CDL ज्ञान परीक्षण और दृष्टि जाँच पास कर लेता है, और आवश्यक दस्तावेज़ प्रदान करता है; कौशल परीक्षण बाद में होता है। स्रोत: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"92":{"q":"CDL कौशल परीक्षण देने से पहले एक आयोवा आवेदक को वाणिज्यिक शिक्षार्थी परमिट कितने समय तक रखना चाहिए?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"आयोवा संघीय नियम लागू करता है जिसके अनुसार कौशल परीक्षण देने से पहले CLP को न्यूनतम 14 दिन तक रखना आवश्यक है। स्रोत: Iowa DOT, How to Get a CDL / Commercial Learner Permits; 49 CFR 383.25."},"93":{"q":"एक आयोवा वाणिज्यिक शिक्षार्थी परमिट (CLP) कितने समय तक वैध रहता है, और क्या इसे नवीनीकृत किया जा सकता है?","options":["एक वर्ष के लिए वैध और इसे नवीनीकृत नहीं किया जा सकता (एक नया CLP प्राप्त करना होगा)","180 दिनों के लिए वैध और एक बार नवीनीकृत किया जा सकता है","दो वर्ष के लिए वैध और प्रतिवर्ष नवीनीकरण योग्य","60 दिनों के लिए वैध, असीमित नवीनीकरण के साथ"],"explanation":"एक आयोवा CLP जारी होने की तिथि से एक वर्ष के लिए वैध है और गैर-नवीनीकरण योग्य है; यदि यह समाप्त हो जाता है, तो आवेदक को फिर से आवेदन करना होगा। स्रोत: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"94":{"q":"7 फ़रवरी 2022 को या उसके बाद जारी किए गए CLP के लिए, एक आयोवा आवेदक के CDL कौशल परीक्षण देने से पहले क्या पूरा और सत्यापित होना चाहिए?","options":["किसी पंजीकृत प्रशिक्षण प्रदाता से प्रवेश-स्तरीय चालक प्रशिक्षण (ELDT)","किसी सामुदायिक कॉलेज में एक रक्षात्मक ड्राइविंग पाठ्यक्रम","न्यूनतम 160 घंटे का अवैतनिक रोड समय","कम से कम 30 दिन बाद लिया गया एक दूसरा ज्ञान परीक्षण"],"explanation":"7 फ़रवरी 2022 को या उसके बाद जारी किए गए CLP के लिए कौशल परीक्षण से पहले FMCSA Training Provider Registry में सूचीबद्ध प्रदाता से प्रवेश-स्तरीय चालक प्रशिक्षण (ELDT) पूरा और सत्यापित होना चाहिए। स्रोत: Iowa DOT, How to Get a CDL; 49 CFR Part 380 Subpart F."},"95":{"q":"ELDT पूर्णता कहाँ दर्ज की जाती है ताकि Iowa DOT कौशल परीक्षण निर्धारित करने से पहले इसे सत्यापित कर सके?","options":["FMCSA Training Provider Registry (TPR) में","आवेदक के CLP कार्ड पर हाथ से","चालक द्वारा रखी गई एक कागज़ी लॉगबुक में","TSA Hazmat डेटाबेस में"],"explanation":"पंजीकृत प्रदाता ELDT प्रमाणन को FMCSA Training Provider Registry में अपलोड करते हैं; Iowa DOT कौशल परीक्षण निर्धारित होने से पहले उस रिकॉर्ड को सत्यापित करता है। स्रोत: Iowa DOT, How to Get a CDL; FMCSA Training Provider Registry (49 CFR Part 380)."},"96":{"q":"आयोवा CDL कौशल परीक्षण में तीन भाग होते हैं। कौन-सी सूची उनका सही नाम बताती है?","options":["प्री-ट्रिप वाहन निरीक्षण, बुनियादी नियंत्रण कौशल, और ऑन-रोड ड्राइविंग","लिखित परीक्षा, दृष्टि परीक्षण, और श्रवण परीक्षण","एयर-ब्रेक क्विज़, हैज़मैट क्विज़, और कॉम्बिनेशन क्विज़","केवल बैकिंग, केवल समानांतर पार्किंग, और केवल हाईवे मर्जिंग"],"explanation":"आयोवा कौशल परीक्षण के तीन भाग होते हैं: प्री-ट्रिप वाहन निरीक्षण, बुनियादी नियंत्रण कौशल परीक्षण (युक्तियाँ और कोन के चारों ओर बैकिंग), और ऑन-रोड ड्राइविंग परीक्षण। स्रोत: Iowa DOT, CDL Testing (iowadot.gov); Iowa CDL Manual."},"97":{"q":"कौशल परीक्षण के आयोवा प्री-ट्रिप वाहन निरीक्षण भाग के दौरान, आवेदक से क्या अपेक्षित है?","options":["वाहन के चारों ओर घूमें और प्रत्येक वस्तु की ओर इशारा करें या उसे छुएँ, यह समझाते हुए कि क्या जाँचा जा रहा है और क्यों","बस यह बताएँ कि वाहन अच्छी स्थिति में है","परीक्षक के लिए ब्रेक प्रणाली को अलग करें (disassemble)","गेजों का वर्णन करते हुए राजमार्ग पर वाहन चलाएँ"],"explanation":"प्री-ट्रिप निरीक्षण में, आवेदक वाहन के चारों ओर घूमता है, प्रत्येक वस्तु की ओर इशारा करता है या उसे छूता है, और परीक्षक को समझाता है कि क्या जाँचा जा रहा है और क्यों, ताकि यह दिखाया जा सके कि वाहन चलाने के लिए सुरक्षित है। स्रोत: Iowa DOT, CDL Testing (iowadot.gov); Iowa CDL Manual."},"98":{"q":"अधिकांश वयस्क चालकों के लिए आयोवा CDL नवीनीकरण चक्र की सामान्य अधिकतम वैधता अवधि क्या है?","options":["8 वर्ष तक (बड़ी उम्र के चालकों के लिए कम, लगभग 80 वर्ष की आयु तक सीमित)","सभी चालकों के लिए ठीक 1 वर्ष","15 वर्ष तक","ठीक 30 दिन"],"explanation":"CDL सहित आयोवा चालक लाइसेंस 8 वर्ष तक के लिए जारी किए जा सकते हैं, बड़ी उम्र के चालकों के लिए छोटी अवधि और एक सीमा के साथ ताकि क्रेडेंशियल चालक के लगभग 80वें जन्मदिन के बाद तक न बढ़े। स्रोत: आयोवा कोड 321.196; Iowa DOT, Renew a CDL."},"99":{"q":"प्रत्येक आयोवा CDL नवीनीकरण पर, खतरनाक सामग्री (H) समर्थन के धारक को ऑनलाइन के बजाय व्यक्तिगत रूप से नवीनीकरण क्यों करना चाहिए?","options":["उन्हें हैज़मैट ज्ञान परीक्षण फिर से देना होगा और एक TSA खतरा मूल्यांकन/पृष्ठभूमि जाँच पूरी करनी होगी","आयोवा में किसी भी CDL धारक के लिए ऑनलाइन नवीनीकरण कभी उपलब्ध नहीं है","उन्हें समर्थन को स्थायी रूप से समर्पित (surrender) करना होगा","उन्हें पहले एक नया ELDT सिद्धांत पाठ्यक्रम ऑनलाइन पूरा करना होगा"],"explanation":"हैज़मैट समर्थन धारकों को प्रत्येक नवीनीकरण पर हैज़मैट ज्ञान परीक्षण फिर से देना होगा और एक TSA सुरक्षा खतरा मूल्यांकन (फ़िंगरप्रिंट-आधारित पृष्ठभूमि जाँच) पूरा करना होगा, इसलिए वे ऑनलाइन नवीनीकरण नहीं कर सकते और उन्हें व्यक्तिगत रूप से आवेदन करना होगा। स्रोत: Iowa DOT, Renew a CDL; 49 CFR 1572 (TSA)."}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة التجارية على طرق آيوا السريعة دون الحصول على تصريح للحمولة الزائدة الحجم؟","options":["8 أقدام و6 بوصات","8 أقدام و0 بوصة","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"يحدد القسم 321.454 من قانون آيوا الحد الأقصى لعرض المركبة، بما في ذلك الحمولة، بـ 8 أقدام و6 بوصات (102 بوصة). أي عرض يتجاوز ذلك يتطلب تصريحاً للحمولة الزائدة الحجم. المصدر: قانون آيوا 321.454؛ متطلبات تصاريح الحمولة الزائدة الحجم/الزائدة الوزن لدى Iowa DOT."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة وحمولتها على طرق آيوا السريعة دون الحصول على تصريح؟","options":["13 قدماً و6 بوصات","13 قدماً و0 بوصة","14 قدماً و0 بوصة","14 قدماً و6 بوصات"],"explanation":"يحدد القسم 321.456 من قانون آيوا ارتفاع المركبة بـ 13 قدماً و6 بوصات. الحمولات الأطول من ذلك تتطلب تصريحاً للحمولة الزائدة الحجم. المصدر: قانون آيوا 321.456؛ متطلبات التصاريح لدى Iowa DOT."},"2":{"q":"على طرق آيوا السريعة، ما هو الحد الأقصى القانوني لطول نصف المقطورة العاملة ضمن تركيبة جرار-نصف مقطورة دون الحصول على تصريح؟","options":["53 قدماً","48 قدماً","57 قدماً","45 قدماً"],"explanation":"تسمح آيوا بنصف مقطورة يصل طولها إلى 53 قدماً (محمّلة أو فارغة) ضمن تركيبة جرار-نصف مقطورة دون الحصول على تصريح. أما المقطورات منخفضة الهيكل (lowboy) التي تنقل معدات البناء فقد يصل طولها إلى 57 قدماً. المصدر: الفصل 321 من قانون آيوا؛ متطلبات التصاريح لدى Iowa DOT."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به على طرق آيوا السريعة دون الحصول على تصريح للوزن الزائد؟","options":["80,000 رطل","73,280 رطلاً","84,000 رطل","76,000 رطل"],"explanation":"يحدد القسم 321.463 من قانون آيوا الحد الأقصى للوزن الإجمالي بـ 80,000 رطل، بما يتوافق مع الحد الفيدرالي. تجاوز هذا الحد يتطلب تصريحاً للوزن الزائد. المصدر: قانون آيوا 321.463؛ Iowa DOT."},"4":{"q":"ما هو الحد الأقصى للوزن المسموح به على المحور الواحد على طرق آيوا السريعة؟","options":["20,000 رطل","18,000 رطل","22,400 رطل","24,000 رطل"],"explanation":"يحدد القسم 321.463 من قانون آيوا وزن المحور الواحد بـ 20,000 رطل، وهو نفس المعيار الفيدرالي للطرق السريعة بين الولايات (Interstate). المصدر: قانون آيوا 321.463؛ Iowa DOT."},"5":{"q":"ما هو الحد الأقصى للوزن المسموح به على مجموعة المحاور المزدوجة (tandem) على طرق آيوا السريعة؟","options":["34,000 رطل","32,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"يحدد القسم 321.463 من قانون آيوا وزن المحور المزدوج بـ 34,000 رطل، بما يطابق المعيار الفيدرالي. المصدر: قانون آيوا 321.463؛ Iowa DOT."},"6":{"q":"ما هي الطريقة التي تستخدمها آيوا لتحديد الحد الأقصى للوزن الإجمالي على أي مجموعة مكونة من محورين متتاليين أو أكثر؟","options":["الصيغة الفيدرالية للجسور (Bridge Formula) (الصيغة B)","حد ثابت قدره 80,000 رطل بغض النظر عن التباعد","تصنيف حمل الإطارات الإجمالي فقط","قاعدة 600 رطل لكل بوصة من عرض الإطار"],"explanation":"تطبّق آيوا الصيغة الفيدرالية للجسور (W = 500[(LN/(N-1)) + 12N + 36]) للحد من الوزن على مجموعات المحاور المتتالية بناءً على عدد المحاور (N) والتباعد (L). المصدر: قانون آيوا 321.463؛ 23 CFR 658.17؛ Iowa DOT."},"7":{"q":"في الصيغة الفيدرالية للجسور كما تُطبَّق في آيوا، ماذا يمثل المتغيران L وN؟","options":["L هي المسافة بالأقدام بين المحورين الخارجيين للمجموعة؛ وN هو عدد المحاور في المجموعة","L هي الحمولة بالأرطال؛ وN هو عدد الإطارات","L هي الطول القانوني للمقطورة؛ وN هو الوزن الصافي","L هي عرض المسار؛ وN هو عدد التصاريح المطلوبة"],"explanation":"في الصيغة W = 500[(LN/(N-1)) + 12N + 36]، يمثل L المسافة بالأقدام بين المحورين الأبعد لأي مجموعة من محورين متتاليين أو أكثر، ويمثل N عدد المحاور في تلك المجموعة. المصدر: 23 CFR 658.17 كما اعتمدها قانون آيوا 321.463."},"8":{"q":"كيف تقارَن حدود الوزن الإجمالي ووزن المحاور في آيوا على نظام الطرق السريعة بين الولايات (Interstate) بتلك المطبقة على الطرق السريعة الأساسية (غير الـ Interstate) في الولاية؟","options":["حدود الوزن الإجمالي 80,000 رطل وحدود المحاور 20,000/34,000 رطل هي نفسها؛ وتُسمح بعض الأوزان الأعلى فقط على الطرق غير الـ Interstate","تسمح الطرق غير الـ Interstate بوزن إجمالي قدره 73,280 رطلاً فقط","تسمح الطرق الـ Interstate بوزن إجمالي قدره 90,000 رطل","لا توجد حدود وزن على الطرق غير الـ Interstate"],"explanation":"تنطبق الحدود الأساسية في آيوا (80,000 رطل للوزن الإجمالي، و20,000 رطل للمحور الواحد، و34,000 رطل للمحور المزدوج) على كل من الطرق الـ Interstate والطرق الأساسية. وتنطبق بعض الاستثناءات القانونية للوزن الإضافي فقط على النظام غير الـ Interstate، لأن الـ Interstate محدود فيدرالياً بـ 80,000 رطل. المصدر: قانون آيوا 321.463؛ Iowa DOT."},"9":{"q":"مركبة نقل ماشية في آيوا بخمسة محاور ومقطورة ذات محاور متباعدة (spread-axle) مستوفية لمتطلبات التباعد، يجوز لها حمل وزن إجمالي أعلى على أي من الطرق التالية؟","options":["الطرق السريعة غير الـ Interstate (الأساسية) فقط، حتى 86,000 رطل","الطرق السريعة الـ Interstate فقط، حتى 86,000 رطل","جميع الطرق السريعة بما فيها الـ Interstate، حتى 90,000 رطل","طرق المقاطعات الحصوية فقط، حتى 80,000 رطل"],"explanation":"يسمح القسم 321.463 من قانون آيوا لمركبة نقل ماشية بخمسة محاور بوزن إجمالي يصل إلى 86,000 رطل على الطرق غير الـ Interstate عندما تكون المسافة بين المحور الأول والمحور الخامس 61 قدماً على الأقل، والمسافة بين المحورين الخلفيين (المتباعدين) 8 أقدام وبوصة واحدة على الأقل. ولا ينطبق ذلك على الـ Interstate. المصدر: قانون آيوا 321.463."},"10":{"q":"بموجب قانون آيوا، يجوز للمركبة التي تنقل منتجات زراعية خام أن تتجاوز وزنها الإجمالي المسجّل (وزن التسجيل) بنسبة تصل إلى كم؟","options":["25 بالمئة","10 بالمئة","15 بالمئة","50 بالمئة"],"explanation":"تسمح آيوا للشاحنات التي تنقل منتجات زراعية خام بأن تعمل بنسبة تصل إلى 25 بالمئة فوق وزنها المسجّل أثناء وجودها في آيوا (مع بقائها خاضعة لحدود المحاور وصيغة الجسور). المصدر: إرشادات ناقلي البضائع لدى Iowa DOT؛ الفصل 321 من قانون آيوا."},"11":{"q":"متى يكون تصريح Iowa DOT للحمولة الزائدة الحجم/الزائدة الوزن مطلوباً لحمولة ما؟","options":["عندما تكون الحمولة غير قابلة للتجزئة وتتجاوز الحدود القانونية للحجم أو الوزن","كلما زاد وزن المركبة عن 26,001 رطل","فقط عندما تعبر المركبة حدود الولاية","في أي وقت يقود فيه سائق CDL بعد حلول الظلام"],"explanation":"يُصدَر التصريح لمركبة أو حمولة غير قابلة للتجزئة تتجاوز الحدود القانونية للحجم أو الوزن. وتُعتبر الحمولة غير قابلة للتجزئة إذا كان فصلها سيدمّر قيمتها، أو يعرّض استخدامها المقصود للخطر، أو يتطلب أكثر من ثماني ساعات عمل لتفكيكها. المصدر: متطلبات تصاريح الحمولة الزائدة الحجم/الزائدة الوزن لدى Iowa DOT؛ الفصل 321E من قانون آيوا."},"12":{"q":"ماذا يعني أن تكون الحمولة \"غير قابلة للتجزئة\" بحيث تكون مؤهلة لتصريح آيوا للحمولة الزائدة الحجم/الزائدة الوزن؟","options":["أنه لا يمكن تقليصها بشكل معقول إلى الأبعاد/الوزن القانوني دون تدمير قيمتها، أو تعريض استخدامها للخطر، أو استغراق أكثر من 8 ساعات عمل لتفكيكها","أنها مختومة في حاوية مقفلة","أنها مملوكة لناقل واحد","أنها تزن 80,000 رطل بالضبط"],"explanation":"تعامل آيوا، اتباعاً للتعريفات الفيدرالية، الحمولة على أنها غير قابلة للتجزئة عندما يكون تقليصها إلى الحدود القانونية سيدمّر قيمتها، أو يعرّض استخدامها المقصود للخطر، أو يتطلب أكثر من ثماني ساعات عمل لتفكيكها باستخدام المعدات المناسبة. أما الحمولات القابلة للتجزئة فلا يمكن منحها تصريحاً عموماً. المصدر: متطلبات التصاريح لدى Iowa DOT؛ 23 CFR 658.5."},"13":{"q":"كيف يتقدّم الناقل بطلب للحصول على تصريح Iowa DOT للحمولة الزائدة الحجم/الزائدة الوزن؟","options":["عبر الإنترنت من خلال نظام تصاريح Iowa DOT (ia.gotpermits.com) أو عن طريق البريد","فقط شخصياً في مكتب عمدة المقاطعة (sheriff)","عن طريق الاتصال بإدارة سلامة ناقلي البضائع الفيدرالية (FMCSA)","فقط من خلال الشركة المصنّعة للمركبة"],"explanation":"يتم الحصول على تصاريح Iowa DOT للحمولة الزائدة الحجم/الزائدة الوزن عبر الإنترنت من خلال بوابة تصاريح الولاية (ia.gotpermits.com) أو عن طريق البريد. وتغطي التصاريح الطرق التابعة للولاية والطرق الـ Interstate فقط؛ وتُطلب تصاريح منفصلة لطرق المدن أو المقاطعات. المصدر: تصاريح الحمولة الزائدة الحجم/الزائدة الوزن لدى Iowa DOT."},"14":{"q":"تصريح آيوا القياسي للرحلة الواحدة للحمولة الزائدة الحجم/الزائدة الوزن يكون صالحاً عادةً لمدة كم؟","options":["5 أيام","24 ساعة","30 يوماً","سنة واحدة"],"explanation":"يكون تصريح آيوا القياسي للرحلة الواحدة (رحلة واحدة/ذهاب وعودة) صالحاً لمدة 5 أيام تقويمية. أما تصاريح الرحلات المتعددة فمدتها 60 يوماً والتصاريح السنوية مدتها 12 شهراً. المصدر: أنواع تصاريح الحمولة الزائدة الحجم/الزائدة الوزن لدى Iowa DOT."},"15":{"q":"تصريح Iowa DOT للحمولة الزائدة الحجم/الزائدة الوزن يُجيز السفر على أي من الطرق التالية؟","options":["الطرق التابعة للولاية والطرق الـ Interstate فقط؛ وتُطلب تصاريح منفصلة لطرق المدن والمقاطعات","جميع الطرق العامة في آيوا، بما في ذلك جميع شوارع المدن وطرق المقاطعات","نظام الـ Interstate فقط","طرق النقل الخاصة فقط"],"explanation":"تغطي تصاريح Iowa DOT نظام الطرق الأساسية التابعة للولاية والطرق الـ Interstate. وللسفر على شوارع المدن أو طرق المقاطعات، يجب على الناقل الحصول على تصاريح منفصلة من تلك الجهات المحلية. المصدر: متطلبات تصاريح الحمولة الزائدة الحجم/الزائدة الوزن لدى Iowa DOT."},"16":{"q":"على طرق آيوا السريعة، تُطلب عموماً علامات التحذير من الحمولة الزائدة الحجم وأعلام الزوايا بمجرد أن تتجاوز المركبة وحمولتها أي من الأبعاد التالية؟","options":["75 قدماً في الطول، أو 8 أقدام و6 بوصات في العرض، أو 14 قدماً و4 بوصات في الارتفاع","40 قدماً في الطول أو 8 أقدام في العرض","100 قدم في الطول أو 12 قدماً في العرض","53 قدماً في الطول أو 10 أقدام في العرض"],"explanation":"تشترط آيوا علامات \"Oversize Load\" والأعلام عندما تتجاوز المركبة المرخّصة وحمولتها 75 قدماً في الطول، و/أو 8 أقدام و6 بوصات في العرض، و/أو 14 قدماً و4 بوصات في الارتفاع. وتُعلَّم أطراف الحمولة بأعلام حمراء (مربعة بقياس 18 بوصة). المصدر: شروط التصاريح بموجب Iowa DOT/مدونة آيوا الإدارية الفصل 761-511."},"17":{"q":"بالنسبة للحمولة الزائدة الحجم، عند أي عرض تقريباً تبدأ آيوا عموماً بطلب مركبة مرافقة (مرشدة) واحدة على الأقل؟","options":["عندما يكون عرض الحمولة أكثر من 14 قدماً و6 بوصات","عندما يكون عرض الحمولة أكثر من 8 أقدام و6 بوصات","عندما يكون عرض الحمولة أكثر من 10 أقدام","لا تُطلب المركبات المرافقة أبداً في آيوا"],"explanation":"في آيوا، تتطلب الحمولات التي يزيد عرضها عن 14 قدماً و6 بوصات عموماً مركبة مرافقة واحدة على الأقل؛ أما الحمولات التي يصل عرضها إلى 14 قدماً و6 بوصات والتي تشغل أكثر من نصف الطريق فقد تستخدم بدلاً من ذلك مركبة مرافقة أمامية أو أضواء تحذير كهرمانية. وقد تفرض مسارات معينة متطلبات أكثر صرامة. المصدر: شروط التصاريح بموجب Iowa DOT/مدونة آيوا الإدارية الفصل 761-511."},"18":{"q":"بموجب شروط التصاريح المعتادة في آيوا، متى يجوز لحمولة كبيرة زائدة الحجم (حمولة أكبر من أن تسافر على مدار الساعة طوال الأسبوع) أن تتحرك؟","options":["من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، بما في ذلك أيام السبت والأحد، مع تجهيزات السلامة المناسبة","فقط بين منتصف الليل والساعة 4 صباحاً","فقط في أيام الأسبوع، وليس أبداً في عطلات نهاية الأسبوع أو الأعياد","في أي وقت دون قيود على وقت اليوم"],"explanation":"تسمح شروط التصاريح في آيوا للحمولات الأكبر الزائدة الحجم بالسفر من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، بما في ذلك عطلات نهاية الأسبوع، مع الإضاءة/التعليم المناسب. أما الحمولات المرخّصة الأصغر (ضمن الحدود المحددة) فقد تتحرك بشكل متواصل (على مدار الساعة طوال الأسبوع). المصدر: شروط التصاريح بموجب Iowa DOT/مدونة آيوا الإدارية الفصل 761-511."},"19":{"q":"تقدّم آيوا تصريحاً متخصصاً للحمولة الزائدة الحجم/الزائدة الوزن مخصصاً تحديداً لنقل أي من السلع المتعلقة بالغابات التالية بأوزان أعلى من الحد القانوني؟","options":["منتجات الغابات الخام","الأثاث الجاهز","العملة الورقية","زينة عيد الميلاد"],"explanation":"من بين التصاريح المتخصصة في آيوا تصريح منتجات الغابات الخام (Raw Forest Products)، الذي يستوعب (مثل التسهيلات الزراعية) حصاد/نقل منتجات الغابات غير المعالَجة فوق الحدود القياسية بموجب شروط محددة. المصدر: أنواع تصاريح الحمولة الزائدة الحجم/الزائدة الوزن لدى Iowa DOT."},"20":{"q":"بموجب قواعد آيوا، أي فئة من CDL مطلوبة لتشغيل مركبة مركّبة بتصنيف وزن إجمالي مركّب (GCWR) قدره 26,001 رطل أو أكثر، حيث تكون الوحدة (الوحدات) المقطورة بتصنيف وزن إجمالي للمركبة (GVWR) يزيد عن 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D (سائق محترف/chauffeur)"],"explanation":"تُصدر آيوا CDL من الفئة A للمركبات المركّبة بتصنيف GCWR قدره 26,001 رطلاً فأكثر حيث تتجاوز الوحدة المقطورة 10,000 رطل من GVWR. المصدر: دليل CDL لـ Iowa DOT / 761 IAC 607.16؛ Iowa DOT 'أنواع رخص القيادة والقيود والتظهيرات (Endorsements).'"},"21":{"q":"يقود سائق في آيوا شاحنة مستقيمة واحدة بتصنيف GVWR قدره 30,000 رطل ويقطر مقطورة صغيرة مصنّفة بـ 8,000 رطل من GVWR. أي فئة من CDL مطلوبة؟","options":["الفئة C","الفئة A","الفئة B","لا حاجة لأي CDL"],"explanation":"تغطي CDL من الفئة B في آيوا المركبة الواحدة بتصنيف GVWR قدره 26,001 رطلاً فأكثر، بما في ذلك قطر وحدة لا يزيد وزنها عن 10,000 رطل من GVWR. وبما أن وزن المقطورة أقل من 10,001 رطل، فهذه فئة B، وليست فئة A. المصدر: دليل CDL لـ Iowa DOT / صفحة أنواع الرخص لدى Iowa DOT؛ 761 IAC 607.16."},"22":{"q":"في آيوا، المركبة التي يقل تصنيف GVWR لها عن 26,001 رطل لكنها مصممة لنقل 16 شخصاً أو أكثر (بما في ذلك السائق)، أو تُستخدم لنقل مواد خطرة (HazMat) تتطلب لوحات تحذير (placards)، تتطلب أي فئة من CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تنطبق CDL من الفئة C في آيوا على المركبات التي تقل عن عتبات الوزن للفئتين A/B والتي إما تنقل 16 شخصاً فأكثر (بما في ذلك السائق) أو تنقل مواد خطرة تتطلب لوحات تحذير. المصدر: Iowa DOT 'أنواع رخص القيادة والقيود والتظهيرات'؛ 761 IAC 607.16."},"23":{"q":"في آيوا، ما هو الحد الأدنى للعمر للحصول على CDL للقيادة داخل الولاية (INTRASTATE) (تشغيل المركبات التجارية داخل آيوا فقط)؟","options":["16 عاماً","18 عاماً","21 عاماً","19 عاماً"],"explanation":"تسمح آيوا بالحصول على CDL للتجارة داخل الولاية (داخل آيوا) عند سن 18. أما القيادة بين الولايات فتتطلب سن 21. المصدر: Iowa DOT Commercial Drivers / Iowa Tax And Tags CDL Endorsements؛ معيار FMCSA المعتمد من آيوا."},"24":{"q":"في آيوا، ما هو الحد الأدنى للعمر لتشغيل مركبة آلية تجارية في التجارة بين الولايات (INTERSTATE) (عبور حدود الولايات)؟","options":["18 عاماً","19 عاماً","21 عاماً","20 عاماً"],"explanation":"تشترط آيوا، اتباعاً للمعيار الفيدرالي، أن يكون عمر السائقين 21 عاماً على الأقل للقيادة في التجارة بين الولايات أو لنقل المواد الخطرة. ويقتصر السائقون من سن 18 إلى 20 على التشغيل داخل الولاية. المصدر: Iowa DOT Commercial Drivers؛ FMCSA 49 CFR 391.11 كما تُطبَّق في آيوا."},"25":{"q":"أي تظهير (endorsement) من CDL تشترطه آيوا لنقل المواد الخطرة بكميات تتطلب وضع لوحات تحذير (placards) على المركبة؟","options":["تظهير N","تظهير H","تظهير T","تظهير X"],"explanation":"تظهير H (المواد الخطرة/Hazardous Materials) مطلوب لنقل المواد الخطرة المعلَّمة باللوحات. المصدر: Iowa Tax And Tags CDL Endorsements؛ دليل CDL لـ Iowa DOT. (ملاحظة: يشير تظهير X إلى تظهير مدمج للصهاريج + المواد الخطرة.)"},"26":{"q":"بالإضافة إلى اجتياز اختبار المعرفة الكتابي، ما هو المتطلب الفيدرالي الإضافي الذي يجب على المتقدم في آيوا استيفاؤه للحصول على تظهير المواد الخطرة (H) (وتجديده)؟","options":["اختبار مهارات قيادة منفصل على متن صهريج","تقييم تهديد أمني قائم على بصمات الأصابع من TSA (فحص خلفية)","خبرة لا تقل عن سنتين في القيادة بـ CDL","إعفاء بصري من FMCSA"],"explanation":"يتطلب تظهير H تقييم تهديد أمني من TSA قائماً على بصمات الأصابع عند التقديم الأولي ومرة أخرى عند كل تجديد، بالإضافة إلى اختبار معرفة المواد الخطرة. المصدر: Iowa Tax And Tags CDL Endorsements؛ برنامج TSA لتقييم تهديد تظهير المواد الخطرة المعتمد في آيوا."},"27":{"q":"أي تظهير CDL في آيوا مطلوب لقيادة مركبة صهريج، المعرّفة بأنها نقل سوائل أو غازات في صهريج بسعة فردية مصنّفة تزيد عن 119 غالوناً وسعة إجمالية مصنّفة تبلغ 1,000 غالون أو أكثر؟","options":["N (صهريج/Tank)","H (مواد خطرة/HazMat)","T (مزدوجة/ثلاثية)","P (ركاب/Passenger)"],"explanation":"يغطي تظهير N (صهريج/Tank) المركبات الصهريجية المستوفية لعتبات السعة الفردية البالغة 119 غالوناً والسعة الإجمالية البالغة 1,000 غالون، ويتطلب اجتياز اختبار معرفة الصهاريج. المصدر: Iowa Tax And Tags CDL Endorsements؛ دليل CDL لـ Iowa DOT."},"28":{"q":"أي تظهير CDL في آيوا مطلوب لقطر مقطورات مزدوجة أو ثلاثية؟","options":["تظهير P","تظهير N","تظهير T","تظهير S"],"explanation":"تظهير T (المزدوجة/الثلاثية)، الذي يُحصل عليه باجتياز اختبار معرفة المقطورات المزدوجة والثلاثية، مطلوب لقطر مقطورات متعددة. المصدر: Iowa Tax And Tags CDL Endorsements؛ دليل CDL لـ Iowa DOT."},"29":{"q":"فيما يتعلق بالمقطورات الثلاثية في آيوا، أي عبارة صحيحة بالنسبة لسائق يحمل تظهير T؟","options":["يحظر قانون آيوا تشغيل المقطورات الثلاثية داخل الولاية، رغم أنه يجوز للمقيم الحصول على تظهير T لاستخدامه في ولايات أخرى","يجوز تشغيل المقطورات الثلاثية على أي طريق Interstate في آيوا","يُسمح بالمقطورات الثلاثية فقط على طرق الرسوم في آيوا","تشترط آيوا تظهيراً منفصلاً 'Y' للمقطورات الثلاثية"],"explanation":"يحظر قانون آيوا تشغيل المقطورات الثلاثية داخل الولاية؛ ومع ذلك، يجوز لمقيم في آيوا الحصول على تظهير T لتشغيل المقطورات الثلاثية بشكل قانوني في الولايات التي تسمح بها. المصدر: Iowa Tax And Tags CDL Endorsements؛ حدود الطول/التركيبة في الفصل 321 من قانون آيوا."},"30":{"q":"أي تظهير CDL في آيوا مطلوب لقيادة مركبة مصممة لنقل 16 شخصاً أو أكثر، بما في ذلك السائق؟","options":["S (حافلة مدرسية/School Bus)","P (ركاب/Passenger)","N (صهريج/Tank)","C (سائق محترف/Chauffeur)"],"explanation":"تظهير P (الركاب/Passenger) مطلوب للمركبات المصممة لنقل 16 شخصاً أو أكثر بما في ذلك السائق. ويتطلب اجتياز اختبار معرفة الركاب بالإضافة إلى اختبار المهارات على متن مركبة ممثلة. المصدر: Iowa Tax And Tags CDL Endorsements؛ دليل CDL لـ Iowa DOT."},"31":{"q":"في آيوا، ماذا يجب أن يحمل السائق بالإضافة إلى تظهير الحافلة المدرسية (S) ليتمكن قانونياً من تشغيل حافلة مدرسية؟","options":["تظهير الركاب (P)","تظهير الصهريج (N)","تظهير المواد الخطرة (H)","لا شيء إضافي؛ فتظهير S وحده كافٍ"],"explanation":"تشترط آيوا حمل تظهيري الحافلة المدرسية (S) والركاب (P) معاً لتشغيل حافلة مدرسية؛ فتظهير P وحده غير صالح لتشغيل الحافلة المدرسية. المصدر: Iowa Tax And Tags CDL Endorsements؛ دليل CDL لـ Iowa DOT."},"32":{"q":"كم من الوقت يجب أن يحمل المتقدم تصريح المتعلم التجاري (CLP) في آيوا قبل أن يُسمح له بإجراء اختبار مهارات (الطريق) لـ CDL؟","options":["7 أيام على الأقل","14 يوماً على الأقل","30 يوماً على الأقل","60 يوماً على الأقل"],"explanation":"تشترط القاعدة الفيدرالية، المطبقة في آيوا، حمل CLP لمدة لا تقل عن 14 يوماً قبل إجراء اختبار المهارات. المصدر: صفحة Iowa DOT Commercial Learner Permits (CLP)؛ 49 CFR 383.25."},"33":{"q":"ما هي مدة صلاحية تصريح المتعلم التجاري (CLP) في آيوا؟","options":["180 يوماً، قابلة للتجديد مرة واحدة","سنة واحدة من تاريخ الإصدار، دون فترة تجديد","سنتان، قابلة للتجديد","90 يوماً، غير قابلة للتجديد"],"explanation":"تبلغ تكلفة CLP في آيوا 12 دولاراً وهو صالح لمدة سنة واحدة من تاريخ الإصدار، دون فترة تجديد. المصدر: صفحة Iowa DOT Commercial Learner Permits (CLP)."},"34":{"q":"ماذا يجب أن يمتلك المتقدم بالفعل قبل التقدم بطلب للحصول على تصريح المتعلم التجاري (CLP) أو CDL في آيوا؟","options":["رخصة قيادة غير تجارية صالحة من آيوا","بطاقة TWIC الفيدرالية","خبرة قيادة عسكرية لمدة سنتين","رخصة دراجة نارية من الفئة M"],"explanation":"تشترط آيوا أن يحمل المتقدمون رخصة قيادة غير تجارية صالحة من آيوا قبل التقدم للحصول على CLP أو CDL. المصدر: صفحة Iowa DOT Commercial Learner Permits (CLP) / Iowa Tax And Tags."},"35":{"q":"يجب إكمال تدريب السائقين المبتدئين (ELDT) في آيوا من خلال أي جهة قبل الاختبار؟","options":["أي مدرب قيادة خاص يختاره المتقدم","مزوّد مدرج في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA","مكتب أمين الخزانة في المقاطعة المحلية","أكاديمية تدريب دورية ولاية آيوا (Iowa State Patrol) فقط"],"explanation":"يجب أن يُقدَّم ELDT من قبل جهة مدرجة في سجل مزوّدي التدريب (Training Provider Registry) التابع لـ FMCSA؛ فلا يجوز سوى للمزوّدين المسجلين تقديم التدريب المطلوب. المصدر: سجل مزوّدي التدريب لدى FMCSA؛ Iowa DOT Commercial Drivers (ينطبق ELDT في آيوا)."},"36":{"q":"تدريب السائقين المبتدئين (ELDT) مطلوب للمتقدمين لأول مرة على أي مما يلي في آيوا؟","options":["CDL من الفئة A أو الفئة B، والتظهيرات S أو P أو H لأول مرة","تظهير المواد الخطرة (H) فقط","تظهير المزدوجة/الثلاثية (T) فقط","تجديدات أي CDL قائم"],"explanation":"يُطلب ELDT للمتقدمين لأول مرة على CDL من الفئة A أو الفئة B، ولترقية من الفئة B إلى الفئة A، وللتظهيرات الأولى للحافلة المدرسية (S) أو الركاب (P) أو المواد الخطرة (H) (نظري فقط لتظهير H). المصدر: قاعدة ELDT لدى FMCSA (لمن حصل على CLP في 7 فبراير 2022 أو بعده)؛ تنطبق في آيوا."},"37":{"q":"حامل CDL في آيوا الذي يقود مركبة تجارية في التجارة بين الولايات ولا يُعفى من قواعد التأهيل البدني الفيدرالية ينبغي أن يصدّق ذاتياً (self-certify) في أي فئة طبية؟","options":["معفى بين الولايات (Excepted interstate)","غير معفى بين الولايات (Non-excepted interstate)","غير معفى داخل الولاية (Non-excepted intrastate)","معفى داخل الولاية (Excepted intrastate)"],"explanation":"يجب على السائق غير المعفى بين الولايات أن يصدّق ذاتياً على ذلك وأن يحتفظ بشهادة الفاحص الطبي (Medical Examiner's Certificate) سارية مودَعة لدى Iowa DOT؛ والإخفاق في ذلك يؤدي إلى تخفيض الرخصة (downgrade). المصدر: Iowa DOT Medical Cards & Certification؛ 761 IAC 607.50."},"38":{"q":"أي فئة من فئات التصديق الذاتي الطبي لا تتطلب تقديم شهادة الفاحص الطبي (Medical Examiner's Certificate) إلى Iowa DOT؟","options":["غير معفى بين الولايات (Non-excepted interstate)","غير معفى داخل الولاية (Non-excepted intrastate)","يجب على الفئات الأربع جميعها تقديمها","السائقون من خارج الولاية فقط معفون"],"explanation":"فقط فئة غير المعفى بين الولايات يجب عليها تقديم شهادة الفاحص الطبي إلى Iowa DOT. أما السائقون غير المعفيين داخل الولاية فيحملونها لكن لا يلزمهم إيداعها، والفئات المعفاة لا تحتاج أياً منها؛ وتتلقى الفئات داخل الولاية قيداً 'K'. المصدر: Iowa DOT Medical Cards & Certification؛ 761 IAC 607.50."},"39":{"q":"أي مجموعة من المستندات تشترط Iowa DOT على المتقدم تقديمها عند التقدم لأول مرة للحصول على CDL/CLP؟","options":["إثبات الهوية/التواجد القانوني، ورقم الضمان الاجتماعي، والإقامة في آيوا","جواز سفر فقط","نموذج عسكري DD-214 فقط","إثبات تأمين المركبة وتسجيلها فقط"],"explanation":"تشترط آيوا إثبات الهوية والجنسية الأمريكية أو التواجد القانوني، ورقم الضمان الاجتماعي، والتحقق من الإقامة في آيوا (مثل رخصة بعنوان حالي في آيوا). المصدر: صفحة Iowa DOT Commercial Learner Permits (CLP)؛ 761 IAC 607."},"40":{"q":"في آيوا، ما هو الحد الأقصى لتركيز الكحول الذي يجوز أن يكون لدى الشخص مع بقائه قانونياً قادراً على تشغيل مركبة آلية تجارية (CMV)؟","options":["0.04","0.08","0.02","0.05"],"explanation":"يحرم القسم 321.208(1)(a) من قانون آيوا السائق الذي يشغّل CMV بتركيز كحول (كما هو معرّف في 321J.1) قدره 0.04 أو أكثر من الأهلية. وبالتالي فإن الحد القانوني لـ CMV هو أقل من 0.04، أي نصف حد الـ 0.08 المطبق على السائقين العاديين. المصدر: قانون آيوا 321.208 / دليل CDL لآيوا."},"41":{"q":"بموجب قانون الموافقة الضمنية في آيوا، ماذا يحدث لحامل CDL الذي يرفض الخضوع للفحص الكيميائي المطلوب بموجب الفصل 321J بعد طلب قانوني؟","options":["يُعامَل كجريمة كبرى، تماماً مثل إدانة بالكحول، ويترتب عليه فقدان الأهلية","لا يحدث شيء لـ CDL لأن الرفض حق دستوري","تُفرض غرامة مدنية صغيرة فقط دون فقدان الأهلية","يتلقى السائق تحذيراً كتابياً عن أول رفض"],"explanation":"يعامل القسمان 321.208(2)(b) و321.208(13) من قانون آيوا رفض الخضوع للفحص الكيميائي بموجب الفصل 321J كجريمة كبرى، تحمل نفس فقدان الأهلية المترتب على إدانة بقيادة المركبة تحت تأثير الكحول (OWI). المصدر: قانون آيوا 321.208 / دليل CDL لآيوا."},"42":{"q":"كم تبلغ مدة فقدان السائق لأهلية تشغيل CMV عن أول جريمة كبرى (مثل OWI أو قيادة CMV بتركيز كحول 0.04 أو أكثر) عند عدم نقل مواد خطرة معلَّمة باللوحات؟","options":["سنة واحدة","3 سنوات","60 يوماً","مدى الحياة"],"explanation":"يفرض القسمان 321.208(1) و(2) من قانون آيوا فقدان أهلية تشغيل CMV لمدة سنة واحدة عن أول جريمة كبرى مثل التشغيل بتركيز كحول قدره 0.04 أو أكثر، أو OWI، أو رفض الفحص. المصدر: قانون آيوا 321.208 (يطابق 49 CFR 383.51)."},"43":{"q":"إذا وقعت أول جريمة كبرى (مثل OWI أو 0.04 BAC) أثناء قيام السائق بتشغيل CMV ينقل مواد خطرة معلَّمة باللوحات، تزداد مدة فقدان الأهلية إلى كم؟","options":["3 سنوات","سنة واحدة","5 سنوات","مدى الحياة"],"explanation":"يرفع القسم 321.208(3) من قانون آيوا مدة فقدان الأهلية عن الجريمة الأولى من سنة واحدة إلى ثلاث سنوات عندما تقع الجريمة أثناء قيام الـ CMV بنقل مواد خطرة تتطلب لوحات تحذير بموجب 49 CFR 383.5. المصدر: قانون آيوا 321.208."},"44":{"q":"ما هي عقوبة ارتكاب جريمة كبرى ثانية (في حادثتين منفصلتين أو أكثر)، مثل OWI ثانٍ أو رفض فحص؟","options":["فقدان الأهلية مدى الحياة (والذي قد يُخفَّض لاحقاً إلى 10 سنوات)","فقدان الأهلية لمدة 3 سنوات","فقدان الأهلية لمدة سنة واحدة","فقدان الأهلية لمدة 120 يوماً"],"explanation":"يحرم القسم 321.208(4) من قانون آيوا السائق من الأهلية مدى الحياة عند ارتكاب جريمتين كبريين أو أكثر من حوادث منفصلة. ويجوز تخفيض فقدان الأهلية مدى الحياة إلى 10 سنوات وفقاً لما هو منصوص عليه في 49 CFR 383.51 بموجب قاعدة الإدارة. المصدر: قانون آيوا 321.208."},"45":{"q":"كم تبلغ مدة فقدان السائق للأهلية لتراكم مخالفتين مروريتين خطيرتين أثناء تشغيل CMV خلال فترة ثلاث سنوات؟","options":["60 يوماً","120 يوماً","30 يوماً","سنة واحدة"],"explanation":"يفرض القسم 321.208(8) من قانون آيوا فقدان الأهلية لمدة 60 يوماً عن مخالفتين مروريتين خطيرتين خلال أي فترة ثلاث سنوات. المصدر: قانون آيوا 321.208 / دليل CDL لآيوا."},"46":{"q":"كم تبلغ مدة فقدان السائق للأهلية لتراكم ثلاث مخالفات مرورية خطيرة أثناء تشغيل CMV خلال فترة ثلاث سنوات؟","options":["120 يوماً","60 يوماً","180 يوماً","سنة واحدة"],"explanation":"يفرض القسم 321.208(8) من قانون آيوا فقدان الأهلية لمدة 120 يوماً عن ثلاث مخالفات مرورية خطيرة خلال أي فترة ثلاث سنوات. وتُحتسب فترات فقدان الأهلية المتعددة بشكل متتالٍ. المصدر: قانون آيوا 321.208."},"47":{"q":"أي مما يلي يُصنَّف كمخالفة مرورية خطيرة تُحتسب ضمن فقدان أهلية تشغيل CMV في آيوا؟","options":["تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد القانوني للسرعة","تجاوز السرعة بمقدار 5 mph فوق الحد القانوني للسرعة","مخالفة وقوف بـ CMV","مخالفة وزن مركبة (وزن زائد)"],"explanation":"يدرج القسم 321.208(7)(d) من قانون آيوا تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد كمخالفة خطيرة. أما مخالفات الوقوف ووزن المركبة فمستبعَدة صراحةً من احتساب المخالفات الخطيرة. المصدر: قانون آيوا 321.208."},"48":{"q":"بموجب قانون آيوا، تُصنَّف الكتابة عبر الرسائل النصية أثناء قيادة مركبة آلية تجارية كأي نوع من مخالفات CDL؟","options":["مخالفة مرورية خطيرة","جريمة كبرى تترتب عليها فقدان الأهلية لمدة سنة واحدة","مخالفة لأمر إيقاف عن الخدمة (out-of-service)","مخالفة معدات بسيطة دون أثر على فقدان الأهلية"],"explanation":"يدرج القسم 321.208(7)(i) من قانون آيوا انتهاك قانون يحظر الكتابة عبر الرسائل النصية أثناء قيادة CMV كمخالفة مرورية خطيرة، تُحتسب ضمن فقدان الأهلية لمدة 60 يوماً/120 يوماً. المصدر: قانون آيوا 321.208."},"49":{"q":"استخدام هاتف محمول باليد أثناء قيادة CMV، بما يخالف قانوناً للتحكم المروري، يُعامَل في آيوا على أنه:","options":["مخالفة مرورية خطيرة تُحتسب ضمن فقدان الأهلية","جريمة كبرى مع فقدان الأهلية مدى الحياة","مخالفة دون أثر على CDL","فقدان أهلية تلقائي لمدة سنة واحدة"],"explanation":"يدرج القسم 321.208(7)(j) من قانون آيوا انتهاك قانون يقيّد أو يحظر استخدام هاتف محمول باليد أثناء قيادة CMV كمخالفة مرورية خطيرة، تُحتسب ضمن عتبات فقدان الأهلية لمدة 60/120 يوماً. المصدر: قانون آيوا 321.208."},"50":{"q":"بالنسبة لأول مخالفة لأمر الإيقاف عن الخدمة (out-of-service) (لا تتعلق بالمواد الخطرة أو بمركبة مصممة لـ 16 راكباً فأكثر)، يكون نطاق فقدان الأهلية في آيوا:","options":["ما لا يقل عن 180 يوماً وما لا يزيد عن سنة واحدة","ما لا يقل عن 60 يوماً وما لا يزيد عن 120 يوماً","ما لا يقل عن 30 يوماً وما لا يزيد عن 90 يوماً","ما لا يقل عن سنتين وما لا يزيد عن 5 سنوات"],"explanation":"يحدد القسم 321.208(10)(a) من قانون آيوا أول مخالفة لأمر الإيقاف عن الخدمة بما لا يقل عن 180 يوماً وما لا يزيد عن سنة واحدة. المصدر: قانون آيوا 321.208."},"51":{"q":"بالنسبة لثاني مخالفة لأمر الإيقاف عن الخدمة في حوادث منفصلة خلال 10 سنوات (غير متعلقة بالمواد الخطرة)، يكون نطاق فقدان الأهلية في آيوا:","options":["ما لا يقل عن سنتين وما لا يزيد عن 5 سنوات","ما لا يقل عن 180 يوماً وما لا يزيد عن سنة واحدة","ما لا يقل عن سنة واحدة وما لا يزيد عن 3 سنوات","مدى الحياة"],"explanation":"يحدد القسم 321.208(10)(a) من قانون آيوا ثاني مخالفة لأمر الإيقاف عن الخدمة (خلال فترة 10 سنوات) بما لا يقل عن سنتين وما لا يزيد عن خمس سنوات. المصدر: قانون آيوا 321.208."},"52":{"q":"أول مخالفة لأمر الإيقاف عن الخدمة تُرتكب أثناء نقل مواد خطرة معلَّمة باللوحات، أو أثناء تشغيل CMV مصممة لنقل أكثر من 15 راكباً، تؤدي إلى فقدان أهلية مدته:","options":["سنة واحدة","180 يوماً","3 سنوات","60 يوماً"],"explanation":"يفرض القسم 321.208(10)(b) من قانون آيوا فقدان الأهلية لمدة سنة واحدة عن أول مخالفة لأمر الإيقاف عن الخدمة عند نقل مواد خطرة معلَّمة باللوحات أو تشغيل CMV مصممة لأكثر من 15 راكباً (بما في ذلك السائق). المصدر: قانون آيوا 321.208."},"53":{"q":"كم تبلغ مدة فقدان السائق للأهلية عن أول مخالفة لتقاطع سكة حديد مع طريق سريع (railroad-highway grade crossing) تُرتكب أثناء تشغيل CMV في آيوا؟","options":["60 يوماً","120 يوماً","30 يوماً","سنة واحدة"],"explanation":"يفرض القسم 321.208(11)(a) من قانون آيوا فقدان الأهلية لمدة 60 يوماً عن أول مخالفة لتقاطع سكة حديد على نفس المستوى (بموجب 321.341 أو 321.343) تُرتكب أثناء تشغيل CMV. المصدر: قانون آيوا 321.208."},"54":{"q":"السائق المدان بمخالفة ثانية لتقاطع سكة حديد مع طريق سريع في CMV، خلال ثلاث سنوات من الأولى، يفقد الأهلية لمدة:","options":["120 يوماً","60 يوماً","180 يوماً","سنة واحدة"],"explanation":"يفرض القسم 321.208(11)(b) من قانون آيوا فقدان الأهلية لمدة 120 يوماً عن مخالفة ثانية لتقاطع سكة حديد على نفس المستوى في CMV تقع خلال ثلاث سنوات من الأولى. المصدر: قانون آيوا 321.208."},"55":{"q":"السائق المدان بمخالفة ثالثة أو لاحقة لتقاطع سكة حديد مع طريق سريع في CMV، خلال ثلاث سنوات من الأولى، يفقد الأهلية لمدة:","options":["سنة واحدة","120 يوماً","60 يوماً","180 يوماً"],"explanation":"يفرض القسم 321.208(11)(c) من قانون آيوا فقدان الأهلية لمدة سنة واحدة عن مخالفة ثالثة أو لاحقة لتقاطع سكة حديد على نفس المستوى في CMV تقع خلال ثلاث سنوات من الأولى. المصدر: قانون آيوا 321.208."},"56":{"q":"استخدام مركبة آلية تجارية في ارتكاب جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها يؤدي إلى أي عقوبة على CDL في آيوا؟","options":["فقدان الأهلية مدى الحياة دون إمكانية التخفيض","فقدان الأهلية لمدة سنة واحدة","فقدان الأهلية لمدة 3 سنوات","فقدان الأهلية لمدة 120 يوماً"],"explanation":"يفرض القسم 321.208(5) من قانون آيوا فقدان الأهلية مدى الحياة، دون أن يخضع لتخفيض الـ 10 سنوات، عند استخدام CMV في جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها. المصدر: قانون آيوا 321.208."},"57":{"q":"عندما تتلقى Iowa DOT سجلاً بإدانة موجبة لفقدان الأهلية، كم تبلغ مدة الإشعار المسبق الذي تمنحه قبل أن يدخل فقدان أهلية تشغيل CMV حيز التنفيذ؟","options":["30 يوماً","10 أيام","60 يوماً","24 ساعة"],"explanation":"ينص القسمان 321.208(12) و(13) من قانون آيوا على أن الإدارة تُسقط أهلية السائق دون جلسة استماع تمهيدية بإشعار مسبق مدته 30 يوماً؛ ويكون تاريخ سريان فقدان الأهلية بعد 30 يوماً من الإشعار. المصدر: قانون آيوا 321.208."},"58":{"q":"سائق CMV الذي يثبت ضابط إنفاذ القانون أن لديه تركيز كحول قدره 0.04 أو أكثر، بالإضافة إلى مواجهته فقدان الأهلية، يُوضع فوراً:","options":["خارج الخدمة لمدة 24 ساعة","يُسمح له بالقيادة بعد راحة لمدة ساعة واحدة","يُسمح له بالاستمرار إذا كان أقل من 0.08","يُغرَّم 25 دولاراً ويُطلق سراحه للقيادة"],"explanation":"تشترط القواعد الفيدرالية المعتمدة في آيوا (49 CFR 392.5) وضع أي سائق بتركيز كحول قدره 0.04 أو أكثر خارج الخدمة لمدة 24 ساعة، بشكل منفصل عن فقدان الأهلية الرسمي بموجب قانون آيوا 321.208. المصدر: 49 CFR 392.5 / دليل CDL لآيوا."},"59":{"q":"إدانتان منفصلتان بجريمتين كبريين ناشئتان عن حادثتين منفصلتين تؤديان إلى فقدان أهلية CDL مدى الحياة في آيوا. وبموجب القاعدة الفيدرالية المعتمدة من آيوا، يجوز تخفيض هذه المدة مدى الحياة إلى حد أدنى قدره:","options":["10 سنوات","5 سنوات","3 سنوات","سنة واحدة"],"explanation":"يجعل القسم 321.208(4) من قانون آيوا فقدان الأهلية مدى الحياة (عن جريمتين كبريين أو أكثر) خاضعاً للتخفيض إلى فقدان أهلية لمدة 10 سنوات وفقاً لما هو منصوص عليه في 49 CFR 383.51 ومعتمد بموجب قاعدة الإدارة. المصدر: قانون آيوا 321.208."},"60":{"q":"بموجب قانون \"أفسح الطريق\" في ولاية آيوا، عندما تقترب من مركبة طوارئ متوقفة وأضواؤها الوامضة مشغّلة أثناء قيادتك على طريق سريع بين الولايات يضم مسارين في اتجاهك، فماذا يلزمك قانون آيوا بأن تفعله أولاً؟","options":["الانتقال إلى مسار غير ملاصق للمركبة المتوقفة إذا كان من الآمن فعل ذلك","التوقف توقفاً تاماً على الكتف حتى تغادر مركبة الطوارئ","إطلاق البوق والاستمرار في المرور في المسار نفسه بسرعتك الحالية","الانعطاف إلى الكتف الأيسر والانتظار حتى يشير لك ضابط أمن بالمرور"],"explanation":"يلزم قانون آيوا 321.323A السائق الذي يقترب من مركبة ساكنة بأضواء وامضة مفعّلة، على طريق يضم مسارين أو أكثر في اتجاه السائق، بأن يغيّر مساره إلى مسار غير ملاصق لتلك المركبة عندما يكون ذلك آمناً وقانونياً. المصدر: Iowa Code 321.323A؛ Iowa DOT 'Move Over or Slow Down.'"},"61":{"q":"بموجب قانون \"أفسح الطريق\" في ولاية آيوا، إذا كان تغيير المسار بعيداً عن مركبة متوقفة تعرض أضواءً وامضة مستحيلاً أو غير آمن، فماذا يجب على سائق آيوا أن يفعل؟","options":["الحفاظ على السرعة المعلنة لكن مع تشغيل أضواء التحذير (الفلاشر)","تخفيض السرعة إلى أقل من حد السرعة المعلن والاستعداد للتوقف","تخفيض السرعة إلى 20 mph بالضبط دون حد السرعة المعلن","التباطؤ إلى 10 mph بغض النظر عن حد السرعة المعلن"],"explanation":"ينص قانون آيوا 321.323A على أنه عندما يكون تغيير المسار مستحيلاً أو محظوراً أو غير آمن، يجب على السائق تخفيض السرعة إلى سرعة معقولة ومناسبة تكون أقل من حد السرعة المعلن والاستعداد للتوقف. ولا تحدد آيوا قيمة ثابتة لتخفيض السرعة بالـ mph. المصدر: Iowa Code 321.323A؛ Iowa DOT."},"62":{"q":"أيٌّ من هذه المركبات الساكنة، عند عرضها لأضوائها الوامضة أو التحذيرية المطلوبة، يشمله قانون \"أفسح الطريق\" في ولاية آيوا (Iowa Code 321.323A)؟","options":["مركبات إنفاذ القانون والإطفاء فقط","سيارات الإسعاف وشاحنات القطر فقط","مركبة جمع النفايات الصلبة أو إعادة التدوير","المركبات المملوكة لـ Iowa DOT فقط"],"explanation":"يشمل قانون آيوا 321.323A مركبات الطوارئ المرخّصة الساكنة، ومركبات القطر/الإنقاذ، ومركبات الصيانة والإنشاء، ومركبات جمع النفايات الصلبة أو إعادة التدوير ذات الأضواء الوامضة، وأي مركبة آلية تعرض باستمرار أضواء التحذير الخاصة بها. المصدر: Iowa Code 321.323A؛ Iowa DOT."},"63":{"q":"على طريق سريع ريفي بين الولايات في آيوا، ما هو حد السرعة الأقصى الذي ينطبق على شاحنة بمقطورة (تراكتور-تريلر)؟","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"يحدد قانون آيوا 321.285 حد السرعة على شبكة الطرق السريعة بين الولايات بـ 70 mph لجميع حركة المركبات. ولا تفرض آيوا حد سرعة منفصلاً أدنى للشاحنات على الطرق السريعة بين الولايات. المصدر: Iowa Code 321.285."},"64":{"q":"هل تحدد آيوا حد سرعة أدنى للشاحنات على الطرق السريعة بين الولايات مقارنة بسيارات الركاب؟","options":["نعم، تُحدّ الشاحنات بـ 65 mph بينما يمكن للسيارات القيادة بـ 70 mph","لا، حد السرعة على الطرق السريعة بين الولايات البالغ 70 mph ينطبق على جميع حركة المركبات على حد سواء","نعم، تُحدّ الشاحنات بـ 60 mph على مستوى الولاية","نعم، تُحدّ الشاحنات التي يزيد وزنها عن 26,000 lbs بـ 55 mph"],"explanation":"على عكس بعض الولايات التي تطبّق حدود سرعة \"مقسّمة\"، يطبّق قانون آيوا 321.285 الحد الأقصى البالغ 70 mph على الطرق السريعة بين الولايات على جميع حركة المركبات، دون حد سرعة منفصل معلن للشاحنات. المصدر: Iowa Code 321.285."},"65":{"q":"حافلة نقل عام في آيوا تنقل ركاباً مقابل أجر تقترب من ملتقى سكة حديد. أين يجب على السائق أن يتوقف؟","options":["على مسافة لا تقل عن 15 feet ولا تزيد عن 50 feet من أقرب قضيب سكة","على مسافة لا تقل عن 10 feet ولا تزيد عن 25 feet من أقرب قضيب سكة","على مسافة لا تقل عن 25 feet ولا تزيد عن 75 feet من أقرب قضيب سكة","ضمن 5 feet من أقرب قضيب سكة"],"explanation":"يلزم قانون آيوا 321.343 المركبة التي تنقل ركاباً مقابل أجر، أو حافلة مدرسية، أو مركبة تحمل لافتات مواد خطرة، بالتوقف ضمن 50 feet لكن على مسافة لا تقل عن 15 feet من أقرب قضيب سكة قبل العبور. المصدر: Iowa Code 321.343."},"66":{"q":"سائق ينقل حمولة تحمل لافتات مواد خطرة في آيوا يصل إلى ملتقى سكة حديد منصوب عليه لافتة \"EXEMPT\" (مُعفى). ما المطلوب؟","options":["التوقف ضمن 15 إلى 50 feet من أقرب قضيب سكة على أي حال","التوقف فقط إذا كان هناك قطار في الأفق","السائق غير ملزم بالتوقف عند ذلك الملتقى","التوقف ووضع مثلثات تحذيرية قبل العبور"],"explanation":"يلزم قانون آيوا 321.343 بالتوقف للحافلات، والمركبات التي تنقل ركاباً مقابل أجر، ومركبات المواد الخطرة التي تحمل لافتات، لكن الملتقى المنصوب عليه لافتة رسمية \"EXEMPT\" لا يستلزم التوقف. المصدر: Iowa Code 321.343؛ Iowa CDL Manual."},"67":{"q":"بعد التوقف عند ملتقى سكة حديد، ماذا يجب على سائق الحافلة المدرسية في آيوا أن يفعل قبل المضي عبر القضبان؟","options":["إطلاق البوق مرتين والمضي دون تأخير","فتح باب الدخول، والنظر والإصغاء بحثاً عن القطارات، ثم العبور فقط عندما يكون آمناً","الانتظار 60 ثانية كاملة بغض النظر عن الظروف","تشغيل المصابيح التحذيرية الكهرمانية والعبور بهدوء"],"explanation":"بموجب قانون آيوا 321.343، بعد التوقف على مسافة 15 إلى 50 feet من أقرب قضيب سكة، يجب على سائق الحافلة المدرسية فتح باب الدخول، والنظر والإصغاء بحثاً عن قطار مقترب، وعدم المضي حتى يكون العبور آمناً. المصدر: Iowa Code 321.343."},"68":{"q":"على طريق سريع ذي مسارين في آيوا، تتوقف حافلة مدرسية وتشغّل مصابيحها الحمراء الوامضة وتمدّ ذراع التوقف لإنزال الأطفال. ماذا يجب على السائق المقترب أن يفعل؟","options":["التباطؤ إلى 20 mph والمرور بحذر","التوقف على مسافة لا تقل عن 15 feet من الحافلة والبقاء متوقفاً حتى يُسحب ذراع التوقف","التوقف فقط إذا كان الأطفال مرئيين على الطريق","الانتقال إلى المسار البعيد وتجاوز الحافلة ببطء"],"explanation":"يلزم قانون آيوا 321.372 المركبات التي تقابل أو تتجاوز حافلة مدرسية متوقفة بمصابيحها الحمراء الوامضة وذراع التوقف ممدوداً بالتوقف على مسافة لا تقل عن 15 feet والبقاء متوقفة حتى يُسحب ذراع التوقف وتتحرك الحافلة مجدداً. المصدر: Iowa Code 321.372."},"69":{"q":"بموجب قانون الحافلات المدرسية في آيوا، على أي نوع من الطرق السريعة يجوز للسائق الذي يقابل حافلة مدرسية متوقفة تسير في الاتجاه المعاكس أن يستمر دون توقف؟","options":["أي طريق سريع يحمل خطاً مرسوماً في المنتصف","طريق سريع يوفّر مسارين أو أكثر للسير في كل اتجاه","أي طريق سريع بسرعة معلنة 55 mph أو أعلى","طريق سريع بأكتاف مرصوفة لا يقل عرضها عن 8 feet"],"explanation":"ينص قانون آيوا 321.372 على أن السائق على طريق سريع يضم مسارين أو أكثر في كل اتجاه لا يحتاج إلى التوقف عند مقابلة حافلة مدرسية تسير في الاتجاه المعاكس، حتى لو كانت متوقفة. أما على الطرق غير المقسّمة، فيجب على جميع الاتجاهات التوقف. المصدر: Iowa Code 321.372."},"70":{"q":"على طريق سريع في آيوا يضم مسارين في كل اتجاه مفصولين بجزيرة وسطية، تتوقف حافلة مدرسية في مسارات الاتجاه المعاكس وأضواؤها الحمراء وامضة. السائق الذي يسير في الاتجاه الآخر يكون:","options":["ملزماً بالتوقف حتى تنطفئ الأضواء الحمراء","ملزماً بالتباطؤ إلى 10 mph لكن يجوز له الاستمرار","غير ملزم بالتوقف لأن الطريق يضم مسارين أو أكثر في كل اتجاه","ملزماً بالتوقف فقط إذا كان عرض الجزيرة الوسطية أقل من 6 feet"],"explanation":"يعتمد استثناء الطريق المقسّم في قانون آيوا 321.372 على عدد المسارات: على طريق سريع يضم مسارين أو أكثر في كل اتجاه، لا يحتاج السائقون الذين يقابلون حافلة متوقفة في الاتجاه المعاكس إلى التوقف. المصدر: Iowa Code 321.372."},"71":{"q":"تعمل حافلة مدرسية على طريق سريع في آيوا يضم أربعة مسارات أو أكثر. فيما يخص التلاميذ الذين يجب عليهم عبور الطريق السريع، فإن الحافلة:","options":["يجوز لها تحميلهم أو إنزالهم في أي مكان طالما أن الأضواء الحمراء مشغّلة","لا يجوز لها التوقف لتحميل أو إنزال التلاميذ الذين يجب عليهم عبور الطريق السريع إلا في نقاط محددة","يجب أن تستخدم المسار الأيسر لإنزالهم","يجوز لها إنزالهم فقط بين الساعة 7 a.m. و7 p.m."],"explanation":"يحظر قانون آيوا 321.372 على الحافلة المدرسية الموجودة على طريق سريع يضم أربعة مسارات أو أكثر التوقف لتحميل أو إنزال التلاميذ الذين يجب عليهم عبور الطريق السريع، إلا عند المحطات/النقاط المحددة المزوّدة بأجهزة تحكم في المرور أو ضباط. المصدر: Iowa Code 321.372."},"72":{"q":"عندما تستعد حافلة مدرسية في آيوا للتوقف من أجل الركاب، أي مصابيح تحذيرية يجب أن تعرضها قبل تشغيل المصابيح الحمراء الوامضة؟","options":["مصابيح خضراء وامضة","مصابيح زرقاء وامضة","مصابيح تحذيرية كهرمانية (صفراء) وامضة","مصابيح ومضية بيضاء (سترُوب)"],"explanation":"يتطلب قانون آيوا وقواعد النقل المدرسي في آيوا من السائق عرض مصابيح تحذيرية كهرمانية وامضة قبل التوقف، ثم التحويل إلى مصابيح حمراء وامضة ومدّ ذراع التوقف عند التوقف. المصدر: Iowa Code 321.372؛ Iowa Admin. Code 281-43."},"73":{"q":"سائق CDL يوقف شاحنة على طريق سريع مستوٍ ومستقيم ذي مسارين في آيوا ويجب عليه وضع المثلثات التحذيرية الثلاثة المطلوبة. الوضع الصحيح هو:","options":["واحد على بُعد 10 ft للخلف، وواحد على بُعد 100 ft للخلف، وواحد على بُعد 100 ft للأمام","واحد على بُعد 25 ft للخلف، وواحد على بُعد 250 ft للخلف، وواحد على بُعد 250 ft للأمام","واحد على بُعد 5 ft، وواحد على بُعد 50 ft، وواحد على بُعد 150 ft، جميعها للخلف","الثلاثة جميعها توضع على بُعد 200 ft خلف المركبة"],"explanation":"تتبع آيوا القاعدة الفيدرالية (49 CFR 392.22) المُدرَّسة في Iowa CDL Manual: على طريق ذي مسارين، توضع المثلثات على بُعد حوالي 10 ft للخلف، و100 ft للخلف، و100 ft أمام المركبة. المصدر: 49 CFR 392.22؛ Iowa CDL Manual."},"74":{"q":"وفقاً لـ Iowa CDL Manual، خلال أي مدة بعد توقف مركبة تجارية معطّلة على الطريق أو الكتف يجب وضع أجهزة التحذير (المثلثات)؟","options":["خلال 3 minutes","خلال 10 minutes","خلال 30 minutes","خلال 1 hour"],"explanation":"تتبع آيوا القاعدة 49 CFR 392.22، التي تلزم السائق بوضع أجهزة التحذير المطلوبة خلال 10 minutes من التوقف. المصدر: 49 CFR 392.22؛ Iowa CDL Manual."},"75":{"q":"سائق CDL يتوقف على طريق سريع باتجاه واحد أو مقسّم في آيوا. أين تُوضع المثلثات التحذيرية الثلاثة؟","options":["10 ft و100 ft و200 ft باتجاه حركة المرور المقتربة (للخلف)","10 ft و100 ft و100 ft، واحد للخلف واثنان للأمام","الثلاثة جميعها على بُعد 10 ft من المركبة على كل جانب","100 ft للأمام، و100 ft للخلف، وواحد بجانب الكابينة"],"explanation":"تتبع آيوا القاعدة 49 CFR 392.22: على طريق سريع باتجاه واحد أو مقسّم، توضع المثلثات على بُعد 10 ft و100 ft و200 ft باتجاه حركة المرور المقتربة. المصدر: 49 CFR 392.22؛ Iowa CDL Manual."},"76":{"q":"قاعدة \"الزم اليمين\" العامة في آيوا (Iowa Code 321.297) توجّه أي مركبات إلى القيادة في المسار الأيمن؟","options":["المركبات المسجّلة كمركبات تجارية فقط","المركبات التي تقطر مقطورات فقط","أي مركبة تتحرك أبطأ من السرعة الطبيعية لحركة المرور، إلا عند التجاوز أو الانعطاف يساراً","المركبات التي يزيد وزنها الإجمالي عن 26,000 pounds فقط"],"explanation":"يلزم قانون آيوا 321.297 أي مركبة تسير أبطأ من السرعة الطبيعية لحركة المرور باستخدام المسار الأيمن، إلا عند التجاوز أو الاستعداد للانعطاف يساراً. وليس لدى آيوا حظر على المسار الأيسر خاص بالشاحنات؛ بل تنطبق القاعدة على جميع حركة المرور الأبطأ. المصدر: Iowa Code 321.297."},"77":{"q":"في آيوا، قبل أن تتطلب المركبة/الحمولة تصريح حجم زائد، فإن الحد الأقصى القانوني للعرض للسير على الطرق العامة هو:","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"تحدد آيوا، تماشياً مع المعيار الفيدرالي، الحد الأقصى القانوني للعرض بـ 8 feet 6 inches؛ وأي شيء أعرض من ذلك يحتاج إلى تصريح حجم زائد. المصدر: Iowa DOT Motor Carrier Services, Oversize/Overweight Permit Requirements؛ Iowa Code ch. 321."},"78":{"q":"في آيوا، يبلغ ارتفاع حمولة غير قابلة للتقسيم 13 feet 6 inches. بدون تصريح، هذا الارتفاع يكون:","options":["فوق الحد القانوني؛ يُطلب تصريح فوق 13 feet 6 inches","أقل بكثير من الحد؛ قانوني حتى 16 feet","فوق الحد؛ الحد الأقصى القانوني هو 12 feet","قانوني فقط إذا كان عرض الحمولة لا يتجاوز 8 feet"],"explanation":"تُدرج Iowa DOT الحد الأقصى القانوني للارتفاع بـ 13 feet 6 inches؛ والحمولات التي تتجاوز 13 feet 6 inches تتطلب تصريح حجم زائد. المصدر: Iowa DOT Oversize/Overweight Permit Requirements."},"79":{"q":"بموجب قواعد تصاريح الحجم الزائد في آيوا، متى يُسمح عموماً بنقل حمولة بحجم زائد؟","options":["فقط بين الساعة 9 a.m. و3 p.m. في أيام الأسبوع","24 ساعة في اليوم دون حدود زمنية","من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها","ليلاً فقط لتجنب حركة المرور"],"explanation":"تسمح آيوا عموماً بنقل الحمولات ذات الحجم الزائد من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، سبعة أيام في الأسبوع، مع قيود في بعض العطلات وللحمولات الكبيرة جداً. المصدر: Iowa DOT Motor Carrier Services oversize/overweight permit rules."},"80":{"q":"أي جهة تصدر رخص القيادة التجارية (CDLs) في آيوا؟","options":["إدارة النقل في آيوا (Iowa DOT)","الإدارة الفيدرالية لسلامة الناقلين بالمركبات (FMCSA)","إدارة السلامة العامة في آيوا","إدارة أمن النقل (TSA)"],"explanation":"تُصدر رخص CDL في آيوا من قبل إدارة النقل في آيوا (Iowa DOT)، وهي جهة ترخيص السائقين في الولاية. تضع FMCSA المعايير الفيدرالية لرخص CDL لكنها لا تصدر الرخص. المصدر: Iowa DOT, Commercial Drivers / How to Get a CDL (iowadot.gov)."},"81":{"q":"أين يمكن لمقدم الطلب أن يجري اختبارات المعرفة والمهارات الخاصة برخصة CDL في آيوا؟","options":["في مواقع مختارة لخدمات رخص القيادة التابعة لـ Iowa DOT وأمين خزينة المقاطعة (County Treasurer)","فقط في المقر الرئيسي الوحيد لـ Iowa DOT في Ames","في أي مكتب ميداني لـ FMCSA في الولاية","في أي قسم شرطة محلي في آيوا"],"explanation":"يُدار اختبار CDL في آيوا في مواقع مختارة لرخص القيادة التابعة لـ Iowa DOT وأمين خزينة المقاطعة؛ وتُدرج مواقع إضافية في صفحة مواقع اختبار CDL لدى Iowa DOT. المصدر: Iowa DOT, CDL Testing (iowadot.gov)."},"82":{"q":"ما هو الحد الأدنى العام للعمر للحصول على رخصة CDL في آيوا للقيادة داخل الولاية (داخل آيوا فقط)؟","options":["18 سنة","16 سنة","21 سنة","25 سنة"],"explanation":"تشترط آيوا أن يكون عمر مقدم طلب رخصة CDL 18 سنة على الأقل للقيادة تجارياً داخل آيوا (داخل الولاية). أما القيادة عبر حدود الولايات (بين الولايات) فتتطلب سن 21 سنة. المصدر: Iowa DOT, How to Get a CDL (iowadot.gov)."},"83":{"q":"ما هو الحد الأدنى للعمر المطلوب لتشغيل مركبة تجارية في التجارة بين الولايات برخصة CDL من آيوا؟","options":["21 سنة","18 سنة","19 سنة","23 سنة"],"explanation":"بموجب القاعدة الفيدرالية المطبّقة في آيوا، يجب أن يكون عمر السائق 21 سنة على الأقل لتشغيل مركبة تجارية في التجارة بين الولايات؛ ويقتصر من تتراوح أعمارهم بين 18 و20 سنة على القيادة داخل الولاية. المصدر: Iowa DOT, How to Get a CDL؛ 49 CFR 391.11 (المعيار الفيدرالي)."},"84":{"q":"أي مستند يجب على مقدم طلب رخصة CDL في آيوا تقديمه لإثبات الهوية والوضع القانوني عند التقديم؟","options":["إثبات الاسم الكامل وتاريخ الميلاد ورقم الضمان الاجتماعي (Social Security number) والجنسية أو الوضع القانوني","فقط فاتورة مرافق حالية باسم مقدم الطلب","خطاب موقّع من صاحب عمل حالي فقط","شهادة الثانوية العامة أو شهادة GED"],"explanation":"تشترط آيوا إثبات الاسم القانوني الكامل وتاريخ الميلاد ورقم الضمان الاجتماعي والجنسية أو الإقامة الدائمة القانونية (مثل شهادة الميلاد أو جواز السفر أو بطاقة الإقامة الدائمة)، إضافة إلى إثبات الإقامة في آيوا. المصدر: Iowa DOT, How to Get a CDL (iowadot.gov)."},"85":{"q":"قبل الاختبار، يجب على كل مقدم طلب رخصة CDL في آيوا أن \"يصادق ذاتياً\" (self-certify). ماذا تعني المصادقة الذاتية؟","options":["الإعلان لـ Iowa DOT عن أي من فئات القيادة الأربع تصف طريقة تشغيلك للمركبة التجارية","توقيع إقرار بأنك لا تملك أي مخالفات مرورية","الوعد بإكمال التدريب خلال سنة واحدة","المصادقة على أنك تملك المركبة التي ستختبر بها"],"explanation":"المصادقة الذاتية هي إعلان السائق لـ Iowa DOT عن أي من فئات تشغيل المركبة التجارية الأربع تنطبق عليه؛ وهي تحدد ما إذا كان يجب أن تكون شهادة الفاحص الطبي على الملف. المصدر: Iowa DOT, Medical Cards & Certification؛ Iowa Admin. Code r. 761-607.50."},"86":{"q":"كم عدد فئات المصادقة الذاتية التي يجب على حامل رخصة CDL في آيوا الاختيار من بينها؟","options":["أربع","اثنتان","ثلاث","ست"],"explanation":"هناك أربع فئات: بين الولايات غير المُستثناة، وبين الولايات المُستثناة، وداخل الولاية غير المُستثناة، وداخل الولاية المُستثناة. المصدر: Iowa DOT, Medical Cards & Certification؛ Iowa Admin. Code r. 761-607.50."},"87":{"q":"أي فئة من فئات المصادقة الذاتية تتطلب وجود شهادة فاحص طبي حالية (Medical Examiner's Certificate) على الملف لدى Iowa DOT؟","options":["بين الولايات غير المُستثناة","بين الولايات المُستثناة","داخل الولاية المُستثناة","داخل الولاية غير المُستثناة"],"explanation":"فقط السائقون من فئة بين الولايات غير المُستثناة يجب عليهم تقديم شهادة فاحص طبي حالية والاحتفاظ بها على الملف لدى Iowa DOT. أما السائقون المُستثنون فلا يلزمهم ذلك، والسائقون داخل الولاية غير المُستثنين يجب أن يحملوا البطاقة لكن لا يلزمهم إيداعها لدى الولاية. المصدر: Iowa DOT, Medical Cards & Certification؛ Iowa Admin. Code r. 761-607.50."},"88":{"q":"بالنسبة لسائق آيوا من فئة بين الولايات غير المُستثناة، كيف تُقدَّم شهادة الفاحص الطبي التابعة لـ DOT إلى الولاية؟","options":["يقدمها الفاحص الطبي المعتمد إلكترونياً إلى السجل الوطني/نظام الولاية","يرسل السائق نسخة ورقية بالبريد إلى FMCSA في واشنطن العاصمة","يرسلها صاحب عمل السائق بالفاكس إلى أمين خزينة المقاطعة","تُنقل تلقائياً من برنامج الفوترة الخاص بالطبيب"],"explanation":"في آيوا، يقدّم الفاحص الطبي المعتمد الشهادة إلكترونياً؛ وتتدفق النتائج عبر السجل الوطني للفاحصين الطبيين المعتمدين (National Registry of Certified Medical Examiners) إلى الولاية. ولا يودعها السائق بنفسه بالنسبة لفئة بين الولايات غير المُستثناة. المصدر: Iowa DOT, Medical Cards & Certification."},"89":{"q":"حامل رخصة CDL في آيوا من فئة بين الولايات غير المُستثناة يترك شهادة الفاحص الطبي الخاصة به تنتهي صلاحيتها دون تقديم شهادة جديدة. ماذا يحدث لرخصة CDL؟","options":["تخفّض Iowa DOT رخصة CDL، فتزيل الامتيازات التجارية بعد إشعار/فترة سماح","لا يتغير شيء حتى تنتهي صلاحية رخصة CDL نفسها","تُلغى رخصة CDL نهائياً في اليوم نفسه الذي تنتهي فيه صلاحية البطاقة","يُنقل السائق تلقائياً إلى فئة داخل الولاية المُستثناة"],"explanation":"إذا انتهت صلاحية الشهادة الطبية، تضبط Iowa DOT الحالة الطبية على \"غير معتمد\"، وتعطي إشعاراً خطياً، وتزيل امتيازات المركبة التجارية (تخفيض) إذا لم تُستلم شهادة حالية خلال فترة الـ 60 day. المصدر: Iowa Admin. Code r. 761-607.50."},"90":{"q":"ما هو أول مستند يحصل عليه مقدم الطلب في آيوا ضمن عملية رخصة CDL، قبل اختبار المهارات؟","options":["تصريح متعلّم القيادة التجارية (CLP)","رخصة CDL كاملة وغير مقيّدة","تأييد المواد الخطرة (HazMat)","شهادة إعفاء طبي"],"explanation":"بعد اجتياز اختبار(ات) المعرفة المطلوبة واستيفاء متطلبات المستندات/الطبية، يحصل مقدم الطلب على تصريح متعلّم القيادة التجارية (CLP)، الذي يتيح التدريب تحت الإشراف قبل اختبار المهارات. المصدر: Iowa DOT, How to Get a CDL؛ Commercial Learner Permits (iowadot.gov)."},"91":{"q":"ماذا يجب على مقدم الطلب في آيوا أن يجتاز ليُمنح تصريح متعلّم القيادة التجارية (CLP)؟","options":["اختبار معرفة CDL (الكتابي) المعمول به وفحص النظر","اختبار المهارات المكوّن من ثلاثة أجزاء فقط","اختبار طريق في سيارته الشخصية","فحص الخلفية لدى TSA الخاص بالمواد الخطرة (hazmat)"],"explanation":"يُصدر تصريح CLP بعد أن يجتاز مقدم الطلب اختبار(ات) معرفة CDL المعمول بها وفحص النظر، ويقدم المستندات المطلوبة؛ ويأتي اختبار المهارات لاحقاً. المصدر: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"92":{"q":"كم من الوقت يجب على مقدم الطلب في آيوا أن يحمل تصريح متعلّم القيادة التجارية قبل إجراء اختبار مهارات CDL؟","options":["14 days على الأقل","30 days على الأقل","7 days على الأقل","60 days على الأقل"],"explanation":"تطبّق آيوا القاعدة الفيدرالية التي تشترط حمل تصريح CLP لمدة لا تقل عن 14 days قبل إمكانية إجراء اختبار المهارات. المصدر: Iowa DOT, How to Get a CDL / Commercial Learner Permits؛ 49 CFR 383.25."},"93":{"q":"ما مدة صلاحية تصريح متعلّم القيادة التجارية (CLP) في آيوا، وهل يمكن تجديده؟","options":["صالح لمدة سنة واحدة ولا يمكن تجديده (يجب الحصول على تصريح CLP جديد)","صالح لمدة 180 day ويمكن تجديده مرة واحدة","صالح لمدة سنتين وقابل للتجديد سنوياً","صالح لمدة 60 day مع تجديدات غير محدودة"],"explanation":"تصريح CLP في آيوا صالح لمدة سنة واحدة من تاريخ الإصدار وغير قابل للتجديد؛ وإذا انتهت صلاحيته، يجب على مقدم الطلب إعادة التقديم. المصدر: Iowa DOT, Commercial Learner Permits (CLP) (iowadot.gov)."},"94":{"q":"بالنسبة لتصاريح CLP الصادرة في أو بعد February 7, 2022، ماذا يجب إكماله والتحقق منه قبل أن يتمكن مقدم الطلب في آيوا من إجراء اختبار مهارات CDL؟","options":["تدريب السائق المبتدئ (ELDT) من مزوّد تدريب مسجّل","دورة قيادة دفاعية في كلية مجتمع","ما لا يقل عن 160 hours من وقت القيادة غير المدفوع","اختبار معرفة ثانٍ يُجرى بعد 30 days على الأقل"],"explanation":"يجب إكمال تدريب السائق المبتدئ (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA والتحقق منه قبل اختبار المهارات لتصاريح CLP الصادرة في أو بعد February 7, 2022. المصدر: Iowa DOT, How to Get a CDL؛ 49 CFR Part 380 Subpart F."},"95":{"q":"أين يُسجَّل إكمال ELDT بحيث يمكن لـ Iowa DOT التحقق منه قبل جدولة اختبار المهارات؟","options":["في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","على بطاقة CLP الخاصة بمقدم الطلب يدوياً","في دفتر سجلات ورقي يحتفظ به السائق","في قاعدة بيانات المواد الخطرة (Hazmat) التابعة لـ TSA"],"explanation":"يرفع المزوّدون المسجّلون شهادة ELDT إلى سجل مزوّدي التدريب التابع لـ FMCSA؛ وتتحقق Iowa DOT من ذلك السجل قبل أن يتسنى جدولة اختبار المهارات. المصدر: Iowa DOT, How to Get a CDL؛ FMCSA Training Provider Registry (49 CFR Part 380)."},"96":{"q":"يتكوّن اختبار مهارات CDL في آيوا من ثلاثة أجزاء. أي قائمة تسمّيها بشكل صحيح؟","options":["الفحص قبل الرحلة للمركبة، ومهارات التحكم الأساسية، والقيادة على الطريق","الاختبار الكتابي، واختبار النظر، واختبار السمع","اختبار مكابح الهواء، واختبار المواد الخطرة، واختبار التركيبة","الرجوع للخلف فقط، والركن الموازي فقط، والاندماج في الطريق السريع فقط"],"explanation":"يتألف اختبار المهارات في آيوا من ثلاثة أجزاء: الفحص قبل الرحلة للمركبة، واختبار مهارات التحكم الأساسية (المناورات والرجوع للخلف حول الأقماع)، واختبار القيادة على الطريق. المصدر: Iowa DOT, CDL Testing (iowadot.gov)؛ Iowa CDL Manual."},"97":{"q":"خلال جزء الفحص قبل الرحلة للمركبة من اختبار المهارات في آيوا، ماذا يُتوقع من مقدم الطلب أن يفعل؟","options":["السير حول المركبة والإشارة إلى كل عنصر أو لمسه مع شرح ما يُفحص ولماذا","مجرد التصريح بأن المركبة في حالة جيدة","تفكيك نظام المكابح للفاحص","قيادة المركبة على الطريق السريع مع وصف العدّادات"],"explanation":"في الفحص قبل الرحلة، يسير مقدم الطلب حول المركبة، ويشير إلى كل عنصر أو يلمسه، ويشرح للفاحص ما يجري فحصه ولماذا، لإظهار أن المركبة آمنة للقيادة. المصدر: Iowa DOT, CDL Testing (iowadot.gov)؛ Iowa CDL Manual."},"98":{"q":"ما هي مدة الصلاحية القصوى المعتادة لدورة تجديد رخصة CDL في آيوا لمعظم السائقين البالغين؟","options":["حتى 8 years (أقصر للسائقين الأكبر سناً، بحد أقصى قرب سن 80)","سنة واحدة بالضبط لجميع السائقين","حتى 15 years","30 days بالضبط"],"explanation":"يمكن إصدار رخص القيادة في آيوا، بما في ذلك رخص CDL، لمدة تصل إلى 8 years، مع مدد أقصر للسائقين الأكبر سناً وحد أقصى بحيث لا يمتد المستند إلى ما بعد عيد ميلاد السائق الـ 80 تقريباً. المصدر: Iowa Code 321.196؛ Iowa DOT, Renew a CDL."},"99":{"q":"في كل تجديد لرخصة CDL في آيوا، لماذا يجب على حامل تأييد المواد الخطرة (H) التجديد شخصياً بدلاً من التجديد عبر الإنترنت؟","options":["يجب عليهم إعادة اختبار معرفة المواد الخطرة (hazmat) وإكمال تقييم تهديد/فحص خلفية لدى TSA","التجديد عبر الإنترنت غير متاح أبداً لأي حامل رخصة CDL في آيوا","يجب عليهم التنازل عن التأييد نهائياً","يجب عليهم إكمال دورة نظرية ELDT جديدة عبر الإنترنت أولاً"],"explanation":"يجب على حاملي تأييد المواد الخطرة إعادة اختبار معرفة المواد الخطرة وإكمال تقييم تهديد أمني لدى TSA (فحص خلفية قائم على البصمات) في كل تجديد، لذا لا يمكنهم التجديد عبر الإنترنت ويجب عليهم التقديم شخصياً. المصدر: Iowa DOT, Renew a CDL؛ 49 CFR 1572 (TSA)."}}};
